//! AXON integration tests — C12: test suite nativo.
//!
//! Covers: lexer, parser, type checker, IR generator, ΛD codec.
//! Each test runs the pipeline from source text, not from .axon files.

use axon::epistemic;
use axon::lexer::Lexer;
use axon::parser::Parser;
use axon::type_checker::TypeChecker;
use axon::ir_generator::IRGenerator;
use axon::lambda_data::{self, LambdaData, Derivation};
use axon::runner;

// ═══════════════════════════════════════════════════════════════════════════
// Helpers
// ═══════════════════════════════════════════════════════════════════════════

/// Lex source and return all tokens (including trailing EOF).
/// Note: `axon check` reports token_count = tokens.len() which includes EOF.
fn lex(src: &str) -> Vec<axon::tokens::Token> {
    Lexer::new(src, "test.axon").tokenize().expect("lex failed")
}

fn parse(src: &str) -> axon::ast::Program {
    let tokens = lex(src);
    let mut parser = Parser::new(tokens);
    parser.parse().expect("parse failed")
}

fn type_check(src: &str) -> Vec<axon::type_checker::TypeError> {
    let program = parse(src);
    TypeChecker::new(&program).check()
}

fn compile_ir(src: &str) -> axon::ir_nodes::IRProgram {
    let program = parse(src);
    let errors = TypeChecker::new(&program).check();
    assert!(errors.is_empty(), "type errors: {:?}", errors);
    IRGenerator::new().generate(&program)
}

fn compile_json(src: &str) -> serde_json::Value {
    let ir = compile_ir(src);
    serde_json::to_value(&ir).expect("serialization failed")
}

// ═══════════════════════════════════════════════════════════════════════════
// Lexer tests
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn lexer_empty_source() {
    let tokens = lex("");
    // Only EOF
    assert_eq!(tokens.len(), 1);
    assert_eq!(tokens[0].ttype, axon::tokens::TokenType::Eof);
}

#[test]
fn lexer_keywords() {
    let tokens = lex("persona context anchor flow run");
    assert_eq!(tokens.len(), 6); // 5 keywords + EOF
    assert_eq!(tokens[0].ttype, axon::tokens::TokenType::Persona);
    assert_eq!(tokens[1].ttype, axon::tokens::TokenType::Context);
    assert_eq!(tokens[2].ttype, axon::tokens::TokenType::Anchor);
    assert_eq!(tokens[3].ttype, axon::tokens::TokenType::Flow);
    assert_eq!(tokens[4].ttype, axon::tokens::TokenType::Run);
}

#[test]
fn lexer_string_literal() {
    let tokens = lex(r#""hello world""#);
    assert_eq!(tokens.len(), 2); // string + EOF
    assert_eq!(tokens[0].ttype, axon::tokens::TokenType::StringLit);
    assert_eq!(tokens[0].value, "hello world");
}

#[test]
fn lexer_numbers() {
    let tokens = lex("42 3.14 0.5");
    assert_eq!(tokens.len(), 4); // 3 numbers + EOF
    assert_eq!(tokens[0].ttype, axon::tokens::TokenType::Integer);
    assert_eq!(tokens[0].value, "42");
    assert_eq!(tokens[1].ttype, axon::tokens::TokenType::Float);
    assert_eq!(tokens[1].value, "3.14");
}

#[test]
fn lexer_operators() {
    let tokens = lex("-> .. > < >= <=");
    assert_eq!(tokens[0].ttype, axon::tokens::TokenType::Arrow);
    assert_eq!(tokens[1].ttype, axon::tokens::TokenType::DotDot);
    assert_eq!(tokens[2].ttype, axon::tokens::TokenType::Gt);
    assert_eq!(tokens[3].ttype, axon::tokens::TokenType::Lt);
    assert_eq!(tokens[4].ttype, axon::tokens::TokenType::Gte);
    assert_eq!(tokens[5].ttype, axon::tokens::TokenType::Lte);
}

#[test]
fn lexer_comments_ignored() {
    let tokens = lex("persona // this is a comment\ncontext");
    assert_eq!(tokens.len(), 3); // 2 keywords + EOF
    assert_eq!(tokens[0].ttype, axon::tokens::TokenType::Persona);
    assert_eq!(tokens[1].ttype, axon::tokens::TokenType::Context);
}

#[test]
fn lexer_block_comments() {
    let tokens = lex("persona /* block comment */ context");
    assert_eq!(tokens.len(), 3); // 2 keywords + EOF
}

#[test]
fn lexer_contract_analyzer_count() {
    // Read the actual contract_analyzer.axon file for exact token parity
    let src = std::fs::read_to_string("../examples/contract_analyzer.axon")
        .expect("contract_analyzer.axon not found — run tests from axon-rs/");
    let tokens = lex(&src);
    assert_eq!(tokens.len(), 168, "contract_analyzer token count must be 168");
}

#[test]
fn lexer_error_unterminated_string() {
    let result = Lexer::new(r#""unterminated"#, "test.axon").tokenize();
    assert!(result.is_err());
}

#[test]
fn lexer_line_tracking() {
    let tokens = lex("persona\ncontext\nanchor");
    assert_eq!(tokens[0].line, 1);
    assert_eq!(tokens[1].line, 2);
    assert_eq!(tokens[2].line, 3);
}

