#[test]
fn parser_empty_program() {
    let program = parse("");
    assert_eq!(program.declarations.len(), 0);
}

#[test]
fn parser_persona() {
    let program = parse(r#"
persona Expert {
    domain: ["contracts"]
    tone: "analytical"
}
"#);
    assert_eq!(program.declarations.len(), 1);
    if let axon::ast::Declaration::Persona(p) = &program.declarations[0] {
        assert_eq!(p.name, "Expert");
        assert_eq!(p.tone, "analytical");
        assert_eq!(p.domain, vec!["contracts"]);
    } else {
        panic!("expected Persona");
    }
}

#[test]
fn parser_context() {
    let program = parse(r#"
context Deep {
    memory: session
    depth: deep
    temperature: 0.5
    max_tokens: 4096
}
"#);
    if let axon::ast::Declaration::Context(c) = &program.declarations[0] {
        assert_eq!(c.name, "Deep");
        assert_eq!(c.memory_scope, "session");
        assert_eq!(c.depth, "deep");
        assert_eq!(c.temperature, Some(0.5));
        assert_eq!(c.max_tokens, Some(4096));
    } else {
        panic!("expected Context");
    }
}

#[test]
fn parser_flow_with_steps() {
    let program = parse(r#"
flow Analyze(doc: String) -> Result {
    step Extract {
        given: doc
        ask: "Extract data"
        output: Data
    }
    step Assess {
        given: Extract.output
        ask: "Assess risks"
    }
}
"#);
    if let axon::ast::Declaration::Flow(f) = &program.declarations[0] {
        assert_eq!(f.name, "Analyze");
        assert_eq!(f.parameters.len(), 1);
        assert_eq!(f.parameters[0].name, "doc");
        assert_eq!(f.body.len(), 2);
    } else {
        panic!("expected Flow");
    }
}

