#[test]
fn parser_flow_tier2_steps() {
    let program = parse(r#"
flow Pipeline() {
    step Start { ask: "Begin" }
    probe Target
    reason Strategy
    validate Output
    refine Output
    focus Attention
    persist Store
}
"#);
    if let axon::ast::Declaration::Flow(f) = &program.declarations[0] {
        assert_eq!(f.body.len(), 7);
        assert!(matches!(&f.body[0], axon::ast::FlowStep::Step(_)));
        assert!(matches!(&f.body[1], axon::ast::FlowStep::Probe(_)));
        assert!(matches!(&f.body[2], axon::ast::FlowStep::Reason(_)));
        assert!(matches!(&f.body[3], axon::ast::FlowStep::Validate(_)));
        assert!(matches!(&f.body[4], axon::ast::FlowStep::Refine(_)));
        assert!(matches!(&f.body[5], axon::ast::FlowStep::Focus(_)));
        assert!(matches!(&f.body[6], axon::ast::FlowStep::Persist(_)));
    } else {
        panic!("expected Flow");
    }
}

#[test]
fn parser_conditional_in_flow() {
    let program = parse(r#"
flow Test() {
    if confidence > 0.8 {
        step Accept { ask: "Accept" }
    } else {
        step Reject { ask: "Reject" }
    }
}
"#);
    if let axon::ast::Declaration::Flow(f) = &program.declarations[0] {
        if let axon::ast::FlowStep::If(cond) = &f.body[0] {
            assert_eq!(cond.condition, "confidence");
            assert_eq!(cond.comparison_op, ">");
            assert_eq!(cond.then_body.len(), 1);
            assert_eq!(cond.else_body.len(), 1);
        } else {
            panic!("expected If");
        }
    } else {
        panic!("expected Flow");
    }
}

#[test]
fn parser_lambda_data() {
    let program = parse(r#"
lambda ExchangeRate {
    ontology: "finance.exchange"
    certainty: 0.95
    temporal_frame: "2024-01-01" .. "2024-12-31"
    provenance: "Reuters"
    derivation: "raw"
}
"#);
    if let axon::ast::Declaration::LambdaData(ld) = &program.declarations[0] {
        assert_eq!(ld.name, "ExchangeRate");
        assert_eq!(ld.ontology, "finance.exchange");
        assert_eq!(ld.certainty, 0.95);
        assert_eq!(ld.derivation, "raw");
    } else {
        panic!("expected LambdaData");
    }
}

