// Lambda Data codec tests
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn ld_encode_decode_roundtrip() {
    let original = LambdaData {
        name: "TestRate".to_string(),
        ontology: "finance.exchange".to_string(),
        value: vec![1, 2, 3, 4],
        certainty: 0.85,
        temporal_frame_start: "2024-01-01".to_string(),
        temporal_frame_end: "2024-12-31".to_string(),
        provenance: "Reuters".to_string(),
        derivation: Derivation::Raw,
    };

    let bytes = lambda_data::encode(&original).expect("encode failed");
    // Magic bytes: 0xCE 0x9B 0x44
    assert_eq!(bytes[0], 0xCE);
    assert_eq!(bytes[1], 0x9B);
    assert_eq!(bytes[2], 0x44);

    let decoded = lambda_data::decode(&bytes).expect("decode failed");
    assert_eq!(decoded.name, "TestRate");
    assert_eq!(decoded.ontology, "finance.exchange");
    assert_eq!(decoded.certainty, 0.85);
    assert_eq!(decoded.provenance, "Reuters");
    assert_eq!(decoded.value, vec![1, 2, 3, 4]);
    assert!(matches!(decoded.derivation, Derivation::Raw));
}

