#[test]
fn ld_compose_theorem_51() {
    let a = LambdaData {
        name: "A".to_string(),
        ontology: "test".to_string(),
        value: vec![],
        certainty: 0.9,
        temporal_frame_start: "2024-01-01".to_string(),
        temporal_frame_end: "2024-12-31".to_string(),
        provenance: "SourceA".to_string(),
        derivation: Derivation::Raw,
    };
    let b = LambdaData {
        name: "B".to_string(),
        ontology: "test".to_string(),
        value: vec![],
        certainty: 0.7,
        temporal_frame_start: "2024-06-01".to_string(),
        temporal_frame_end: "2024-12-31".to_string(),
        provenance: "SourceB".to_string(),
        derivation: Derivation::Derived,
    };
    let composed = lambda_data::compose(&a, &b, "AB", "test").expect("compose failed");
    // Theorem 5.1: c_out = min(0.9, 0.7) = 0.7
    assert_eq!(composed.certainty, 0.7);
    // δ_out = max(Raw=0, Derived=1) = Derived
    assert!(matches!(composed.derivation, Derivation::Derived));
    // τ_out = intersection
    assert_eq!(composed.temporal_frame_start, "2024-06-01");
    assert_eq!(composed.temporal_frame_end, "2024-12-31");
    // ρ_out = chain
    assert!(composed.provenance.contains("SourceA"));
    assert!(composed.provenance.contains("SourceB"));
}

