// C13: Epistemic lattice
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn epistemic_builtin_types_complete() {
    let bt = epistemic::builtin_types();
    // Epistemic types
    assert!(bt.contains("FactualClaim"));
    assert!(bt.contains("Opinion"));
    assert!(bt.contains("Speculation"));
    assert!(bt.contains("Uncertainty"));
    // Content types
    assert!(bt.contains("Document"));
    assert!(bt.contains("Summary"));
    assert!(bt.contains("Chunk"));
    // Analysis types
    assert!(bt.contains("RiskScore"));
    assert!(bt.contains("ConfidenceScore"));
    assert!(bt.contains("SentimentScore"));
    // Primitive types
    assert!(bt.contains("String"));
    assert!(bt.contains("Integer"));
    assert!(bt.contains("Float"));
    assert!(bt.contains("Boolean"));
    assert!(bt.contains("List"));
    // Lattice-internal
    assert!(bt.contains("Any"));
    assert!(bt.contains("Never"));
    assert!(bt.contains("HighConfidenceFact"));
    assert!(bt.contains("CitedFact"));
}

#[test]
fn epistemic_subtype_lattice_chain() {
    // HighConfidenceFact ≤ CitedFact ≤ FactualClaim ≤ Any
    assert!(epistemic::is_subtype("HighConfidenceFact", "CitedFact"));
    assert!(epistemic::is_subtype("HighConfidenceFact", "FactualClaim"));
    assert!(epistemic::is_subtype("HighConfidenceFact", "Any"));
    assert!(epistemic::is_subtype("CitedFact", "FactualClaim"));
    assert!(epistemic::is_subtype("FactualClaim", "Any"));
    // Not reverse
    assert!(!epistemic::is_subtype("Any", "FactualClaim"));
    assert!(!epistemic::is_subtype("FactualClaim", "CitedFact"));
}

#[test]
fn epistemic_never_is_bottom() {
    assert!(epistemic::is_subtype("Never", "Any"));
    assert!(epistemic::is_subtype("Never", "FactualClaim"));
    assert!(epistemic::is_subtype("Never", "String"));
    assert!(epistemic::is_subtype("Never", "Opinion"));
}

#[test]
fn epistemic_uncertainty_taints() {
    assert!(epistemic::is_subtype("Uncertainty", "FactualClaim"));
    assert!(epistemic::is_subtype("Uncertainty", "String"));
    assert_eq!(epistemic::join("FactualClaim", "Uncertainty"), "Uncertainty");
    assert_eq!(epistemic::join("Uncertainty", "String"), "Uncertainty");
}

#[test]
fn epistemic_coercions() {
    // FactualClaim/CitedFact → String
    assert!(epistemic::is_subtype("FactualClaim", "String"));
    assert!(epistemic::is_subtype("CitedFact", "String"));
    // Numeric scores → Float
    assert!(epistemic::is_subtype("RiskScore", "Float"));
    assert!(epistemic::is_subtype("ConfidenceScore", "Float"));
    assert!(epistemic::is_subtype("SentimentScore", "Float"));
    // StructuredReport → any output
    assert!(epistemic::is_subtype("StructuredReport", "ContractData"));
}

#[test]
fn epistemic_join_operations() {
    assert_eq!(epistemic::join("HighConfidenceFact", "CitedFact"), "CitedFact");
    assert_eq!(epistemic::join("FactualClaim", "Opinion"), "Any");
    assert_eq!(epistemic::join("Never", "FactualClaim"), "FactualClaim");
    assert_eq!(epistemic::join("String", "Never"), "String");
}

#[test]
fn epistemic_meet_operations() {
    assert_eq!(epistemic::meet("HighConfidenceFact", "FactualClaim"), "HighConfidenceFact");
    assert_eq!(epistemic::meet("FactualClaim", "HighConfidenceFact"), "HighConfidenceFact");
    assert_eq!(epistemic::meet("Opinion", "Speculation"), "Never");
}

#[test]
fn epistemic_propagate_uncertainty() {
    assert_eq!(epistemic::propagate_uncertainty(&["FactualClaim"]), "FactualClaim");
    assert_eq!(epistemic::propagate_uncertainty(&["CitedFact", "Opinion"]), "Any");
    assert_eq!(epistemic::propagate_uncertainty(&["HighConfidenceFact", "CitedFact"]), "CitedFact");
    // Uncertainty taints everything
    assert_eq!(
        epistemic::propagate_uncertainty(&["FactualClaim", "CitedFact", "Uncertainty"]),
        "Uncertainty"
    );
}

#[test]
fn epistemic_ranged_types() {
    let rt = epistemic::ranged_types();
    assert_eq!(rt["RiskScore"], (0.0, 1.0));
    assert_eq!(rt["ConfidenceScore"], (0.0, 1.0));
    assert_eq!(rt["SentimentScore"], (-1.0, 1.0));
}

