    // Full pipeline with trace
    let trace_path = "../examples/contract_analyzer.trace.json";
    // Clean up any prior trace
    let _ = std::fs::remove_file(trace_path);

    let exit_code = runner::run_run(
        "../examples/contract_analyzer.axon",
        "anthropic",
        true,
        "stub",
        false,
        "text",
        false,
    );
