    let src = r#"
persona Expert { tone: "analytical" }
context Deep { depth: "deep" }
anchor Facts { require: "verifiable" }
flow Analyze() { step Do { ask: "analyze" } }
run Analyze() as Expert within Deep constrained_by [Facts]
"#;
    let ir = compile_ir(src);
    assert_eq!(ir.runs.len(), 1);
