#[test]
fn backend_all_providers_recognized() {
    // All 7 providers should be recognized (get_api_key doesn't fail on unknown backend)
    use axon::backend;
    for name in backend::SUPPORTED_BACKENDS {
        // Clear env vars to get "not set" error (not "unknown backend" error)
        let result = backend::get_api_key(name);
        if *name == "ollama" {
            // Ollama allows empty key (local)
            assert!(result.is_ok(), "ollama should succeed with empty key");
        } else {
            // Other providers should fail with "not set", NOT "unknown backend"
            let err = result.unwrap_err();
            assert!(
                err.message.contains("not set"),
                "backend '{}' should be recognized but key not set, got: {}",
                name, err.message
            );
        }
    }
}

