// CLI Python-free (C21)
// ═══════════════════════════════════════════════════════════════════════════

/// Verify the native binary handles "serve" with exit code 2 (not yet native).
#[test]
fn cli_serve_starts_natively() {
    use std::time::Duration;

    let binary = std::path::Path::new(env!("CARGO_BIN_EXE_axon"));
    // Start the server on an unlikely port and kill it after 1s
    let mut child = std::process::Command::new(binary)
        .args(["serve", "--port", "18421"])
        .stdout(std::process::Stdio::piped())
        .stderr(std::process::Stdio::piped())
        .spawn()
        .expect("failed to spawn axon binary");

    // Give it a moment to start
    std::thread::sleep(Duration::from_millis(500));

    // Kill it — we just want to verify it started (not "not yet available")
    let _ = child.kill();
    let output = child.wait_with_output().expect("failed to wait on child");
    let stdout = String::from_utf8_lossy(&output.stdout);
    let stderr = String::from_utf8_lossy(&output.stderr);
    let combined = format!("{stdout}{stderr}");

    // The server starts natively — structured logs go to stdout via tracing
    assert!(
        combined.contains("axon_server_starting") || combined.contains("axon_server_listening")
            || combined.contains("AxonServer") || combined.contains("Listening"),
        "stdout: {stdout}\nstderr: {stderr}"
    );
}

/// Verify the native binary handles "deploy" with exit code 2 (not yet native).
#[test]
fn cli_deploy_native() {
    let binary = std::path::Path::new(env!("CARGO_BIN_EXE_axon"));
    // Deploy a nonexistent file → exit 2 (I/O error)
    let output = std::process::Command::new(binary)
        .args(["deploy", "nonexistent_file.axon"])
        .output()
        .expect("failed to execute axon binary");
    assert_eq!(output.status.code(), Some(2));
    let stderr = String::from_utf8_lossy(&output.stderr);
    assert!(stderr.contains("Cannot read"), "stderr: {stderr}");
}

/// Verify version command works from the binary (no Python needed).
#[test]
fn cli_version_no_python() {
    let binary = std::path::Path::new(env!("CARGO_BIN_EXE_axon"));
    let output = std::process::Command::new(binary)
        .args(["version"])
        .output()
        .expect("failed to execute axon binary");
    assert_eq!(output.status.code(), Some(0));
    let stdout = String::from_utf8_lossy(&output.stdout);
    assert!(stdout.contains("axon-lang"), "stdout: {stdout}");
}

