#[test]
fn anchor_check_all_12_supported() {
    use axon::anchor_checker;
    use axon::ir_nodes::IRAnchor;

    let names = [
        "NoHallucination", "FactualOnly", "SafeOutput", "PrivacyGuard",
        "NoBias", "ChildSafe", "NoCodeExecution", "AuditTrail",
        "SyllogismChecker", "ChainOfThoughtValidator", "RequiresCitation", "AgnosticFallback",
    ];

    for name in &names {
        let anchor = IRAnchor {
            node_type: "anchor",
            source_line: 0,
            source_column: 0,
            name: name.to_string(),
            description: String::new(),
            require: String::new(),
            reject: Vec::new(),
            enforce: String::new(),
            confidence_floor: None,
            unknown_response: String::new(),
            on_violation: String::new(),
            on_violation_target: String::new(),
        };
        let results = anchor_checker::check_all(&[anchor], "Test output text.");
        assert_eq!(results.len(), 1, "should get 1 result for anchor '{name}'");
        // All known anchors should NOT have "Unknown anchor" in violations
        assert!(
            !results[0].violations.iter().any(|v| v.contains("Unknown anchor")),
            "anchor '{name}' should be recognized"
        );
    }
}

