#[test]
fn anchor_retry_feedback_includes_only_errors() {
    use axon::anchor_checker::{self, AnchorResult};

    let results = vec![
        AnchorResult {
            anchor_name: "NoHallucination".to_string(),
            passed: false,
            violations: vec!["Hedging phrase 'i think' without citation".to_string()],
            severity: "error",
            confidence: 0.85,
        },
        AnchorResult {
            anchor_name: "NoBias".to_string(),
            passed: false,
            violations: vec!["Potential bias marker: 'obviously'".to_string()],
            severity: "warning",
            confidence: 0.80,
        },
        AnchorResult {
            anchor_name: "FactualOnly".to_string(),
            passed: true,
            violations: Vec::new(),
            severity: "error",
            confidence: 1.0,
        },
    ];

    let feedback = anchor_checker::build_retry_feedback(&results).unwrap();
    assert!(feedback.contains("NoHallucination"), "should include error breach");
    assert!(!feedback.contains("NoBias"), "should exclude warning breach");
    assert!(!feedback.contains("FactualOnly"), "should exclude passed anchor");
    assert!(feedback.starts_with("1."), "should be numbered");
}

