#[test]
fn confidence_all_12_anchors_produce_score() {
    use axon::anchor_checker;
    use axon::ir_nodes::IRAnchor;

    let names = [
        "NoHallucination", "FactualOnly", "SafeOutput", "PrivacyGuard",
        "NoBias", "ChildSafe", "NoCodeExecution", "AuditTrail",
        "SyllogismChecker", "ChainOfThoughtValidator", "RequiresCitation", "AgnosticFallback",
    ];

    let anchors: Vec<IRAnchor> = names.iter().map(|n| IRAnchor {
        node_type: "anchor", source_line: 0, source_column: 0,
        name: n.to_string(), description: String::new(), require: String::new(),
        reject: Vec::new(), enforce: String::new(), confidence_floor: None,
        unknown_response: String::new(), on_violation: String::new(), on_violation_target: String::new(),
    }).collect();

    let results = anchor_checker::check_all(&anchors, "The temperature is 22 degrees Celsius.");
    for r in &results {
        assert!(r.confidence >= 0.0 && r.confidence <= 1.0,
            "Anchor {} confidence {} not in [0,1]", r.anchor_name, r.confidence);
    }
}

#[test]
fn confidence_floor_causes_breach() {
    use axon::anchor_checker;
    use axon::ir_nodes::IRAnchor;

    // RequiresCitation with a single bracket citation → confidence ~0.35
    // Set floor at 0.70 → should breach
    let anchor = IRAnchor {
        node_type: "anchor", source_line: 0, source_column: 0,
        name: "RequiresCitation".to_string(), description: String::new(),
        require: String::new(), reject: Vec::new(), enforce: String::new(),
        confidence_floor: Some(0.70),
        unknown_response: String::new(), on_violation: String::new(), on_violation_target: String::new(),
    };

    let results = anchor_checker::check_all(&[anchor], "As noted in [1], the result holds.");
    assert!(!results[0].passed, "Should breach: confidence below floor");
    assert!(results[0].violations.iter().any(|v| v.contains("below floor")));
}

#[test]
fn confidence_floor_passes_when_exceeded() {
    use axon::anchor_checker;
    use axon::ir_nodes::IRAnchor;

    // NoHallucination on clean text → confidence 1.0, floor 0.80 → pass
    let anchor = IRAnchor {
        node_type: "anchor", source_line: 0, source_column: 0,
        name: "NoHallucination".to_string(), description: String::new(),
        require: String::new(), reject: Vec::new(), enforce: String::new(),
        confidence_floor: Some(0.80),
        unknown_response: String::new(), on_violation: String::new(), on_violation_target: String::new(),
    };

    let results = anchor_checker::check_all(&[anchor], "The boiling point of water is 100 degrees Celsius.");
    assert!(results[0].passed, "Should pass: confidence exceeds floor");
    assert!(results[0].confidence >= 0.80);
}

#[test]
fn confidence_violations_lower_score() {
    use axon::anchor_checker;
    use axon::ir_nodes::IRAnchor;

    let make = |name: &str| IRAnchor {
        node_type: "anchor", source_line: 0, source_column: 0,
        name: name.to_string(), description: String::new(), require: String::new(),
        reject: Vec::new(), enforce: String::new(), confidence_floor: None,
        unknown_response: String::new(), on_violation: String::new(), on_violation_target: String::new(),
    };

    // Clean text
    let r_clean = anchor_checker::check_all(&[make("FactualOnly")], "The temperature is 22 degrees.");
    // Opinionated text
    let r_opinion = anchor_checker::check_all(&[make("FactualOnly")], "In my opinion, I feel the answer is wrong. Personally, I prefer a different approach.");

    assert!(r_clean[0].confidence > r_opinion[0].confidence,
        "Clean text ({}) should have higher confidence than opinionated text ({})",
        r_clean[0].confidence, r_opinion[0].confidence);
}

