#[test]
fn session_store_remember_recall_cycle() {
    use axon::session_store::SessionStore;

    let tmp = std::env::temp_dir().join("axon_test_session_cycle.axon");
    let mut store = SessionStore::new(tmp.to_str().unwrap());

    store.remember("analysis_result", "The answer is 42", "step_analyze");
    store.remember("confidence", "high", "step_evaluate");

    let entry = store.recall("analysis_result").unwrap();
    assert_eq!(entry.value, "The answer is 42");
    assert_eq!(entry.source_step, "step_analyze");

    assert_eq!(store.memory_count(), 2);
    assert!(store.recall("nonexistent").is_none());
}

#[test]
fn session_store_persist_retrieve_across_instances() {
    use axon::session_store::SessionStore;

    let tmp = std::env::temp_dir().join("axon_test_session_persist.axon");
    let store_path;

    // First run: persist data
    {
        let mut store = SessionStore::new(tmp.to_str().unwrap());
        store.persist("user_preference", "dark_mode", "settings_step");
        store.persist("last_result", "success", "final_step");
        store.flush().unwrap();
        store_path = store.store_path().to_path_buf();
    }

    // Second run: retrieve persisted data
    {
        let store = SessionStore::new(tmp.to_str().unwrap());
        let pref = store.retrieve("user_preference").unwrap();
        assert_eq!(pref.value, "dark_mode");
        let result = store.retrieve("last_result").unwrap();
        assert_eq!(result.value, "success");
        assert_eq!(store.store_count(), 2);
    }

    // Cleanup
    let _ = std::fs::remove_file(&store_path);
}

#[test]
fn session_store_mutate_and_purge() {
    use axon::session_store::SessionStore;

    let tmp = std::env::temp_dir().join("axon_test_session_mutate.axon");
    let mut store = SessionStore::new(tmp.to_str().unwrap());

    store.persist("counter", "1", "init");
    assert!(store.mutate("counter", "2", "update"));
    assert_eq!(store.retrieve("counter").unwrap().value, "2");

    assert!(store.purge("counter"));
    assert!(store.retrieve("counter").is_none());
    assert_eq!(store.store_count(), 0);

    // Cleanup
    let _ = std::fs::remove_file(store.store_path());
}

#[test]
fn session_store_query_search() {
    use axon::session_store::SessionStore;

    let tmp = std::env::temp_dir().join("axon_test_session_query.axon");
    let mut store = SessionStore::new(tmp.to_str().unwrap());

    store.persist("analysis_v1", "draft", "s1");
    store.persist("analysis_v2", "final", "s2");
    store.persist("config_theme", "dark", "s3");

    let results = store.retrieve_query("analysis");
    assert_eq!(results.len(), 2);

    let removed = store.purge_query("analysis");
    assert_eq!(removed, 2);
    assert_eq!(store.store_count(), 1);

    // Cleanup
    let _ = std::fs::remove_file(store.store_path());
}

#[test]
fn session_store_path_derivation() {
    use axon::session_store::SessionStore;

    let store = SessionStore::new("examples/contract_analyzer.axon");
    let path = store.store_path().to_string_lossy().to_string();
    assert!(path.contains(".contract_analyzer.session.json"),
        "Store path should derive from source: {path}");
}

