#[test]
fn exec_context_new_has_unit_vars() {
    use axon::exec_context::ExecContext;

    let ctx = ExecContext::new("AnalyzeContract", "LegalExpert", 2);
    assert_eq!(ctx.get("flow_name"), Some("AnalyzeContract"));
    assert_eq!(ctx.get("persona_name"), Some("LegalExpert"));
    assert_eq!(ctx.get("unit_index"), Some("3")); // 1-based
    assert_eq!(ctx.get("result"), Some(""));
    assert_eq!(ctx.var_count(), 4);
}

#[test]
fn exec_context_step_and_result_chain() {
    use axon::exec_context::ExecContext;

    let mut ctx = ExecContext::new("Review", "Analyst", 0);
    ctx.set_step("Gather", "step", 0);
    ctx.set_step("Analyze", "step", 1);
    ctx.set_result("Analyze", "Finding: all clear");

    // $result tracks the latest step output
    assert_eq!(ctx.get("result"), Some("Finding: all clear"));
    // Named step result accessible via ${Analyze}
    assert_eq!(ctx.get("Analyze"), Some("Finding: all clear"));
    // Step metadata reflects the latest set_step call
    assert_eq!(ctx.get("step_name"), Some("Analyze"));
    assert_eq!(ctx.get("step_index"), Some("2")); // 1-based
}

