#[test]
fn conversation_history_accumulates_turns() {
    use axon::conversation::ConversationHistory;

    let mut h = ConversationHistory::new();
    assert!(h.is_empty());

    h.add_user("Analyze this contract");
    h.add_assistant("The contract has 3 clauses...");
    h.add_user("What about clause 2?");
    h.add_assistant("Clause 2 covers liability...");

    assert_eq!(h.len(), 4);
    assert_eq!(h.turn_count(), 2);

    let msgs = h.messages();
    assert_eq!(msgs[0].role, "user");
    assert_eq!(msgs[1].role, "assistant");
    assert_eq!(msgs[2].role, "user");
    assert_eq!(msgs[3].role, "assistant");
}

#[test]
