// Context Window Management (D9)
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn context_window_truncates_long_history() {
    use axon::conversation::{ConversationHistory, ContextWindow};

    let mut h = ConversationHistory::new();
    for i in 0..10 {
        h.add_user(&format!("Question number {i} with some padding text"));
        h.add_assistant(&format!("Answer number {i} with detailed response"));
    }
    let original_chars = h.total_chars();
    assert!(original_chars > 100);

    // Tight budget — should drop oldest turns
    let mut cw = ContextWindow::with_budget(100);
    let dropped = cw.enforce(&mut h);
    assert!(dropped > 0);
    assert!(h.total_chars() <= 100);
    assert!(cw.was_truncated());

    // Most recent turn should survive
    let msgs = h.messages();
    let last = &msgs[msgs.len() - 1];
    assert_eq!(last.content, "Answer number 9 with detailed response");
}

#[test]
fn context_window_unlimited_never_truncates() {
    use axon::conversation::{ConversationHistory, ContextWindow};

    let mut h = ConversationHistory::new();
    for i in 0..100 {
        h.add_user(&format!("Q{i}"));
        h.add_assistant(&format!("A{i}"));
    }

    let mut cw = ContextWindow::unlimited();
    let dropped = cw.enforce(&mut h);
    assert_eq!(dropped, 0);
    assert_eq!(h.len(), 200);
    assert!(!cw.was_truncated());
}

#[test]
fn context_window_default_budget_is_100k() {
    use axon::conversation::ContextWindow;

    let cw = ContextWindow::new();
    assert_eq!(cw.max_chars, 100_000);
}

#[test]
fn context_window_overflow_count_preview() {
    use axon::conversation::ConversationHistory;

    let mut h = ConversationHistory::new();
    for i in 0..5 {
        h.add_user(&format!("Q{i}")); // 2 chars each
        h.add_assistant(&format!("A{i}")); // 2 chars each
    }
    // Total: 20 chars, budget 8 → would drop 6 messages
    let overflow = h.overflow_count(8);
    assert_eq!(overflow, 6);
    // History not modified
    assert_eq!(h.len(), 10);
}

#[test]
fn context_window_token_estimation() {
    use axon::conversation::ContextWindow;

    // 100k chars ≈ 25k tokens
    assert_eq!(ContextWindow::estimate_tokens(100_000), 25_000);
    // 0 chars = 0 tokens
    assert_eq!(ContextWindow::estimate_tokens(0), 0);
    // 7 chars → ceiling(7/4) = 2
    assert_eq!(ContextWindow::estimate_tokens(7), 2);
}

