#[test]
fn anchor_chain_rules_count() {
    use axon::anchor_checker;

    let rules = anchor_checker::chain_rules();
    assert_eq!(rules.len(), 5);

    // Verify all 5 trigger-enforced pairs
    let pairs: Vec<(&str, &str)> = rules.iter().map(|r| (r.trigger, r.enforced)).collect();
    assert!(pairs.contains(&("NoHallucination", "RequiresCitation")));
    assert!(pairs.contains(&("FactualOnly", "RequiresCitation")));
    assert!(pairs.contains(&("NoBias", "AgnosticFallback")));
    assert!(pairs.contains(&("SafeOutput", "ChildSafe")));
    assert!(pairs.contains(&("NoCodeExecution", "SafeOutput")));
}

#[test]
fn anchor_chain_resolves_on_breach() {
    use axon::anchor_checker::{self, AnchorResult};
    use axon::ir_nodes::IRAnchor;

    let existing = vec![IRAnchor {
        node_type: "anchor",
        source_line: 0,
        source_column: 0,
        name: "NoHallucination".to_string(),
        description: String::new(),
        require: String::new(),
        reject: Vec::new(),
        enforce: String::new(),
        confidence_floor: None,
        unknown_response: String::new(),
        on_violation: String::new(),
        on_violation_target: String::new(),
    }];

    let results = vec![AnchorResult {
        anchor_name: "NoHallucination".into(),
        passed: false,
        violations: vec!["hedging detected".into()],
        severity: "error",
        confidence: 0.35,
    }];

    let chains = anchor_checker::resolve_chains(&results, &existing);
    assert_eq!(chains.len(), 1);
    assert_eq!(chains[0].0.trigger, "NoHallucination");
    assert_eq!(chains[0].0.enforced, "RequiresCitation");
}

#[test]
fn anchor_chain_deduplicates_enforced() {
    use axon::anchor_checker::{self, AnchorResult};
    use axon::ir_nodes::IRAnchor;

    fn make_anchor(name: &str) -> IRAnchor {
        IRAnchor {
            node_type: "anchor",
            source_line: 0,
            source_column: 0,
            name: name.to_string(),
            description: String::new(),
            require: String::new(),
            reject: Vec::new(),
            enforce: String::new(),
            confidence_floor: None,
            unknown_response: String::new(),
            on_violation: String::new(),
            on_violation_target: String::new(),
        }
    }

    // Both NoHallucination and FactualOnly chain to RequiresCitation
    let existing = vec![
        make_anchor("NoHallucination"),
        make_anchor("FactualOnly"),
    ];

    let results = vec![
        AnchorResult {
            anchor_name: "NoHallucination".into(),
            passed: false,
            violations: vec!["hedging".into()],
            severity: "error",
            confidence: 0.35,
        },
        AnchorResult {
            anchor_name: "FactualOnly".into(),
            passed: false,
            violations: vec!["opinion".into()],
            severity: "error",
            confidence: 0.30,
        },
    ];

    let chains = anchor_checker::resolve_chains(&results, &existing);
    // RequiresCitation should only appear once (deduplicated)
    assert_eq!(chains.len(), 1);
    assert_eq!(chains[0].0.enforced, "RequiresCitation");
}

#[test]
fn anchor_chain_check_chained_detects_missing_citations() {
    use axon::anchor_checker::{self, AnchorResult};
    use axon::ir_nodes::IRAnchor;

    let existing = vec![IRAnchor {
        node_type: "anchor",
        source_line: 0,
        source_column: 0,
        name: "NoHallucination".to_string(),
        description: String::new(),
        require: String::new(),
        reject: Vec::new(),
        enforce: String::new(),
        confidence_floor: None,
        unknown_response: String::new(),
        on_violation: String::new(),
        on_violation_target: String::new(),
    }];

    let results = vec![AnchorResult {
        anchor_name: "NoHallucination".into(),
        passed: false,
        violations: vec!["hedging".into()],
        severity: "error",
        confidence: 0.35,
    }];

    // No citations in output → chained RequiresCitation should breach
    let output = "I think maybe this could possibly be correct.";
    let chain_results = anchor_checker::check_chained(&results, &existing, output);
    assert_eq!(chain_results.len(), 1);
    assert!(!chain_results[0].1.passed);
    assert_eq!(chain_results[0].1.anchor_name, "RequiresCitation");
}

#[test]
fn anchor_chain_no_chain_when_all_pass() {
    use axon::anchor_checker::{self, AnchorResult};
    use axon::ir_nodes::IRAnchor;

    let existing = vec![IRAnchor {
        node_type: "anchor",
        source_line: 0,
        source_column: 0,
        name: "NoHallucination".to_string(),
        description: String::new(),
        require: String::new(),
        reject: Vec::new(),
        enforce: String::new(),
        confidence_floor: None,
        unknown_response: String::new(),
        on_violation: String::new(),
        on_violation_target: String::new(),
    }];

    let results = vec![AnchorResult {
        anchor_name: "NoHallucination".into(),
        passed: true,
        violations: Vec::new(),
        severity: "error",
        confidence: 0.95,
    }];

    let chains = anchor_checker::resolve_chains(&results, &existing);
    assert_eq!(chains.len(), 0); // No breaches → no chains
}

