#[test]
fn report_builder_json_serialization() {
    use axon::output::{ReportBuilder, StepReport};
    use axon::hooks::HookManager;

    let mut hooks = HookManager::new();
    let mut rb = ReportBuilder::new("test.axon", "anthropic", "stub");

    hooks.on_unit_start("AnalyzeData", "DataExpert");
    rb.begin_unit("AnalyzeData", "DataExpert");

    hooks.on_step_start("Gather", "step");
    hooks.on_step_end(100, 50, 0, 0, false);
    rb.record_step(StepReport {
        name: "Gather".into(),
        step_type: "step".into(),
        result: "gathered data".into(),
        duration_ms: 0,
        input_tokens: 100,
        output_tokens: 50,
        anchor_breaches: 0,
        chain_activations: 0,
        was_retried: false,
    });

    hooks.on_unit_end();
    rb.end_unit(&hooks);

    let report = rb.build(true, &hooks);
    let json_str = ReportBuilder::to_json(&report);

    // Verify JSON is valid and contains expected fields
    let parsed: serde_json::Value = serde_json::from_str(&json_str).unwrap();
    assert_eq!(parsed["source_file"], "test.axon");
    assert_eq!(parsed["backend"], "anthropic");
    assert_eq!(parsed["mode"], "stub");
    assert_eq!(parsed["success"], true);
    assert_eq!(parsed["units"][0]["flow_name"], "AnalyzeData");
    assert_eq!(parsed["units"][0]["steps"][0]["name"], "Gather");
    assert_eq!(parsed["units"][0]["steps"][0]["result"], "gathered data");
    assert_eq!(parsed["summary"]["total_steps"], 1);
    assert_eq!(parsed["summary"]["total_input_tokens"], 100);
}

