#[test]
fn step_deps_linear_chain() {
    use axon::step_deps::{analyze, StepInfo};

    let steps = vec![
        StepInfo { name: "Extract".into(), step_type: "step".into(), user_prompt: "Extract entities".into(), argument: String::new() },
        StepInfo { name: "Assess".into(), step_type: "step".into(), user_prompt: "Assess ${Extract}".into(), argument: String::new() },
    ];

    let graph = analyze(&steps);
    assert_eq!(graph.steps.len(), 2);
    assert!(graph.steps[0].is_root);
    assert!(!graph.steps[1].is_root);
    assert_eq!(graph.steps[1].depends_on, vec!["Extract"]);
    assert_eq!(graph.max_depth, 1);
    assert!(graph.parallel_groups.is_empty());
}

#[test]
fn step_deps_parallel_detection() {
    use axon::step_deps::{analyze, StepInfo};

    // A → B, A → C (B and C can be parallel)
    let steps = vec![
        StepInfo { name: "A".into(), step_type: "step".into(), user_prompt: "Start".into(), argument: String::new() },
        StepInfo { name: "B".into(), step_type: "step".into(), user_prompt: "Path B from ${A}".into(), argument: String::new() },
        StepInfo { name: "C".into(), step_type: "step".into(), user_prompt: "Path C from ${A}".into(), argument: String::new() },
    ];

    let graph = analyze(&steps);
    assert_eq!(graph.max_depth, 1);
    assert!(!graph.parallel_groups.is_empty());
    let group = &graph.parallel_groups[0];
    assert!(group.contains(&"B".to_string()));
    assert!(group.contains(&"C".to_string()));
}

