// Parallel Step Scheduler (D18)
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn schedule_from_dependency_graph() {
    use axon::step_deps::{analyze, StepInfo};
    use axon::parallel::build_schedule;

    // Diamond: A → B, C → D
    let steps = vec![
        StepInfo { name: "A".into(), step_type: "step".into(), user_prompt: "start".into(), argument: String::new() },
        StepInfo { name: "B".into(), step_type: "step".into(), user_prompt: "$A b".into(), argument: String::new() },
        StepInfo { name: "C".into(), step_type: "step".into(), user_prompt: "$A c".into(), argument: String::new() },
        StepInfo { name: "D".into(), step_type: "step".into(), user_prompt: "$B $C".into(), argument: String::new() },
    ];

    let graph = analyze(&steps);
    let sched = build_schedule(&graph);

    assert_eq!(sched.waves.len(), 3);
    assert!(sched.has_parallelism());
    assert_eq!(sched.parallel_waves, 1);
    assert_eq!(sched.max_parallelism, 2);
    // B and C are in the parallel wave
    assert!(sched.waves[1].is_parallel);
    assert!(sched.waves[1].steps.contains(&"B".to_string()));
    assert!(sched.waves[1].steps.contains(&"C".to_string()));
}

#[test]
fn execute_wave_parallel_produces_results() {
    use axon::parallel::{Wave, WaveStepResult, execute_wave};

    let wave = Wave {
        depth: 0,
        steps: vec!["X".into(), "Y".into(), "Z".into()],
        is_parallel: true,
    };

    let results = execute_wave(&wave, |name| WaveStepResult {
        step_name: name.to_string(),
        output: format!("done_{name}"),
        success: true,
    });

    assert_eq!(results.len(), 3);
    let mut names: Vec<String> = results.iter().map(|r| r.step_name.clone()).collect();
    names.sort();
    assert_eq!(names, vec!["X", "Y", "Z"]);
    assert!(results.iter().all(|r| r.success));
}

#[test]
fn schedule_wave_lookup() {
    use axon::step_deps::{analyze, StepInfo};
    use axon::parallel::build_schedule;

    let steps = vec![
        StepInfo { name: "A".into(), step_type: "step".into(), user_prompt: "do".into(), argument: String::new() },
        StepInfo { name: "B".into(), step_type: "step".into(), user_prompt: "$A".into(), argument: String::new() },
    ];

    let graph = analyze(&steps);
    let sched = build_schedule(&graph);

    assert_eq!(sched.wave_of("A"), Some(0));
    assert_eq!(sched.wave_of("B"), Some(1));
    assert_eq!(sched.wave_of("nonexistent"), None);
}

#[test]
fn schedule_summary_readable() {
    use axon::step_deps::{analyze, StepInfo};
    use axon::parallel::build_schedule;

    let steps = vec![
        StepInfo { name: "Init".into(), step_type: "step".into(), user_prompt: "start".into(), argument: String::new() },
        StepInfo { name: "Left".into(), step_type: "step".into(), user_prompt: "$Init".into(), argument: String::new() },
        StepInfo { name: "Right".into(), step_type: "step".into(), user_prompt: "$Init".into(), argument: String::new() },
        StepInfo { name: "Merge".into(), step_type: "step".into(), user_prompt: "$Left $Right".into(), argument: String::new() },
    ];

    let graph = analyze(&steps);
    let sched = build_schedule(&graph);
    let summary = sched.summary();

    // Summary should mention the parallel group
    assert!(summary.contains("Left | Right"), "summary: {summary}");
    assert!(summary.contains("3 waves"));
}

