#[test]
fn emcp_blame_tracker_integration() {
    use axon::emcp::{BlameTracker, McpCallResult, Blame, EpistemicTaint};

    let mut tracker = BlameTracker::new();

    // Simulate a successful call
    tracker.record(&McpCallResult {
        tool_name: "ToolA".into(),
        output: "data".into(),
        success: true,
        blame: Blame::None,
        taint: EpistemicTaint::Untrusted,
        server: "http://mcp-server".into(),
        effects: vec!["network".into()],
    });

    // Simulate a server failure
    tracker.record(&McpCallResult {
        tool_name: "ToolB".into(),
        output: "server crash".into(),
        success: false,
        blame: Blame::Server,
        taint: EpistemicTaint::Untrusted,
        server: "http://mcp-server".into(),
        effects: vec!["network".into()],
    });

    assert_eq!(tracker.total(), 2);
    assert_eq!(tracker.server_faults(), 1);
    assert_eq!(tracker.caller_faults(), 0);
    assert_eq!(tracker.network_faults(), 0);
}

#[test]
fn emcp_taint_always_untrusted() {
    use axon::emcp::{McpCallResult, Blame, EpistemicTaint};

    // Even successful MCP data starts as Untrusted (⊥ in epistemic lattice)
    let result = McpCallResult {
        tool_name: "DataAPI".into(),
        output: "patient records".into(),
        success: true,
        blame: Blame::None,
        taint: EpistemicTaint::Untrusted,
        server: "http://mcp.hospital.internal".into(),
        effects: vec!["network".into(), "epistemic:speculate".into()],
    };

    // Contract: all MCP-sourced data must be born Untrusted
    assert_eq!(result.taint, EpistemicTaint::Untrusted);
    assert!(result.success);
    // Taint elevation requires shield/know block (future sessions)

    // Verify serialization preserves taint
    let json = serde_json::to_string(&result).unwrap();
    assert!(json.contains("\"Untrusted\""));
    assert!(json.contains("epistemic:speculate"));
}

#[test]
fn emcp_mcp_no_longer_falls_through() {
    use axon::tool_registry::{ToolRegistry, ToolEntry, ToolSource};

    // Before D19, "mcp" fell through to LLM. Now it's handled.
    let mut reg = ToolRegistry::new();
    reg.register(ToolEntry {
        name: "FhirAPI".to_string(),
        provider: "mcp".to_string(),
        timeout: "5s".to_string(),
        runtime: "https://mcp.hospital.internal/fhir".to_string(),
        sandbox: Some(true),
        max_results: None,
        output_schema: "JSON".to_string(),
        effect_row: vec!["network".to_string(), "io".to_string(), "epistemic:speculate".to_string()],
        source: ToolSource::Program,
    });

    let result = reg.dispatch("FhirAPI", r#"{"patient_id": "123"}"#);
    assert!(result.is_some(), "MCP provider should be handled by ℰMCP transducer");
}

