#[test]
fn plan_diff_added_flow_and_step() {
    use axon::plan_diff;

    let old = serde_json::json!({
        "units": [{
            "flow_name": "Original",
            "persona_name": "P",
            "context_name": "default",
            "effort": "medium",
            "anchor_count": 0,
            "anchors": [],
            "steps": [
                { "name": "A", "step_type": "step", "prompt_preview": "do A", "depends_on": [], "is_root": true },
            ]
        }],
        "tools": { "total": 0, "builtin": [], "program": [], "registered": [] },
        "dependencies": { "max_depth": 0, "parallel_groups": [], "unresolved_refs": [] },
    });

    let new = serde_json::json!({
        "units": [
            {
                "flow_name": "Original",
                "persona_name": "P",
                "context_name": "default",
                "effort": "medium",
                "anchor_count": 0,
                "anchors": [],
                "steps": [
                    { "name": "A", "step_type": "step", "prompt_preview": "do A", "depends_on": [], "is_root": true },
                    { "name": "B", "step_type": "step", "prompt_preview": "do B using $A", "depends_on": ["A"], "is_root": false },
                ]
            },
            {
                "flow_name": "NewFlow",
                "persona_name": "P2",
                "context_name": "default",
                "effort": "high",
                "anchor_count": 1,
                "anchors": ["NoHallucination"],
                "steps": [
                    { "name": "X", "step_type": "step", "prompt_preview": "new", "depends_on": [], "is_root": true },
                ]
            }
        ],
        "tools": { "total": 1, "builtin": ["Calculator"], "program": [], "registered": [
            { "name": "Calculator", "provider": "native", "source": "builtin" }
        ]},
        "dependencies": { "max_depth": 1, "parallel_groups": [["A"]], "unresolved_refs": [] },
    });

    let diff = plan_diff::diff_plans(&old, &new);
    assert!(!diff.identical);
    assert_eq!(diff.summary.units_added, 1);  // NewFlow
    assert_eq!(diff.summary.units_modified, 1); // Original (step B added)
    assert!(diff.summary.steps_added >= 2);    // B + X
    assert_eq!(diff.tools.added, vec!["Calculator"]);
}

#[test]
fn plan_diff_cli_json_output() {
    use axon::plan_diff;

    // Create two temp files
    let tmp_a = std::env::temp_dir().join("axon_diff_int_a.json");
    let tmp_b = std::env::temp_dir().join("axon_diff_int_b.json");

    let plan_a = serde_json::json!({
        "units": [{ "flow_name": "F", "persona_name": "P", "context_name": "c", "effort": "m", "anchor_count": 0, "anchors": [], "steps": [
            { "name": "S", "step_type": "step", "prompt_preview": "old prompt", "depends_on": [], "is_root": true }
        ]}],
        "tools": { "total": 0, "builtin": [], "program": [], "registered": [] },
        "dependencies": { "max_depth": 0, "parallel_groups": [], "unresolved_refs": [] },
    });

    let mut plan_b = plan_a.clone();
    plan_b["units"][0]["steps"][0]["prompt_preview"] = serde_json::json!("new prompt");

    std::fs::write(&tmp_a, serde_json::to_string(&plan_a).unwrap()).unwrap();
    std::fs::write(&tmp_b, serde_json::to_string(&plan_b).unwrap()).unwrap();

    // Should return 1 (plans differ)
    let exit = plan_diff::run_diff(
        tmp_a.to_str().unwrap(),
        tmp_b.to_str().unwrap(),
        true,
    );
    assert_eq!(exit, 1);

    // Identical → 0
    let exit = plan_diff::run_diff(
        tmp_a.to_str().unwrap(),
        tmp_a.to_str().unwrap(),
        true,
    );
    assert_eq!(exit, 0);

    let _ = std::fs::remove_file(tmp_a);
    let _ = std::fs::remove_file(tmp_b);
}

