#[test]
fn replay_regression_comparison() {
    use axon::replay;

    let trace_a = serde_json::json!({
        "_meta": { "source": "a.axon", "backend": "anthropic", "tool_mode": "stub", "axon_version": "1.0.0", "mode": "stub" },
        "events": [
            { "event": "unit_start", "unit": "F", "step": "", "detail": "" },
            { "event": "step_complete", "unit": "F", "step": "X", "detail": "output_v1" },
            { "event": "step_complete", "unit": "F", "step": "Y", "detail": "same" },
            { "event": "unit_complete", "unit": "F", "step": "", "detail": "" },
        ]
    });

    let trace_b = serde_json::json!({
        "_meta": { "source": "b.axon", "backend": "anthropic", "tool_mode": "stub", "axon_version": "1.0.0", "mode": "stub" },
        "events": [
            { "event": "unit_start", "unit": "F", "step": "", "detail": "" },
            { "event": "step_complete", "unit": "F", "step": "X", "detail": "output_v2" },
            { "event": "step_complete", "unit": "F", "step": "Y", "detail": "same" },
            { "event": "step_complete", "unit": "F", "step": "Z", "detail": "new step" },
            { "event": "unit_complete", "unit": "F", "step": "", "detail": "" },
        ]
    });

    let old = replay::parse_trace(&trace_a);
    let new = replay::parse_trace(&trace_b);
    let diff = replay::compare_traces(&old, &new);

    assert!(!diff.identical);
    assert_eq!(diff.summary.changed, 1);  // X changed
    assert_eq!(diff.summary.matched, 1);  // Y matched
    assert_eq!(diff.summary.added, 1);    // Z added
}

