// D26 — Flow Versioning
// ═══════════════════════════════════════════════════════════════════════════

use axon::flow_version::VersionRegistry;

#[test]
fn version_tracking_via_deploy() {
    let mut reg = VersionRegistry::new();

    // First deploy
    let r1 = reg.record_deploy(
        &vec!["Greet".to_string()],
        "flow Greet { step Hello { tool: echo } }",
        "greet.axon",
        "anthropic",
    );
    assert_eq!(r1, vec![("Greet".to_string(), 1)]);
    assert_eq!(reg.get_active("Greet").unwrap().version, 1);

    // Second deploy — same flow, new source
    let r2 = reg.record_deploy(
        &vec!["Greet".to_string()],
        "flow Greet { step Hello { tool: echo } step Bye { tool: echo } }",
        "greet.axon",
        "anthropic",
    );
    assert_eq!(r2, vec![("Greet".to_string(), 2)]);
    assert_eq!(reg.get_active("Greet").unwrap().version, 2);

    // Source hashes differ
    let v1 = reg.get_version("Greet", 1).unwrap();
    let v2 = reg.get_version("Greet", 2).unwrap();
    assert_ne!(v1.source_hash, v2.source_hash);
    assert_eq!(v1.source_hash.len(), 12);
}

#[test]
fn version_rollback_restores_source() {
    let mut reg = VersionRegistry::new();
    let src_v1 = "flow F { step A { tool: x } }";
    let src_v2 = "flow F { step A { tool: y } }";
    let src_v3 = "flow F { step A { tool: z } }";

    reg.record_deploy(&vec!["F".to_string()], src_v1, "f.axon", "anthropic");
    reg.record_deploy(&vec!["F".to_string()], src_v2, "f.axon", "anthropic");
    reg.record_deploy(&vec!["F".to_string()], src_v3, "f.axon", "anthropic");

    // Active is v3
    assert_eq!(reg.get_active("F").unwrap().version, 3);

    // Rollback to v1
    let source = reg.rollback("F", 1).unwrap();
    assert_eq!(source, src_v1);
    assert_eq!(reg.get_active("F").unwrap().version, 1);

    // Rollback to non-existent version fails
    assert!(reg.rollback("F", 99).is_err());
    // Rollback to non-existent flow fails
    assert!(reg.rollback("NoFlow", 1).is_err());
}

#[test]
fn version_history_listing() {
    let mut reg = VersionRegistry::new();
    reg.record_deploy(&vec!["Alpha".to_string()], "a1", "a.axon", "anthropic");
    reg.record_deploy(&vec!["Alpha".to_string()], "a2", "a.axon", "anthropic");
    reg.record_deploy(&vec!["Beta".to_string()], "b1", "b.axon", "anthropic");

    let list = reg.list_flows();
    assert_eq!(list.len(), 2);

    let alpha = list.iter().find(|f| f.flow_name == "Alpha").unwrap();
    assert_eq!(alpha.active_version, 2);
    assert_eq!(alpha.total_versions, 2);
    assert_eq!(alpha.deploy_count, 2);

    let beta = list.iter().find(|f| f.flow_name == "Beta").unwrap();
    assert_eq!(beta.active_version, 1);
    assert_eq!(beta.total_versions, 1);

    assert_eq!(reg.flow_count(), 2);
    assert_eq!(reg.total_versions(), 3);
}

