// D27 — Trace Analytics
// ═══════════════════════════════════════════════════════════════════════════

use axon::trace_stats;

fn sample_trace_json(flow: &str, steps: &[(&str, bool)], duration_detail: &str) -> serde_json::Value {
    let mut events = vec![
        serde_json::json!({ "event": "unit_start", "unit": flow, "step": "", "detail": "" }),
    ];
    for (name, success) in steps {
        if *success {
            events.push(serde_json::json!({ "event": "step_complete", "unit": flow, "step": name, "detail": "ok" }));
        } else {
            events.push(serde_json::json!({ "event": "step_error", "unit": flow, "step": name, "detail": "error" }));
        }
    }
    if !duration_detail.is_empty() {
        events.push(serde_json::json!({ "event": "hook_unit_metrics", "unit": flow, "step": "", "detail": duration_detail }));
    }
    events.push(serde_json::json!({ "event": "unit_complete", "unit": flow, "step": "", "detail": "" }));

    serde_json::json!({
        "_meta": { "source": "test.axon", "backend": "anthropic", "tool_mode": "stub", "axon_version": "1.0.0", "mode": "stub" },
        "events": events,
    })
}

#[test]
fn trace_stats_aggregate_multiple_traces() {
    let t1 = sample_trace_json("Flow1", &[("Analyze", true), ("Summarize", true)], "duration_ms=100, input_tokens=50, output_tokens=20");
    let t2 = sample_trace_json("Flow2", &[("Analyze", true), ("Generate", false)], "duration_ms=200, input_tokens=70, output_tokens=30");

    let parsed1 = axon::replay::parse_trace(&t1);
    let parsed2 = axon::replay::parse_trace(&t2);

    let analytics = trace_stats::compute_analytics(&[parsed1, parsed2]);

    assert_eq!(analytics.trace_count, 2);
    assert_eq!(analytics.errors.total_steps, 4);
    assert_eq!(analytics.errors.total_errors, 1); // Generate failed
    assert_eq!(analytics.steps.unique_steps, 3); // Analyze, Summarize, Generate
    assert_eq!(analytics.steps.top_steps[0].step_name, "Analyze");
    assert_eq!(analytics.steps.top_steps[0].count, 2);
}

#[test]
fn trace_stats_cli_json_output() {
    let tmp = std::env::temp_dir().join("axon_int_stats.trace.json");
    let data = sample_trace_json("F", &[("S1", true), ("S2", true)], "");
    std::fs::write(&tmp, serde_json::to_string(&data).unwrap()).unwrap();

    let files = vec![tmp.to_str().unwrap().to_string()];
    assert_eq!(trace_stats::run_stats(&files, "json"), 0);

    let _ = std::fs::remove_file(tmp);
}

#[test]
fn trace_stats_with_anchors() {
    let mut data = sample_trace_json("F", &[("S1", true)], "");
    // Insert anchor events before step_complete
    let events = data["events"].as_array_mut().unwrap();
    // Insert anchor_pass and anchor_breach before step_complete (index 1)
    events.insert(1, serde_json::json!({ "event": "anchor_pass", "unit": "F", "step": "S1", "detail": "SafeOutput: ok" }));
    events.insert(2, serde_json::json!({ "event": "anchor_breach", "unit": "F", "step": "S1", "detail": "NoHallucination: hedging detected" }));

    let parsed = axon::replay::parse_trace(&data);
    let analytics = trace_stats::compute_analytics(&[parsed]);

    assert_eq!(analytics.anchors.total_checks, 2);
    assert_eq!(analytics.anchors.total_passes, 1);
    assert_eq!(analytics.anchors.total_breaches, 1);
    assert!((analytics.anchors.pass_rate - 0.5).abs() < 0.01);
}

// ═══════════════════════════════════════════════════════════════════════════
// D28 — Session Persistence in AxonServer
// ═══════════════════════════════════════════════════════════════════════════

use axon::session_store::SessionStore;

#[test]
fn session_remember_recall_in_server_context() {
    let mut store = SessionStore::new("axon-server-test-d28a");

    // Remember (ephemeral)
    store.remember("user_intent", "analyze quarterly data", "api");
    let entry = store.recall("user_intent").unwrap();
    assert_eq!(entry.value, "analyze quarterly data");
    assert_eq!(entry.source_step, "api");

    // Recall missing key
    assert!(store.recall("nonexistent").is_none());

    // Overwrite
    store.remember("user_intent", "updated intent", "api");
    assert_eq!(store.recall("user_intent").unwrap().value, "updated intent");
    assert_eq!(store.memory_count(), 1);
}

#[test]
fn session_persist_retrieve_mutate_purge() {
    let tmp = std::env::temp_dir().join("axon_d28_persist_test.axon");
    let mut store = SessionStore::new(tmp.to_str().unwrap());

    // Persist
    store.persist("analysis_result", "Revenue up 15%", "Analyze");
    store.persist("summary", "Q4 exceeded targets", "Summarize");
    assert_eq!(store.store_count(), 2);

    // Retrieve
    let entry = store.retrieve("analysis_result").unwrap();
    assert_eq!(entry.value, "Revenue up 15%");

    // Query
    let results = store.retrieve_query("analysis");
    assert_eq!(results.len(), 1);

    // Mutate
    assert!(store.mutate("analysis_result", "Revenue up 18% (revised)", "Revise"));
    assert_eq!(store.retrieve("analysis_result").unwrap().value, "Revenue up 18% (revised)");
    assert!(!store.mutate("no_such_key", "val", "step"));

    // Purge
    assert!(store.purge("summary"));
    assert_eq!(store.store_count(), 1);
    assert!(!store.purge("summary")); // already gone

    // Flush and reload
    store.flush().unwrap();
    let store2 = SessionStore::new(tmp.to_str().unwrap());
    assert_eq!(store2.retrieve("analysis_result").unwrap().value, "Revenue up 18% (revised)");

    // Cleanup
    let _ = std::fs::remove_file(store.store_path());
}

#[test]
fn session_store_server_state_integration() {
    // Verify SessionStore integrates into ServerState by exercising the same
    // patterns the API handlers use: remember/recall + persist/retrieve + metrics
    let mut store = SessionStore::new("axon-server-test-d28c");

    // Simulate API handler: remember
    store.remember("ctx_flow", "Greet", "deploy_handler");
    store.remember("ctx_backend", "anthropic", "deploy_handler");

    // Simulate API handler: persist
    store.persist("last_deploy", "Greet v2", "deploy_handler");
    store.persist("config_key", "max_retries=3", "admin");

    // Metrics-style counts
    assert_eq!(store.memory_count(), 2);
    assert_eq!(store.store_count(), 2);

    // Query across persistent store
    let deploy_entries = store.retrieve_query("deploy");
    assert_eq!(deploy_entries.len(), 1); // "last_deploy" matches

    // Purge query
    let removed = store.purge_query("config");
    assert_eq!(removed, 1);
    assert_eq!(store.store_count(), 1);
}

// ═══════════════════════════════════════════════════════════════════════════
// D29 — Version Diff
// ═══════════════════════════════════════════════════════════════════════════

use axon::version_diff;

#[test]
fn version_diff_detects_changes() {
    let mut reg = VersionRegistry::new();
    let flows = vec!["Greet".to_string()];

    let src_v1 = "persona Bot {\n  tone: \"friendly\"\n}\nflow Greet {\n  step Hello {\n    tool: echo\n  }\n}";
    let src_v2 = "persona Bot {\n  tone: \"professional\"\n}\nflow Greet {\n  step Hello {\n    tool: echo\n  }\n  step Bye {\n    tool: echo\n  }\n}";

    reg.record_deploy(&flows, src_v1, "greet.axon", "anthropic");
    reg.record_deploy(&flows, src_v2, "greet.axon", "anthropic");

    let diff = version_diff::diff_versions(&reg, "Greet", 1, 2).unwrap();
    assert!(!diff.identical);
    assert_eq!(diff.flow_name, "Greet");
    assert_eq!(diff.from_version, 1);
    assert_eq!(diff.to_version, 2);
    assert!(diff.summary.lines_added > 0);
    assert!(diff.summary.lines_removed > 0);
    assert!(diff.summary.hunks > 0);

    // Verify JSON serialization
    let json = serde_json::to_value(&diff).unwrap();
    assert_eq!(json["flow_name"], "Greet");
    assert_eq!(json["identical"], false);
}

#[test]
fn version_diff_identical_source() {
    let mut reg = VersionRegistry::new();
    let flows = vec!["F".to_string()];
    let src = "flow F {\n  step S {\n    tool: x\n  }\n}";

    reg.record_deploy(&flows, src, "f.axon", "anthropic");
    reg.record_deploy(&flows, src, "f.axon", "anthropic");

    let diff = version_diff::diff_versions(&reg, "F", 1, 2).unwrap();
    assert!(diff.identical);
    assert_eq!(diff.summary.lines_added, 0);
    assert_eq!(diff.summary.lines_removed, 0);
    assert!(diff.hunks.is_empty());
}

#[test]
fn version_diff_error_cases() {
    let mut reg = VersionRegistry::new();
    let flows = vec!["F".to_string()];
    reg.record_deploy(&flows, "src", "f.axon", "anthropic");

    // Flow not found
    assert!(version_diff::diff_versions(&reg, "NoFlow", 1, 2).is_err());
    // Version not found
    assert!(version_diff::diff_versions(&reg, "F", 1, 99).is_err());
}

