// D31 — Graph Export (DOT + Mermaid)
// ═══════════════════════════════════════════════════════════════════════════

use axon::graph_export;
use axon::step_deps;

#[test]
fn graph_export_dot_from_dependency_graph() {
    let steps = vec![
        step_deps::StepInfo { name: "Extract".into(), step_type: "step".into(), user_prompt: "Extract data".into(), argument: String::new() },
        step_deps::StepInfo { name: "Analyze".into(), step_type: "step".into(), user_prompt: "Analyze ${Extract}".into(), argument: String::new() },
        step_deps::StepInfo { name: "Report".into(), step_type: "step".into(), user_prompt: "Report on ${Analyze}".into(), argument: String::new() },
    ];
    let graph = step_deps::analyze(&steps);
    let dot = graph_export::to_dot("TestFlow", &graph);

    assert!(dot.contains("digraph \"TestFlow\""));
    assert!(dot.contains("\"Extract\""));
    assert!(dot.contains("\"Extract\" -> \"Analyze\""));
    assert!(dot.contains("\"Analyze\" -> \"Report\""));
    assert!(dot.contains("fillcolor="));
}

#[test]
fn graph_export_mermaid_from_dependency_graph() {
    let steps = vec![
        step_deps::StepInfo { name: "Start".into(), step_type: "step".into(), user_prompt: "Begin".into(), argument: String::new() },
        step_deps::StepInfo { name: "Left".into(), step_type: "step".into(), user_prompt: "Path ${Start} L".into(), argument: String::new() },
        step_deps::StepInfo { name: "Right".into(), step_type: "use_tool".into(), user_prompt: "Path ${Start} R".into(), argument: String::new() },
        step_deps::StepInfo { name: "End".into(), step_type: "step".into(), user_prompt: "Merge ${Left} ${Right}".into(), argument: String::new() },
    ];
    let graph = step_deps::analyze(&steps);
    let mermaid = graph_export::to_mermaid("Diamond", &graph);

    assert!(mermaid.contains("title: Diamond"));
    assert!(mermaid.contains("graph TD"));
    assert!(mermaid.contains("Start --> Left"));
    assert!(mermaid.contains("Start --> Right"));
    assert!(mermaid.contains("Left --> End"));
    assert!(mermaid.contains("Right --> End"));
    assert!(mermaid.contains("classDef wave0"));
    // Tool step should get diamond shape
    assert!(mermaid.contains("Right{"));
}

#[test]
fn graph_export_from_axon_source() {
    let src = r#"
persona Expert { tone: "analytical" }
context C { depth: "deep" }

flow Analyze() {
  step Gather { ask: "Gather relevant data" }
  step Process { ask: "Process the data from ${Gather}" }
  step Summarize { ask: "Summarize findings from ${Process}" }
}

run Analyze() as Expert within C
"#;

    let tokens = axon::lexer::Lexer::new(src, "test.axon").tokenize().unwrap();
    let program = axon::parser::Parser::new(tokens).parse().unwrap();
    let ir = axon::ir_generator::IRGenerator::new().generate(&program);
    let graphs = graph_export::graph_from_ir(&ir);

    assert_eq!(graphs.len(), 1);
    assert_eq!(graphs[0].0, "Analyze");

    let dot = graph_export::to_dot(&graphs[0].0, &graphs[0].1);
    assert!(dot.contains("\"Gather\""));
    assert!(dot.contains("\"Process\""));
    assert!(dot.contains("\"Summarize\""));
    assert!(dot.contains("\"Gather\" -> \"Process\""));
    assert!(dot.contains("\"Process\" -> \"Summarize\""));
}

