#[test]
fn cost_estimator_pricing_models_differ() {
    use axon::cost_estimator;

    let source = r#"
        persona A { tone: "neutral" }
        context C { depth: shallow }
        flow Simple() {
            step Do {
                ask: "Execute task"
            }
        }
        run Simple() as A within C
    "#;

    let tokens = axon::lexer::Lexer::new(source, "test.axon").tokenize().unwrap();
    let ast = axon::parser::Parser::new(tokens).parse().unwrap();
    let ir = axon::ir_generator::IRGenerator::new().generate(&ast);

    let sonnet_report = cost_estimator::estimate_program(&ir, &cost_estimator::PricingModel::default_sonnet());
    let opus_report = cost_estimator::estimate_program(&ir, &cost_estimator::PricingModel::opus());
    let haiku_report = cost_estimator::estimate_program(&ir, &cost_estimator::PricingModel::haiku());

    // Same token counts, different costs
    assert_eq!(sonnet_report.total_tokens, opus_report.total_tokens);
    assert_eq!(sonnet_report.total_tokens, haiku_report.total_tokens);

    // Opus > Sonnet > Haiku in cost
    assert!(opus_report.estimated_cost_usd > sonnet_report.estimated_cost_usd);
    assert!(sonnet_report.estimated_cost_usd > haiku_report.estimated_cost_usd);

    // JSON output works
    let json = serde_json::to_string(&sonnet_report).unwrap();
    assert!(json.contains("\"estimated_cost_usd\""));
}

