// ── D36: Rate Limiter ────────────────────────────────────────────────────

#[test]
fn rate_limiter_sliding_window_basic() {
    use axon::rate_limiter::{RateLimiter, RateLimitConfig};
    use std::time::Duration;

    let config = RateLimitConfig {
        max_requests: 5,
        window: Duration::from_secs(60),
        enabled: true,
    };
    let mut limiter = RateLimiter::new(config);

    // Should allow 5 requests
    for i in 0..5 {
        let result = limiter.check("test-client");
        assert!(result.allowed, "request {} should be allowed", i);
        assert_eq!(result.remaining, 4 - i as u32);
        assert_eq!(result.limit, 5);
    }

    // 6th should be denied
    let denied = limiter.check("test-client");
    assert!(!denied.allowed);
    assert_eq!(denied.remaining, 0);

    // Different client should still be allowed
    let other = limiter.check("other-client");
    assert!(other.allowed);
    assert_eq!(other.remaining, 4);
}

#[test]
fn rate_limiter_window_expiry() {
    use axon::rate_limiter::{RateLimiter, RateLimitConfig};
    use std::time::Duration;

    let config = RateLimitConfig {
        max_requests: 2,
        window: Duration::from_millis(1),
        enabled: true,
    };
    let mut limiter = RateLimiter::new(config);

    // Exhaust limit
    assert!(limiter.check("client").allowed);
    assert!(limiter.check("client").allowed);
    assert!(!limiter.check("client").allowed);

    // Wait for window to expire
    std::thread::sleep(Duration::from_millis(5));

    // Should be allowed again
    let result = limiter.check("client");
    assert!(result.allowed);
}

#[test]
fn rate_limiter_disabled_and_peek() {
    use axon::rate_limiter::{RateLimiter, RateLimitConfig};

    // Disabled limiter always allows
    let mut disabled = RateLimiter::new(RateLimitConfig::disabled());
    for _ in 0..100 {
        assert!(disabled.check("flood").allowed);
    }

    // Peek doesn't consume quota
    let config = RateLimitConfig::default_config();
    let mut limiter = RateLimiter::new(config);
    limiter.check("client"); // consume 1

    let peek1 = limiter.peek("client");
    let peek2 = limiter.peek("client");
    assert_eq!(peek1.remaining, peek2.remaining); // unchanged

    // Cleanup removes expired buckets
    let mut short = RateLimiter::new(RateLimitConfig {
        max_requests: 10,
        window: std::time::Duration::from_millis(1),
        enabled: true,
    });
    short.check("temp");
    assert_eq!(short.client_count(), 1);
    std::thread::sleep(std::time::Duration::from_millis(5));
    short.cleanup();
    assert_eq!(short.client_count(), 0);
}

// ── D37: Session Scoping ─────────────────────────────────────────────────

#[test]
fn session_scope_isolation_between_flows() {
    use axon::session_scope::{ScopedSessionManager, flow_scope};

    let base = std::env::temp_dir().join("axon_integ_scope_isolation");
    let mut mgr = ScopedSessionManager::new(base.to_str().unwrap());

    // Same key in two different flow scopes
    let scope_a = flow_scope("analyze");
    let scope_b = flow_scope("report");

    mgr.remember(&scope_a, "result", "42", "step1");
    mgr.remember(&scope_b, "result", "99", "step1");

    assert_eq!(mgr.recall(&scope_a, "result").unwrap().value, "42");
    assert_eq!(mgr.recall(&scope_b, "result").unwrap().value, "99");

    // Global scope is independent
    assert!(mgr.recall("global", "result").is_none());

    // Persist in one scope doesn't affect another
    mgr.persist(&scope_a, "config", "verbose=true", "init");
    assert!(mgr.retrieve(&scope_a, "config").is_some());
    assert!(mgr.retrieve(&scope_b, "config").is_none());
}

#[test]
fn session_scope_summary_and_counts() {
    use axon::session_scope::{ScopedSessionManager, daemon_scope};

    let base = std::env::temp_dir().join("axon_integ_scope_summary");
    let mut mgr = ScopedSessionManager::new(base.to_str().unwrap());

    mgr.remember("global", "a", "1", "s");
    mgr.remember("global", "b", "2", "s");
    mgr.persist(&daemon_scope("worker"), "c", "3", "s");

    assert_eq!(mgr.total_memory_count(), 2);
    assert_eq!(mgr.total_store_count(), 1);
    assert!(mgr.scope_count() >= 2);

    let summary = mgr.summary();
    let global = summary.iter().find(|s| s.scope == "global").unwrap();
    assert_eq!(global.memory_count, 2);

    let worker = summary.iter().find(|s| s.scope == "daemon:worker").unwrap();
    assert_eq!(worker.store_count, 1);

    // Summary serializes
    let json = serde_json::to_string(&summary).unwrap();
    assert!(json.contains("\"global\""));
    assert!(json.contains("\"daemon:worker\""));
}

#[test]
fn session_scope_mutate_purge_scoped() {
    use axon::session_scope::{ScopedSessionManager, flow_scope};

    let base = std::env::temp_dir().join("axon_integ_scope_mutpurge");
    let mut mgr = ScopedSessionManager::new(base.to_str().unwrap());

    let scope = flow_scope("test");
    mgr.persist(&scope, "key", "old", "s1");

    // Mutate in correct scope
    assert!(mgr.mutate(&scope, "key", "new", "s2"));
    assert_eq!(mgr.retrieve(&scope, "key").unwrap().value, "new");

    // Mutate in wrong scope fails
    assert!(!mgr.mutate("global", "key", "val", "s3"));

    // Purge in correct scope
    assert!(mgr.purge(&scope, "key"));
    assert!(mgr.retrieve(&scope, "key").is_none());

    // Query scoped
    mgr.persist(&scope, "analysis_1", "r1", "s");
    mgr.persist(&scope, "analysis_2", "r2", "s");
    let results = mgr.query(&scope, "analysis");
    assert_eq!(results.len(), 2);
}

// ── D38: Request Logger ──────────────────────────────────────────────────

#[test]
fn request_logger_record_and_stats() {
    use axon::request_log::{RequestLogger, RequestLogConfig};
    use std::time::Duration;

    let mut logger = RequestLogger::new(RequestLogConfig::default_config());

    // Record various requests
    logger.record("GET", "/v1/health", 200, Duration::from_micros(100), "anon");
    logger.record("POST", "/v1/deploy", 200, Duration::from_micros(2000), "token_a");
    logger.record("POST", "/v1/deploy", 500, Duration::from_micros(500), "token_a");
    logger.record("GET", "/v1/metrics", 401, Duration::from_micros(50), "anon");

    assert_eq!(logger.len(), 4);
    assert_eq!(logger.total_requests(), 4);

    // Stats
    let stats = logger.stats();
    assert_eq!(stats.total_requests, 4);
    assert_eq!(stats.total_errors, 2); // 500 + 401
    assert_eq!(stats.buffered_entries, 4);
    assert!(stats.avg_latency_us > 0);
    assert_eq!(stats.max_latency_us, 2000);

    // Top paths
    assert_eq!(stats.top_paths[0].0, "/v1/deploy");
    assert_eq!(stats.top_paths[0].1, 2);

    // Recent (newest first)
    let recent = logger.recent(10, None);
    assert_eq!(recent[0].path, "/v1/metrics");
    assert_eq!(recent[3].path, "/v1/health");
}

#[test]
fn request_logger_ring_buffer_and_filtering() {
    use axon::request_log::{RequestLogger, RequestLogConfig, LogFilter};
    use std::time::Duration;

    // Small ring buffer
    let config = RequestLogConfig { capacity: 5, enabled: true };
    let mut logger = RequestLogger::new(config);

    for i in 0..10 {
        let status = if i % 3 == 0 { 500 } else { 200 };
        logger.record("GET", &format!("/v1/r{}", i), status, Duration::from_micros(100), "c");
    }

    // Only 5 entries buffered
    assert_eq!(logger.len(), 5);
    assert_eq!(logger.total_requests(), 10);

    // Filter by error status
    let filter = LogFilter { min_status: Some(400), ..Default::default() };
    let errors = logger.recent(10, Some(&filter));
    // Of entries 5-9, status 500 at i=6,9
    assert!(errors.len() >= 1);

    // Filter by path prefix
    let filter = LogFilter { path_prefix: Some("/v1/r9".into()), ..Default::default() };
    let r9 = logger.recent(10, Some(&filter));
    assert_eq!(r9.len(), 1);
    assert_eq!(r9[0].path, "/v1/r9");
}

#[test]
fn request_logger_disabled_and_serialization() {
    use axon::request_log::{RequestLogger, RequestLogConfig, RequestLogEntry, LogStats};
    use std::time::Duration;

    // Disabled logger records nothing
    let mut disabled = RequestLogger::new(RequestLogConfig::disabled());
    disabled.record("GET", "/v1/a", 200, Duration::from_micros(100), "c");
    assert_eq!(disabled.len(), 0);
    assert_eq!(disabled.total_requests(), 0);

    // Entry serializes
    let entry = RequestLogEntry {
        timestamp: 1700000000,
        method: "POST".into(),
        path: "/v1/deploy".into(),
        status: 200,
        latency_us: 1500,
        client_key: "token".into(),
    };
    let json = serde_json::to_value(&entry).unwrap();
    assert_eq!(json["method"], "POST");
    assert_eq!(json["status"], 200);
    assert_eq!(json["latency_us"], 1500);

    // Stats serializes
    let stats = LogStats {
        total_requests: 50,
        total_errors: 3,
        buffered_entries: 50,
        avg_latency_us: 200,
        max_latency_us: 5000,
        top_paths: vec![("/v1/health".into(), 20)],
        status_breakdown: vec![(200, 47), (500, 3)],
        uptime_secs: 600,
    };
    let json = serde_json::to_value(&stats).unwrap();
    assert_eq!(json["total_requests"], 50);
    assert_eq!(json["total_errors"], 3);
}

// ── D39: API Key Management ──────────────────────────────────────────────

#[test]
fn api_keys_create_validate_revoke() {
    use axon::api_keys::{ApiKeyManager, KeyRole};

    let mut mgr = ApiKeyManager::new(Some("admin_secret"));
    assert!(mgr.is_enabled());
    assert_eq!(mgr.active_count(), 1);

    // Create operator key
    assert!(mgr.create_key("service_a", "tok_service_a", KeyRole::Operator, Some(50)));
    assert_eq!(mgr.active_count(), 2);

    // Validate
    let result = mgr.validate("tok_service_a");
    assert!(result.valid);
    assert_eq!(result.key_name.unwrap(), "service_a");
    assert_eq!(result.role.unwrap(), KeyRole::Operator);
    assert_eq!(result.rate_limit, Some(50));

    // Invalid token
    assert!(!mgr.validate("bad_token").valid);

    // Revoke by name
    assert!(mgr.revoke_by_name("service_a"));
    assert!(!mgr.validate("tok_service_a").valid);
    assert_eq!(mgr.active_count(), 1);

    // List shows all including revoked
    let list = mgr.list();
    assert_eq!(list.len(), 2);
    let revoked = list.iter().find(|k| k.name == "service_a").unwrap();
    assert!(!revoked.active);
}

#[test]
fn api_keys_rotation_and_roles() {
    use axon::api_keys::{ApiKeyManager, KeyRole};

    let mut mgr = ApiKeyManager::new(None);
    mgr.create_key("rotating", "old_tok", KeyRole::Operator, Some(25));

    // Rotate
    let name = mgr.rotate("old_tok", "new_tok").unwrap();
    assert_eq!(name, "rotating");

    // Old revoked, new active with same role/rate_limit
    assert!(!mgr.validate("old_tok").valid);
    let result = mgr.validate("new_tok");
    assert!(result.valid);
    assert_eq!(result.role.unwrap(), KeyRole::Operator);
    assert_eq!(result.rate_limit, Some(25));

    // Role permissions
    assert!(KeyRole::Admin.can_write());
    assert!(KeyRole::Admin.can_manage_keys());
    assert!(KeyRole::Operator.can_write());
    assert!(!KeyRole::Operator.can_manage_keys());
    assert!(!KeyRole::ReadOnly.can_write());
    assert!(!KeyRole::ReadOnly.can_manage_keys());
}

#[test]
fn api_keys_usage_tracking_and_serialization() {
    use axon::api_keys::{ApiKeyManager, KeyRole};

    let mut mgr = ApiKeyManager::new(None);
    mgr.create_key("tracked", "tok_tracked", KeyRole::ReadOnly, None);

    // Peek doesn't increment
    mgr.peek("tok_tracked");
    mgr.peek("tok_tracked");
    let list = mgr.list();
    assert_eq!(list[0].request_count, 0);
    assert!(list[0].last_used.is_none());

    // Validate increments
    mgr.validate("tok_tracked");
    mgr.validate("tok_tracked");
    mgr.validate("tok_tracked");
    let list = mgr.list();
    assert_eq!(list[0].request_count, 3);
    assert!(list[0].last_used.is_some());

    // Summary serializes with masked token
    let json = serde_json::to_value(&list[0]).unwrap();
    assert_eq!(json["role"], "readonly");
    assert!(json["token_prefix"].as_str().unwrap().contains("****"));
    assert_eq!(json["request_count"], 3);
}

// ═══════════════════════════════════════════════════════════════════════════
// D40 — Auth Middleware (role-based access control)
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn auth_middleware_role_enforcement() {
    use axon::api_keys::{ApiKeyManager, KeyRole};
    use axon::auth_middleware::{self, AccessLevel};
    use axum::http::HeaderMap;

    fn headers(token: &str) -> HeaderMap {
        let mut h = HeaderMap::new();
        h.insert("authorization", format!("Bearer {token}").parse().unwrap());
        h
    }

    let mut mgr = ApiKeyManager::new(Some("admin_master"));
    mgr.create_key("ops", "ops_token", KeyRole::Operator, Some(50));
    mgr.create_key("viewer", "view_token", KeyRole::ReadOnly, None);

    // Admin can access everything
    let h = headers("admin_master");
    assert!(auth_middleware::check(&mut mgr, &h, AccessLevel::ReadOnly).is_ok());
    assert!(auth_middleware::check(&mut mgr, &h, AccessLevel::Write).is_ok());
    assert!(auth_middleware::check(&mut mgr, &h, AccessLevel::Admin).is_ok());

    // Operator can read and write, not admin
    let h = headers("ops_token");
    assert!(auth_middleware::check(&mut mgr, &h, AccessLevel::ReadOnly).is_ok());
    assert!(auth_middleware::check(&mut mgr, &h, AccessLevel::Write).is_ok());
    let err = auth_middleware::check(&mut mgr, &h, AccessLevel::Admin).unwrap_err();
    assert_eq!(err, axum::http::StatusCode::FORBIDDEN);

    // ReadOnly can only read
    let h = headers("view_token");
    assert!(auth_middleware::check(&mut mgr, &h, AccessLevel::ReadOnly).is_ok());
    let err = auth_middleware::check(&mut mgr, &h, AccessLevel::Write).unwrap_err();
    assert_eq!(err, axum::http::StatusCode::FORBIDDEN);
    let err = auth_middleware::check(&mut mgr, &h, AccessLevel::Admin).unwrap_err();
    assert_eq!(err, axum::http::StatusCode::FORBIDDEN);
}

#[test]
fn auth_middleware_endpoint_classification() {
    use axon::auth_middleware::{classify_endpoint, AccessLevel};

    // Public
    assert_eq!(classify_endpoint("GET", "/v1/health"), AccessLevel::Public);
    assert_eq!(classify_endpoint("GET", "/v1/health/live"), AccessLevel::Public);
    assert_eq!(classify_endpoint("GET", "/v1/health/ready"), AccessLevel::Public);
    assert_eq!(classify_endpoint("GET", "/v1/version"), AccessLevel::Public);
    assert_eq!(classify_endpoint("GET", "/v1/rate-limit"), AccessLevel::Public);

    // ReadOnly
    assert_eq!(classify_endpoint("GET", "/v1/metrics"), AccessLevel::ReadOnly);
    assert_eq!(classify_endpoint("GET", "/v1/daemons"), AccessLevel::ReadOnly);
    assert_eq!(classify_endpoint("GET", "/v1/logs"), AccessLevel::ReadOnly);
    assert_eq!(classify_endpoint("GET", "/v1/keys"), AccessLevel::ReadOnly);
    assert_eq!(classify_endpoint("GET", "/v1/session"), AccessLevel::ReadOnly);
    assert_eq!(classify_endpoint("GET", "/v1/versions"), AccessLevel::ReadOnly);

    // Write (POST/DELETE to non-keys)
    assert_eq!(classify_endpoint("POST", "/v1/deploy"), AccessLevel::Write);
    assert_eq!(classify_endpoint("POST", "/v1/estimate"), AccessLevel::Write);
    assert_eq!(classify_endpoint("POST", "/v1/events"), AccessLevel::Write);
    assert_eq!(classify_endpoint("DELETE", "/v1/daemons/x"), AccessLevel::Write);
    assert_eq!(classify_endpoint("POST", "/v1/session/remember"), AccessLevel::Write);

    // Admin (POST to /v1/keys)
    assert_eq!(classify_endpoint("POST", "/v1/keys"), AccessLevel::Admin);
    assert_eq!(classify_endpoint("POST", "/v1/keys/revoke"), AccessLevel::Admin);
    assert_eq!(classify_endpoint("POST", "/v1/keys/rotate"), AccessLevel::Admin);
}

#[test]
fn auth_middleware_usage_tracking_and_peek() {
    use axon::api_keys::{ApiKeyManager, KeyRole};
    use axon::auth_middleware::{self, AccessLevel};
    use axum::http::HeaderMap;

    fn headers(token: &str) -> HeaderMap {
        let mut h = HeaderMap::new();
        h.insert("authorization", format!("Bearer {token}").parse().unwrap());
        h
    }

    let mut mgr = ApiKeyManager::new(Some("admin_tok"));
    mgr.create_key("svc", "svc_tok", KeyRole::Operator, Some(25));

    // peek does NOT record usage
    let h = headers("svc_tok");
    auth_middleware::peek(&mgr, &h, AccessLevel::ReadOnly).unwrap();
    auth_middleware::peek(&mgr, &h, AccessLevel::ReadOnly).unwrap();
    let list = mgr.list();
    let key = list.iter().find(|k| k.name == "svc").unwrap();
    assert_eq!(key.request_count, 0);

    // check DOES record usage
    auth_middleware::check(&mut mgr, &h, AccessLevel::Write).unwrap();
    auth_middleware::check(&mut mgr, &h, AccessLevel::ReadOnly).unwrap();
    let list = mgr.list();
    let key = list.iter().find(|k| k.name == "svc").unwrap();
    assert_eq!(key.request_count, 2);
    assert!(key.last_used.is_some());

    // rate_limit is carried through AuthResult
    let result = auth_middleware::check(&mut mgr, &h, AccessLevel::Write).unwrap();
    assert_eq!(result.rate_limit, Some(25));
    assert_eq!(result.key_name, Some("svc".to_string()));
    assert_eq!(result.role, Some(KeyRole::Operator));

    // Disabled manager allows everything without token
    let mut disabled = ApiKeyManager::new(None);
    let empty_h = HeaderMap::new();
    assert!(auth_middleware::check(&mut disabled, &empty_h, AccessLevel::Admin).is_ok());
    assert!(auth_middleware::peek(&disabled, &empty_h, AccessLevel::Write).is_ok());

    // Revoked key is denied
    mgr.revoke("svc_tok");
    let err = auth_middleware::check(&mut mgr, &h, AccessLevel::ReadOnly).unwrap_err();
    assert_eq!(err, axum::http::StatusCode::FORBIDDEN);
}

