#[test]
fn server_config_snapshot_and_apply() {
    use axon::api_keys::ApiKeyManager;
    use axon::rate_limiter::{RateLimiter, RateLimitConfig};
    use axon::request_log::{RequestLogger, RequestLogConfig};
    use axon::server_config::{self, ConfigUpdate, RateLimitUpdate, RequestLogUpdate};

    let mut rl = RateLimiter::new(RateLimitConfig::default_config());
    let mut log = RequestLogger::new(RequestLogConfig::default_config());
    let keys = ApiKeyManager::new(None);

    // Snapshot captures defaults
    let snap = server_config::snapshot(&rl, &log, &keys);
    assert_eq!(snap.rate_limit.max_requests, 100);
    assert_eq!(snap.rate_limit.window_secs, 60);
    assert!(snap.rate_limit.enabled);
    assert_eq!(snap.request_log.capacity, 1000);
    assert!(snap.request_log.enabled);
    assert!(!snap.auth.enabled);

    // Apply partial update
    let changes = server_config::apply_rate_limit(
        &RateLimitUpdate { max_requests: Some(250), window_secs: Some(120), enabled: None },
        &mut rl,
    );
    assert_eq!(changes.len(), 2);
    assert_eq!(changes[0].field, "max_requests");
    assert_eq!(changes[0].old_value, "100");
    assert_eq!(changes[0].new_value, "250");

    let changes = server_config::apply_request_log(
        &RequestLogUpdate { capacity: Some(500), enabled: Some(false) },
        &mut log,
    );
    assert_eq!(changes.len(), 2);

    // Verify new snapshot reflects changes
    let snap = server_config::snapshot(&rl, &log, &keys);
    assert_eq!(snap.rate_limit.max_requests, 250);
    assert_eq!(snap.rate_limit.window_secs, 120);
    assert_eq!(snap.request_log.capacity, 500);
    assert!(!snap.request_log.enabled);
}

#[test]
fn server_config_no_op_when_same_values() {
    use axon::rate_limiter::{RateLimiter, RateLimitConfig};
    use axon::server_config::{self, RateLimitUpdate};

    let mut rl = RateLimiter::new(RateLimitConfig::default_config());

    // Applying same values produces no changes
    let changes = server_config::apply_rate_limit(
        &RateLimitUpdate { max_requests: Some(100), window_secs: Some(60), enabled: Some(true) },
        &mut rl,
    );
    assert!(changes.is_empty());
}

#[test]
fn server_config_change_tracking_and_serialization() {
    use axon::api_keys::ApiKeyManager;
    use axon::rate_limiter::{RateLimiter, RateLimitConfig};
    use axon::request_log::{RequestLogger, RequestLogConfig};
    use axon::server_config::{self, ConfigUpdate, RateLimitUpdate, RequestLogUpdate, AuthSection};

    let mut rl = RateLimiter::new(RateLimitConfig::default_config());
    let mut log = RequestLogger::new(RequestLogConfig::default_config());
    let auth = AuthSection { enabled: true, active_keys: 2, total_keys: 3 };

    let update = ConfigUpdate {
        rate_limit: Some(RateLimitUpdate {
            max_requests: Some(50),
            window_secs: None,
            enabled: Some(false),
        }),
        request_log: Some(RequestLogUpdate {
            capacity: Some(2000),
            enabled: None,
        }),
    };

    let result = server_config::apply(&update, &mut rl, &mut log, &auth);
    assert!(result.applied);
    assert_eq!(result.changes.len(), 3); // max_requests + enabled + capacity

    // Result serializes to JSON
    let json = serde_json::to_value(&result).unwrap();
    assert_eq!(json["applied"], true);
    assert_eq!(json["snapshot"]["rate_limit"]["max_requests"], 50);
    assert_eq!(json["snapshot"]["rate_limit"]["enabled"], false);
    assert_eq!(json["snapshot"]["request_log"]["capacity"], 2000);
    assert_eq!(json["snapshot"]["auth"]["enabled"], true);
    assert_eq!(json["snapshot"]["auth"]["active_keys"], 2);

    // Changes array has section/field/old/new
    let changes = json["changes"].as_array().unwrap();
    assert!(changes.iter().any(|c| c["field"] == "max_requests" && c["old_value"] == "100"));
    assert!(changes.iter().any(|c| c["field"] == "enabled" && c["section"] == "rate_limit"));
    assert!(changes.iter().any(|c| c["field"] == "capacity" && c["old_value"] == "1000"));
}

