#[test]
fn webhooks_register_dispatch_unregister() {
    use axon::webhooks::WebhookRegistry;

    let mut reg = WebhookRegistry::new();

    // Register webhooks with different topic filters
    let id1 = reg.register("deploy-hook", "https://example.com/deploy", vec!["deploy".into()], None);
    let id2 = reg.register("all-hook", "https://example.com/all", vec!["*".into()], Some("secret123".into()));
    let id3 = reg.register("daemon-hook", "https://example.com/daemon", vec!["daemon.*".into()], None);

    assert_eq!(reg.count(), 3);
    assert_eq!(reg.active_count(), 3);

    // Dispatch deploy event — should match id1 (deploy) and id2 (*)
    let result = reg.dispatch("deploy", &serde_json::json!({"flow": "F1"}), "server");
    assert_eq!(result.matched, 2);
    assert!(result.webhook_ids.contains(&id1));
    assert!(result.webhook_ids.contains(&id2));

    // Dispatch daemon event — should match id2 (*) and id3 (daemon.*)
    let result = reg.dispatch("daemon.started", &serde_json::json!({}), "server");
    assert_eq!(result.matched, 2);
    assert!(result.webhook_ids.contains(&id2));
    assert!(result.webhook_ids.contains(&id3));

    // Dispatch config event — should match only id2 (*)
    let result = reg.dispatch("config.updated", &serde_json::json!({}), "server");
    assert_eq!(result.matched, 1);

    // Unregister
    assert!(reg.unregister(&id1));
    assert_eq!(reg.count(), 2);
    let result = reg.dispatch("deploy", &serde_json::json!({}), "server");
    assert_eq!(result.matched, 1); // only id2 now
}

#[test]
fn webhooks_toggle_and_delivery_tracking() {
    use axon::webhooks::WebhookRegistry;

    let mut reg = WebhookRegistry::new();
    let id = reg.register("toggler", "https://t.com", vec!["deploy".into()], None);

    // Active webhook matches
    assert_eq!(reg.match_topic("deploy").len(), 1);

    // Toggle off
    assert_eq!(reg.toggle(&id), Some(false));
    assert_eq!(reg.match_topic("deploy").len(), 0);
    assert_eq!(reg.active_count(), 0);

    // Toggle back on
    assert_eq!(reg.toggle(&id), Some(true));
    assert_eq!(reg.match_topic("deploy").len(), 1);

    // Record completed deliveries
    reg.record_completed(&id, "deploy", 200, 45, None, 0);
    reg.record_completed(&id, "deploy", 502, 120, Some("bad gateway".into()), 0);
    reg.record_completed(&id, "deploy", 200, 30, None, 1);

    let deliveries = reg.recent_deliveries(10, Some(&id));
    assert_eq!(deliveries.len(), 3);
    assert!(deliveries[0].success); // 200 (newest = attempt 1)
    assert!(!deliveries[1].success); // 502
    assert!(deliveries[2].success); // 200 (oldest)

    let stats = reg.stats();
    assert_eq!(stats.total_webhooks, 1);
    assert_eq!(stats.total_failures, 1);
}

#[test]
fn webhooks_stats_and_serialization() {
    use axon::webhooks::WebhookRegistry;

    let mut reg = WebhookRegistry::new();
    let id1 = reg.register("alpha", "https://a.com", vec!["deploy".into(), "config.*".into()], Some("sec".into()));
    let id2 = reg.register("beta", "https://b.com", vec!["*".into()], None);

    // Dispatch events
    reg.dispatch("deploy", &serde_json::json!({}), "server");
    reg.dispatch("config.updated", &serde_json::json!({}), "server");
    reg.record_completed(&id1, "deploy", 200, 50, None, 0);
    reg.record_completed(&id2, "deploy", 500, 100, Some("error".into()), 0);

    // Stats
    let stats = reg.stats();
    assert_eq!(stats.total_webhooks, 2);
    assert_eq!(stats.active_webhooks, 2);
    assert!(stats.total_deliveries >= 2);
    assert_eq!(stats.total_failures, 1);

    // List serialization
    let list = reg.list();
    assert_eq!(list.len(), 2);
    let json = serde_json::to_value(&list[0]).unwrap();
    assert!(json["id"].as_str().unwrap().starts_with("wh_"));
    assert!(json["events"].as_array().unwrap().len() >= 1);

    // Has_secret is true for alpha, false for beta
    let alpha = list.iter().find(|w| w.name == "alpha").unwrap();
    let beta = list.iter().find(|w| w.name == "beta").unwrap();
    assert!(alpha.has_secret);
    assert!(!beta.has_secret);

    // Signature computation is deterministic
    let sig = WebhookRegistry::compute_signature("secret", b"test payload");
    assert!(sig.starts_with("sha256="));
    assert_eq!(sig, WebhookRegistry::compute_signature("secret", b"test payload"));
}

