// D43 — Config Persistence (save/load to disk)
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn config_persistence_save_load_roundtrip() {
    use axon::config_persistence::{self, PersistedConfig};
    use axon::server_config::{ConfigSnapshot, RateLimitSection, RequestLogSection, AuthSection};
    use std::path::PathBuf;

    let path = std::env::temp_dir().join(format!("axon_integ_roundtrip_{}.json", std::process::id()));

    let snap = ConfigSnapshot {
        rate_limit: RateLimitSection { max_requests: 250, window_secs: 90, enabled: true },
        request_log: RequestLogSection { capacity: 2000, enabled: false },
        auth: AuthSection { enabled: true, active_keys: 3, total_keys: 5 },
    };

    // Save
    let result = config_persistence::save(&snap, &path, "0.30.0-test");
    assert!(result.success);
    assert_eq!(result.save_count, 1);

    // Load
    let loaded = config_persistence::load(&path).unwrap();
    assert_eq!(loaded.version, 1);
    assert_eq!(loaded.save_count, 1);
    assert_eq!(loaded.config.rate_limit.max_requests, 250);
    assert_eq!(loaded.config.rate_limit.window_secs, 90);
    assert_eq!(loaded.config.request_log.capacity, 2000);
    assert!(!loaded.config.request_log.enabled);

    // Save again increments count
    let result = config_persistence::save(&snap, &path, "0.30.0-test");
    assert_eq!(result.save_count, 2);

    // Convert to update
    let update = config_persistence::snapshot_to_update(&loaded.config);
    let rl = update.rate_limit.unwrap();
    assert_eq!(rl.max_requests, Some(250));
    assert_eq!(rl.window_secs, Some(90));
    let log = update.request_log.unwrap();
    assert_eq!(log.capacity, Some(2000));
    assert_eq!(log.enabled, Some(false));

    // Cleanup
    std::fs::remove_file(&path).ok();
}

#[test]
fn config_persistence_restore_applies_to_components() {
    use axon::config_persistence;
    use axon::rate_limiter::{RateLimiter, RateLimitConfig};
    use axon::request_log::{RequestLogger, RequestLogConfig};
    use axon::server_config::{self, ConfigSnapshot, RateLimitSection, RequestLogSection, AuthSection};

    let path = std::env::temp_dir().join(format!("axon_integ_restore_{}.json", std::process::id()));

    // Save a non-default config
    let snap = ConfigSnapshot {
        rate_limit: RateLimitSection { max_requests: 500, window_secs: 300, enabled: false },
        request_log: RequestLogSection { capacity: 100, enabled: true },
        auth: AuthSection { enabled: false, active_keys: 0, total_keys: 0 },
    };
    config_persistence::save(&snap, &path, "test");

    // Create fresh components with defaults
    let mut rl = RateLimiter::new(RateLimitConfig::default_config());
    let mut log = RequestLogger::new(RequestLogConfig::default_config());

    // Verify defaults
    assert_eq!(rl.config().max_requests, 100);
    assert_eq!(log.config().capacity, 1000);

    // Load and apply
    let persisted = config_persistence::load(&path).unwrap();
    let update = config_persistence::snapshot_to_update(&persisted.config);
    if let Some(ref rl_update) = update.rate_limit {
        server_config::apply_rate_limit(rl_update, &mut rl);
    }
    if let Some(ref log_update) = update.request_log {
        server_config::apply_request_log(log_update, &mut log);
    }

    // Verify restored values
    assert_eq!(rl.config().max_requests, 500);
    assert_eq!(rl.config().window.as_secs(), 300);
    assert!(!rl.config().enabled);
    assert_eq!(log.config().capacity, 100);
    assert!(log.config().enabled);

    std::fs::remove_file(&path).ok();
}

#[test]
fn config_persistence_exists_and_remove() {
    use axon::config_persistence;
    use axon::server_config::{ConfigSnapshot, RateLimitSection, RequestLogSection, AuthSection};

    let path = std::env::temp_dir().join(format!("axon_integ_remove_{}.json", std::process::id()));

    assert!(!config_persistence::exists(&path));

    let snap = ConfigSnapshot {
        rate_limit: RateLimitSection { max_requests: 100, window_secs: 60, enabled: true },
        request_log: RequestLogSection { capacity: 1000, enabled: true },
        auth: AuthSection { enabled: false, active_keys: 0, total_keys: 0 },
    };
    config_persistence::save(&snap, &path, "test");
    assert!(config_persistence::exists(&path));

    assert!(config_persistence::remove(&path));
    assert!(!config_persistence::exists(&path));
    assert!(!config_persistence::remove(&path)); // already gone

    // Load nonexistent returns error
    let result = config_persistence::load(&path);
    assert!(result.is_err());
}

// ── D44: Audit Trail ─────────────────────────────────────────────────────

#[test]
fn audit_trail_record_query_and_filter() {
    use axon::audit_trail::{AuditLog, AuditAction, AuditFilter};

    let mut log = AuditLog::new(1000);

    // Record a mix of actions
    log.record("alice", AuditAction::Deploy, "FlowA", serde_json::json!({"flows": 1}), true);
    log.record("bob", AuditAction::KeyCreate, "api-key-1", serde_json::json!({"role": "operator"}), true);
    log.record("alice", AuditAction::ConfigUpdate, "rate_limit", serde_json::json!({"changes": 2}), true);
    log.record("alice", AuditAction::WebhookRegister, "wh_1", serde_json::json!({"url": "http://example.com"}), true);
    log.record("bob", AuditAction::Deploy, "FlowB", serde_json::json!(null), false);

    assert_eq!(log.len(), 5);
    assert_eq!(log.total_recorded(), 5);

    // Unfiltered query returns newest first
    let all = log.query(10, None);
    assert_eq!(all.len(), 5);
    assert_eq!(all[0].target, "FlowB"); // newest

    // Filter by action
    let deploy_filter = AuditFilter {
        action: Some(AuditAction::Deploy),
        ..Default::default()
    };
    let deploys = log.query(10, Some(&deploy_filter));
    assert_eq!(deploys.len(), 2);

    // Filter by actor
    let alice_filter = AuditFilter {
        actor: Some("alice".into()),
        ..Default::default()
    };
    let alice_entries = log.query(10, Some(&alice_filter));
    assert_eq!(alice_entries.len(), 3);

    // Combined filter: alice + deploy + success
    let combined = AuditFilter {
        actor: Some("alice".into()),
        action: Some(AuditAction::Deploy),
        success: Some(true),
        ..Default::default()
    };
    let results = log.query(10, Some(&combined));
    assert_eq!(results.len(), 1);
    assert_eq!(results[0].target, "FlowA");

    // get() by ID
    assert!(log.get(1).is_some());
    assert!(log.get(999).is_none());
}

#[test]
fn audit_trail_stats_and_capacity() {
    use axon::audit_trail::{AuditLog, AuditAction};

    let mut log = AuditLog::new(3); // small capacity

    for i in 0..5 {
        let success = i != 2; // entry 3 fails
        log.record("actor", AuditAction::Deploy, &format!("f{i}"), serde_json::json!(null), success);
    }

    assert_eq!(log.len(), 3); // capped at capacity
    assert_eq!(log.total_recorded(), 5); // all recorded

    let stats = log.stats();
    assert_eq!(stats.total_entries, 5);
    assert_eq!(stats.buffered_entries, 3);
    // Entry i=2 (id=3, success=false) is still buffered (ids 3,4,5 remain)
    assert_eq!(stats.failure_count, 1);
    assert!(stats.actions_breakdown.contains_key("deploy"));
    assert_eq!(stats.top_actors.len(), 1);
    assert_eq!(stats.top_actors[0].0, "actor");
    assert!(stats.oldest_timestamp.is_some());
    assert!(stats.newest_timestamp.is_some());

    // Serializes to JSON
    let json = serde_json::to_value(&stats).unwrap();
    assert_eq!(json["total_entries"], 5);
    assert!(json["actions_breakdown"].is_object());
}

#[test]
fn audit_trail_parse_action_and_entry_serialization() {
    use axon::audit_trail::{AuditLog, AuditAction, parse_action};

    // parse_action roundtrip for all 15 variants
    let action_strs = [
        "deploy", "config_update", "config_save", "config_load", "config_delete",
        "key_create", "key_revoke", "key_rotate", "webhook_register", "webhook_remove",
        "webhook_toggle", "daemon_delete", "rollback", "session_write", "session_purge",
        "server_shutdown",
    ];
    for s in &action_strs {
        assert!(parse_action(s).is_some(), "failed to parse: {s}");
    }
    assert!(parse_action("nonexistent").is_none());

    // Entry serialization
    let mut log = AuditLog::new(100);
    log.record("admin", AuditAction::KeyCreate, "my-key", serde_json::json!({"role": "admin"}), true);
    let entry = log.get(1).unwrap();
    let json = serde_json::to_value(entry).unwrap();
    assert_eq!(json["id"], 1);
    assert_eq!(json["actor"], "admin");
    assert_eq!(json["action"], "key_create");
    assert_eq!(json["target"], "my-key");
    assert_eq!(json["success"], true);
    assert_eq!(json["detail"]["role"], "admin");
    assert!(json["timestamp"].is_u64());
}

// ── D45: Health Check Deep ───────────────────────────────────────────────

#[test]
fn health_check_deep_all_nine_components() {
    use axon::health_check;

    let mut states = std::collections::HashMap::new();
    states.insert("running".to_string(), 1);

    let input = health_check::HealthInput {
        uptime_secs: 600,
        axon_version: "0.31.0".to_string(),
        daemon_count: 1,
        daemon_state_counts: states,
        bus_events_published: 200,
        bus_subscriber_count: 5,
        session_memory_count: 10,
        session_store_count: 3,
        flows_tracked: 3,
        versions_total: 8,
        rate_limiter_enabled: true,
        rate_limiter_max_requests: 200,
        rate_limiter_window_secs: 120,
        request_log_enabled: true,
        request_log_entries: 50,
        request_log_capacity: 500,
        api_keys_enabled: true,
        api_keys_active: 4,
        api_keys_total: 6,
        webhooks_active: 3,
        webhooks_total: 4,
        webhooks_total_failures: 2,
        audit_log_entries: 200,
        audit_log_total_recorded: 350,
    };

    let report = health_check::evaluate(&input);
    assert_eq!(report.status, health_check::HealthStatus::Healthy);
    assert_eq!(report.components.len(), 9);

    let names: Vec<&str> = report.components.iter().map(|c| c.name.as_str()).collect();
    assert!(names.contains(&"event_bus"));
    assert!(names.contains(&"supervisor"));
    assert!(names.contains(&"session_store"));
    assert!(names.contains(&"version_registry"));
    assert!(names.contains(&"rate_limiter"));
    assert!(names.contains(&"request_logger"));
    assert!(names.contains(&"api_keys"));
    assert!(names.contains(&"webhooks"));
    assert!(names.contains(&"audit_log"));

    // All healthy with these values
    for c in &report.components {
        assert_eq!(c.status, health_check::HealthStatus::Healthy, "{} not healthy", c.name);
    }

    // Check specific details
    let rl = report.components.iter().find(|c| c.name == "rate_limiter").unwrap();
    assert_eq!(rl.details.as_ref().unwrap()["max_requests"], 200);

    let al = report.components.iter().find(|c| c.name == "audit_log").unwrap();
    assert_eq!(al.details.as_ref().unwrap()["total_recorded"], 350);
}

