// ── D46: Graceful Shutdown ───────────────────────────────────────────────

#[test]
fn graceful_shutdown_coordinator_trigger_and_idempotency() {
    use axon::graceful_shutdown::ShutdownCoordinator;
    use std::time::Instant;

    let coord = ShutdownCoordinator::new(Instant::now());
    assert!(!coord.is_triggered());

    // First trigger succeeds
    assert!(coord.trigger());
    assert!(coord.is_triggered());

    // Second trigger is idempotent (returns false)
    assert!(!coord.trigger());
    assert!(coord.is_triggered());

    // Uptime is small
    assert!(coord.uptime_secs() < 5);
}

#[tokio::test]
async fn graceful_shutdown_coordinator_wait_resolves() {
    use axon::graceful_shutdown::ShutdownCoordinator;
    use std::sync::Arc;
    use std::time::{Duration, Instant};

    let coord = Arc::new(ShutdownCoordinator::new(Instant::now()));
    let coord2 = coord.clone();

    // Trigger from spawned task after short delay
    tokio::spawn(async move {
        tokio::time::sleep(Duration::from_millis(20)).await;
        coord2.trigger();
    });

    // wait() should resolve within timeout
    tokio::time::timeout(Duration::from_secs(2), coord.wait())
        .await
        .expect("wait should resolve");

    assert!(coord.is_triggered());

    // Calling wait() again when already triggered resolves immediately
    tokio::time::timeout(Duration::from_millis(50), coord.wait())
        .await
        .expect("wait should resolve immediately when already triggered");
}

#[test]
fn graceful_shutdown_reason_and_status_serialization() {
    use axon::graceful_shutdown::{ShutdownReason, ShutdownStatus};

    // Reason serialization
    assert_eq!(ShutdownReason::Signal.as_str(), "signal");
    assert_eq!(ShutdownReason::Api.as_str(), "api");

    let signal_json = serde_json::to_value(ShutdownReason::Signal).unwrap();
    assert_eq!(signal_json, "signal");
    let api_json = serde_json::to_value(ShutdownReason::Api).unwrap();
    assert_eq!(api_json, "api");

    // Status serialization
    let status = ShutdownStatus {
        initiated: true,
        reason: ShutdownReason::Api,
        uptime_secs: 7200,
        message: "graceful shutdown initiated".to_string(),
    };
    let json = serde_json::to_value(&status).unwrap();
    assert_eq!(json["initiated"], true);
    assert_eq!(json["reason"], "api");
    assert_eq!(json["uptime_secs"], 7200);
    assert_eq!(json["message"], "graceful shutdown initiated");
}

