#[test]
fn webhook_delivery_config_defaults_and_serialization() {
    use axon::webhook_delivery::{DeliveryConfig, DeliveryResult, WebhookPayload};

    // Default config
    let config = DeliveryConfig::default();
    assert_eq!(config.timeout.as_secs(), 10);
    assert_eq!(config.max_retries, 3);
    assert_eq!(config.base_delay.as_millis(), 500);
    assert_eq!(config.max_delay.as_secs(), 30);

    // DeliveryResult serialization
    let result = DeliveryResult {
        webhook_id: "wh_1".to_string(),
        topic: "deploy".to_string(),
        status_code: 200,
        success: true,
        latency_ms: 42,
        attempts: 1,
        error: None,
    };
    let json = serde_json::to_value(&result).unwrap();
    assert_eq!(json["webhook_id"], "wh_1");
    assert_eq!(json["status_code"], 200);
    assert_eq!(json["success"], true);
    assert_eq!(json["attempts"], 1);
    assert!(json["error"].is_null());

    // Failed result
    let fail = DeliveryResult {
        webhook_id: "wh_2".to_string(),
        topic: "config.updated".to_string(),
        status_code: 500,
        success: false,
        latency_ms: 150,
        attempts: 4,
        error: Some("HTTP 500: Server Error".to_string()),
    };
    let json = serde_json::to_value(&fail).unwrap();
    assert_eq!(json["attempts"], 4);
    assert_eq!(json["error"], "HTTP 500: Server Error");

    // WebhookPayload serialization
    let payload = WebhookPayload {
        event: "deploy".to_string(),
        payload: serde_json::json!({"flows": ["A"]}),
        source: "server".to_string(),
        timestamp: 1700000000,
    };
    let json = serde_json::to_value(&payload).unwrap();
    assert_eq!(json["event"], "deploy");
    assert_eq!(json["timestamp"], 1700000000u64);
}

#[tokio::test]
async fn webhook_delivery_connection_refused_returns_error() {
    use axon::webhook_delivery::{deliver_one, WebhookPayload};
    use std::time::Duration;

    let body = WebhookPayload {
        event: "test".to_string(),
        payload: serde_json::json!(null),
        source: "test".to_string(),
        timestamp: 0,
    };

    let (status, _latency, error) = deliver_one(
        "http://127.0.0.1:19999/nonexistent",
        &body,
        None,
        Duration::from_secs(2),
    ).await;

    assert_eq!(status, 0);
    assert!(error.is_some());
}

#[tokio::test]
async fn webhook_delivery_retry_exhausts_on_failure() {
    use axon::webhook_delivery::{deliver_with_retry, DeliveryConfig, WebhookPayload};
    use std::time::Duration;

    let body = WebhookPayload {
        event: "test.retry".to_string(),
        payload: serde_json::json!({"key": "value"}),
        source: "integration-test".to_string(),
        timestamp: 0,
    };

    let config = DeliveryConfig {
        timeout: Duration::from_secs(1),
        max_retries: 1, // 1 retry only to keep test fast
        base_delay: Duration::from_millis(50),
        max_delay: Duration::from_millis(100),
    };

    let result = deliver_with_retry(
        "http://127.0.0.1:19999/nonexistent",
        &body,
        Some("sha256=test"),
        &config,
    ).await;

    assert!(!result.success);
    assert_eq!(result.attempts, 2); // initial + 1 retry
    assert!(result.error.is_some());
    assert_eq!(result.topic, "test.retry");
}

