// D49: Request middleware — RequestId, timing, config, stats
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn request_middleware_id_generator_and_config() {
    use axon::request_middleware::{RequestIdGenerator, MiddlewareConfig, MiddlewareStats};

    // Sequential ID generation
    let gen = RequestIdGenerator::new();
    assert_eq!(gen.next_id(), "axr-0");
    assert_eq!(gen.next_id(), "axr-1");
    assert_eq!(gen.next_id(), "axr-2");
    assert_eq!(gen.count(), 3);

    // Custom prefix
    let gen2 = RequestIdGenerator::with_prefix("test");
    assert_eq!(gen2.next_id(), "test-0");
    assert_eq!(gen2.count(), 1);

    // Default config
    let cfg = MiddlewareConfig::default();
    assert!(cfg.enabled);
    assert_eq!(cfg.slow_threshold_ms, 5000);
    assert!(cfg.inject_request_id);
    assert!(cfg.inject_response_time);

    // Disabled config
    let disabled = MiddlewareConfig::disabled();
    assert!(!disabled.enabled);
    assert!(!disabled.inject_request_id);
    assert!(!disabled.inject_response_time);

    // Serialization roundtrip
    let json = serde_json::to_value(&cfg).unwrap();
    assert_eq!(json["enabled"], true);
    assert_eq!(json["slow_threshold_ms"], 5000);
    let deserialized: MiddlewareConfig = serde_json::from_value(json).unwrap();
    assert_eq!(deserialized.slow_threshold_ms, 5000);

    // Stats serialization
    let stats = MiddlewareStats {
        total_requests: 42,
        config: cfg,
    };
    let stats_json = serde_json::to_value(&stats).unwrap();
    assert_eq!(stats_json["total_requests"], 42);
    assert_eq!(stats_json["config"]["enabled"], true);
}

#[test]
fn request_middleware_update_and_change_tracking() {
    use axon::request_middleware::{MiddlewareConfig, MiddlewareUpdate, apply_update};

    let mut cfg = MiddlewareConfig::default();

    // Partial update — changes tracked
    let update = MiddlewareUpdate {
        enabled: None,
        slow_threshold_ms: Some(2000),
        inject_request_id: Some(false),
        inject_response_time: None,
    };
    let changes = apply_update(&mut cfg, &update);
    assert_eq!(changes.len(), 2);
    assert!(changes.contains(&"slow_threshold_ms".to_string()));
    assert!(changes.contains(&"inject_request_id".to_string()));
    assert_eq!(cfg.slow_threshold_ms, 2000);
    assert!(!cfg.inject_request_id);

    // No-op when values are same
    let same_update = MiddlewareUpdate {
        enabled: None,
        slow_threshold_ms: Some(2000),
        inject_request_id: Some(false),
        inject_response_time: None,
    };
    let no_changes = apply_update(&mut cfg, &same_update);
    assert!(no_changes.is_empty());

    // All fields update
    let full_update = MiddlewareUpdate {
        enabled: Some(false),
        slow_threshold_ms: Some(100),
        inject_request_id: Some(true),
        inject_response_time: Some(false),
    };
    let all_changes = apply_update(&mut cfg, &full_update);
    assert_eq!(all_changes.len(), 4);
    assert!(!cfg.enabled);
    assert_eq!(cfg.slow_threshold_ms, 100);
    assert!(cfg.inject_request_id);
    assert!(!cfg.inject_response_time);
}

