// D51: Flow inspector — runtime introspection for deployed flows
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn flow_inspect_full_introspection() {
    use axon::flow_inspect::{inspect_flow, FlowInspection};

    let source = r#"
persona Researcher {
  tone: "analytical"
  domain: ["science"]
}

anchor NoHallucination {
  description: "Prevent fabrication"
  require: factual
  enforce: strict
  on_violation: retry
}

tool WebSearch {
  provider: builtin
  timeout: 10s
}

flow Research(topic: Text) -> Report {
  step search use Researcher {
    given: topic
    ask: "Find relevant papers on the topic"
  }
  step synthesize use Researcher {
    given: search.output
    ask: "Synthesize findings into a report"
  }
}
"#;

    let result = inspect_flow("Research", source, "research.axon", "hash123");
    assert!(result.is_ok());
    let inspection = result.unwrap();

    // Identity
    assert_eq!(inspection.name, "Research");
    assert_eq!(inspection.source_file, "research.axon");
    assert_eq!(inspection.source_hash, "hash123");

    // Signature
    assert_eq!(inspection.signature.parameters.len(), 1);
    assert_eq!(inspection.signature.parameters[0].name, "topic");

    // Steps
    assert_eq!(inspection.steps.len(), 2);
    assert_eq!(inspection.steps[0].name, "search");
    assert_eq!(inspection.steps[1].name, "synthesize");
    assert_eq!(inspection.steps[0].persona_ref, "Researcher");

    // Personas
    assert!(inspection.personas_referenced.contains(&"Researcher".to_string()));

    // Anchors & tools
    assert_eq!(inspection.anchors.len(), 1);
    assert_eq!(inspection.anchors[0].name, "NoHallucination");
    assert_eq!(inspection.tools.len(), 1);
    assert_eq!(inspection.tools[0].name, "WebSearch");

    // Compilation (type errors are non-fatal for inspection)
    assert_eq!(inspection.compilation.flow_count, 1);
    assert!(inspection.compilation.token_count > 0);

    // Serialization
    let json = serde_json::to_value(&inspection).unwrap();
    assert!(json["signature"].is_object());
    assert!(json["steps"].is_array());
    assert!(json["compilation"].is_object());
}

