#[test]
fn trace_store_record_query_and_filter() {
    use axon::trace_store::*;

    let mut store = TraceStore::new(TraceStoreConfig::default());

    // Record traces for different flows and statuses
    let mut t1 = build_trace("FlowAlpha", "alpha.axon", "anthropic", "key_a", TraceStatus::Success, 4, 200);
    t1.tokens_input = 500;
    t1.tokens_output = 250;
    t1.anchor_checks = 3;
    let id1 = store.record(t1);

    let mut t2 = build_trace("FlowBeta", "beta.axon", "openai", "key_b", TraceStatus::Failed, 2, 800);
    t2.errors = 2;
    t2.retries = 1;
    let id2 = store.record(t2);

    let t3 = build_trace("FlowAlpha", "alpha.axon", "anthropic", "key_a", TraceStatus::Timeout, 1, 5000);
    let id3 = store.record(t3);

    assert_eq!(store.len(), 3);
    assert_eq!(store.total_recorded(), 3);
    assert!(id1 > 0 && id2 > 0 && id3 > 0);

    // Retrieve by ID
    let entry = store.get(id1).unwrap();
    assert_eq!(entry.flow_name, "FlowAlpha");
    assert_eq!(entry.status, TraceStatus::Success);
    assert_eq!(entry.steps_executed, 4);
    assert_eq!(entry.tokens_input, 500);
    assert!(entry.timestamp > 0);

    // Filter by flow name
    let filter_alpha = TraceFilter { flow_name: Some("FlowAlpha".into()), ..Default::default() };
    let alpha_traces = store.recent(100, Some(&filter_alpha));
    assert_eq!(alpha_traces.len(), 2);

    // Filter by status
    let filter_failed = TraceFilter { status: Some("failed".into()), ..Default::default() };
    let failed_traces = store.recent(100, Some(&filter_failed));
    assert_eq!(failed_traces.len(), 1);
    assert_eq!(failed_traces[0].flow_name, "FlowBeta");

    // Filter by has_errors
    let filter_errors = TraceFilter { has_errors: Some(true), ..Default::default() };
    let error_traces = store.recent(100, Some(&filter_errors));
    assert_eq!(error_traces.len(), 1);
    assert_eq!(error_traces[0].errors, 2);

    // Filter by min_latency_ms
    let filter_slow = TraceFilter { min_latency_ms: Some(1000), ..Default::default() };
    let slow_traces = store.recent(100, Some(&filter_slow));
    assert_eq!(slow_traces.len(), 1);
    assert_eq!(slow_traces[0].latency_ms, 5000);

    // Recent returns newest first
    let all = store.recent(100, None);
    assert_eq!(all[0].id, id3);
    assert_eq!(all[2].id, id1);

    // Non-existent ID
    assert!(store.get(999).is_none());
}

#[test]
fn trace_store_stats_and_ring_buffer() {
    use axon::trace_store::*;

    let config = TraceStoreConfig { capacity: 5, enabled: true, max_events_per_trace: 50, max_age_secs: 0 };
    let mut store = TraceStore::new(config);

    // Record 8 traces — only 5 should remain (ring buffer)
    for i in 0..8 {
        let mut t = build_trace(
            &format!("Flow{}", i % 3),
            "test.axon",
            "anthropic",
            "key_x",
            if i % 2 == 0 { TraceStatus::Success } else { TraceStatus::Failed },
            i + 1,
            (i as u64 + 1) * 100,
        );
        t.tokens_input = (i as u64 + 1) * 50;
        t.tokens_output = (i as u64 + 1) * 25;
        t.errors = if i % 2 == 0 { 0 } else { 1 };
        t.anchor_checks = 2;
        t.anchor_breaches = if i == 7 { 1 } else { 0 };
        t.retries = if i == 5 { 2 } else { 0 };
        store.record(t);
    }

    assert_eq!(store.len(), 5);
    assert_eq!(store.total_recorded(), 8);

    // Stats cover buffered entries only (indices 3..8)
    let stats = store.stats();
    assert_eq!(stats.total_recorded, 8);
    assert_eq!(stats.buffered, 5);
    assert!(stats.avg_latency_ms > 0);
    assert_eq!(stats.max_latency_ms, 800); // entry 7: 8*100
    assert!(stats.total_tokens_input > 0);
    assert!(stats.total_tokens_output > 0);
    assert!(stats.total_steps > 0);
    assert!(stats.total_anchor_checks > 0);

    // top_flows should be present
    assert!(!stats.top_flows.is_empty());
    // status_breakdown should have at least one entry
    assert!(!stats.status_breakdown.is_empty());

    // Stats serializes correctly
    let json = serde_json::to_value(&stats).unwrap();
    assert_eq!(json["total_recorded"], 8);
    assert_eq!(json["buffered"], 5);
    assert!(json["top_flows"].is_array());
    assert!(json["status_breakdown"].is_array());
}

#[test]
fn trace_store_events_and_config() {
    use axon::trace_store::*;

    // Test event truncation
    let config = TraceStoreConfig { capacity: 10, enabled: true, max_events_per_trace: 5, max_age_secs: 0 };
    let mut store = TraceStore::new(config);

    let mut t = build_trace("FlowX", "x.axon", "anthropic", "key_z", TraceStatus::Success, 3, 150);
    for i in 0..20 {
        t.events.push(TraceEvent {
            event_type: "step_start".into(),
            offset_ms: i * 10,
            step_name: format!("step_{}", i),
            detail: "running".into(),
        });
    }
    let id = store.record(t);
    let entry = store.get(id).unwrap();
    assert_eq!(entry.events.len(), 5); // truncated to max_events_per_trace

    // Config is accessible and serializable
    let cfg = store.config();
    assert_eq!(cfg.capacity, 10);
    assert_eq!(cfg.max_events_per_trace, 5);
    assert!(cfg.enabled);
    let cfg_json = serde_json::to_value(cfg).unwrap();
    assert_eq!(cfg_json["capacity"], 10);

    // Disabled store records nothing
    let mut disabled = TraceStore::new(TraceStoreConfig::disabled());
    let id = disabled.record(build_trace("Y", "y.axon", "x", "k", TraceStatus::Failed, 1, 50));
    assert_eq!(id, 0);
    assert!(disabled.is_empty());
    assert_eq!(disabled.total_recorded(), 0);

    // Clear preserves total
    store.clear();
    assert_eq!(store.len(), 0);
    assert!(store.is_empty());
    assert_eq!(store.total_recorded(), 1); // the one we recorded earlier
}

