// D54 — Trace Store Integration (auto-recording from server execute)
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn trace_auto_record_on_server_state() {
    use axon::trace_store::*;
    use axon::axon_server::ServerConfig;

    // Build a server state and verify trace store is initialized
    let config = ServerConfig {
        host: "127.0.0.1".into(),
        port: 0,
        channel: "test".into(),
        auth_token: String::new(),
        log_level: "error".into(),
        log_format: "json".into(),
        log_file: None,
        database_url: None,
        config_path: None,
    };

    let (_router, state) = axon::axon_server::build_router_with_state(config);

    // Verify trace store exists in state and is empty
    {
        let s = state.lock().unwrap();
        assert!(s.trace_store.is_empty());
        assert_eq!(s.trace_store.total_recorded(), 0);
        assert!(s.trace_store.config().enabled);
        assert_eq!(s.trace_store.config().capacity, 500);
    }

    // Simulate execution: record traces directly into state (as the execute handler would)
    {
        let mut s = state.lock().unwrap();
        let t1 = build_trace("FlowA", "a.axon", "stub", "client_x", TraceStatus::Success, 3, 120);
        let id1 = s.trace_store.record(t1);
        assert!(id1 > 0);

        let mut t2 = build_trace("FlowB", "b.axon", "stub", "client_y", TraceStatus::Failed, 1, 500);
        t2.errors = 1;
        let id2 = s.trace_store.record(t2);
        assert!(id2 > id1);
    }

    // Verify traces are queryable
    {
        let s = state.lock().unwrap();
        assert_eq!(s.trace_store.len(), 2);
        assert_eq!(s.trace_store.total_recorded(), 2);

        let all = s.trace_store.recent(10, None);
        assert_eq!(all.len(), 2);
        assert_eq!(all[0].flow_name, "FlowB"); // newest first

        let filter = TraceFilter { status: Some("success".into()), ..Default::default() };
        let success_only = s.trace_store.recent(10, Some(&filter));
        assert_eq!(success_only.len(), 1);
        assert_eq!(success_only[0].flow_name, "FlowA");

        let stats = s.trace_store.stats();
        assert_eq!(stats.total_recorded, 2);
        assert_eq!(stats.buffered, 2);
        assert_eq!(stats.total_errors, 1);
    }
}

