#[test]
fn audit_action_execute_variant() {
    use axon::audit_trail::{AuditAction, AuditLog};

    // Verify the Execute audit action exists and serializes correctly
    let action = AuditAction::Execute;
    assert_eq!(action.as_str(), "execute");

    // Record an execution audit entry
    let mut log = AuditLog::new(100);
    log.record(
        "client_a",
        AuditAction::Execute,
        "TestFlow",
        serde_json::json!({"flow": "TestFlow", "success": true, "trace_id": 1}),
        true,
    );

    assert_eq!(log.len(), 1);
    let entries = log.query(10, None);
    assert_eq!(entries[0].action.as_str(), "execute");
    assert_eq!(entries[0].target, "TestFlow");
    assert!(entries[0].success);
}

