// D55 — Trace Export (JSONL / CSV / Prometheus)
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn trace_export_jsonl_with_spans() {
    use axon::trace_store::*;

    let mut store = TraceStore::new(TraceStoreConfig::default());

    let mut t1 = build_trace("FlowAlpha", "alpha.axon", "anthropic", "key_a", TraceStatus::Success, 4, 200);
    t1.tokens_input = 500;
    t1.tokens_output = 250;
    t1.anchor_checks = 3;
    t1.events.push(TraceEvent {
        event_type: "step_start".into(),
        offset_ms: 0,
        step_name: "gather".into(),
        detail: "starting data collection".into(),
    });
    t1.events.push(TraceEvent {
        event_type: "step_end".into(),
        offset_ms: 100,
        step_name: "gather".into(),
        detail: "completed".into(),
    });
    store.record(t1);

    let mut t2 = build_trace("FlowBeta", "beta.axon", "openai", "key_b", TraceStatus::Failed, 2, 800);
    t2.errors = 2;
    t2.retries = 1;
    store.record(t2);

    let entries = store.recent(100, None);

    // JSONL export
    let jsonl = export_jsonl(&entries);
    let lines: Vec<&str> = jsonl.lines().collect();
    assert_eq!(lines.len(), 2);

    // Parse first line (newest = FlowBeta)
    let span1: serde_json::Value = serde_json::from_str(lines[0]).unwrap();
    assert_eq!(span1["name"], "FlowBeta");
    assert_eq!(span1["status"], "failed");
    assert!(span1["trace_id"].as_str().unwrap().starts_with("axt-"));
    assert_eq!(span1["duration_ms"], 800);
    assert_eq!(span1["resource"]["service_name"], "axon-server");
    assert_eq!(span1["resource"]["backend"], "openai");
    assert_eq!(span1["attributes"]["errors"], 2);
    assert_eq!(span1["attributes"]["retries"], 1);

    // Parse second line (FlowAlpha)
    let span2: serde_json::Value = serde_json::from_str(lines[1]).unwrap();
    assert_eq!(span2["name"], "FlowAlpha");
    assert_eq!(span2["status"], "success");
    assert_eq!(span2["attributes"]["tokens_input"], 500);
    assert_eq!(span2["attributes"]["tokens_output"], 250);
    assert_eq!(span2["attributes"]["tokens_total"], 750);
    assert_eq!(span2["attributes"]["anchor_checks"], 3);
    assert_eq!(span2["events"].as_array().unwrap().len(), 2);
    assert_eq!(span2["events"][0]["name"], "step_start");
    assert_eq!(span2["events"][0]["attributes"]["step"], "gather");
}

#[test]
fn trace_export_csv_and_prometheus_formats() {
    use axon::trace_store::*;

    let mut store = TraceStore::new(TraceStoreConfig::default());
    let mut t1 = build_trace("A", "a.axon", "anthropic", "k1", TraceStatus::Success, 3, 100);
    t1.tokens_input = 200;
    t1.tokens_output = 100;
    store.record(t1);

    let mut t2 = build_trace("B", "b.axon", "openai", "k2", TraceStatus::Failed, 1, 500);
    t2.errors = 1;
    t2.anchor_checks = 5;
    t2.anchor_breaches = 2;
    store.record(t2);

    let entries = store.recent(100, None);

    // CSV export
    let csv = export_csv(&entries);
    let csv_lines: Vec<&str> = csv.lines().collect();
    assert_eq!(csv_lines.len(), 3); // header + 2 rows
    assert!(csv_lines[0].starts_with("trace_id,"));
    assert!(csv_lines[0].contains("tokens_input"));
    assert!(csv_lines[0].contains("event_count"));

    // Data rows have correct field count (16 columns)
    let header_cols = csv_lines[0].split(',').count();
    for row in &csv_lines[1..] {
        assert_eq!(row.split(',').count(), header_cols, "Column mismatch in: {}", row);
    }

    // Prometheus export
    let prom = export_prometheus(&entries);
    assert!(prom.contains("axon_trace_export_count 2"));
    assert!(prom.contains("axon_trace_export_latency_avg_ms 300")); // (100+500)/2
    assert!(prom.contains("axon_trace_export_latency_max_ms 500"));
    assert!(prom.contains("axon_trace_export_tokens_total{type=\"input\"} 200"));
    assert!(prom.contains("axon_trace_export_tokens_total{type=\"output\"} 100"));
    assert!(prom.contains("axon_trace_export_errors_total 1"));
    assert!(prom.contains("axon_trace_export_anchor_checks_total 5"));
    assert!(prom.contains("axon_trace_export_anchor_breaches_total 2"));
    assert!(prom.contains("axon_trace_export_by_status{status=\"success\"} 1"));
    assert!(prom.contains("axon_trace_export_by_status{status=\"failed\"} 1"));

    // All HELP lines have matching TYPE lines
    let help_count = prom.lines().filter(|l| l.starts_with("# HELP")).count();
    let type_count = prom.lines().filter(|l| l.starts_with("# TYPE")).count();
    assert!(help_count >= 9);
    assert_eq!(help_count, type_count);
}

#[test]
fn trace_export_format_selection_and_filtering() {
    use axon::trace_store::*;

    // Format parsing
    assert_eq!(ExportFormat::from_str("jsonl"), ExportFormat::JsonLines);
    assert_eq!(ExportFormat::from_str("csv"), ExportFormat::Csv);
    assert_eq!(ExportFormat::from_str("prometheus"), ExportFormat::Prometheus);
    assert_eq!(ExportFormat::from_str("prom"), ExportFormat::Prometheus);
    assert_eq!(ExportFormat::from_str("JSONL"), ExportFormat::JsonLines);
    assert_eq!(ExportFormat::from_str("CSV"), ExportFormat::Csv);
    assert_eq!(ExportFormat::from_str("anything"), ExportFormat::JsonLines); // default

    // Content types
    assert_eq!(ExportFormat::JsonLines.content_type(), "application/x-ndjson");
    assert_eq!(ExportFormat::Csv.content_type(), "text/csv");
    assert!(ExportFormat::Prometheus.content_type().contains("text/plain"));

    // Filtered export
    let mut store = TraceStore::new(TraceStoreConfig::default());
    store.record(build_trace("X", "x.axon", "a", "k", TraceStatus::Success, 1, 50));
    store.record(build_trace("Y", "y.axon", "a", "k", TraceStatus::Failed, 1, 100));
    store.record(build_trace("X", "x.axon", "a", "k", TraceStatus::Success, 2, 150));

    let filter = TraceFilter { flow_name: Some("X".into()), ..Default::default() };
    let filtered = store.recent(100, Some(&filter));
    assert_eq!(filtered.len(), 2);

    let jsonl = export_jsonl(&filtered);
    let lines: Vec<&str> = jsonl.lines().collect();
    assert_eq!(lines.len(), 2);
    // Both should be flow X
    let s1: serde_json::Value = serde_json::from_str(lines[0]).unwrap();
    let s2: serde_json::Value = serde_json::from_str(lines[1]).unwrap();
    assert_eq!(s1["name"], "X");
    assert_eq!(s2["name"], "X");

    // Empty export
    let empty: Vec<&TraceEntry> = vec![];
    assert!(export_jsonl(&empty).is_empty());
    assert_eq!(export_csv(&empty).lines().count(), 1); // header only
    assert!(export_prometheus(&empty).contains("axon_trace_export_count 0"));
}

