// D56 — Daemon Executor (supervised flow execution)
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn daemon_lifecycle_state_transitions() {
    use axon::event_bus::{EventBus, DaemonSupervisor, RestartPolicy, SupervisorState};

    let bus = EventBus::new();
    let mut supervisor = DaemonSupervisor::new(bus);

    // Register → Registered
    supervisor.register("FlowA", RestartPolicy::default());
    let d = supervisor.get("FlowA").unwrap();
    assert_eq!(d.state, SupervisorState::Registered);
    assert_eq!(d.restart_count, 0);

    // Start → Running
    assert!(supervisor.mark_started("FlowA"));
    let d = supervisor.get("FlowA").unwrap();
    assert_eq!(d.state, SupervisorState::Running);

    // Heartbeat
    assert!(supervisor.heartbeat("FlowA"));

    // Mark waiting (success path) → Waiting
    assert!(supervisor.mark_waiting("FlowA"));
    let d = supervisor.get("FlowA").unwrap();
    assert_eq!(d.state, SupervisorState::Waiting);

    // Start again → Running (re-execution)
    assert!(supervisor.mark_started("FlowA"));
    let d = supervisor.get("FlowA").unwrap();
    assert_eq!(d.state, SupervisorState::Running);

    // Crash → Restarting (policy allows it)
    let will_restart = supervisor.report_crash("FlowA", "compilation error");
    assert!(will_restart);
    let d = supervisor.get("FlowA").unwrap();
    assert_eq!(d.state, SupervisorState::Restarting);
    assert_eq!(d.restart_count, 1);
    assert_eq!(d.crash_reason.as_deref(), Some("compilation error"));

    // Crash 3 more times → Dead (OnCrash { max_restarts: 3 })
    supervisor.report_crash("FlowA", "error 2");
    supervisor.report_crash("FlowA", "error 3");
    let will_restart = supervisor.report_crash("FlowA", "error 4");
    assert!(!will_restart);
    let d = supervisor.get("FlowA").unwrap();
    assert_eq!(d.state, SupervisorState::Dead);
    assert_eq!(d.restart_count, 4);
}

#[test]
fn daemon_executor_state_sync_with_server() {
    use axon::axon_server::{ServerConfig, DaemonState};
    use axon::event_bus::SupervisorState;

    let config = ServerConfig {
        host: "127.0.0.1".into(),
        port: 0,
        channel: "test".into(),
        auth_token: String::new(),
        log_level: "error".into(),
        log_format: "json".into(),
        log_file: None,
        database_url: None,
        config_path: None,
    };

    let (_router, state) = axon::axon_server::build_router_with_state(config);

    // Simulate a deploy: add daemon and register with supervisor
    {
        let mut s = state.lock().unwrap();
        let daemon = axon::axon_server::DaemonInfo {
            name: "TestFlow".to_string(),
            state: DaemonState::Idle,
            source_file: "test.axon".to_string(),
            flow_name: "TestFlow".to_string(),
            event_count: 0,
            restart_count: 0,
            trigger_topic: None,
            output_topic: None,
            lifecycle_events: Vec::new(),
        };
        s.daemons.insert("TestFlow".to_string(), daemon);
        s.supervisor.register("TestFlow", axon::event_bus::RestartPolicy::default());
    }

    // Verify initial state
    {
        let s = state.lock().unwrap();
        assert_eq!(s.daemons.get("TestFlow").unwrap().state, DaemonState::Idle);
        assert_eq!(s.supervisor.get("TestFlow").unwrap().state, SupervisorState::Registered);
    }

    // Simulate execution lifecycle: start → heartbeat → waiting
    {
        let mut s = state.lock().unwrap();

        // Start
        s.supervisor.mark_started("TestFlow");
        s.daemons.get_mut("TestFlow").unwrap().state = DaemonState::Running;

        assert_eq!(s.supervisor.get("TestFlow").unwrap().state, SupervisorState::Running);
        assert_eq!(s.daemons.get("TestFlow").unwrap().state, DaemonState::Running);

        // Heartbeat
        s.supervisor.heartbeat("TestFlow");

        // Execution success → waiting
        s.supervisor.mark_waiting("TestFlow");
        s.daemons.get_mut("TestFlow").unwrap().state = DaemonState::Hibernating;
        s.daemons.get_mut("TestFlow").unwrap().event_count += 1;

        assert_eq!(s.supervisor.get("TestFlow").unwrap().state, SupervisorState::Waiting);
        assert_eq!(s.daemons.get("TestFlow").unwrap().state, DaemonState::Hibernating);
        assert_eq!(s.daemons.get("TestFlow").unwrap().event_count, 1);
    }

    // Simulate crash path
    {
        let mut s = state.lock().unwrap();
        s.supervisor.mark_started("TestFlow");
        s.daemons.get_mut("TestFlow").unwrap().state = DaemonState::Running;

        let will_restart = s.supervisor.report_crash("TestFlow", "test error");
        assert!(will_restart);

        // Daemon state should reflect restart possibility
        let daemon = s.daemons.get_mut("TestFlow").unwrap();
        daemon.restart_count += 1;
        daemon.state = DaemonState::Idle; // eligible for restart
        assert_eq!(daemon.restart_count, 1);
    }
}

#[test]
fn daemon_supervisor_state_counts_and_summary() {
    use axon::event_bus::{EventBus, DaemonSupervisor, RestartPolicy, SupervisorState};

    let bus = EventBus::new();
    let mut supervisor = DaemonSupervisor::new(bus);

    // Register several daemons in various states
    supervisor.register("A", RestartPolicy::default());
    supervisor.register("B", RestartPolicy::default());
    supervisor.register("C", RestartPolicy::Never);
    supervisor.register("D", RestartPolicy::Always);

    supervisor.mark_started("A");
    supervisor.mark_started("B");
    supervisor.mark_waiting("B");
    supervisor.stop("C");
    supervisor.mark_started("D");
    supervisor.report_crash("D", "test crash");

    // State counts
    let counts = supervisor.state_counts();
    assert_eq!(counts.get("running"), Some(&1)); // A
    assert_eq!(counts.get("waiting"), Some(&1)); // B
    assert_eq!(counts.get("stopped"), Some(&1)); // C
    assert_eq!(counts.get("restarting"), Some(&1)); // D (Always policy, so restarts)

    // Summary
    let summary = supervisor.summary();
    assert!(summary.contains("4 daemons"));
    assert!(summary.contains("1 running"));
    assert!(summary.contains("1 waiting"));

    // List all
    let list = supervisor.list();
    assert_eq!(list.len(), 4);

    // Verify individual states
    assert_eq!(supervisor.get("A").unwrap().state, SupervisorState::Running);
    assert_eq!(supervisor.get("B").unwrap().state, SupervisorState::Waiting);
    assert_eq!(supervisor.get("C").unwrap().state, SupervisorState::Stopped);
    assert_eq!(supervisor.get("D").unwrap().state, SupervisorState::Restarting);

    // Unregister removes completely
    assert!(supervisor.unregister("C"));
    assert!(supervisor.get("C").is_none());
    assert_eq!(supervisor.list().len(), 3);
}

