#[test]
fn daemon_trigger_topic_binding() {
    use axon::axon_server::{ServerConfig, DaemonInfo, DaemonState};

    let config = ServerConfig {
        host: "127.0.0.1".into(),
        port: 0,
        channel: "test".into(),
        auth_token: String::new(),
        log_level: "error".into(),
        log_format: "json".into(),
        log_file: None,
        database_url: None,
        config_path: None,
    };

    let (_router, state) = axon::axon_server::build_router_with_state(config);

    // Add daemons
    {
        let mut s = state.lock().unwrap();
        for name in &["FlowA", "FlowB", "FlowC"] {
            s.daemons.insert(name.to_string(), DaemonInfo {
                name: name.to_string(),
                state: DaemonState::Idle,
                source_file: "test.axon".into(),
                flow_name: name.to_string(),
                event_count: 0,
                restart_count: 0,
                trigger_topic: None,
                output_topic: None,
                lifecycle_events: Vec::new(),
            });
        }
    }

    // All start with no trigger
    {
        let s = state.lock().unwrap();
        assert!(s.daemons.get("FlowA").unwrap().trigger_topic.is_none());
        assert!(s.daemons.get("FlowB").unwrap().trigger_topic.is_none());
    }

    // Set triggers
    {
        let mut s = state.lock().unwrap();
        s.daemons.get_mut("FlowA").unwrap().trigger_topic = Some("deploy".into());
        s.daemons.get_mut("FlowB").unwrap().trigger_topic = Some("data.*".into());
        // FlowC stays manual-only
    }

    // Verify triggers
    {
        let s = state.lock().unwrap();
        assert_eq!(s.daemons.get("FlowA").unwrap().trigger_topic.as_deref(), Some("deploy"));
        assert_eq!(s.daemons.get("FlowB").unwrap().trigger_topic.as_deref(), Some("data.*"));
        assert!(s.daemons.get("FlowC").unwrap().trigger_topic.is_none());
    }

    // Topic matching: find daemons whose trigger matches a given topic
    {
        let s = state.lock().unwrap();
        let topic = "deploy";
        let matched: Vec<&str> = s.daemons.values()
            .filter(|d| {
                if let Some(ref trigger) = d.trigger_topic {
                    axon::event_bus::TopicFilter::new(trigger).matches(topic)
                } else {
                    false
                }
            })
            .map(|d| d.name.as_str())
            .collect();
        assert_eq!(matched, vec!["FlowA"]);
    }

    // Wildcard matching
    {
        let s = state.lock().unwrap();
        let topic = "data.ingested";
        let matched: Vec<&str> = s.daemons.values()
            .filter(|d| {
                if let Some(ref trigger) = d.trigger_topic {
                    axon::event_bus::TopicFilter::new(trigger).matches(topic)
                } else {
                    false
                }
            })
            .map(|d| d.name.as_str())
            .collect();
        assert_eq!(matched, vec!["FlowB"]);
    }

    // Non-matching topic
    {
        let s = state.lock().unwrap();
        let topic = "shutdown";
        let matched: Vec<&str> = s.daemons.values()
            .filter(|d| {
                if let Some(ref trigger) = d.trigger_topic {
                    axon::event_bus::TopicFilter::new(trigger).matches(topic)
                } else {
                    false
                }
            })
            .map(|d| d.name.as_str())
            .collect();
        assert!(matched.is_empty());
    }

    // Clear trigger
    {
        let mut s = state.lock().unwrap();
        s.daemons.get_mut("FlowA").unwrap().trigger_topic = None;
        assert!(s.daemons.get("FlowA").unwrap().trigger_topic.is_none());
    }
}

#[test]
fn daemon_trigger_filters_crashed_and_stopped() {
    use axon::axon_server::{DaemonInfo, DaemonState};

    // Crashed and stopped daemons should not be dispatched
    let daemons = vec![
        DaemonInfo { name: "Active".into(), state: DaemonState::Idle, source_file: "t.axon".into(), flow_name: "Active".into(), event_count: 0, restart_count: 0, trigger_topic: Some("test".into()), output_topic: None, lifecycle_events: Vec::new() },
        DaemonInfo { name: "Hibernating".into(), state: DaemonState::Hibernating, source_file: "t.axon".into(), flow_name: "Hibernating".into(), event_count: 5, restart_count: 0, trigger_topic: Some("test".into()), output_topic: None, lifecycle_events: Vec::new() },
        DaemonInfo { name: "Crashed".into(), state: DaemonState::Crashed, source_file: "t.axon".into(), flow_name: "Crashed".into(), event_count: 3, restart_count: 3, trigger_topic: Some("test".into()), output_topic: None, lifecycle_events: Vec::new() },
        DaemonInfo { name: "Stopped".into(), state: DaemonState::Stopped, source_file: "t.axon".into(), flow_name: "Stopped".into(), event_count: 1, restart_count: 0, trigger_topic: Some("test".into()), output_topic: None, lifecycle_events: Vec::new() },
        DaemonInfo { name: "Manual".into(), state: DaemonState::Idle, source_file: "t.axon".into(), flow_name: "Manual".into(), event_count: 0, restart_count: 0, trigger_topic: None, output_topic: None, lifecycle_events: Vec::new() },
    ];

    let topic = "test";
    let eligible: Vec<&str> = daemons.iter()
        .filter(|d| {
            if let Some(ref trigger) = d.trigger_topic {
                axon::event_bus::TopicFilter::new(trigger).matches(topic)
            } else {
                false
            }
        })
        .filter(|d| d.state != DaemonState::Crashed && d.state != DaemonState::Stopped)
        .map(|d| d.name.as_str())
        .collect();

    assert_eq!(eligible.len(), 2);
    assert!(eligible.contains(&"Active"));
    assert!(eligible.contains(&"Hibernating"));
    // Crashed, Stopped, and Manual (no trigger) are excluded
}

#[test]
fn topic_filter_patterns_for_daemon_triggers() {
    use axon::event_bus::TopicFilter;

    // Exact match
    let f1 = TopicFilter::new("deploy");
    assert!(f1.matches("deploy"));
    assert!(!f1.matches("deploy.done"));
    assert!(!f1.matches("undeploy"));

    // Prefix wildcard
    let f2 = TopicFilter::new("data.*");
    assert!(f2.matches("data.ingested"));
    assert!(f2.matches("data.processed"));
    assert!(f2.matches("data")); // prefix match includes exact prefix
    assert!(!f2.matches("database"));

    // Global wildcard
    let f3 = TopicFilter::new("*");
    assert!(f3.matches("deploy"));
    assert!(f3.matches("data.ingested"));
    assert!(f3.matches("anything"));

    // Nested prefix
    let f4 = TopicFilter::new("supervisor.*");
    assert!(f4.matches("supervisor.started"));
    assert!(f4.matches("supervisor.stopped"));
    assert!(f4.matches("supervisor.dead"));
    assert!(f4.matches("supervisor")); // prefix match includes exact prefix

    // DaemonInfo trigger serializes correctly
    let daemon = axon::axon_server::DaemonInfo {
        name: "TestDaemon".into(),
        state: axon::axon_server::DaemonState::Idle,
        source_file: "test.axon".into(),
        flow_name: "TestFlow".into(),
        event_count: 0,
        restart_count: 0,
        trigger_topic: Some("deploy".into()),
        output_topic: None,
        lifecycle_events: Vec::new(),
    };
    let json = serde_json::to_value(&daemon).unwrap();
    assert_eq!(json["trigger_topic"], "deploy");
    assert_eq!(json["name"], "TestDaemon");

    // None trigger serializes as null
    let daemon2 = axon::axon_server::DaemonInfo {
        trigger_topic: None,
        ..daemon
    };
    let json2 = serde_json::to_value(&daemon2).unwrap();
    assert!(json2["trigger_topic"].is_null());
}

// ── D58: Execution Replay ─────────────────────────────────────────────────

#[test]
fn trace_replay_of_field_and_linking() {
    use axon::trace_store::*;

    let mut store = TraceStore::new(TraceStoreConfig::default());

    // Record an original trace
    let t1 = build_trace("FlowA", "a.axon", "anthropic", "key_a", TraceStatus::Success, 4, 200);
    let original_id = store.record(t1);
    assert_eq!(original_id, 1);

    // Record a replay trace linked to the original
    let mut t2 = build_trace("FlowA", "a.axon", "anthropic", "key_a", TraceStatus::Success, 4, 180);
    t2.replay_of = Some(original_id);
    let replay_id = store.record(t2);
    assert_eq!(replay_id, 2);

    // Verify original has no replay_of
    let original = store.get(original_id).unwrap();
    assert!(original.replay_of.is_none());

    // Verify replay links back to original
    let replay = store.get(replay_id).unwrap();
    assert_eq!(replay.replay_of, Some(original_id));
    assert_eq!(replay.flow_name, "FlowA");

    // Verify serialization: original omits replay_of (skip_serializing_if)
    let json_original = serde_json::to_value(original).unwrap();
    assert!(json_original.get("replay_of").is_none());

    // Replay includes replay_of in JSON
    let json_replay = serde_json::to_value(replay).unwrap();
    assert_eq!(json_replay["replay_of"], original_id);

    // Record a third trace — replay of a replay (chain)
    let mut t3 = build_trace("FlowA", "a.axon", "stub", "key_b", TraceStatus::Partial, 3, 220);
    t3.replay_of = Some(replay_id);
    let chain_id = store.record(t3);

    let chain = store.get(chain_id).unwrap();
    assert_eq!(chain.replay_of, Some(replay_id));
    assert_eq!(chain.backend, "stub"); // backend override
    assert_eq!(chain.status, TraceStatus::Partial);
}

#[test]
fn trace_replay_diff_calculation() {
    use axon::trace_store::*;

    let mut store = TraceStore::new(TraceStoreConfig::default());

    // Original: successful, 4 steps, 200ms, 0 errors
    let mut t1 = build_trace("FlowX", "x.axon", "anthropic", "key_a", TraceStatus::Success, 4, 200);
    t1.tokens_input = 500;
    t1.tokens_output = 250;
    t1.anchor_checks = 3;
    let original_id = store.record(t1);

    // Replay: partial (regression), 3 steps, 300ms, 2 errors
    let mut t2 = build_trace("FlowX", "x.axon", "anthropic", "key_a", TraceStatus::Partial, 3, 300);
    t2.errors = 2;
    t2.replay_of = Some(original_id);
    let replay_id = store.record(t2);

    // Extract original values before further borrows
    let orig_latency = store.get(original_id).unwrap().latency_ms;
    let orig_steps = store.get(original_id).unwrap().steps_executed;
    let orig_errors = store.get(original_id).unwrap().errors;
    let orig_status = store.get(original_id).unwrap().status;

    let replay = store.get(replay_id).unwrap();

    // Calculate diff manually (mirrors what the handler does)
    let latency_delta = replay.latency_ms as i64 - orig_latency as i64;
    let steps_delta = replay.steps_executed as i64 - orig_steps as i64;
    let errors_delta = replay.errors as i64 - orig_errors as i64;
    let status_changed = orig_status != replay.status;

    assert_eq!(latency_delta, 100); // 300 - 200
    assert_eq!(steps_delta, -1);    // 3 - 4
    assert_eq!(errors_delta, 2);    // 2 - 0
    assert!(status_changed);         // Success → Partial

    // Replay with same outcome — no diff
    let mut t3 = build_trace("FlowX", "x.axon", "anthropic", "key_a", TraceStatus::Success, 4, 200);
    t3.replay_of = Some(original_id);
    let replay2_id = store.record(t3);

    let replay2 = store.get(replay2_id).unwrap();
    let latency_delta2 = replay2.latency_ms as i64 - orig_latency as i64;
    let steps_delta2 = replay2.steps_executed as i64 - orig_steps as i64;
    let errors_delta2 = replay2.errors as i64 - orig_errors as i64;
    let status_changed2 = orig_status != replay2.status;

    assert_eq!(latency_delta2, 0);
    assert_eq!(steps_delta2, 0);
    assert_eq!(errors_delta2, 0);
    assert!(!status_changed2);
}

#[test]
fn trace_replay_preserves_metadata_and_filters() {
    use axon::trace_store::*;

    let mut store = TraceStore::new(TraceStoreConfig::default());

    // Record original traces for different flows
    let t1 = build_trace("FlowA", "a.axon", "anthropic", "client_1", TraceStatus::Success, 3, 100);
    let id1 = store.record(t1);

    let t2 = build_trace("FlowB", "b.axon", "openai", "client_2", TraceStatus::Failed, 1, 500);
    let id2 = store.record(t2);

    // Record replays
    let mut r1 = build_trace("FlowA", "a.axon", "stub", "client_1", TraceStatus::Success, 3, 90);
    r1.replay_of = Some(id1);
    let rid1 = store.record(r1);

    let mut r2 = build_trace("FlowB", "b.axon", "openai", "client_2", TraceStatus::Success, 2, 300);
    r2.replay_of = Some(id2);
    let rid2 = store.record(r2);

    // Filter by flow name — should return both original and replay
    let flow_a_filter = TraceFilter {
        flow_name: Some("FlowA".into()),
        ..Default::default()
    };
    let flow_a_traces = store.recent(100, Some(&flow_a_filter));
    assert_eq!(flow_a_traces.len(), 2); // original + replay
    // newest first: replay, then original
    assert_eq!(flow_a_traces[0].id, rid1);
    assert_eq!(flow_a_traces[0].replay_of, Some(id1));
    assert_eq!(flow_a_traces[1].id, id1);
    assert!(flow_a_traces[1].replay_of.is_none());

    // Filter by status — failed traces
    let failed_filter = TraceFilter {
        status: Some("failed".into()),
        ..Default::default()
    };
    let failed_traces = store.recent(100, Some(&failed_filter));
    assert_eq!(failed_traces.len(), 1); // only original FlowB
    assert_eq!(failed_traces[0].id, id2);

    // All traces total
    let all = store.recent(100, None);
    assert_eq!(all.len(), 4);

    // Verify replay_of chain: r2 fixed the originally failed flow
    let r2_entry = store.get(rid2).unwrap();
    assert_eq!(r2_entry.replay_of, Some(id2));
    assert_eq!(r2_entry.status, TraceStatus::Success);
    let original_b = store.get(id2).unwrap();
    assert_eq!(original_b.status, TraceStatus::Failed);
    // Status regression check
    assert_ne!(original_b.status, r2_entry.status);
}

