#[test]
fn schedule_entry_crud_and_state() {
    use axon::axon_server::ScheduleEntry;

    // Create a schedule entry
    let mut entry = ScheduleEntry {
        flow_name: "DataPipeline".into(),
        interval_secs: 60,
        enabled: true,
        backend: "stub".into(),
        last_run: 0,
        next_run: 1000060,
        run_count: 0,
        error_count: 0,
        history: Vec::new(),
    };

    // Verify initial state
    assert_eq!(entry.flow_name, "DataPipeline");
    assert_eq!(entry.interval_secs, 60);
    assert!(entry.enabled);
    assert_eq!(entry.last_run, 0);
    assert_eq!(entry.next_run, 1000060);
    assert_eq!(entry.run_count, 0);
    assert_eq!(entry.error_count, 0);

    // Simulate a tick execution
    entry.last_run = 1000060;
    entry.next_run = 1000060 + entry.interval_secs;
    entry.run_count += 1;

    assert_eq!(entry.last_run, 1000060);
    assert_eq!(entry.next_run, 1000120);
    assert_eq!(entry.run_count, 1);

    // Simulate an error
    entry.last_run = 1000120;
    entry.next_run = 1000120 + entry.interval_secs;
    entry.run_count += 1;
    entry.error_count += 1;

    assert_eq!(entry.run_count, 2);
    assert_eq!(entry.error_count, 1);

    // Toggle disabled
    entry.enabled = false;
    assert!(!entry.enabled);

    // Serialization
    let json = serde_json::to_value(&entry).unwrap();
    assert_eq!(json["flow_name"], "DataPipeline");
    assert_eq!(json["interval_secs"], 60);
    assert_eq!(json["enabled"], false);
    assert_eq!(json["run_count"], 2);
    assert_eq!(json["error_count"], 1);
    assert_eq!(json["backend"], "stub");
}

#[test]
fn schedule_collection_management() {
    use std::collections::HashMap;
    use axon::axon_server::ScheduleEntry;

    let mut schedules: HashMap<String, ScheduleEntry> = HashMap::new();

    // Add multiple schedules
    let now = 1000000u64;

    schedules.insert("FlowA".into(), ScheduleEntry {
        flow_name: "FlowA".into(),
        interval_secs: 30,
        enabled: true,
        backend: "anthropic".into(),
        last_run: 0,
        next_run: now + 30,
        run_count: 0,
        error_count: 0,
        history: Vec::new(),
    });

    schedules.insert("FlowB".into(), ScheduleEntry {
        flow_name: "FlowB".into(),
        interval_secs: 300,
        enabled: true,
        backend: "stub".into(),
        last_run: 0,
        next_run: now + 300,
        run_count: 0,
        error_count: 0,
        history: Vec::new(),
    });

    schedules.insert("FlowC".into(), ScheduleEntry {
        flow_name: "FlowC".into(),
        interval_secs: 60,
        enabled: false, // disabled
        backend: "openai".into(),
        last_run: 0,
        next_run: now + 60,
        run_count: 0,
        error_count: 0,
        history: Vec::new(),
    });

    assert_eq!(schedules.len(), 3);

    // Check which are due at now + 31 (only FlowA with 30s interval)
    let tick_time = now + 31;
    let due: Vec<&String> = schedules.iter()
        .filter(|(_, e)| e.enabled && tick_time >= e.next_run)
        .map(|(name, _)| name)
        .collect();
    assert_eq!(due.len(), 1);
    assert_eq!(due[0], "FlowA");

    // At now + 301, FlowA and FlowB are due (FlowC disabled)
    let tick_time2 = now + 301;
    let due2: Vec<&String> = schedules.iter()
        .filter(|(_, e)| e.enabled && tick_time2 >= e.next_run)
        .map(|(name, _)| name)
        .collect();
    assert_eq!(due2.len(), 2);
    assert!(due2.contains(&&"FlowA".to_string()));
    assert!(due2.contains(&&"FlowB".to_string()));
    // FlowC is not included (disabled)
    assert!(!due2.contains(&&"FlowC".to_string()));

    // Delete a schedule
    schedules.remove("FlowB");
    assert_eq!(schedules.len(), 2);
    assert!(schedules.get("FlowB").is_none());

    // Toggle FlowC enabled
    schedules.get_mut("FlowC").unwrap().enabled = true;
    let due3: Vec<&String> = schedules.iter()
        .filter(|(_, e)| e.enabled && tick_time2 >= e.next_run)
        .map(|(name, _)| name)
        .collect();
    assert_eq!(due3.len(), 2); // FlowA + FlowC now
    assert!(due3.contains(&&"FlowC".to_string()));
}

#[test]
fn schedule_interval_advancement_and_error_tracking() {
    use axon::axon_server::ScheduleEntry;

    let mut entry = ScheduleEntry {
        flow_name: "PeriodicFlow".into(),
        interval_secs: 120,
        enabled: true,
        backend: "stub".into(),
        last_run: 0,
        next_run: 1000120,
        run_count: 0,
        error_count: 0,
        history: Vec::new(),
    };

    // Simulate 5 successful ticks
    let base = 1000120u64;
    for i in 0..5u64 {
        let tick_time = base + i * 120;
        assert!(tick_time >= entry.next_run);
        entry.last_run = tick_time;
        entry.next_run = tick_time + entry.interval_secs;
        entry.run_count += 1;
    }

    assert_eq!(entry.run_count, 5);
    assert_eq!(entry.error_count, 0);
    assert_eq!(entry.last_run, base + 4 * 120);
    assert_eq!(entry.next_run, base + 5 * 120);

    // Simulate 2 error ticks
    for _ in 0..2 {
        let tick_time = entry.next_run;
        entry.last_run = tick_time;
        entry.next_run = tick_time + entry.interval_secs;
        entry.run_count += 1;
        entry.error_count += 1;
    }

    assert_eq!(entry.run_count, 7);
    assert_eq!(entry.error_count, 2);

    // Error rate
    let error_rate = entry.error_count as f64 / entry.run_count as f64;
    assert!((error_rate - 2.0 / 7.0).abs() < 0.001);

    // Verify interval consistency: next_run is always last_run + interval_secs
    assert_eq!(entry.next_run, entry.last_run + entry.interval_secs);

    // Disable and verify it would be skipped
    entry.enabled = false;
    let future_time = entry.next_run + 10000;
    let would_run = entry.enabled && future_time >= entry.next_run;
    assert!(!would_run);

    // Re-enable
    entry.enabled = true;
    let would_run2 = entry.enabled && future_time >= entry.next_run;
    assert!(would_run2);
}

