#[test]
fn trace_annotation_crud_and_serialization() {
    use axon::trace_store::*;

    let mut store = TraceStore::new(TraceStoreConfig::default());
    let t = build_trace("FlowA", "a.axon", "anthropic", "key_a", TraceStatus::Success, 3, 100);
    let id = store.record(t);

    // Initially no annotations
    let entry = store.get(id).unwrap();
    assert!(entry.annotations.is_empty());

    // Serialization: empty annotations omitted (skip_serializing_if)
    let json = serde_json::to_value(entry).unwrap();
    assert!(json.get("annotations").is_none());

    // Add first annotation
    let ok = store.annotate(id, TraceAnnotation {
        author: "alice".into(),
        text: "Investigating latency spike".into(),
        tags: vec!["bug".into(), "latency".into()],
        timestamp: 1000001,
    });
    assert!(ok);

    // Add second annotation
    let ok2 = store.annotate(id, TraceAnnotation {
        author: "bob".into(),
        text: "Root cause: cold start".into(),
        tags: vec!["resolved".into()],
        timestamp: 1000002,
    });
    assert!(ok2);

    // Verify annotations
    let entry = store.get(id).unwrap();
    assert_eq!(entry.annotations.len(), 2);
    assert_eq!(entry.annotations[0].author, "alice");
    assert_eq!(entry.annotations[0].text, "Investigating latency spike");
    assert_eq!(entry.annotations[0].tags, vec!["bug", "latency"]);
    assert_eq!(entry.annotations[0].timestamp, 1000001);
    assert_eq!(entry.annotations[1].author, "bob");
    assert_eq!(entry.annotations[1].tags, vec!["resolved"]);

    // Serialization: non-empty annotations included
    let json2 = serde_json::to_value(entry).unwrap();
    let anns = json2["annotations"].as_array().unwrap();
    assert_eq!(anns.len(), 2);
    assert_eq!(anns[0]["author"], "alice");
    assert_eq!(anns[0]["tags"][0], "bug");
    assert_eq!(anns[1]["text"], "Root cause: cold start");

    // Annotate non-existent trace returns false
    let ok3 = store.annotate(999, TraceAnnotation {
        author: "x".into(),
        text: "y".into(),
        tags: vec![],
        timestamp: 0,
    });
    assert!(!ok3);
}

#[test]
fn trace_annotation_tag_filter() {
    use axon::trace_store::*;

    let mut store = TraceStore::new(TraceStoreConfig::default());

    // Create traces
    let t1 = build_trace("FlowA", "a.axon", "stub", "k1", TraceStatus::Success, 3, 100);
    let id1 = store.record(t1);

    let t2 = build_trace("FlowB", "b.axon", "stub", "k2", TraceStatus::Failed, 1, 500);
    let id2 = store.record(t2);

    let t3 = build_trace("FlowC", "c.axon", "stub", "k3", TraceStatus::Success, 2, 200);
    let id3 = store.record(t3);

    // Annotate trace 1 with "bug" tag
    store.annotate(id1, TraceAnnotation {
        author: "alice".into(),
        text: "regression".into(),
        tags: vec!["bug".into(), "p1".into()],
        timestamp: 1,
    });

    // Annotate trace 2 with "bug" and "resolved" tags
    store.annotate(id2, TraceAnnotation {
        author: "bob".into(),
        text: "fixed".into(),
        tags: vec!["bug".into(), "resolved".into()],
        timestamp: 2,
    });

    // Trace 3 has no annotations

    // Filter by tag "bug" — should return traces 1 and 2
    let filter_bug = TraceFilter {
        tag: Some("bug".into()),
        ..Default::default()
    };
    let results = store.recent(100, Some(&filter_bug));
    assert_eq!(results.len(), 2);
    // newest first: id3 is newest but no tag → skipped; id2, then id1
    assert_eq!(results[0].id, id2);
    assert_eq!(results[1].id, id1);

    // Filter by tag "resolved" — only trace 2
    let filter_resolved = TraceFilter {
        tag: Some("resolved".into()),
        ..Default::default()
    };
    let results2 = store.recent(100, Some(&filter_resolved));
    assert_eq!(results2.len(), 1);
    assert_eq!(results2[0].id, id2);

    // Filter by tag "p1" — only trace 1
    let filter_p1 = TraceFilter {
        tag: Some("p1".into()),
        ..Default::default()
    };
    let results3 = store.recent(100, Some(&filter_p1));
    assert_eq!(results3.len(), 1);
    assert_eq!(results3[0].id, id1);

    // Filter by non-existent tag — empty
    let filter_none = TraceFilter {
        tag: Some("nonexistent".into()),
        ..Default::default()
    };
    let results4 = store.recent(100, Some(&filter_none));
    assert_eq!(results4.len(), 0);

    // Combined filter: tag + status
    let filter_combined = TraceFilter {
        tag: Some("bug".into()),
        status: Some("failed".into()),
        ..Default::default()
    };
    let results5 = store.recent(100, Some(&filter_combined));
    assert_eq!(results5.len(), 1);
    assert_eq!(results5[0].id, id2);

    // No filter — all 3
    let all = store.recent(100, None);
    assert_eq!(all.len(), 3);
}

#[test]
fn trace_annotation_multiple_traces_and_authors() {
    use axon::trace_store::*;

    let mut store = TraceStore::new(TraceStoreConfig::default());

    // Create two traces
    let t1 = build_trace("Flow1", "1.axon", "stub", "k", TraceStatus::Success, 2, 80);
    let id1 = store.record(t1);

    let t2 = build_trace("Flow2", "2.axon", "stub", "k", TraceStatus::Partial, 1, 400);
    let id2 = store.record(t2);

    // Multiple authors annotate the same trace
    for (i, author) in ["alice", "bob", "carol"].iter().enumerate() {
        store.annotate(id1, TraceAnnotation {
            author: author.to_string(),
            text: format!("Note #{}", i + 1),
            tags: vec!["review".into()],
            timestamp: 1000 + i as u64,
        });
    }

    // Single annotation on trace 2
    store.annotate(id2, TraceAnnotation {
        author: "dave".into(),
        text: "Needs investigation".into(),
        tags: vec!["todo".into()],
        timestamp: 2000,
    });

    // Verify trace 1 has 3 annotations
    let entry1 = store.get(id1).unwrap();
    assert_eq!(entry1.annotations.len(), 3);
    let authors: Vec<&str> = entry1.annotations.iter().map(|a| a.author.as_str()).collect();
    assert_eq!(authors, vec!["alice", "bob", "carol"]);

    // Verify trace 2 has 1 annotation
    let entry2 = store.get(id2).unwrap();
    assert_eq!(entry2.annotations.len(), 1);
    assert_eq!(entry2.annotations[0].author, "dave");

    // Filter by "review" tag — only trace 1
    let filter = TraceFilter {
        tag: Some("review".into()),
        ..Default::default()
    };
    let results = store.recent(100, Some(&filter));
    assert_eq!(results.len(), 1);
    assert_eq!(results[0].id, id1);

    // Filter by "todo" tag — only trace 2
    let filter2 = TraceFilter {
        tag: Some("todo".into()),
        ..Default::default()
    };
    let results2 = store.recent(100, Some(&filter2));
    assert_eq!(results2.len(), 1);
    assert_eq!(results2[0].id, id2);

    // Annotations are ordered chronologically
    let entry1 = store.get(id1).unwrap();
    assert!(entry1.annotations[0].timestamp < entry1.annotations[1].timestamp);
    assert!(entry1.annotations[1].timestamp < entry1.annotations[2].timestamp);
}

