#[test]
fn daemon_chain_output_topic_crud() {
    use axon::axon_server::{DaemonInfo, DaemonState};

    // Create daemon with no chain
    let mut daemon = DaemonInfo {
        name: "Extractor".into(),
        state: DaemonState::Idle,
        source_file: "extract.axon".into(),
        flow_name: "ExtractFlow".into(),
        event_count: 0,
        restart_count: 0,
        trigger_topic: Some("data.raw".into()),
        output_topic: None,
        lifecycle_events: Vec::new(),
    };

    // Initially no output chain
    assert!(daemon.output_topic.is_none());

    // Serialization: None output_topic is omitted (skip_serializing_if)
    let json = serde_json::to_value(&daemon).unwrap();
    assert!(json.get("output_topic").is_none());

    // Set output chain
    daemon.output_topic = Some("data.extracted".into());
    assert_eq!(daemon.output_topic.as_deref(), Some("data.extracted"));

    // Serialization: present output_topic is included
    let json2 = serde_json::to_value(&daemon).unwrap();
    assert_eq!(json2["output_topic"], "data.extracted");

    // Full chain info: trigger → daemon → output
    assert_eq!(json2["trigger_topic"], "data.raw");
    assert_eq!(json2["name"], "Extractor");
    assert_eq!(json2["output_topic"], "data.extracted");

    // Clear chain
    daemon.output_topic = None;
    let json3 = serde_json::to_value(&daemon).unwrap();
    assert!(json3.get("output_topic").is_none());
}

#[test]
fn daemon_chain_pipeline_topology() {
    use std::collections::HashMap;
    use axon::axon_server::{DaemonInfo, DaemonState};

    let mut daemons: HashMap<String, DaemonInfo> = HashMap::new();

    // Build a 3-stage pipeline: Ingest → Transform → Load
    // Ingest: triggered by "data.raw", outputs to "data.ingested"
    daemons.insert("Ingest".into(), DaemonInfo {
        name: "Ingest".into(),
        state: DaemonState::Idle,
        source_file: "ingest.axon".into(),
        flow_name: "IngestFlow".into(),
        event_count: 0,
        restart_count: 0,
        trigger_topic: Some("data.raw".into()),
        output_topic: Some("data.ingested".into()),
        lifecycle_events: Vec::new(),
    });

    // Transform: triggered by "data.ingested", outputs to "data.transformed"
    daemons.insert("Transform".into(), DaemonInfo {
        name: "Transform".into(),
        state: DaemonState::Idle,
        source_file: "transform.axon".into(),
        flow_name: "TransformFlow".into(),
        event_count: 0,
        restart_count: 0,
        trigger_topic: Some("data.ingested".into()),
        output_topic: Some("data.transformed".into()),
        lifecycle_events: Vec::new(),
    });

    // Load: triggered by "data.transformed", no output (terminal)
    daemons.insert("Load".into(), DaemonInfo {
        name: "Load".into(),
        state: DaemonState::Idle,
        source_file: "load.axon".into(),
        flow_name: "LoadFlow".into(),
        event_count: 0,
        restart_count: 0,
        trigger_topic: Some("data.transformed".into()),
        output_topic: None,
        lifecycle_events: Vec::new(),
    });

    // Verify pipeline topology
    assert_eq!(daemons.len(), 3);

    // Stage 1: "data.raw" triggers Ingest
    let topic1 = "data.raw";
    let stage1: Vec<&str> = daemons.values()
        .filter(|d| {
            d.trigger_topic.as_ref().map_or(false, |t| {
                let f = axon::event_bus::TopicFilter::new(t);
                f.matches(topic1)
            })
        })
        .map(|d| d.name.as_str())
        .collect();
    assert_eq!(stage1, vec!["Ingest"]);

    // Ingest outputs to "data.ingested" → triggers Transform
    let ingest_output = daemons["Ingest"].output_topic.as_deref().unwrap();
    assert_eq!(ingest_output, "data.ingested");

    let stage2: Vec<&str> = daemons.values()
        .filter(|d| {
            d.trigger_topic.as_ref().map_or(false, |t| {
                let f = axon::event_bus::TopicFilter::new(t);
                f.matches(ingest_output)
            })
        })
        .map(|d| d.name.as_str())
        .collect();
    assert_eq!(stage2, vec!["Transform"]);

    // Transform outputs to "data.transformed" → triggers Load
    let transform_output = daemons["Transform"].output_topic.as_deref().unwrap();
    assert_eq!(transform_output, "data.transformed");

    let stage3: Vec<&str> = daemons.values()
        .filter(|d| {
            d.trigger_topic.as_ref().map_or(false, |t| {
                let f = axon::event_bus::TopicFilter::new(t);
                f.matches(transform_output)
            })
        })
        .map(|d| d.name.as_str())
        .collect();
    assert_eq!(stage3, vec!["Load"]);

    // Load is terminal — no output
    assert!(daemons["Load"].output_topic.is_none());

    // Chains listing: all 3 have trigger or output
    let chains: Vec<&str> = daemons.values()
        .filter(|d| d.trigger_topic.is_some() || d.output_topic.is_some())
        .map(|d| d.name.as_str())
        .collect();
    assert_eq!(chains.len(), 3);
}

#[test]
fn daemon_chain_fan_out_and_convergence() {
    use std::collections::HashMap;
    use axon::axon_server::{DaemonInfo, DaemonState};
    use axon::event_bus::TopicFilter;

    let mut daemons: HashMap<String, DaemonInfo> = HashMap::new();

    // Fan-out: one event triggers multiple daemons
    // "event.new" triggers both Analyzer and Archiver
    daemons.insert("Analyzer".into(), DaemonInfo {
        name: "Analyzer".into(),
        state: DaemonState::Idle,
        source_file: "a.axon".into(),
        flow_name: "AnalyzeFlow".into(),
        event_count: 0,
        restart_count: 0,
        trigger_topic: Some("event.new".into()),
        output_topic: Some("analysis.done".into()),
        lifecycle_events: Vec::new(),
    });

    daemons.insert("Archiver".into(), DaemonInfo {
        name: "Archiver".into(),
        state: DaemonState::Idle,
        source_file: "a.axon".into(),
        flow_name: "ArchiveFlow".into(),
        event_count: 0,
        restart_count: 0,
        trigger_topic: Some("event.new".into()),
        output_topic: Some("archive.done".into()),
        lifecycle_events: Vec::new(),
    });

    // Convergence: Reporter triggered by both analysis.done and archive.done via wildcard
    daemons.insert("Reporter".into(), DaemonInfo {
        name: "Reporter".into(),
        state: DaemonState::Idle,
        source_file: "r.axon".into(),
        flow_name: "ReportFlow".into(),
        event_count: 0,
        restart_count: 0,
        trigger_topic: Some("*.done".into()), // would need prefix, let's use wildcard
        output_topic: None,
        lifecycle_events: Vec::new(),
    });

    // Fan-out check: "event.new" triggers 2 daemons
    let fan_out: Vec<&str> = daemons.values()
        .filter(|d| {
            d.trigger_topic.as_ref().map_or(false, |t| {
                TopicFilter::new(t).matches("event.new")
            })
        })
        .filter(|d| d.state != DaemonState::Crashed && d.state != DaemonState::Stopped)
        .map(|d| d.name.as_str())
        .collect();
    assert_eq!(fan_out.len(), 2);
    assert!(fan_out.contains(&"Analyzer"));
    assert!(fan_out.contains(&"Archiver"));

    // Wildcard trigger: "*" matches everything
    daemons.get_mut("Reporter").unwrap().trigger_topic = Some("*".into());
    let wildcard_matches: Vec<&str> = daemons.values()
        .filter(|d| {
            d.trigger_topic.as_ref().map_or(false, |t| {
                TopicFilter::new(t).matches("analysis.done")
            })
        })
        .map(|d| d.name.as_str())
        .collect();
    assert!(wildcard_matches.contains(&"Reporter"));

    // Stopped daemon not in fan-out
    daemons.get_mut("Archiver").unwrap().state = DaemonState::Stopped;
    let active_fan: Vec<&str> = daemons.values()
        .filter(|d| {
            d.trigger_topic.as_ref().map_or(false, |t| {
                TopicFilter::new(t).matches("event.new")
            })
        })
        .filter(|d| d.state != DaemonState::Crashed && d.state != DaemonState::Stopped)
        .map(|d| d.name.as_str())
        .collect();
    // Analyzer matches "event.new" directly, Reporter matches via wildcard "*"
    assert_eq!(active_fan.len(), 2);
    assert!(active_fan.contains(&"Analyzer"));
    assert!(active_fan.contains(&"Reporter"));
    // Archiver is Stopped — excluded
    assert!(!active_fan.contains(&"Archiver"));

    // Chain listing: all daemons have trigger or output
    let chains: Vec<&str> = daemons.values()
        .filter(|d| d.trigger_topic.is_some() || d.output_topic.is_some())
        .map(|d| d.name.as_str())
        .collect();
    assert_eq!(chains.len(), 3);
}

// ── D62: Trace Diff ──────────────────────────────────────────────────────

#[test]
fn trace_diff_identical_traces() {
    use axon::trace_store::*;

    let mut store = TraceStore::new(TraceStoreConfig::default());

    // Two identical traces
    let mut t1 = build_trace("FlowA", "a.axon", "anthropic", "key_a", TraceStatus::Success, 4, 200);
    t1.tokens_input = 500;
    t1.tokens_output = 250;
    t1.anchor_checks = 3;
    let id1 = store.record(t1);

    let mut t2 = build_trace("FlowA", "a.axon", "anthropic", "key_a", TraceStatus::Success, 4, 200);
    t2.tokens_input = 500;
    t2.tokens_output = 250;
    t2.anchor_checks = 3;
    let id2 = store.record(t2);

    let a = store.get(id1).unwrap();
    let b = store.get(id2).unwrap();

    // Compare fields — should be identical
    assert_eq!(a.flow_name, b.flow_name);
    assert_eq!(a.status, b.status);
    assert_eq!(a.backend, b.backend);
    assert_eq!(a.steps_executed, b.steps_executed);
    assert_eq!(a.latency_ms, b.latency_ms);
    assert_eq!(a.tokens_input, b.tokens_input);
    assert_eq!(a.tokens_output, b.tokens_output);
    assert_eq!(a.anchor_checks, b.anchor_checks);
    assert_eq!(a.errors, b.errors);
    assert_eq!(a.retries, b.retries);
    assert_eq!(a.source_file, b.source_file);
    assert_eq!(a.client_key, b.client_key);

    // Count diffs (mirrors handler logic)
    let mut diffs = 0u32;
    if a.flow_name != b.flow_name { diffs += 1; }
    if a.status != b.status { diffs += 1; }
    if a.backend != b.backend { diffs += 1; }
    if a.steps_executed != b.steps_executed { diffs += 1; }
    if a.latency_ms != b.latency_ms { diffs += 1; }
    if a.tokens_input != b.tokens_input { diffs += 1; }
    if a.tokens_output != b.tokens_output { diffs += 1; }
    if a.errors != b.errors { diffs += 1; }
    assert_eq!(diffs, 0);
}

#[test]
fn trace_diff_divergent_traces() {
    use axon::trace_store::*;

    let mut store = TraceStore::new(TraceStoreConfig::default());

    // Trace A: successful, fast, no errors
    let mut t1 = build_trace("FlowX", "x.axon", "anthropic", "client_1", TraceStatus::Success, 5, 100);
    t1.tokens_input = 1000;
    t1.tokens_output = 500;
    t1.anchor_checks = 4;
    let id1 = store.record(t1);

    // Trace B: failed, slow, with errors, different backend
    let mut t2 = build_trace("FlowX", "x.axon", "openai", "client_1", TraceStatus::Failed, 2, 800);
    t2.tokens_input = 600;
    t2.tokens_output = 200;
    t2.anchor_checks = 4;
    t2.anchor_breaches = 2;
    t2.errors = 3;
    t2.retries = 1;
    let id2 = store.record(t2);

    let a = store.get(id1).unwrap();
    let b = store.get(id2).unwrap();

    // Compute deltas (b - a)
    let latency_delta = b.latency_ms as i64 - a.latency_ms as i64;
    let steps_delta = b.steps_executed as i64 - a.steps_executed as i64;
    let tokens_in_delta = b.tokens_input as i64 - a.tokens_input as i64;
    let tokens_out_delta = b.tokens_output as i64 - a.tokens_output as i64;
    let errors_delta = b.errors as i64 - a.errors as i64;
    let retries_delta = b.retries as i64 - a.retries as i64;
    let breach_delta = b.anchor_breaches as i64 - a.anchor_breaches as i64;

    assert_eq!(latency_delta, 700);    // 800 - 100
    assert_eq!(steps_delta, -3);       // 2 - 5
    assert_eq!(tokens_in_delta, -400); // 600 - 1000
    assert_eq!(tokens_out_delta, -300); // 200 - 500
    assert_eq!(errors_delta, 3);       // 3 - 0
    assert_eq!(retries_delta, 1);      // 1 - 0
    assert_eq!(breach_delta, 2);       // 2 - 0

    // Status changed
    assert_ne!(a.status, b.status);

    // Backend changed
    assert_ne!(a.backend, b.backend);
    assert_eq!(a.backend, "anthropic");
    assert_eq!(b.backend, "openai");

    // Same fields
    assert_eq!(a.flow_name, b.flow_name); // both FlowX
    assert_eq!(a.source_file, b.source_file); // both x.axon
    assert_eq!(a.client_key, b.client_key); // both client_1
    assert_eq!(a.anchor_checks, b.anchor_checks); // both 4

    // Count expected differences
    let mut diff_count = 0u32;
    if a.status != b.status { diff_count += 1; }         // yes
    if a.backend != b.backend { diff_count += 1; }       // yes
    if a.steps_executed != b.steps_executed { diff_count += 1; } // yes
    if a.latency_ms != b.latency_ms { diff_count += 1; } // yes
    if a.tokens_input != b.tokens_input { diff_count += 1; } // yes
    if a.tokens_output != b.tokens_output { diff_count += 1; } // yes
    if a.anchor_breaches != b.anchor_breaches { diff_count += 1; } // yes
    if a.errors != b.errors { diff_count += 1; }         // yes
    if a.retries != b.retries { diff_count += 1; }       // yes
    assert_eq!(diff_count, 9);
}

#[test]
fn trace_diff_cross_flow_comparison() {
    use axon::trace_store::*;

    let mut store = TraceStore::new(TraceStoreConfig::default());

    // Different flows entirely
    let t1 = build_trace("FlowAlpha", "alpha.axon", "anthropic", "alice", TraceStatus::Success, 3, 150);
    let id1 = store.record(t1);

    let mut t2 = build_trace("FlowBeta", "beta.axon", "openai", "bob", TraceStatus::Partial, 7, 900);
    t2.tokens_input = 2000;
    t2.tokens_output = 1000;
    t2.errors = 1;
    let id2 = store.record(t2);

    let a = store.get(id1).unwrap();
    let b = store.get(id2).unwrap();

    // Every field differs except anchor_checks (both 0) and retries (both 0)
    assert_ne!(a.flow_name, b.flow_name);
    assert_ne!(a.source_file, b.source_file);
    assert_ne!(a.backend, b.backend);
    assert_ne!(a.client_key, b.client_key);
    assert_ne!(a.status, b.status);
    assert_ne!(a.steps_executed, b.steps_executed);
    assert_ne!(a.latency_ms, b.latency_ms);
    assert_ne!(a.tokens_input, b.tokens_input);
    assert_ne!(a.tokens_output, b.tokens_output);
    assert_ne!(a.errors, b.errors);

    // Same fields
    assert_eq!(a.anchor_checks, b.anchor_checks); // both 0
    assert_eq!(a.retries, b.retries); // both 0
    assert_eq!(a.anchor_breaches, b.anchor_breaches); // both 0

    // Summary comparison
    let summary_a = serde_json::json!({
        "flow": a.flow_name,
        "status": a.status.as_str(),
        "steps": a.steps_executed,
        "latency_ms": a.latency_ms,
        "errors": a.errors,
    });
    let summary_b = serde_json::json!({
        "flow": b.flow_name,
        "status": b.status.as_str(),
        "steps": b.steps_executed,
        "latency_ms": b.latency_ms,
        "errors": b.errors,
    });

    assert_eq!(summary_a["flow"], "FlowAlpha");
    assert_eq!(summary_b["flow"], "FlowBeta");
    assert_eq!(summary_a["status"], "success");
    assert_eq!(summary_b["status"], "partial");
    assert_eq!(summary_a["steps"], 3);
    assert_eq!(summary_b["steps"], 7);
    assert_eq!(summary_a["latency_ms"], 150);
    assert_eq!(summary_b["latency_ms"], 900);
}

// ── D63: Pipeline Visualizer ─────────────────────────────────────────────

#[test]
fn chain_graph_dot_format_linear_pipeline() {
    use std::collections::{HashMap, HashSet};
    use axon::axon_server::{DaemonInfo, DaemonState};

    let mut daemons: HashMap<String, DaemonInfo> = HashMap::new();

    // 3-stage pipeline: Ingest → Transform → Load
    daemons.insert("Ingest".into(), DaemonInfo {
        name: "Ingest".into(), state: DaemonState::Idle,
        source_file: "i.axon".into(), flow_name: "IngestFlow".into(),
        event_count: 0, restart_count: 0,
        trigger_topic: Some("data.raw".into()),
        output_topic: Some("data.ingested".into()),
        lifecycle_events: Vec::new(),
    });
    daemons.insert("Transform".into(), DaemonInfo {
        name: "Transform".into(), state: DaemonState::Running,
        source_file: "t.axon".into(), flow_name: "TransformFlow".into(),
        event_count: 5, restart_count: 0,
        trigger_topic: Some("data.ingested".into()),
        output_topic: Some("data.transformed".into()),
        lifecycle_events: Vec::new(),
    });
    daemons.insert("Load".into(), DaemonInfo {
        name: "Load".into(), state: DaemonState::Hibernating,
        source_file: "l.axon".into(), flow_name: "LoadFlow".into(),
        event_count: 3, restart_count: 0,
        trigger_topic: Some("data.transformed".into()),
        output_topic: None,
        lifecycle_events: Vec::new(),
    });

    // Build DOT output (mirrors handler logic)
    let mut topics: HashSet<String> = HashSet::new();
    let mut edges: Vec<(String, String, &str)> = Vec::new();

    for d in daemons.values() {
        if let Some(ref trigger) = d.trigger_topic {
            topics.insert(trigger.clone());
            edges.push((format!("topic:{}", trigger), format!("daemon:{}", d.name), "triggers"));
        }
        if let Some(ref output) = d.output_topic {
            topics.insert(output.clone());
            edges.push((format!("daemon:{}", d.name), format!("topic:{}", output), "outputs"));
        }
    }

    // Verify topology
    assert_eq!(topics.len(), 3); // data.raw, data.ingested, data.transformed (deduplicated)
    assert!(topics.contains("data.raw"));
    assert!(topics.contains("data.ingested"));
    assert!(topics.contains("data.transformed"));
    assert_eq!(edges.len(), 5); // 3 triggers + 2 outputs (Load has no output)

    // Build DOT string
    let mut lines = vec!["digraph chains {".to_string(), "    rankdir=LR;".to_string()];
    for topic in &topics {
        let safe_id = topic.replace('.', "_");
        lines.push(format!("    \"t_{}\" [label=\"{}\" shape=ellipse];", safe_id, topic));
    }
    for d in daemons.values().filter(|d| d.trigger_topic.is_some() || d.output_topic.is_some()) {
        lines.push(format!("    \"d_{}\" [label=\"{}\" shape=box];", d.name, d.name));
    }
    for (from, to, label) in &edges {
        let from_id = if from.starts_with("topic:") {
            format!("t_{}", from[6..].replace('.', "_"))
        } else {
            format!("d_{}", &from[7..])
        };
        let to_id = if to.starts_with("topic:") {
            format!("t_{}", to[6..].replace('.', "_"))
        } else {
            format!("d_{}", &to[7..])
        };
        lines.push(format!("    \"{}\" -> \"{}\" [label=\"{}\"];", from_id, to_id, label));
    }
    lines.push("}".to_string());

    let dot = lines.join("\n");

    // Validate DOT structure
    assert!(dot.starts_with("digraph chains {"));
    assert!(dot.ends_with("}"));
    assert!(dot.contains("rankdir=LR"));
    assert!(dot.contains("shape=ellipse")); // topic nodes
    assert!(dot.contains("shape=box"));     // daemon nodes
    assert!(dot.contains("\"d_Ingest\""));
    assert!(dot.contains("\"d_Transform\""));
    assert!(dot.contains("\"d_Load\""));
    assert!(dot.contains("label=\"triggers\""));
    assert!(dot.contains("label=\"outputs\""));
}

#[test]
fn chain_graph_mermaid_format() {
    use std::collections::{HashMap, HashSet};
    use axon::axon_server::{DaemonInfo, DaemonState};

    let mut daemons: HashMap<String, DaemonInfo> = HashMap::new();

    daemons.insert("A".into(), DaemonInfo {
        name: "A".into(), state: DaemonState::Idle,
        source_file: "a.axon".into(), flow_name: "FlowA".into(),
        event_count: 0, restart_count: 0,
        trigger_topic: Some("input".into()),
        output_topic: Some("middle".into()),
        lifecycle_events: Vec::new(),
    });
    daemons.insert("B".into(), DaemonInfo {
        name: "B".into(), state: DaemonState::Crashed,
        source_file: "b.axon".into(), flow_name: "FlowB".into(),
        event_count: 2, restart_count: 3,
        trigger_topic: Some("middle".into()),
        output_topic: None,
        lifecycle_events: Vec::new(),
    });

    // Build Mermaid output
    let mut topics: HashSet<String> = HashSet::new();
    let mut edges: Vec<(String, String, &str)> = Vec::new();

    for d in daemons.values() {
        if let Some(ref trigger) = d.trigger_topic {
            topics.insert(trigger.clone());
            edges.push((format!("topic:{}", trigger), format!("daemon:{}", d.name), "triggers"));
        }
        if let Some(ref output) = d.output_topic {
            topics.insert(output.clone());
            edges.push((format!("daemon:{}", d.name), format!("topic:{}", output), "outputs"));
        }
    }

    let mut lines = vec!["graph LR".to_string()];
    for topic in &topics {
        let safe_id = topic.replace('.', "_");
        lines.push(format!("    t_{}(({}))", safe_id, topic));
    }
    for d in daemons.values().filter(|d| d.trigger_topic.is_some() || d.output_topic.is_some()) {
        lines.push(format!("    d_{}[{}]", d.name, d.name));
    }
    for (from, to, label) in &edges {
        let from_id = if from.starts_with("topic:") {
            format!("t_{}", from[6..].replace('.', "_"))
        } else {
            format!("d_{}", &from[7..])
        };
        let to_id = if to.starts_with("topic:") {
            format!("t_{}", to[6..].replace('.', "_"))
        } else {
            format!("d_{}", &to[7..])
        };
        lines.push(format!("    {} -->|{}| {}", from_id, label, to_id));
    }
    let mermaid = lines.join("\n");

    // Validate Mermaid structure
    assert!(mermaid.starts_with("graph LR"));
    assert!(mermaid.contains("t_input((input))"));   // topic circles
    assert!(mermaid.contains("t_middle((middle))")); // topic circles
    assert!(mermaid.contains("d_A[A]"));  // daemon rect
    assert!(mermaid.contains("d_B[B]"));
    assert!(mermaid.contains("-->|triggers|")); // edge labels
    assert!(mermaid.contains("-->|outputs|"));

    // Topics: input, middle
    assert_eq!(topics.len(), 2);
    // Edges: 2 triggers + 1 output = 3
    assert_eq!(edges.len(), 3);
}

#[test]
fn chain_graph_empty_and_wildcard_topology() {
    use std::collections::{HashMap, HashSet};
    use axon::axon_server::{DaemonInfo, DaemonState};

    // Empty: no daemons with chains
    let empty_daemons: HashMap<String, DaemonInfo> = HashMap::new();
    let topics: HashSet<String> = HashSet::new();
    let edges: Vec<(String, String)> = Vec::new();

    // Empty graph
    assert_eq!(topics.len(), 0);
    assert_eq!(edges.len(), 0);

    // DOT for empty graph should be valid minimal structure
    let dot = format!("digraph chains {{\n    rankdir=LR;\n}}");
    assert!(dot.contains("digraph chains"));
    assert!(dot.contains("rankdir=LR"));
    assert_eq!(empty_daemons.len(), 0);

    // Wildcard topology
    let mut daemons: HashMap<String, DaemonInfo> = HashMap::new();

    // Daemon with wildcard trigger
    daemons.insert("Monitor".into(), DaemonInfo {
        name: "Monitor".into(), state: DaemonState::Idle,
        source_file: "m.axon".into(), flow_name: "MonitorFlow".into(),
        event_count: 0, restart_count: 0,
        trigger_topic: Some("*".into()),
        output_topic: Some("monitor.alert".into()),
        lifecycle_events: Vec::new(),
    });

    // Daemon with prefix trigger
    daemons.insert("Logger".into(), DaemonInfo {
        name: "Logger".into(), state: DaemonState::Idle,
        source_file: "l.axon".into(), flow_name: "LogFlow".into(),
        event_count: 0, restart_count: 0,
        trigger_topic: Some("data.*".into()),
        output_topic: None,
        lifecycle_events: Vec::new(),
    });

    // Manual daemon (no chain)
    daemons.insert("Manual".into(), DaemonInfo {
        name: "Manual".into(), state: DaemonState::Idle,
        source_file: "x.axon".into(), flow_name: "ManualFlow".into(),
        event_count: 0, restart_count: 0,
        trigger_topic: None,
        output_topic: None,
        lifecycle_events: Vec::new(),
    });

    // Build graph
    let mut wild_topics: HashSet<String> = HashSet::new();
    let mut wild_edges: Vec<(String, String, &str)> = Vec::new();

    for d in daemons.values() {
        if let Some(ref trigger) = d.trigger_topic {
            wild_topics.insert(trigger.clone());
            wild_edges.push((format!("topic:{}", trigger), format!("daemon:{}", d.name), "triggers"));
        }
        if let Some(ref output) = d.output_topic {
            wild_topics.insert(output.clone());
            wild_edges.push((format!("daemon:{}", d.name), format!("topic:{}", output), "outputs"));
        }
    }

    // Topics: *, data.*, monitor.alert
    assert_eq!(wild_topics.len(), 3);
    assert!(wild_topics.contains("*"));
    assert!(wild_topics.contains("data.*"));
    assert!(wild_topics.contains("monitor.alert"));

    // Edges: 2 triggers + 1 output = 3
    assert_eq!(wild_edges.len(), 3);

    // Chain participants: Monitor and Logger (Manual has no trigger/output)
    let chain_daemons: Vec<&str> = daemons.values()
        .filter(|d| d.trigger_topic.is_some() || d.output_topic.is_some())
        .map(|d| d.name.as_str())
        .collect();
    assert_eq!(chain_daemons.len(), 2);
    assert!(chain_daemons.contains(&"Monitor"));
    assert!(chain_daemons.contains(&"Logger"));
    assert!(!chain_daemons.contains(&"Manual"));

    // DOT safe ID for wildcard: * → star
    let star_id = "*".replace('*', "star");
    assert_eq!(star_id, "star");
    let prefix_id = "data.*".replace('.', "_").replace('*', "star");
    assert_eq!(prefix_id, "data_star");
}

