// ── D65 — Trace Search ──────────────────────────────────────────────

#[test]
fn trace_search_by_flow_name_and_backend() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, TraceEvent, TraceAnnotation, build_trace};

    let mut store = TraceStore::new(TraceStoreConfig { enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0 });

    // Record traces with different flow names and backends
    let t1 = build_trace("IngestPipeline", "ingest.axon", "anthropic", "client-a", TraceStatus::Success, 3, 100);
    let t2 = build_trace("TransformData", "transform.axon", "openai", "client-b", TraceStatus::Success, 5, 200);
    let t3 = build_trace("ExportReport", "export.axon", "anthropic", "client-a", TraceStatus::Failed, 2, 50);

    store.record(t1);
    store.record(t2);
    store.record(t3);

    // Search by flow name substring
    let results = store.search("Ingest", 50);
    assert_eq!(results.len(), 1);
    assert_eq!(results[0].flow_name, "IngestPipeline");

    // Search by backend
    let results = store.search("anthropic", 50);
    assert_eq!(results.len(), 2);

    // Search by source file
    let results = store.search("transform.axon", 50);
    assert_eq!(results.len(), 1);
    assert_eq!(results[0].flow_name, "TransformData");

    // Case insensitive
    let results = store.search("ingestpipeline", 50);
    assert_eq!(results.len(), 1);

    // No match
    let results = store.search("nonexistent", 50);
    assert_eq!(results.len(), 0);

    // Limit
    let results = store.search("client", 1);
    assert_eq!(results.len(), 1);
}

#[test]
fn trace_search_by_events_and_annotations() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, TraceEvent, TraceAnnotation, build_trace};

    let mut store = TraceStore::new(TraceStoreConfig { enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0 });

    let mut t1 = build_trace("FlowA", "a.axon", "stub", "k1", TraceStatus::Success, 2, 100);
    t1.events.push(TraceEvent {
        event_type: "step_start".into(),
        offset_ms: 0,
        step_name: "ValidateInput".into(),
        detail: "checking schema compliance".into(),
    });
    t1.events.push(TraceEvent {
        event_type: "step_end".into(),
        offset_ms: 50,
        step_name: "GenerateOutput".into(),
        detail: "model returned 200 tokens".into(),
    });

    let mut t2 = build_trace("FlowB", "b.axon", "stub", "k2", TraceStatus::Success, 1, 80);
    t2.events.push(TraceEvent {
        event_type: "anchor_check".into(),
        offset_ms: 10,
        step_name: "AnchorGate".into(),
        detail: "NoHallucination passed".into(),
    });

    store.record(t1);
    let id2 = store.record(t2);

    // Add an annotation to t2
    store.annotate(id2, TraceAnnotation {
        author: "reviewer".into(),
        text: "Performance looks excellent here".into(),
        tags: vec!["perf".into(), "approved".into()],
        timestamp: 1000,
    });

    // Search by step name
    let results = store.search("ValidateInput", 50);
    assert_eq!(results.len(), 1);
    assert_eq!(results[0].flow_name, "FlowA");

    // Search by event detail
    let results = store.search("schema compliance", 50);
    assert_eq!(results.len(), 1);

    // Search by annotation text
    let results = store.search("excellent", 50);
    assert_eq!(results.len(), 1);
    assert_eq!(results[0].flow_name, "FlowB");

    // Search by annotation tag
    let results = store.search("approved", 50);
    assert_eq!(results.len(), 1);
    assert_eq!(results[0].flow_name, "FlowB");

    // Search matching event detail in both (both have "step" type events with different details)
    let results = store.search("passed", 50);
    assert_eq!(results.len(), 1); // only t2 has "passed" in detail
}

#[test]
fn trace_search_cross_field_and_empty_query() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, TraceEvent, TraceAnnotation, build_trace};

    let mut store = TraceStore::new(TraceStoreConfig { enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0 });

    let mut t1 = build_trace("DataPipeline", "pipeline.axon", "anthropic", "admin-key", TraceStatus::Success, 4, 300);
    t1.events.push(TraceEvent {
        event_type: "model_call".into(),
        offset_ms: 100,
        step_name: "Summarize".into(),
        detail: "claude-3 invoked with 500 tokens".into(),
    });

    let mut t2 = build_trace("DataPipeline", "pipeline.axon", "openai", "user-key", TraceStatus::Failed, 2, 150);
    t2.errors = 1;
    t2.events.push(TraceEvent {
        event_type: "error".into(),
        offset_ms: 80,
        step_name: "Validate".into(),
        detail: "anchor breach detected in output".into(),
    });

    store.record(t1);
    let id2 = store.record(t2);

    store.annotate(id2, TraceAnnotation {
        author: "oncall".into(),
        text: "Investigating anchor breach root cause".into(),
        tags: vec!["incident".into(), "p1".into()],
        timestamp: 2000,
    });

    // Search by shared flow name — both match
    let results = store.search("DataPipeline", 50);
    assert_eq!(results.len(), 2);

    // Search by client key
    let results = store.search("admin-key", 50);
    assert_eq!(results.len(), 1);
    assert_eq!(results[0].client_key, "admin-key");

    // Search matching event detail + annotation in same trace (t2 only)
    let results = store.search("anchor breach", 50);
    assert_eq!(results.len(), 1);
    assert_eq!(results[0].errors, 1);

    // Search by annotation tag
    let results = store.search("incident", 50);
    assert_eq!(results.len(), 1);

    // Search by "claude" — only in t1's event detail
    let results = store.search("claude", 50);
    assert_eq!(results.len(), 1);
    assert_eq!(results[0].client_key, "admin-key");

    // Empty store search
    let empty_store = TraceStore::new(TraceStoreConfig { enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0 });
    let results = empty_store.search("anything", 50);
    assert_eq!(results.len(), 0);
}

// ── D66 — Health Check Deep ─────────────────────────────────────────

#[test]
fn health_components_trace_store_status() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, build_trace};

    // Healthy: enabled, well under capacity
    let store = TraceStore::new(TraceStoreConfig { enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0 });
    assert!(store.config().enabled);
    assert_eq!(store.len(), 0);
    assert_eq!(store.config().capacity, 100);
    let utilization = (store.len() as f64 / store.config().capacity as f64 * 100.0) as u64;
    assert_eq!(utilization, 0);

    // Degraded: at capacity (ring buffer full)
    let mut store = TraceStore::new(TraceStoreConfig { enabled: true, capacity: 3, max_events_per_trace: 50, max_age_secs: 0 });
    for i in 0..3 {
        let t = build_trace(&format!("flow{}", i), "f.axon", "stub", "k", TraceStatus::Success, 1, 10);
        store.record(t);
    }
    assert_eq!(store.len(), 3);
    assert_eq!(store.config().capacity, 3);
    let at_capacity = store.len() >= store.config().capacity;
    assert!(at_capacity);

    // Disabled: not enabled
    let disabled = TraceStore::new(TraceStoreConfig::disabled());
    assert!(!disabled.config().enabled);
}

#[test]
fn health_components_event_bus_and_supervisor() {
    use axon::event_bus::{EventBus, DaemonSupervisor, RestartPolicy};

    let bus = EventBus::new();
    let stats = bus.stats();
    assert_eq!(stats.events_published, 0);
    assert_eq!(stats.events_dropped, 0);

    // Publish some events
    bus.publish("test.topic", serde_json::json!({"data": 1}), "test");
    bus.publish("test.other", serde_json::json!({"data": 2}), "test");
    let stats = bus.stats();
    assert_eq!(stats.events_published, 2);
    assert_eq!(stats.topics_seen.len(), 2);
    // No drops = healthy
    assert_eq!(stats.events_dropped, 0);

    // Supervisor: healthy when no crashes
    let mut sup = DaemonSupervisor::new(bus.clone());
    sup.register("worker-1", RestartPolicy::Never);
    sup.register("worker-2", RestartPolicy::Never);
    let counts = sup.state_counts();
    let crashed = counts.get("crashed").copied().unwrap_or(0);
    assert_eq!(crashed, 0);
    assert_eq!(sup.list().len(), 2);

    // Supervisor: degraded when dead daemon exists
    sup.mark_started("worker-1");
    sup.report_crash("worker-1", "out of memory");
    let counts = sup.state_counts();
    let dead = counts.get("dead").copied().unwrap_or(0);
    assert!(dead > 0);
}

#[test]
fn health_components_schedules_and_audit() {
    use axon::axon_server::ScheduleEntry;
    use axon::audit_trail::AuditLog;
    use std::collections::HashMap;

    // Schedules: healthy when no errors
    let mut schedules: HashMap<String, ScheduleEntry> = HashMap::new();
    schedules.insert("s1".into(), ScheduleEntry {
        flow_name: "FlowA".into(),
        interval_secs: 60,
        enabled: true,
        backend: "stub".into(),
        last_run: 0,
        next_run: 60,
        run_count: 5,
        error_count: 0,
        history: Vec::new(),
    });
    schedules.insert("s2".into(), ScheduleEntry {
        flow_name: "FlowB".into(),
        interval_secs: 120,
        enabled: false,
        backend: "stub".into(),
        last_run: 0,
        next_run: 120,
        run_count: 0,
        error_count: 0,
        history: Vec::new(),
    });

    let total = schedules.len();
    let enabled = schedules.values().filter(|e| e.enabled).count();
    let errors: u64 = schedules.values().map(|e| e.error_count).sum();
    assert_eq!(total, 2);
    assert_eq!(enabled, 1);
    assert_eq!(errors, 0); // healthy

    // Schedules: degraded when errors exist
    schedules.get_mut("s1").unwrap().error_count = 3;
    let errors: u64 = schedules.values().map(|e| e.error_count).sum();
    assert_eq!(errors, 3); // degraded

    // Audit log: capacity getter
    let audit = AuditLog::new(500);
    assert_eq!(audit.capacity(), 500);
    assert_eq!(audit.len(), 0);
}

