// ── D68 — Trace Retention ───────────────────────────────────────────

#[test]
fn trace_retention_evict_expired_by_ttl() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, build_trace};
    use std::time::{SystemTime, UNIX_EPOCH};

    let mut store = TraceStore::new(TraceStoreConfig {
        enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 60,
    });

    // Record 3 traces
    let id1 = store.record(build_trace("Old1", "a.axon", "stub", "k", TraceStatus::Success, 1, 10));
    let id2 = store.record(build_trace("Old2", "b.axon", "stub", "k", TraceStatus::Success, 1, 20));
    let id3 = store.record(build_trace("Recent", "c.axon", "stub", "k", TraceStatus::Success, 1, 30));

    assert_eq!(store.len(), 3);

    // Backdate id1 and id2 to 120 seconds ago (beyond 60s TTL)
    let now = SystemTime::now().duration_since(UNIX_EPOCH).unwrap().as_secs();
    store.get_mut(id1).unwrap().timestamp = now - 120;
    store.get_mut(id2).unwrap().timestamp = now - 90;
    // id3 stays at current time (within TTL)

    let evicted = store.evict_expired();
    assert_eq!(evicted, 2);
    assert_eq!(store.len(), 1);
    assert!(store.get(id1).is_none());
    assert!(store.get(id2).is_none());
    assert!(store.get(id3).is_some());
    assert_eq!(store.get(id3).unwrap().flow_name, "Recent");
}

#[test]
fn trace_retention_zero_ttl_no_eviction() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, build_trace};
    use std::time::{SystemTime, UNIX_EPOCH};

    // max_age_secs = 0 means no TTL eviction
    let mut store = TraceStore::new(TraceStoreConfig {
        enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0,
    });

    let id1 = store.record(build_trace("Flow1", "a.axon", "stub", "k", TraceStatus::Success, 1, 10));
    let id2 = store.record(build_trace("Flow2", "b.axon", "stub", "k", TraceStatus::Success, 1, 20));

    // Backdate to very old
    let now = SystemTime::now().duration_since(UNIX_EPOCH).unwrap().as_secs();
    store.get_mut(id1).unwrap().timestamp = now - 999999;

    // Evict should be no-op with TTL=0
    let evicted = store.evict_expired();
    assert_eq!(evicted, 0);
    assert_eq!(store.len(), 2);

    // Update TTL and re-evict
    let prev = store.set_max_age_secs(3600);
    assert_eq!(prev, 0);

    let evicted = store.evict_expired();
    assert_eq!(evicted, 1); // id1 is too old
    assert_eq!(store.len(), 1);
    assert!(store.get(id2).is_some());
}

#[test]
fn trace_retention_config_update_and_immediate_eviction() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, build_trace};
    use std::time::{SystemTime, UNIX_EPOCH};

    let mut store = TraceStore::new(TraceStoreConfig {
        enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 300,
    });

    // Record 5 traces with varying ages
    let now = SystemTime::now().duration_since(UNIX_EPOCH).unwrap().as_secs();
    for i in 0..5 {
        let id = store.record(build_trace(&format!("Flow{}", i), "f.axon", "stub", "k", TraceStatus::Success, 1, 10));
        // Age: 0=400s, 1=200s, 2=100s, 3=50s, 4=10s
        let ages = [400, 200, 100, 50, 10];
        store.get_mut(id).unwrap().timestamp = now - ages[i as usize];
    }
    assert_eq!(store.len(), 5);

    // With TTL=300, traces older than 300s are evicted (only Flow0 at 400s)
    let evicted = store.evict_expired();
    assert_eq!(evicted, 1);
    assert_eq!(store.len(), 4);

    // Tighten TTL to 60s — evicts Flow1(200s) and Flow2(100s)
    store.set_max_age_secs(60);
    let evicted = store.evict_expired();
    assert_eq!(evicted, 2);
    assert_eq!(store.len(), 2);

    // Verify config reflects new TTL
    assert_eq!(store.config().max_age_secs, 60);

    // Remaining traces are Flow3(50s) and Flow4(10s) — both within 60s TTL
    let remaining = store.recent(10, None);
    assert_eq!(remaining.len(), 2);
}

