#[test]
fn trace_bulk_delete_by_ids() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, build_trace};

    let mut store = TraceStore::new(TraceStoreConfig {
        enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0,
    });

    let id1 = store.record(build_trace("FlowA", "a.axon", "stub", "k", TraceStatus::Success, 1, 10));
    let id2 = store.record(build_trace("FlowB", "b.axon", "stub", "k", TraceStatus::Success, 2, 20));
    let id3 = store.record(build_trace("FlowC", "c.axon", "stub", "k", TraceStatus::Success, 3, 30));
    let id4 = store.record(build_trace("FlowD", "d.axon", "stub", "k", TraceStatus::Failed, 1, 50));
    let id5 = store.record(build_trace("FlowE", "e.axon", "stub", "k", TraceStatus::Success, 4, 40));

    assert_eq!(store.len(), 5);

    // Delete a subset
    let deleted = store.bulk_delete(&[id2, id4]);
    assert_eq!(deleted, 2);
    assert_eq!(store.len(), 3);
    assert!(store.get(id1).is_some());
    assert!(store.get(id2).is_none());
    assert!(store.get(id3).is_some());
    assert!(store.get(id4).is_none());
    assert!(store.get(id5).is_some());

    // Delete with non-existent IDs — only existing ones removed
    let deleted = store.bulk_delete(&[id1, 999, 1000]);
    assert_eq!(deleted, 1);
    assert_eq!(store.len(), 2);

    // Delete remaining
    let deleted = store.bulk_delete(&[id3, id5]);
    assert_eq!(deleted, 2);
    assert_eq!(store.len(), 0);

    // Delete on empty store
    let deleted = store.bulk_delete(&[1, 2, 3]);
    assert_eq!(deleted, 0);
}

#[test]
fn trace_bulk_annotate_multiple_traces() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, TraceAnnotation, build_trace};

    let mut store = TraceStore::new(TraceStoreConfig {
        enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0,
    });

    let id1 = store.record(build_trace("FlowA", "a.axon", "stub", "k", TraceStatus::Success, 1, 10));
    let id2 = store.record(build_trace("FlowB", "b.axon", "stub", "k", TraceStatus::Success, 2, 20));
    let id3 = store.record(build_trace("FlowC", "c.axon", "stub", "k", TraceStatus::Failed, 3, 30));

    // Bulk annotate id1 and id3
    let annotation = TraceAnnotation {
        author: "reviewer".into(),
        text: "Batch review complete".into(),
        tags: vec!["reviewed".into(), "batch".into()],
        timestamp: 5000,
    };
    let annotated = store.bulk_annotate(&[id1, id3], annotation);
    assert_eq!(annotated, 2);

    // Verify annotations applied
    let t1 = store.get(id1).unwrap();
    assert_eq!(t1.annotations.len(), 1);
    assert_eq!(t1.annotations[0].author, "reviewer");
    assert_eq!(t1.annotations[0].text, "Batch review complete");
    assert_eq!(t1.annotations[0].tags, vec!["reviewed", "batch"]);

    let t2 = store.get(id2).unwrap();
    assert_eq!(t2.annotations.len(), 0); // not in bulk list

    let t3 = store.get(id3).unwrap();
    assert_eq!(t3.annotations.len(), 1);

    // Bulk annotate again — adds second annotation
    let annotation2 = TraceAnnotation {
        author: "oncall".into(),
        text: "Escalated".into(),
        tags: vec!["p1".into()],
        timestamp: 6000,
    };
    let annotated = store.bulk_annotate(&[id1, id2, id3], annotation2);
    assert_eq!(annotated, 3);

    assert_eq!(store.get(id1).unwrap().annotations.len(), 2);
    assert_eq!(store.get(id2).unwrap().annotations.len(), 1);
    assert_eq!(store.get(id3).unwrap().annotations.len(), 2);
}

#[test]
fn trace_bulk_operations_mixed_workflow() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, TraceAnnotation, build_trace};

    let mut store = TraceStore::new(TraceStoreConfig {
        enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0,
    });

    // Record 6 traces: 3 success, 3 failed
    let mut success_ids = Vec::new();
    let mut failed_ids = Vec::new();
    for i in 0..3 {
        let id = store.record(build_trace(
            &format!("Success{}", i), "s.axon", "stub", "k",
            TraceStatus::Success, 2, 100,
        ));
        success_ids.push(id);
    }
    for i in 0..3 {
        let id = store.record(build_trace(
            &format!("Failed{}", i), "f.axon", "stub", "k",
            TraceStatus::Failed, 1, 200,
        ));
        failed_ids.push(id);
    }
    assert_eq!(store.len(), 6);

    // Annotate all failed traces
    let annotation = TraceAnnotation {
        author: "system".into(),
        text: "Marked for review".into(),
        tags: vec!["failure".into(), "auto-flagged".into()],
        timestamp: 7000,
    };
    let annotated = store.bulk_annotate(&failed_ids, annotation);
    assert_eq!(annotated, 3);

    // Delete all success traces
    let deleted = store.bulk_delete(&success_ids);
    assert_eq!(deleted, 3);
    assert_eq!(store.len(), 3);

    // Verify only failed traces remain, each with annotation
    for &fid in &failed_ids {
        let t = store.get(fid).unwrap();
        assert_eq!(t.annotations.len(), 1);
        assert_eq!(t.annotations[0].tags[0], "failure");
    }
    for &sid in &success_ids {
        assert!(store.get(sid).is_none());
    }

    // Bulk annotate with non-existent IDs — only existing ones annotated
    let annotation2 = TraceAnnotation {
        author: "admin".into(),
        text: "Final review".into(),
        tags: vec!["closed".into()],
        timestamp: 8000,
    };
    let annotated = store.bulk_annotate(&[failed_ids[0], 999, 1000], annotation2);
    assert_eq!(annotated, 1);
    assert_eq!(store.get(failed_ids[0]).unwrap().annotations.len(), 2);
}

