// ── D77 — Trace Flamegraph ──────────────────────────────────────────

#[test]
fn trace_flamegraph_nested_spans() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, TraceEvent, build_trace};

    let mut store = TraceStore::new(TraceStoreConfig {
        enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0,
    });

    let mut t = build_trace("Pipeline", "p.axon", "stub", "k", TraceStatus::Success, 3, 200);
    t.events = vec![
        TraceEvent { event_type: "step_start".into(), offset_ms: 0, step_name: "Validate".into(), detail: "start validation".into() },
        TraceEvent { event_type: "anchor_check".into(), offset_ms: 10, step_name: "NoHallucination".into(), detail: "passed".into() },
        TraceEvent { event_type: "step_end".into(), offset_ms: 50, step_name: "Validate".into(), detail: "done".into() },
        TraceEvent { event_type: "step_start".into(), offset_ms: 50, step_name: "Generate".into(), detail: "start generation".into() },
        TraceEvent { event_type: "model_call".into(), offset_ms: 60, step_name: "claude-3".into(), detail: "500 tokens".into() },
        TraceEvent { event_type: "step_end".into(), offset_ms: 150, step_name: "Generate".into(), detail: "done".into() },
        TraceEvent { event_type: "step_start".into(), offset_ms: 150, step_name: "Format".into(), detail: "formatting output".into() },
        TraceEvent { event_type: "step_end".into(), offset_ms: 200, step_name: "Format".into(), detail: "done".into() },
    ];

    let id = store.record(t);
    let entry = store.get(id).unwrap();

    // Build flamegraph manually (same logic as handler)
    let mut root_spans: Vec<serde_json::Value> = Vec::new();
    let mut stack: Vec<serde_json::Value> = Vec::new();

    for ev in &entry.events {
        match ev.event_type.as_str() {
            "step_start" => {
                stack.push(serde_json::json!({
                    "name": ev.step_name,
                    "start_ms": ev.offset_ms,
                    "children": [],
                }));
            }
            "step_end" => {
                if let Some(mut span) = stack.pop() {
                    span["end_ms"] = serde_json::json!(ev.offset_ms);
                    span["duration_ms"] = serde_json::json!(ev.offset_ms - span["start_ms"].as_u64().unwrap());
                    if let Some(parent) = stack.last_mut() {
                        parent["children"].as_array_mut().unwrap().push(span);
                    } else {
                        root_spans.push(span);
                    }
                }
            }
            _ => {
                let leaf = serde_json::json!({
                    "name": ev.step_name,
                    "event_type": ev.event_type,
                    "offset_ms": ev.offset_ms,
                });
                if let Some(parent) = stack.last_mut() {
                    parent["children"].as_array_mut().unwrap().push(leaf);
                } else {
                    root_spans.push(leaf);
                }
            }
        }
    }

    // 3 root spans: Validate, Generate, Format
    assert_eq!(root_spans.len(), 3);
    assert_eq!(root_spans[0]["name"], "Validate");
    assert_eq!(root_spans[0]["duration_ms"], 50);
    // Validate has 1 child (anchor_check)
    assert_eq!(root_spans[0]["children"].as_array().unwrap().len(), 1);

    assert_eq!(root_spans[1]["name"], "Generate");
    assert_eq!(root_spans[1]["duration_ms"], 100);
    // Generate has 1 child (model_call)
    assert_eq!(root_spans[1]["children"].as_array().unwrap().len(), 1);

    assert_eq!(root_spans[2]["name"], "Format");
    assert_eq!(root_spans[2]["duration_ms"], 50);
    assert_eq!(root_spans[2]["children"].as_array().unwrap().len(), 0);
}

#[test]
fn trace_flamegraph_unclosed_spans() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, TraceEvent, build_trace};

    let mut store = TraceStore::new(TraceStoreConfig {
        enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0,
    });

    // Trace with unclosed step (no step_end) — e.g., crash mid-execution
    let mut t = build_trace("CrashedFlow", "c.axon", "stub", "k", TraceStatus::Failed, 1, 300);
    t.events = vec![
        TraceEvent { event_type: "step_start".into(), offset_ms: 0, step_name: "Init".into(), detail: "initializing".into() },
        TraceEvent { event_type: "step_start".into(), offset_ms: 50, step_name: "Process".into(), detail: "processing".into() },
        TraceEvent { event_type: "error".into(), offset_ms: 100, step_name: "Process".into(), detail: "crash!".into() },
        // No step_end for either — both unclosed
    ];

    let id = store.record(t);
    let entry = store.get(id).unwrap();

    // Simulate flamegraph handler logic for unclosed spans
    let mut root_spans = Vec::new();
    let mut stack: Vec<(String, u64, Vec<serde_json::Value>)> = Vec::new(); // (name, start_ms, children)

    for ev in &entry.events {
        match ev.event_type.as_str() {
            "step_start" => {
                stack.push((ev.step_name.clone(), ev.offset_ms, Vec::new()));
            }
            "step_end" => {
                if let Some((name, start, children)) = stack.pop() {
                    let span = serde_json::json!({"name": name, "start": start, "end": ev.offset_ms, "children": children});
                    if let Some(parent) = stack.last_mut() {
                        parent.2.push(span);
                    } else {
                        root_spans.push(span);
                    }
                }
            }
            _ => {
                let leaf = serde_json::json!({"name": ev.step_name, "type": ev.event_type});
                if let Some(parent) = stack.last_mut() {
                    parent.2.push(leaf);
                } else {
                    root_spans.push(leaf);
                }
            }
        }
    }
    // Flush unclosed
    while let Some((name, start, children)) = stack.pop() {
        let span = serde_json::json!({"name": name, "start": start, "end": entry.latency_ms, "children": children});
        if let Some(parent) = stack.last_mut() {
            parent.2.push(span);
        } else {
            root_spans.push(span);
        }
    }

    // Init is root, Process is child of Init (because it was pushed while Init was on stack)
    assert_eq!(root_spans.len(), 1);
    assert_eq!(root_spans[0]["name"], "Init");
    let init_children = root_spans[0]["children"].as_array().unwrap();
    assert_eq!(init_children.len(), 1); // Process (with error child)
    assert_eq!(init_children[0]["name"], "Process");
    let process_children = init_children[0]["children"].as_array().unwrap();
    assert_eq!(process_children.len(), 1); // error event
    assert_eq!(process_children[0]["type"], "error");
}

