// ── D78 — Trace Comparison Matrix ───────────────────────────────────

#[test]
fn trace_compare_matrix_basic() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, build_trace};

    let mut store = TraceStore::new(TraceStoreConfig {
        enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0,
    });

    let mut t1 = build_trace("FlowA", "a.axon", "anthropic", "k1", TraceStatus::Success, 3, 100);
    t1.tokens_input = 200;
    t1.tokens_output = 100;
    let id1 = store.record(t1);

    let mut t2 = build_trace("FlowA", "a.axon", "anthropic", "k2", TraceStatus::Success, 4, 150);
    t2.tokens_input = 300;
    t2.tokens_output = 150;
    let id2 = store.record(t2);

    let mut t3 = build_trace("FlowA", "a.axon", "openai", "k1", TraceStatus::Failed, 2, 200);
    t3.tokens_input = 100;
    t3.tokens_output = 50;
    t3.errors = 1;
    let id3 = store.record(t3);

    // Gather comparison data
    let ids = vec![id1, id2, id3];
    let mut rows = Vec::new();
    let mut latencies = Vec::new();
    let mut total_errors = 0usize;

    for &id in &ids {
        let e = store.get(id).unwrap();
        latencies.push(e.latency_ms);
        total_errors += e.errors;
        rows.push(serde_json::json!({
            "id": e.id,
            "flow_name": e.flow_name,
            "latency_ms": e.latency_ms,
            "errors": e.errors,
            "tokens_total": e.tokens_input + e.tokens_output,
        }));
    }

    assert_eq!(rows.len(), 3);
    latencies.sort();
    let avg = latencies.iter().sum::<u64>() / latencies.len() as u64;
    let spread = latencies.last().unwrap() - latencies.first().unwrap();

    assert_eq!(avg, 150); // (100+150+200)/3
    assert_eq!(spread, 100); // 200-100
    assert_eq!(total_errors, 1);
    assert_eq!(rows[0]["tokens_total"], 300);
    assert_eq!(rows[1]["tokens_total"], 450);
    assert_eq!(rows[2]["tokens_total"], 150);
}

