#[test]
fn trace_compare_multi_flow_multi_backend_summary() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, build_trace};
    use std::collections::HashSet;

    let mut store = TraceStore::new(TraceStoreConfig {
        enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0,
    });

    let id1 = store.record(build_trace("Ingest", "i.axon", "anthropic", "k", TraceStatus::Success, 2, 50));
    let id2 = store.record(build_trace("Transform", "t.axon", "openai", "k", TraceStatus::Success, 4, 200));
    let id3 = store.record(build_trace("Ingest", "i.axon", "anthropic", "k", TraceStatus::Success, 2, 60));
    let id4 = store.record(build_trace("Export", "e.axon", "stub", "k", TraceStatus::Success, 1, 30));

    let ids = vec![id1, id2, id3, id4];
    let mut flow_set = HashSet::new();
    let mut backend_set = HashSet::new();
    let mut latencies = Vec::new();

    for &id in &ids {
        let e = store.get(id).unwrap();
        flow_set.insert(e.flow_name.clone());
        backend_set.insert(e.backend.clone());
        latencies.push(e.latency_ms);
    }

    assert_eq!(flow_set.len(), 3); // Ingest, Transform, Export
    assert_eq!(backend_set.len(), 3); // anthropic, openai, stub
    assert!(flow_set.contains("Ingest"));
    assert!(flow_set.contains("Transform"));
    assert!(flow_set.contains("Export"));

    latencies.sort();
    assert_eq!(latencies[0], 30); // min
    assert_eq!(latencies[3], 200); // max
    let avg = latencies.iter().sum::<u64>() / 4;
    assert_eq!(avg, 85); // (50+200+60+30)/4 = 340/4
    assert_eq!(latencies[3] - latencies[0], 170); // spread
}

