#[test]
fn config_snapshot_save_and_list() {
    use axon::axon_server::NamedConfigSnapshot;
    use axon::server_config::ConfigSnapshot;

    let mut snapshots: Vec<NamedConfigSnapshot> = Vec::new();

    // Save first snapshot
    let snap1 = ConfigSnapshot {
        rate_limit: axon::server_config::RateLimitSection {
            max_requests: 100, window_secs: 60, enabled: true,
        },
        request_log: axon::server_config::RequestLogSection {
            capacity: 1000, enabled: true,
        },
        auth: axon::server_config::AuthSection {
            enabled: false, active_keys: 0, total_keys: 0,
        },
    };
    snapshots.push(NamedConfigSnapshot {
        name: "baseline".into(),
        created_at: 1000,
        snapshot: snap1,
    });

    // Save second snapshot
    let snap2 = ConfigSnapshot {
        rate_limit: axon::server_config::RateLimitSection {
            max_requests: 200, window_secs: 120, enabled: true,
        },
        request_log: axon::server_config::RequestLogSection {
            capacity: 2000, enabled: true,
        },
        auth: axon::server_config::AuthSection {
            enabled: true, active_keys: 2, total_keys: 3,
        },
    };
    snapshots.push(NamedConfigSnapshot {
        name: "production".into(),
        created_at: 2000,
        snapshot: snap2,
    });

    assert_eq!(snapshots.len(), 2);
    assert_eq!(snapshots[0].name, "baseline");
    assert_eq!(snapshots[1].name, "production");

    // Duplicate check
    let has_dup = snapshots.iter().any(|s| s.name == "baseline");
    assert!(has_dup);

    // Serialization
    let json = serde_json::to_value(&snapshots[0]).unwrap();
    assert_eq!(json["name"], "baseline");
    assert_eq!(json["created_at"], 1000);
    assert_eq!(json["snapshot"]["rate_limit"]["max_requests"], 100);
}

#[test]
fn config_snapshot_restore_applies_settings() {
    use axon::server_config::{ConfigSnapshot, RateLimitSection, RequestLogSection, AuthSection};
    use axon::rate_limiter::{RateLimiter, RateLimitConfig};
    use axon::request_log::{RequestLogger, RequestLogConfig};
    use std::time::Duration;

    // Create limiter and logger with initial settings
    let mut limiter = RateLimiter::new(RateLimitConfig {
        max_requests: 100,
        window: Duration::from_secs(60),
        enabled: true,
    });
    let mut logger = RequestLogger::new(RequestLogConfig {
        capacity: 1000,
        enabled: true,
    });

    // Verify initial state
    assert_eq!(limiter.config().max_requests, 100);
    assert!(logger.config().enabled);

    // Create a snapshot representing different settings
    let snap = ConfigSnapshot {
        rate_limit: RateLimitSection { max_requests: 50, window_secs: 30, enabled: false },
        request_log: RequestLogSection { capacity: 500, enabled: false },
        auth: AuthSection { enabled: false, active_keys: 0, total_keys: 0 },
    };

    // Apply snapshot (simulating restore)
    limiter.update_config(
        Some(snap.rate_limit.max_requests),
        Some(snap.rate_limit.window_secs),
        Some(snap.rate_limit.enabled),
    );
    logger.update_config(
        Some(snap.request_log.capacity),
        Some(snap.request_log.enabled),
    );

    // Verify settings changed
    assert_eq!(limiter.config().max_requests, 50);
    assert_eq!(limiter.config().window.as_secs(), 30);
    assert!(!limiter.config().enabled);
    assert_eq!(logger.config().capacity, 500);
    assert!(!logger.config().enabled);
}

#[test]
fn config_snapshot_cap_at_50() {
    use axon::axon_server::NamedConfigSnapshot;
    use axon::server_config::{ConfigSnapshot, RateLimitSection, RequestLogSection, AuthSection};

    let mut snapshots: Vec<NamedConfigSnapshot> = Vec::new();

    // Add 55 snapshots
    for i in 0..55 {
        snapshots.push(NamedConfigSnapshot {
            name: format!("snap-{}", i),
            created_at: i as u64,
            snapshot: ConfigSnapshot {
                rate_limit: RateLimitSection { max_requests: i as u32, window_secs: 60, enabled: true },
                request_log: RequestLogSection { capacity: 1000, enabled: true },
                auth: AuthSection { enabled: false, active_keys: 0, total_keys: 0 },
            },
        });
        if snapshots.len() > 50 {
            snapshots.remove(0);
        }
    }

    assert_eq!(snapshots.len(), 50);
    assert_eq!(snapshots[0].name, "snap-5"); // first 5 evicted
    assert_eq!(snapshots[49].name, "snap-54");

    // Verify latest snapshot has correct config
    assert_eq!(snapshots[49].snapshot.rate_limit.max_requests, 54);
}

// ── D80 — Trace Timeline ────────────────────────────────────────────

#[test]
fn trace_timeline_merged_chronological_order() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, TraceEvent, build_trace};
    use std::time::{SystemTime, UNIX_EPOCH};

    let mut store = TraceStore::new(TraceStoreConfig {
        enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0,
    });

    let now = SystemTime::now().duration_since(UNIX_EPOCH).unwrap().as_secs();

    // Trace 1: starts at now, events at 0ms, 50ms, 100ms
    let mut t1 = build_trace("FlowA", "a.axon", "stub", "k", TraceStatus::Success, 2, 100);
    t1.events = vec![
        TraceEvent { event_type: "step_start".into(), offset_ms: 0, step_name: "Init".into(), detail: "".into() },
        TraceEvent { event_type: "step_end".into(), offset_ms: 50, step_name: "Init".into(), detail: "".into() },
        TraceEvent { event_type: "step_start".into(), offset_ms: 50, step_name: "Run".into(), detail: "".into() },
        TraceEvent { event_type: "step_end".into(), offset_ms: 100, step_name: "Run".into(), detail: "".into() },
    ];
    let id1 = store.record(t1);
    store.get_mut(id1).unwrap().timestamp = now;

    // Trace 2: starts at now + 0 (same second), events at 25ms, 75ms
    let mut t2 = build_trace("FlowB", "b.axon", "stub", "k", TraceStatus::Success, 1, 80);
    t2.events = vec![
        TraceEvent { event_type: "model_call".into(), offset_ms: 25, step_name: "Generate".into(), detail: "claude".into() },
        TraceEvent { event_type: "anchor_check".into(), offset_ms: 75, step_name: "Safety".into(), detail: "passed".into() },
    ];
    let id2 = store.record(t2);
    store.get_mut(id2).unwrap().timestamp = now;

    // Build timeline manually
    let e1 = store.get(id1).unwrap();
    let e2 = store.get(id2).unwrap();

    let mut timeline: Vec<(u64, u64, String, String)> = Vec::new(); // (abs_ms, trace_id, flow, step)

    for ev in &e1.events {
        timeline.push((e1.timestamp * 1000 + ev.offset_ms, e1.id, e1.flow_name.clone(), ev.step_name.clone()));
    }
    for ev in &e2.events {
        timeline.push((e2.timestamp * 1000 + ev.offset_ms, e2.id, e2.flow_name.clone(), ev.step_name.clone()));
    }
    timeline.sort_by_key(|t| t.0);

    // 6 events total, sorted by absolute time
    assert_eq!(timeline.len(), 6);

    // Events interleaved: t1@0, t2@25, t1@50, t1@50, t2@75, t1@100
    // (both traces at same timestamp, so absolute ms difference is just offset)
    assert_eq!(timeline[0].3, "Init"); // t1 offset 0
    assert_eq!(timeline[1].3, "Generate"); // t2 offset 25
    // offsets 50 from both t1 events appear next
    assert!(timeline[2].0 == timeline[3].0); // both at same abs_ms
}

#[test]
fn trace_timeline_with_time_range_filter() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, TraceEvent, build_trace};
    use std::time::{SystemTime, UNIX_EPOCH};

    let mut store = TraceStore::new(TraceStoreConfig {
        enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0,
    });

    let now = SystemTime::now().duration_since(UNIX_EPOCH).unwrap().as_secs();

    let mut t1 = build_trace("Pipeline", "p.axon", "stub", "k", TraceStatus::Success, 3, 500);
    t1.events = vec![
        TraceEvent { event_type: "step_start".into(), offset_ms: 0, step_name: "A".into(), detail: "".into() },
        TraceEvent { event_type: "step_end".into(), offset_ms: 100, step_name: "A".into(), detail: "".into() },
        TraceEvent { event_type: "step_start".into(), offset_ms: 200, step_name: "B".into(), detail: "".into() },
        TraceEvent { event_type: "step_end".into(), offset_ms: 300, step_name: "B".into(), detail: "".into() },
        TraceEvent { event_type: "step_start".into(), offset_ms: 400, step_name: "C".into(), detail: "".into() },
        TraceEvent { event_type: "step_end".into(), offset_ms: 500, step_name: "C".into(), detail: "".into() },
    ];
    let id1 = store.record(t1);
    store.get_mut(id1).unwrap().timestamp = now;

    let entry = store.get(id1).unwrap();
    let base_ms = entry.timestamp * 1000;

    // Build all events with absolute timestamps
    let mut timeline: Vec<(u64, String)> = entry.events.iter()
        .map(|ev| (base_ms + ev.offset_ms, ev.step_name.clone()))
        .collect();
    timeline.sort_by_key(|t| t.0);

    assert_eq!(timeline.len(), 6);
    let earliest = timeline[0].0;

    // Filter: from_ms=150, to_ms=350 (relative to earliest)
    let from_ms = 150u64;
    let to_ms = 350u64;
    let filtered: Vec<&(u64, String)> = timeline.iter()
        .filter(|(abs, _)| {
            let rel = abs.saturating_sub(earliest);
            rel >= from_ms && rel <= to_ms
        })
        .collect();

    // Events at offsets 200 and 300 are in range
    assert_eq!(filtered.len(), 2);
    assert_eq!(filtered[0].1, "B"); // offset 200
    assert_eq!(filtered[1].1, "B"); // offset 300
}

