// ── D81 — Trace Heatmap ─────────────────────────────────────────────

#[test]
fn trace_heatmap_bucketing_by_timestamp() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, build_trace};
    use std::collections::BTreeMap;
    use std::time::{SystemTime, UNIX_EPOCH};

    let mut store = TraceStore::new(TraceStoreConfig {
        enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0,
    });

    let base = 1000000u64; // fixed base timestamp
    let bucket_secs = 60u64;

    // Bucket 0 (1000000–1000059): 3 traces
    for i in 0..3 {
        let id = store.record(build_trace("Flow", "f.axon", "stub", "k", TraceStatus::Success, 2, 100 + i * 10));
        store.get_mut(id).unwrap().timestamp = base + i;
    }
    // Bucket 1 (1000060–1000119): 2 traces, 1 with error
    for i in 0..2 {
        let mut t = build_trace("Flow", "f.axon", "stub", "k", TraceStatus::Success, 1, 200 + i * 50);
        if i == 1 { t.errors = 1; }
        let id = store.record(t);
        store.get_mut(id).unwrap().timestamp = base + 60 + i * 10;
    }
    // Bucket 2 (1000120–1000179): 1 trace
    let id = store.record(build_trace("Flow", "f.axon", "stub", "k", TraceStatus::Success, 3, 50));
    store.get_mut(id).unwrap().timestamp = base + 120;

    // Group into buckets
    let mut buckets: BTreeMap<u64, Vec<u64>> = BTreeMap::new(); // bucket_start → latencies
    let entries = store.recent(store.len(), None);
    for e in &entries {
        let bucket_start = (e.timestamp / bucket_secs) * bucket_secs;
        buckets.entry(bucket_start).or_default().push(e.latency_ms);
    }

    assert_eq!(buckets.len(), 3);

    // Bucket 0
    let b0_start = (base / bucket_secs) * bucket_secs;
    let b0 = buckets.get(&b0_start).unwrap();
    assert_eq!(b0.len(), 3);

    // Bucket 1
    let b1_start = ((base + 60) / bucket_secs) * bucket_secs;
    let b1 = buckets.get(&b1_start).unwrap();
    assert_eq!(b1.len(), 2);

    // Bucket 2
    let b2_start = ((base + 120) / bucket_secs) * bucket_secs;
    let b2 = buckets.get(&b2_start).unwrap();
    assert_eq!(b2.len(), 1);
}

#[test]
fn trace_heatmap_latency_stats_per_bucket() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, build_trace};
    use std::time::{SystemTime, UNIX_EPOCH};

    let mut store = TraceStore::new(TraceStoreConfig {
        enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0,
    });

    let base = 2000000u64;

    // 5 traces in same bucket with latencies: 10, 20, 30, 40, 50
    for i in 1..=5 {
        let mut t = build_trace("Flow", "f.axon", "stub", "k", TraceStatus::Success, 1, i * 10);
        t.tokens_input = 100;
        t.tokens_output = 50;
        if i == 4 || i == 5 { t.errors = 1; }
        let id = store.record(t);
        store.get_mut(id).unwrap().timestamp = base + i;
    }

    let entries = store.recent(store.len(), None);
    let mut latencies: Vec<u64> = entries.iter().map(|e| e.latency_ms).collect();
    latencies.sort();

    let count = latencies.len() as u64;
    let avg = latencies.iter().sum::<u64>() / count;
    let max = *latencies.last().unwrap();
    let errors = entries.iter().filter(|e| e.errors > 0).count() as u64;
    let tokens: u64 = entries.iter().map(|e| e.tokens_input + e.tokens_output).sum();

    assert_eq!(count, 5);
    assert_eq!(avg, 30); // (10+20+30+40+50)/5
    assert_eq!(max, 50);
    assert_eq!(errors, 2);
    assert!((errors as f64 / count as f64 - 0.4).abs() < 0.001);
    assert_eq!(tokens, 5 * 150);

    // P50: index = ceil(50*5/100)-1 = ceil(2.5)-1 = 3-1 = 2 → latencies[2] = 30
    let p50_idx = ((50 * latencies.len() + 99) / 100).min(latencies.len()) - 1;
    assert_eq!(latencies[p50_idx], 30);
}

#[test]
fn trace_heatmap_empty_and_single_bucket() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, build_trace};
    use std::collections::BTreeMap;

    // Empty store → no buckets
    let store = TraceStore::new(TraceStoreConfig {
        enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0,
    });
    let entries = store.recent(store.len(), None);
    assert_eq!(entries.len(), 0);

    // Single trace → single bucket
    let mut store = TraceStore::new(TraceStoreConfig {
        enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0,
    });
    let id = store.record(build_trace("Solo", "s.axon", "stub", "k", TraceStatus::Success, 1, 42));
    store.get_mut(id).unwrap().timestamp = 3000000;

    let entries = store.recent(store.len(), None);
    let mut buckets: BTreeMap<u64, Vec<u64>> = BTreeMap::new();
    for e in &entries {
        let bucket_start = (e.timestamp / 60) * 60;
        buckets.entry(bucket_start).or_default().push(e.latency_ms);
    }
    assert_eq!(buckets.len(), 1);
    let bucket = buckets.values().next().unwrap();
    assert_eq!(bucket.len(), 1);
    assert_eq!(bucket[0], 42);
}

// ── D82 — Daemon Dependency Graph ───────────────────────────────────

#[test]
fn daemon_dependency_linear_chain() {
    use axon::axon_server::{DaemonInfo, DaemonState};
    use std::collections::HashMap;

    // Linear chain: Ingest → Transform → Export
    let daemons = vec![
        DaemonInfo { name: "Ingest".into(), state: DaemonState::Idle, source_file: "i.axon".into(), flow_name: "Ingest".into(), event_count: 0, restart_count: 0, trigger_topic: Some("data.raw".into()), output_topic: Some("data.ingested".into()), lifecycle_events: Vec::new() },
        DaemonInfo { name: "Transform".into(), state: DaemonState::Idle, source_file: "t.axon".into(), flow_name: "Transform".into(), event_count: 0, restart_count: 0, trigger_topic: Some("data.ingested".into()), output_topic: Some("data.transformed".into()), lifecycle_events: Vec::new() },
        DaemonInfo { name: "Export".into(), state: DaemonState::Idle, source_file: "e.axon".into(), flow_name: "Export".into(), event_count: 0, restart_count: 0, trigger_topic: Some("data.transformed".into()), output_topic: None, lifecycle_events: Vec::new() },
    ];

    // Build edges
    let mut edges: Vec<(String, String, String)> = Vec::new();
    let mut downstream: HashMap<String, Vec<String>> = HashMap::new();
    let mut upstream: HashMap<String, Vec<String>> = HashMap::new();

    for a in &daemons {
        if let Some(ref out) = a.output_topic {
            for b in &daemons {
                if a.name == b.name { continue; }
                if let Some(ref trig) = b.trigger_topic {
                    if trig == out {
                        edges.push((a.name.clone(), b.name.clone(), out.clone()));
                        downstream.entry(a.name.clone()).or_default().push(b.name.clone());
                        upstream.entry(b.name.clone()).or_default().push(a.name.clone());
                    }
                }
            }
        }
    }

    assert_eq!(edges.len(), 2); // Ingest→Transform, Transform→Export
    assert_eq!(edges[0], ("Ingest".into(), "Transform".into(), "data.ingested".into()));
    assert_eq!(edges[1], ("Transform".into(), "Export".into(), "data.transformed".into()));

    // Roots: daemons with no upstream
    let roots: Vec<&str> = daemons.iter()
        .filter(|d| !upstream.contains_key(&d.name))
        .map(|d| d.name.as_str())
        .collect();
    assert_eq!(roots, vec!["Ingest"]);

    // Leaves: daemons with no downstream
    let leaves: Vec<&str> = daemons.iter()
        .filter(|d| !downstream.contains_key(&d.name))
        .map(|d| d.name.as_str())
        .collect();
    assert_eq!(leaves, vec!["Export"]);
}

#[test]
fn daemon_dependency_fan_out_and_depth() {
    use axon::axon_server::{DaemonInfo, DaemonState};
    use std::collections::{HashMap, VecDeque};

    // Fan-out: Source → [Analyzer, Logger, Archiver]
    let daemons = vec![
        DaemonInfo { name: "Source".into(), state: DaemonState::Idle, source_file: "s.axon".into(), flow_name: "Source".into(), event_count: 0, restart_count: 0, trigger_topic: None, output_topic: Some("events.new".into()), lifecycle_events: Vec::new() },
        DaemonInfo { name: "Analyzer".into(), state: DaemonState::Idle, source_file: "a.axon".into(), flow_name: "Analyzer".into(), event_count: 0, restart_count: 0, trigger_topic: Some("events.new".into()), output_topic: None, lifecycle_events: Vec::new() },
        DaemonInfo { name: "Logger".into(), state: DaemonState::Idle, source_file: "l.axon".into(), flow_name: "Logger".into(), event_count: 0, restart_count: 0, trigger_topic: Some("events.new".into()), output_topic: None, lifecycle_events: Vec::new() },
        DaemonInfo { name: "Archiver".into(), state: DaemonState::Idle, source_file: "r.axon".into(), flow_name: "Archiver".into(), event_count: 0, restart_count: 0, trigger_topic: Some("events.new".into()), output_topic: None, lifecycle_events: Vec::new() },
    ];

    let mut downstream: HashMap<String, Vec<String>> = HashMap::new();
    let mut upstream: HashMap<String, Vec<String>> = HashMap::new();

    for a in &daemons {
        if let Some(ref out) = a.output_topic {
            for b in &daemons {
                if a.name == b.name { continue; }
                if let Some(ref trig) = b.trigger_topic {
                    if trig == out {
                        downstream.entry(a.name.clone()).or_default().push(b.name.clone());
                        upstream.entry(b.name.clone()).or_default().push(a.name.clone());
                    }
                }
            }
        }
    }

    // Source fans out to 3
    assert_eq!(downstream.get("Source").unwrap().len(), 3);

    // Compute depth via BFS
    let roots: Vec<String> = daemons.iter()
        .filter(|d| !upstream.contains_key(&d.name))
        .map(|d| d.name.clone())
        .collect();
    assert_eq!(roots, vec!["Source"]);

    let mut depth_map: HashMap<String, u32> = HashMap::new();
    let mut queue: VecDeque<(String, u32)> = VecDeque::new();
    for r in &roots {
        queue.push_back((r.clone(), 0));
        depth_map.insert(r.clone(), 0);
    }
    while let Some((name, depth)) = queue.pop_front() {
        if let Some(children) = downstream.get(&name) {
            for child in children {
                if !depth_map.contains_key(child) {
                    depth_map.insert(child.clone(), depth + 1);
                    queue.push_back((child.clone(), depth + 1));
                }
            }
        }
    }

    assert_eq!(*depth_map.get("Source").unwrap(), 0);
    assert_eq!(*depth_map.get("Analyzer").unwrap(), 1);
    assert_eq!(*depth_map.get("Logger").unwrap(), 1);
    assert_eq!(*depth_map.get("Archiver").unwrap(), 1);
    assert_eq!(depth_map.values().copied().max().unwrap(), 1);
}

#[test]
fn daemon_dependency_no_chains_empty_graph() {
    use axon::axon_server::{DaemonInfo, DaemonState};
    use std::collections::HashMap;

    // Daemons with no output topics → no edges
    let daemons = vec![
        DaemonInfo { name: "Worker1".into(), state: DaemonState::Idle, source_file: "w.axon".into(), flow_name: "Worker1".into(), event_count: 0, restart_count: 0, trigger_topic: Some("work".into()), output_topic: None, lifecycle_events: Vec::new() },
        DaemonInfo { name: "Worker2".into(), state: DaemonState::Idle, source_file: "w.axon".into(), flow_name: "Worker2".into(), event_count: 0, restart_count: 0, trigger_topic: Some("work".into()), output_topic: None, lifecycle_events: Vec::new() },
        DaemonInfo { name: "Manual".into(), state: DaemonState::Idle, source_file: "m.axon".into(), flow_name: "Manual".into(), event_count: 0, restart_count: 0, trigger_topic: None, output_topic: None, lifecycle_events: Vec::new() },
    ];

    let mut edges: Vec<(String, String)> = Vec::new();
    let mut upstream: HashMap<String, Vec<String>> = HashMap::new();
    let mut downstream: HashMap<String, Vec<String>> = HashMap::new();

    for a in &daemons {
        if let Some(ref out) = a.output_topic {
            for b in &daemons {
                if a.name == b.name { continue; }
                if let Some(ref trig) = b.trigger_topic {
                    if trig == out {
                        edges.push((a.name.clone(), b.name.clone()));
                        downstream.entry(a.name.clone()).or_default().push(b.name.clone());
                        upstream.entry(b.name.clone()).or_default().push(a.name.clone());
                    }
                }
            }
        }
    }

    assert_eq!(edges.len(), 0);

    // All daemons are roots (no upstream) and leaves (no downstream)
    let roots: Vec<&str> = daemons.iter()
        .filter(|d| !upstream.contains_key(&d.name))
        .map(|d| d.name.as_str())
        .collect();
    assert_eq!(roots.len(), 3);

    let leaves: Vec<&str> = daemons.iter()
        .filter(|d| !downstream.contains_key(&d.name))
        .map(|d| d.name.as_str())
        .collect();
    assert_eq!(leaves.len(), 3);

    // Empty daemons
    let empty: Vec<DaemonInfo> = Vec::new();
    assert_eq!(empty.len(), 0);
}

