#[test]
fn audit_export_jsonl_format() {
    use axon::audit_trail::{AuditLog, AuditAction};

    let mut log = AuditLog::new(100);
    log.record("admin", AuditAction::Deploy, "FlowA", serde_json::json!({"version": 1}), true);
    log.record("user1", AuditAction::Execute, "FlowA", serde_json::json!({"trace": 42}), true);
    log.record("admin", AuditAction::ConfigUpdate, "rate_limit", serde_json::json!({"max": 200}), true);

    let entries = log.query(100, None);
    assert_eq!(entries.len(), 3);

    // Build JSONL
    let mut jsonl = String::new();
    for e in &entries {
        let line = serde_json::json!({
            "id": e.id,
            "timestamp": e.timestamp,
            "actor": e.actor,
            "action": e.action.as_str(),
            "target": e.target,
            "success": e.success,
            "detail": e.detail,
        });
        jsonl.push_str(&serde_json::to_string(&line).unwrap());
        jsonl.push('\n');
    }

    let lines: Vec<&str> = jsonl.trim().split('\n').collect();
    assert_eq!(lines.len(), 3);

    // Each line is valid JSON
    for line in &lines {
        let parsed: serde_json::Value = serde_json::from_str(line).unwrap();
        assert!(parsed["id"].is_number());
        assert!(parsed["actor"].is_string());
        assert!(parsed["action"].is_string());
        assert!(parsed["success"].is_boolean());
    }

    // Most recent first (query returns rev order)
    let first: serde_json::Value = serde_json::from_str(lines[0]).unwrap();
    assert_eq!(first["action"], "config_update");
}

#[test]
fn audit_export_csv_format() {
    use axon::audit_trail::{AuditLog, AuditAction};

    let mut log = AuditLog::new(100);
    log.record("admin", AuditAction::Deploy, "Pipeline", serde_json::json!({"file": "p.axon"}), true);
    log.record("system", AuditAction::ServerShutdown, "server", serde_json::json!({}), true);

    let entries = log.query(100, None);

    // Build CSV
    let mut csv = String::from("id,timestamp,actor,action,target,success,detail\n");
    for e in &entries {
        let detail_str = serde_json::to_string(&e.detail).unwrap().replace('"', "\"\"");
        csv.push_str(&format!(
            "{},{},{},{},{},{},\"{}\"\n",
            e.id, e.timestamp, e.actor, e.action.as_str(), e.target, e.success, detail_str
        ));
    }

    let lines: Vec<&str> = csv.trim().split('\n').collect();
    assert_eq!(lines.len(), 3); // header + 2 entries
    assert_eq!(lines[0], "id,timestamp,actor,action,target,success,detail");

    // Verify data rows contain expected fields
    assert!(lines[1].contains("server_shutdown"));
    assert!(lines[2].contains("deploy"));
    assert!(lines[2].contains("Pipeline"));
}

#[test]
fn audit_export_date_range_filter() {
    use axon::audit_trail::{AuditLog, AuditAction};

    let mut log = AuditLog::new(100);

    // Record entries — timestamps are auto-set to now
    let id1 = log.record("a", AuditAction::Deploy, "F1", serde_json::json!({}), true);
    let id2 = log.record("b", AuditAction::Execute, "F2", serde_json::json!({}), true);
    let id3 = log.record("c", AuditAction::ConfigUpdate, "cfg", serde_json::json!({}), true);

    assert!(id1 > 0);
    assert!(id2 > 0);
    assert!(id3 > 0);

    let entries = log.query(100, None);
    assert_eq!(entries.len(), 3);

    // All entries have same timestamp (same second)
    let ts = entries[0].timestamp;

    // Filter: from = ts (should include all), to = ts (should include all)
    let filtered: Vec<_> = entries.iter()
        .filter(|e| e.timestamp >= ts && e.timestamp <= ts)
        .collect();
    assert_eq!(filtered.len(), 3);

    // Filter: from = ts + 1 (should exclude all since they're at ts)
    let filtered_none: Vec<_> = entries.iter()
        .filter(|e| e.timestamp >= ts + 1)
        .collect();
    assert_eq!(filtered_none.len(), 0);

    // Filter: to = ts - 1 (should exclude all)
    let filtered_before: Vec<_> = entries.iter()
        .filter(|e| e.timestamp <= ts.saturating_sub(1))
        .collect();
    assert_eq!(filtered_before.len(), 0);
}

// ── D84 — Server Uptime Metrics ─────────────────────────────────────

#[test]
fn server_uptime_formatting() {
    // Test uptime formatting logic
    let test_cases: Vec<(u64, &str)> = vec![
        (0, "0d 0h 0m 0s"),
        (59, "0d 0h 0m 59s"),
        (3600, "0d 1h 0m 0s"),
        (86400, "1d 0h 0m 0s"),
        (90061, "1d 1h 1m 1s"),
        (172800 + 7200 + 180 + 5, "2d 2h 3m 5s"),
    ];

    for (secs, expected) in test_cases {
        let days = secs / 86400;
        let hours = (secs % 86400) / 3600;
        let minutes = (secs % 3600) / 60;
        let s = secs % 60;
        let formatted = format!("{}d {}h {}m {}s", days, hours, minutes, s);
        assert_eq!(formatted, expected, "Failed for {} secs", secs);
    }
}

#[test]
fn server_uptime_hourly_buckets() {
    // Test hourly bucket computation
    let uptime_secs = 7500u64; // 2h 5m

    let total_hours = (uptime_secs as f64 / 3600.0).ceil() as u64;
    assert_eq!(total_hours, 3); // ceil(7500/3600) = 3

    let buckets: Vec<(u64, u64, f64)> = (0..total_hours.min(24)).map(|h| {
        let bucket_start = h * 3600;
        let bucket_end = ((h + 1) * 3600).min(uptime_secs);
        let bucket_duration = bucket_end.saturating_sub(bucket_start);
        let pct = (bucket_duration as f64 / 3600.0 * 100.0).min(100.0);
        (h, bucket_duration, pct)
    }).collect();

    assert_eq!(buckets.len(), 3);

    // Hour 0: full 3600s = 100%
    assert_eq!(buckets[0].1, 3600);
    assert!((buckets[0].2 - 100.0).abs() < 0.01);

    // Hour 1: full 3600s = 100%
    assert_eq!(buckets[1].1, 3600);
    assert!((buckets[1].2 - 100.0).abs() < 0.01);

    // Hour 2: partial 300s = 8.33%
    assert_eq!(buckets[2].1, 300);
    assert!((buckets[2].2 - 8.33).abs() < 0.1);
}

