// ── D85 — Event Bus Replay ──────────────────────────────────────────

#[test]
fn event_bus_history_recording() {
    use axon::event_bus::EventBus;

    let bus = EventBus::new();

    // Publish several events
    bus.publish("deploy", serde_json::json!({"flow": "A"}), "server");
    bus.publish("deploy", serde_json::json!({"flow": "B"}), "server");
    bus.publish("daemon.started", serde_json::json!({"name": "w1"}), "supervisor");
    bus.publish("flow.complete", serde_json::json!({"id": 1}), "runner");

    // Check history
    let history = bus.recent_events(10, None);
    assert_eq!(history.len(), 4);
    // Newest first
    assert_eq!(history[0].topic, "flow.complete");
    assert_eq!(history[3].topic, "deploy");

    // Filter by topic
    let deploys = bus.recent_events(10, Some("deploy"));
    assert_eq!(deploys.len(), 2);
    assert!(deploys.iter().all(|e| e.topic == "deploy"));

    // Filter by prefix
    let daemon_events = bus.recent_events(10, Some("daemon.*"));
    assert_eq!(daemon_events.len(), 1);
    assert_eq!(daemon_events[0].topic, "daemon.started");

    // Wildcard
    let all = bus.recent_events(10, Some("*"));
    assert_eq!(all.len(), 4);

    // Limit
    let limited = bus.recent_events(2, None);
    assert_eq!(limited.len(), 2);
}

#[test]
fn event_bus_history_cap_at_200() {
    use axon::event_bus::EventBus;

    let bus = EventBus::new();

    // Publish 210 events
    for i in 0..210 {
        bus.publish("test", serde_json::json!({"i": i}), "test");
    }

    let stats = bus.stats();
    assert_eq!(stats.events_published, 210);
    assert_eq!(stats.event_history.len(), 200); // capped

    // Oldest events evicted — first event should be i=10
    assert_eq!(stats.event_history[0].payload["i"], 10);
    assert_eq!(stats.event_history[199].payload["i"], 209);
}

#[test]
fn event_bus_replay_re_publishes() {
    use axon::event_bus::EventBus;

    let bus = EventBus::new();

    // Publish original events
    bus.publish("data.new", serde_json::json!({"record": 1}), "ingest");
    bus.publish("data.new", serde_json::json!({"record": 2}), "ingest");
    bus.publish("alert.fired", serde_json::json!({"level": "warning"}), "monitor");

    assert_eq!(bus.stats().events_published, 3);

    // Get events matching "data.new" for replay
    let to_replay = bus.recent_events(10, Some("data.new"));
    assert_eq!(to_replay.len(), 2);

    // Re-publish (simulating replay)
    for ev in &to_replay {
        bus.publish(&ev.topic, ev.payload.clone(), &format!("replay:{}", ev.source));
    }

    // Total published should now be 5
    assert_eq!(bus.stats().events_published, 5);

    // History should have 5 events
    let history = bus.recent_events(10, None);
    assert_eq!(history.len(), 5);

    // Replayed events have "replay:" prefix in source
    let replayed = bus.recent_events(10, Some("data.new"));
    assert_eq!(replayed.len(), 4); // 2 original + 2 replayed
    let replay_sources: Vec<&str> = replayed.iter()
        .filter(|e| e.source.starts_with("replay:"))
        .map(|e| e.source.as_str())
        .collect();
    assert_eq!(replay_sources.len(), 2);
}

// ── D86 — Flow Execution Queue ──────────────────────────────────────

#[test]
fn execution_queue_priority_ordering() {
    use axon::axon_server::QueuedExecution;

    let mut queue: Vec<QueuedExecution> = Vec::new();

    // Enqueue items with different priorities
    let items = vec![
        ("FlowC", "stub", 5u32, "user1"),
        ("FlowA", "stub", 1, "admin"),
        ("FlowD", "stub", 8, "user2"),
        ("FlowB", "stub", 3, "user1"),
        ("FlowE", "stub", 1, "admin"), // same priority as FlowA, should come after
    ];

    let mut next_id = 1u64;
    for (flow, backend, priority, client) in &items {
        let item = QueuedExecution {
            id: next_id,
            flow_name: flow.to_string(),
            backend: backend.to_string(),
            priority: *priority,
            client_key: client.to_string(),
            enqueued_at: 1000 + next_id,
            status: "pending".into(),
        };
        next_id += 1;

        // Insert sorted by priority
        let pos = queue.iter().position(|q| q.priority > *priority)
            .unwrap_or(queue.len());
        queue.insert(pos, item);
    }

    assert_eq!(queue.len(), 5);

    // Priority order: 1, 1, 3, 5, 8
    assert_eq!(queue[0].flow_name, "FlowA"); // priority 1, first
    assert_eq!(queue[1].flow_name, "FlowE"); // priority 1, second (FIFO within same)
    assert_eq!(queue[2].flow_name, "FlowB"); // priority 3
    assert_eq!(queue[3].flow_name, "FlowC"); // priority 5
    assert_eq!(queue[4].flow_name, "FlowD"); // priority 8
}

#[test]
fn execution_queue_dequeue_takes_highest_priority() {
    use axon::axon_server::QueuedExecution;

    let mut queue: Vec<QueuedExecution> = vec![
        QueuedExecution { id: 1, flow_name: "Low".into(), backend: "stub".into(), priority: 8, client_key: "k".into(), enqueued_at: 100, status: "pending".into() },
        QueuedExecution { id: 2, flow_name: "High".into(), backend: "stub".into(), priority: 1, client_key: "k".into(), enqueued_at: 200, status: "pending".into() },
        QueuedExecution { id: 3, flow_name: "Med".into(), backend: "stub".into(), priority: 5, client_key: "k".into(), enqueued_at: 300, status: "pending".into() },
    ];

    // Sort by priority (lower = higher priority)
    queue.sort_by_key(|q| q.priority);

    // Dequeue = take first pending
    let next = queue.iter_mut().find(|q| q.status == "pending").unwrap();
    assert_eq!(next.flow_name, "High");
    assert_eq!(next.priority, 1);
    next.status = "processing".into();

    // Next dequeue
    let next = queue.iter_mut().find(|q| q.status == "pending").unwrap();
    assert_eq!(next.flow_name, "Med");
    assert_eq!(next.priority, 5);
    next.status = "processing".into();

    // Next dequeue
    let next = queue.iter_mut().find(|q| q.status == "pending").unwrap();
    assert_eq!(next.flow_name, "Low");
    next.status = "processing".into();

    // Queue empty of pending
    assert!(queue.iter().find(|q| q.status == "pending").is_none());
    assert_eq!(queue.iter().filter(|q| q.status == "processing").count(), 3);
}

#[test]
fn execution_queue_cap_and_serialization() {
    use axon::axon_server::QueuedExecution;

    let mut queue: Vec<QueuedExecution> = Vec::new();

    // Fill to 105 items
    for i in 0..105 {
        queue.push(QueuedExecution {
            id: i + 1,
            flow_name: format!("Flow{}", i),
            backend: "stub".into(),
            priority: 5,
            client_key: "k".into(),
            enqueued_at: 1000 + i,
            status: "pending".into(),
        });
    }

    // Cap at 100
    if queue.len() > 100 {
        queue.truncate(100);
    }
    assert_eq!(queue.len(), 100);

    // Serialization
    let json = serde_json::to_value(&queue[0]).unwrap();
    assert_eq!(json["id"], 1);
    assert_eq!(json["flow_name"], "Flow0");
    assert_eq!(json["priority"], 5);
    assert_eq!(json["status"], "pending");
    assert!(json["enqueued_at"].is_number());
    assert!(json["client_key"].is_string());
}

