// ── D90 — Cost Budget Alerts ────────────────────────────────────────

#[test]
fn cost_budget_set_and_check() {
    use axon::axon_server::{CostBudget, CostAlert, FlowCostSummary};

    let mut budgets: std::collections::HashMap<String, CostBudget> = std::collections::HashMap::new();

    // Set budgets
    budgets.insert("FlowA".into(), CostBudget { max_cost_usd: 10.0, warn_threshold: 0.8 });
    budgets.insert("FlowB".into(), CostBudget { max_cost_usd: 5.0, warn_threshold: 0.9 });

    assert_eq!(budgets.len(), 2);
    assert_eq!(budgets["FlowA"].max_cost_usd, 10.0);
    assert_eq!(budgets["FlowB"].warn_threshold, 0.9);

    // Simulate costs
    let costs = vec![
        FlowCostSummary { flow_name: "FlowA".into(), executions: 100, total_input_tokens: 1000000, total_output_tokens: 500000, estimated_cost_usd: 8.5 },
        FlowCostSummary { flow_name: "FlowB".into(), executions: 50, total_input_tokens: 500000, total_output_tokens: 200000, estimated_cost_usd: 6.0 },
        FlowCostSummary { flow_name: "FlowC".into(), executions: 10, total_input_tokens: 100000, total_output_tokens: 50000, estimated_cost_usd: 0.5 },
    ];

    // Check alerts
    let mut alerts: Vec<CostAlert> = Vec::new();
    for (flow_name, budget) in &budgets {
        let current_cost = costs.iter()
            .find(|c| &c.flow_name == flow_name)
            .map(|c| c.estimated_cost_usd)
            .unwrap_or(0.0);
        let usage_pct = if budget.max_cost_usd > 0.0 { current_cost / budget.max_cost_usd } else { 0.0 };

        if usage_pct >= 1.0 {
            alerts.push(CostAlert { flow_name: flow_name.clone(), current_cost_usd: current_cost, budget_usd: budget.max_cost_usd, usage_pct, level: "exceeded".into() });
        } else if usage_pct >= budget.warn_threshold {
            alerts.push(CostAlert { flow_name: flow_name.clone(), current_cost_usd: current_cost, budget_usd: budget.max_cost_usd, usage_pct, level: "warning".into() });
        }
    }

    assert_eq!(alerts.len(), 2);
    // FlowA: 8.5/10.0 = 0.85 >= 0.8 → warning
    let a_alert = alerts.iter().find(|a| a.flow_name == "FlowA").unwrap();
    assert_eq!(a_alert.level, "warning");
    assert!((a_alert.usage_pct - 0.85).abs() < 0.01);

    // FlowB: 6.0/5.0 = 1.2 >= 1.0 → exceeded
    let b_alert = alerts.iter().find(|a| a.flow_name == "FlowB").unwrap();
    assert_eq!(b_alert.level, "exceeded");
    assert!(b_alert.usage_pct > 1.0);
}

#[test]
fn cost_budget_no_alerts_under_threshold() {
    use axon::axon_server::{CostBudget, FlowCostSummary};

    let mut budgets: std::collections::HashMap<String, CostBudget> = std::collections::HashMap::new();
    budgets.insert("FlowA".into(), CostBudget { max_cost_usd: 100.0, warn_threshold: 0.8 });

    let costs = vec![
        FlowCostSummary { flow_name: "FlowA".into(), executions: 10, total_input_tokens: 10000, total_output_tokens: 5000, estimated_cost_usd: 0.5 },
    ];

    let mut alerts = Vec::new();
    for (flow_name, budget) in &budgets {
        let current = costs.iter().find(|c| &c.flow_name == flow_name).map(|c| c.estimated_cost_usd).unwrap_or(0.0);
        let pct = current / budget.max_cost_usd;
        if pct >= 1.0 { alerts.push("exceeded"); }
        else if pct >= budget.warn_threshold { alerts.push("warning"); }
    }

    // 0.5/100 = 0.005 → well under 0.8 threshold
    assert_eq!(alerts.len(), 0);

    // Flow with no cost data → no alert
    budgets.insert("FlowZ".into(), CostBudget { max_cost_usd: 50.0, warn_threshold: 0.9 });
    let z_cost = costs.iter().find(|c| c.flow_name == "FlowZ").map(|c| c.estimated_cost_usd).unwrap_or(0.0);
    assert_eq!(z_cost, 0.0);
    let z_pct = z_cost / 50.0;
    assert!(z_pct < 0.9); // no alert
}

#[test]
fn cost_budget_serialization_and_delete() {
    use axon::axon_server::{CostBudget, CostAlert};

    // Serialization
    let budget = CostBudget { max_cost_usd: 25.0, warn_threshold: 0.75 };
    let json = serde_json::to_value(&budget).unwrap();
    assert_eq!(json["max_cost_usd"], 25.0);
    assert_eq!(json["warn_threshold"], 0.75);

    // Deserialization
    let parsed: CostBudget = serde_json::from_value(serde_json::json!({
        "max_cost_usd": 50.0,
        "warn_threshold": 0.9
    })).unwrap();
    assert_eq!(parsed.max_cost_usd, 50.0);

    // Alert serialization
    let alert = CostAlert {
        flow_name: "Pipeline".into(),
        current_cost_usd: 42.5,
        budget_usd: 50.0,
        usage_pct: 0.85,
        level: "warning".into(),
    };
    let aj = serde_json::to_value(&alert).unwrap();
    assert_eq!(aj["flow_name"], "Pipeline");
    assert_eq!(aj["level"], "warning");
    assert_eq!(aj["usage_pct"], 0.85);

    // Delete budget
    let mut budgets: std::collections::HashMap<String, CostBudget> = std::collections::HashMap::new();
    budgets.insert("X".into(), CostBudget { max_cost_usd: 10.0, warn_threshold: 0.8 });
    assert_eq!(budgets.len(), 1);
    budgets.remove("X");
    assert_eq!(budgets.len(), 0);
}

