#[test]
fn dashboard_subsystem_aggregation() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, build_trace};
    use axon::event_bus::EventBus;
    use axon::axon_server::{CostPricing, ScheduleEntry, QueuedExecution};
    use std::collections::HashMap;

    // Traces subsystem
    let mut store = TraceStore::new(TraceStoreConfig {
        enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0,
    });
    for _ in 0..5 {
        store.record(build_trace("Flow", "f.axon", "stub", "k", TraceStatus::Success, 2, 100));
    }
    let stats = store.stats();
    assert_eq!(stats.buffered, 5);
    assert_eq!(stats.avg_latency_ms, 100);

    // Event bus subsystem
    let bus = EventBus::new();
    bus.publish("test.a", serde_json::json!({}), "src");
    bus.publish("test.b", serde_json::json!({}), "src");
    let bus_stats = bus.stats();
    assert_eq!(bus_stats.events_published, 2);
    assert_eq!(bus_stats.topics_seen.len(), 2);

    // Schedule subsystem
    let mut schedules: HashMap<String, ScheduleEntry> = HashMap::new();
    schedules.insert("s1".into(), ScheduleEntry {
        flow_name: "Flow".into(), interval_secs: 60, enabled: true, backend: "stub".into(),
        last_run: 0, next_run: 60, run_count: 10, error_count: 1, history: Vec::new(),
    });
    let enabled = schedules.values().filter(|e| e.enabled).count();
    assert_eq!(enabled, 1);

    // Queue subsystem
    let queue = vec![
        QueuedExecution { id: 1, flow_name: "A".into(), backend: "stub".into(), priority: 1, client_key: "k".into(), enqueued_at: 100, status: "pending".into() },
        QueuedExecution { id: 2, flow_name: "B".into(), backend: "stub".into(), priority: 2, client_key: "k".into(), enqueued_at: 200, status: "processing".into() },
        QueuedExecution { id: 3, flow_name: "C".into(), backend: "stub".into(), priority: 3, client_key: "k".into(), enqueued_at: 300, status: "completed".into() },
    ];
    let pending = queue.iter().filter(|q| q.status == "pending").count();
    let processing = queue.iter().filter(|q| q.status == "processing").count();
    assert_eq!(pending, 1);
    assert_eq!(processing, 1);
}

