// ── D94 — Request Log Export ────────────────────────────────────────

#[test]
fn request_log_export_jsonl() {
    use axon::request_log::{RequestLogger, RequestLogConfig};
    use std::time::Duration;

    let mut logger = RequestLogger::new(RequestLogConfig::default_config());
    logger.record("GET", "/v1/health", 200, Duration::from_millis(5), "admin");
    logger.record("POST", "/v1/deploy", 201, Duration::from_millis(120), "admin");
    logger.record("GET", "/v1/traces", 200, Duration::from_millis(15), "user1");
    logger.record("POST", "/v1/execute", 500, Duration::from_millis(200), "user2");

    let entries = logger.recent(100, None);
    assert_eq!(entries.len(), 4);

    // Build JSONL
    let mut jsonl = String::new();
    for e in &entries {
        let line = serde_json::json!({
            "timestamp": e.timestamp, "method": e.method, "path": e.path,
            "status": e.status, "latency_us": e.latency_us, "client_key": e.client_key,
        });
        jsonl.push_str(&serde_json::to_string(&line).unwrap());
        jsonl.push('\n');
    }

    let lines: Vec<&str> = jsonl.trim().split('\n').collect();
    assert_eq!(lines.len(), 4);

    // Each line is valid JSON
    for line in &lines {
        let parsed: serde_json::Value = serde_json::from_str(line).unwrap();
        assert!(parsed["method"].is_string());
        assert!(parsed["path"].is_string());
        assert!(parsed["status"].is_number());
    }
}

#[test]
fn request_log_export_csv_with_filtering() {
    use axon::request_log::{RequestLogger, RequestLogConfig};
    use std::time::Duration;

    let mut logger = RequestLogger::new(RequestLogConfig::default_config());
    logger.record("GET", "/v1/health", 200, Duration::from_millis(3), "k1");
    logger.record("POST", "/v1/deploy", 201, Duration::from_millis(100), "k1");
    logger.record("GET", "/v1/traces", 200, Duration::from_millis(10), "k2");
    logger.record("GET", "/v1/metrics", 403, Duration::from_millis(1), "k3");
    logger.record("POST", "/v1/execute", 500, Duration::from_millis(200), "k2");

    let entries = logger.recent(100, None);

    // Filter: method = GET
    let get_entries: Vec<_> = entries.iter()
        .filter(|e| e.method.eq_ignore_ascii_case("GET"))
        .collect();
    assert_eq!(get_entries.len(), 3);

    // Filter: path prefix = /v1/trace
    let trace_entries: Vec<_> = entries.iter()
        .filter(|e| e.path.starts_with("/v1/trace"))
        .collect();
    assert_eq!(trace_entries.len(), 1);

    // Filter: min_status = 400
    let error_entries: Vec<_> = entries.iter()
        .filter(|e| e.status >= 400)
        .collect();
    assert_eq!(error_entries.len(), 2); // 403 + 500

    // Build CSV from error entries
    let mut csv = String::from("timestamp,method,path,status,latency_us,client_key\n");
    for e in &error_entries {
        csv.push_str(&format!(
            "{},{},{},{},{},{}\n",
            e.timestamp, e.method, e.path, e.status, e.latency_us, e.client_key
        ));
    }
    let lines: Vec<&str> = csv.trim().split('\n').collect();
    assert_eq!(lines.len(), 3); // header + 2 entries
    assert_eq!(lines[0], "timestamp,method,path,status,latency_us,client_key");
}

#[test]
fn request_log_export_empty_and_combined_filters() {
    use axon::request_log::{RequestLogger, RequestLogConfig};
    use std::time::Duration;

    // Empty logger
    let logger = RequestLogger::new(RequestLogConfig::default_config());
    let entries = logger.recent(100, None);
    assert_eq!(entries.len(), 0);

    // Combined filters
    let mut logger = RequestLogger::new(RequestLogConfig::default_config());
    logger.record("GET", "/v1/traces", 200, Duration::from_millis(10), "admin");
    logger.record("GET", "/v1/traces/1", 200, Duration::from_millis(5), "admin");
    logger.record("POST", "/v1/traces/1/replay", 200, Duration::from_millis(100), "admin");
    logger.record("GET", "/v1/health", 200, Duration::from_millis(2), "anon");
    logger.record("GET", "/v1/traces", 500, Duration::from_millis(50), "user");

    let entries = logger.recent(100, None);

    // Combined: method=GET AND path_prefix=/v1/traces AND min_status=200
    let combined: Vec<_> = entries.iter()
        .filter(|e| e.method == "GET" && e.path.starts_with("/v1/traces") && e.status >= 200)
        .collect();
    assert_eq!(combined.len(), 3); // traces(200), traces/1(200), traces(500)

    // Combined: method=GET AND path_prefix=/v1/traces AND min_status=400
    let errors: Vec<_> = entries.iter()
        .filter(|e| e.method == "GET" && e.path.starts_with("/v1/traces") && e.status >= 400)
        .collect();
    assert_eq!(errors.len(), 1); // traces(500)
}

