#[test]
fn sandbox_limits_structure() {
    use axon::axon_server::{SandboxLimits, SandboxResult};

    let limits = SandboxLimits {
        max_steps: 50,
        timeout_ms: 5000,
        max_tokens: 10000,
    };

    let json = serde_json::to_value(&limits).unwrap();
    assert_eq!(json["max_steps"], 50);
    assert_eq!(json["timeout_ms"], 5000);
    assert_eq!(json["max_tokens"], 10000);

    // SandboxResult with no limits hit
    let result = SandboxResult {
        success: true,
        flow_name: "TestFlow".into(),
        backend: "stub".into(),
        steps_executed: 3,
        latency_ms: 100,
        tokens_input: 500,
        tokens_output: 200,
        errors: 0,
        step_names: vec!["Init".into(), "Process".into(), "Output".into()],
        limits_applied: limits.clone(),
        limits_hit: Vec::new(),
        trace_id: None,
        sandboxed: true,
    };

    let rj = serde_json::to_value(&result).unwrap();
    assert_eq!(rj["success"], true);
    assert_eq!(rj["sandboxed"], true);
    assert_eq!(rj["steps_executed"], 3);
    assert!(rj["limits_hit"].as_array().unwrap().is_empty());
    assert!(rj["trace_id"].is_null());
}

#[test]
fn sandbox_limits_hit_detection() {
    use axon::axon_server::SandboxLimits;

    let limits = SandboxLimits {
        max_steps: 10,
        timeout_ms: 1000,
        max_tokens: 5000,
    };

    // Simulate execution results exceeding limits
    let steps_executed = 15usize;
    let latency = 2000u64;
    let total_tokens = 8000u64;

    let mut limits_hit = Vec::new();
    if limits.max_steps > 0 && steps_executed > limits.max_steps {
        limits_hit.push("max_steps".to_string());
    }
    if limits.timeout_ms > 0 && latency > limits.timeout_ms {
        limits_hit.push("timeout_ms".to_string());
    }
    if limits.max_tokens > 0 && total_tokens > limits.max_tokens {
        limits_hit.push("max_tokens".to_string());
    }

    assert_eq!(limits_hit.len(), 3);
    assert!(limits_hit.contains(&"max_steps".to_string()));
    assert!(limits_hit.contains(&"timeout_ms".to_string()));
    assert!(limits_hit.contains(&"max_tokens".to_string()));

    // Under limits → no hits
    let mut ok_hits = Vec::new();
    let ok_steps = 5usize;
    let ok_latency = 500u64;
    let ok_tokens = 3000u64;
    if limits.max_steps > 0 && ok_steps > limits.max_steps { ok_hits.push("max_steps"); }
    if limits.timeout_ms > 0 && ok_latency > limits.timeout_ms { ok_hits.push("timeout_ms"); }
    if limits.max_tokens > 0 && ok_tokens > limits.max_tokens { ok_hits.push("max_tokens"); }
    assert!(ok_hits.is_empty());
}

#[test]
fn sandbox_result_with_trace_recording() {
    use axon::axon_server::{SandboxLimits, SandboxResult};

    // With trace recording enabled
    let result_with_trace = SandboxResult {
        success: true,
        flow_name: "Pipeline".into(),
        backend: "anthropic".into(),
        steps_executed: 5,
        latency_ms: 250,
        tokens_input: 1000,
        tokens_output: 500,
        errors: 0,
        step_names: vec!["A".into(), "B".into(), "C".into(), "D".into(), "E".into()],
        limits_applied: SandboxLimits { max_steps: 50, timeout_ms: 5000, max_tokens: 10000 },
        limits_hit: Vec::new(),
        trace_id: Some(42),
        sandboxed: true,
    };

    let json = serde_json::to_value(&result_with_trace).unwrap();
    assert_eq!(json["trace_id"], 42);
    assert_eq!(json["sandboxed"], true);
    assert_eq!(json["step_names"].as_array().unwrap().len(), 5);

    // Without trace recording
    let result_no_trace = SandboxResult {
        trace_id: None,
        ..result_with_trace.clone()
    };
    let json2 = serde_json::to_value(&result_no_trace).unwrap();
    assert!(json2["trace_id"].is_null());

    // Failed with limits hit
    let failed = SandboxResult {
        success: false,
        limits_hit: vec!["timeout_ms".into()],
        errors: 1,
        ..result_with_trace
    };
    let json3 = serde_json::to_value(&failed).unwrap();
    assert_eq!(json3["success"], false);
    assert_eq!(json3["limits_hit"].as_array().unwrap().len(), 1);
    assert_eq!(json3["limits_hit"][0], "timeout_ms");
}

