#[test]
fn reload_result_structure() {
    use axon::axon_server::ReloadResult;

    // Unchanged flow
    let unchanged = ReloadResult {
        flow_name: "FlowA".into(),
        source_file: "a.axon".into(),
        previous_hash: "abc123def456".into(),
        current_hash: "abc123def456".into(),
        changed: false,
        redeployed: false,
        error: None,
    };
    let json = serde_json::to_value(&unchanged).unwrap();
    assert_eq!(json["changed"], false);
    assert_eq!(json["redeployed"], false);
    assert!(json["error"].is_null());
    assert_eq!(json["previous_hash"], json["current_hash"]);

    // Changed and redeployed
    let redeployed = ReloadResult {
        flow_name: "FlowB".into(),
        source_file: "b.axon".into(),
        previous_hash: "old_hash_1234".into(),
        current_hash: "new_hash_5678".into(),
        changed: true,
        redeployed: true,
        error: None,
    };
    let json2 = serde_json::to_value(&redeployed).unwrap();
    assert_eq!(json2["changed"], true);
    assert_eq!(json2["redeployed"], true);
    assert_ne!(json2["previous_hash"], json2["current_hash"]);

    // Error reading file
    let errored = ReloadResult {
        flow_name: "FlowC".into(),
        source_file: "/nonexistent/path.axon".into(),
        previous_hash: "hash_value".into(),
        current_hash: String::new(),
        changed: false,
        redeployed: false,
        error: Some("cannot read file: No such file".into()),
    };
    let json3 = serde_json::to_value(&errored).unwrap();
    assert_eq!(json3["changed"], false);
    assert!(json3["error"].as_str().unwrap().contains("cannot read file"));
}

#[test]
fn reload_hash_comparison() {
    // FNV-1a hash matching the flow_version module's algorithm
    fn compute_hash(source: &str) -> String {
        let mut hash: u64 = 0xcbf29ce484222325;
        for byte in source.bytes() {
            hash ^= byte as u64;
            hash = hash.wrapping_mul(0x100000001b3);
        }
        format!("{:016x}", hash)[..12].to_string()
    }

    let source_v1 = "flow Analyze {\n  step Check { ask \"validate\" }\n}";
    let source_v2 = "flow Analyze {\n  step Check { ask \"validate v2\" }\n}";

    let hash_v1 = compute_hash(source_v1);
    let hash_v2 = compute_hash(source_v2);

    // Same source → same hash
    assert_eq!(hash_v1, compute_hash(source_v1));

    // Different source → different hash
    assert_ne!(hash_v1, hash_v2);

    // Hash is 12 chars
    assert_eq!(hash_v1.len(), 12);
    assert_eq!(hash_v2.len(), 12);
}

#[test]
fn reload_summary_aggregation() {
    use axon::axon_server::ReloadResult;

    let results = vec![
        ReloadResult { flow_name: "A".into(), source_file: "a.axon".into(), previous_hash: "h1".into(), current_hash: "h1".into(), changed: false, redeployed: false, error: None },
        ReloadResult { flow_name: "B".into(), source_file: "b.axon".into(), previous_hash: "h2".into(), current_hash: "h3".into(), changed: true, redeployed: true, error: None },
        ReloadResult { flow_name: "C".into(), source_file: "c.axon".into(), previous_hash: "h4".into(), current_hash: "h5".into(), changed: true, redeployed: false, error: Some("parse error".into()) },
        ReloadResult { flow_name: "D".into(), source_file: "d.axon".into(), previous_hash: "h6".into(), current_hash: String::new(), changed: false, redeployed: false, error: Some("file not found".into()) },
    ];

    let checked = results.len();
    let changed = results.iter().filter(|r| r.changed).count();
    let redeployed = results.iter().filter(|r| r.redeployed).count();
    let errors = results.iter().filter(|r| r.error.is_some()).count();

    assert_eq!(checked, 4);
    assert_eq!(changed, 2);
    assert_eq!(redeployed, 1);
    assert_eq!(errors, 2);

    // Serialization of full response
    let response = serde_json::json!({
        "checked": checked,
        "changed": changed,
        "redeployed": redeployed,
        "errors": errors,
        "results": results.iter().map(|r| serde_json::to_value(r).unwrap()).collect::<Vec<_>>(),
    });
    assert_eq!(response["checked"], 4);
    assert_eq!(response["redeployed"], 1);
    assert_eq!(response["results"].as_array().unwrap().len(), 4);
}

// ── D100 — Execution Queue Process ──────────────────────────────────

#[test]
fn queue_process_dequeues_highest_priority() {
    use axon::axon_server::QueuedExecution;

    let mut queue = vec![
        QueuedExecution { id: 1, flow_name: "Low".into(), backend: "stub".into(), priority: 8, client_key: "k".into(), enqueued_at: 100, status: "pending".into() },
        QueuedExecution { id: 2, flow_name: "High".into(), backend: "stub".into(), priority: 1, client_key: "k".into(), enqueued_at: 200, status: "pending".into() },
        QueuedExecution { id: 3, flow_name: "Med".into(), backend: "stub".into(), priority: 5, client_key: "k".into(), enqueued_at: 300, status: "pending".into() },
    ];

    // Sort by priority
    queue.sort_by_key(|q| q.priority);

    // Process = dequeue first pending + mark processing
    let next = queue.iter_mut().find(|q| q.status == "pending").unwrap();
    assert_eq!(next.flow_name, "High");
    assert_eq!(next.priority, 1);
    next.status = "processing".into();

    // After execution succeeds → completed
    let completed = queue.iter_mut().find(|q| q.id == 2).unwrap();
    completed.status = "completed".into();

    // Next process call gets Med (priority 5)
    let next2 = queue.iter_mut().find(|q| q.status == "pending").unwrap();
    assert_eq!(next2.flow_name, "Med");
    next2.status = "completed".into();

    // Next gets Low
    let next3 = queue.iter_mut().find(|q| q.status == "pending").unwrap();
    assert_eq!(next3.flow_name, "Low");
    next3.status = "completed".into();

    // No more pending
    assert!(queue.iter().find(|q| q.status == "pending").is_none());
    assert_eq!(queue.iter().filter(|q| q.status == "completed").count(), 3);
}

#[test]
fn queue_process_empty_returns_no_pending() {
    use axon::axon_server::QueuedExecution;

    // Empty queue
    let queue: Vec<QueuedExecution> = Vec::new();
    let next = queue.iter().find(|q| q.status == "pending");
    assert!(next.is_none());

    // Queue with no pending items
    let queue2 = vec![
        QueuedExecution { id: 1, flow_name: "A".into(), backend: "stub".into(), priority: 1, client_key: "k".into(), enqueued_at: 100, status: "completed".into() },
        QueuedExecution { id: 2, flow_name: "B".into(), backend: "stub".into(), priority: 2, client_key: "k".into(), enqueued_at: 200, status: "failed".into() },
        QueuedExecution { id: 3, flow_name: "C".into(), backend: "stub".into(), priority: 3, client_key: "k".into(), enqueued_at: 300, status: "processing".into() },
    ];
    let next2 = queue2.iter().find(|q| q.status == "pending");
    assert!(next2.is_none());
}

#[test]
fn queue_process_failure_marks_failed() {
    use axon::axon_server::QueuedExecution;

    let mut queue = vec![
        QueuedExecution { id: 1, flow_name: "WillFail".into(), backend: "stub".into(), priority: 1, client_key: "k".into(), enqueued_at: 100, status: "pending".into() },
        QueuedExecution { id: 2, flow_name: "WillSucceed".into(), backend: "stub".into(), priority: 2, client_key: "k".into(), enqueued_at: 200, status: "pending".into() },
    ];

    // Process first — simulate failure
    let item = queue.iter_mut().find(|q| q.status == "pending").unwrap();
    assert_eq!(item.flow_name, "WillFail");
    item.status = "processing".into();

    // Execution fails → mark failed
    let failed = queue.iter_mut().find(|q| q.id == 1).unwrap();
    failed.status = "failed".into();

    // Process second — simulate success
    let item2 = queue.iter_mut().find(|q| q.status == "pending").unwrap();
    assert_eq!(item2.flow_name, "WillSucceed");
    item2.status = "processing".into();
    let succeeded = queue.iter_mut().find(|q| q.id == 2).unwrap();
    succeeded.status = "completed".into();

    // Final state
    assert_eq!(queue[0].status, "failed");
    assert_eq!(queue[1].status, "completed");
}

