#[test]
fn dry_run_cost_estimation_logic() {
    use axon::axon_server::CostPricing;

    let pricing = CostPricing::default();

    // 5 steps → ~2500 input, ~1250 output
    let num_steps = 5u64;
    let est_tokens_per_step = 500u64;
    let est_input = est_tokens_per_step * num_steps;
    let est_output = est_input / 2;

    assert_eq!(est_input, 2500);
    assert_eq!(est_output, 1250);

    // Anthropic pricing
    let input_price = *pricing.input_per_million.get("anthropic").unwrap();
    let output_price = *pricing.output_per_million.get("anthropic").unwrap();
    let cost = (est_input as f64 / 1_000_000.0) * input_price + (est_output as f64 / 1_000_000.0) * output_price;
    // 2500/1M * 3.0 + 1250/1M * 15.0 = 0.0075 + 0.01875 = 0.02625
    assert!((cost - 0.02625).abs() < 0.001);

    // Stub pricing → zero cost
    let stub_input = *pricing.input_per_million.get("stub").unwrap();
    let stub_output = *pricing.output_per_million.get("stub").unwrap();
    let stub_cost = (est_input as f64 / 1_000_000.0) * stub_input + (est_output as f64 / 1_000_000.0) * stub_output;
    assert_eq!(stub_cost, 0.0);

    // Zero steps → zero cost
    let zero_input = 0u64;
    let zero_cost = (zero_input as f64 / 1_000_000.0) * input_price;
    assert_eq!(zero_cost, 0.0);
}

