#[test]
fn flow_validation_rules_crud() {
    use axon::axon_server::{FlowValidationRules, ValidationResult};

    // Create rules
    let rules = FlowValidationRules {
        max_steps: 10,
        required_anchors: vec!["NoHallucination".into(), "SafeOutput".into()],
        banned_tools: vec!["DangerousTool".into()],
        allowed_backends: vec!["anthropic".into(), "openai".into()],
        max_cost_usd: 5.0,
    };

    // Serialization
    let json = serde_json::to_value(&rules).unwrap();
    assert_eq!(json["max_steps"], 10);
    assert_eq!(json["required_anchors"].as_array().unwrap().len(), 2);
    assert_eq!(json["banned_tools"][0], "DangerousTool");
    assert_eq!(json["allowed_backends"].as_array().unwrap().len(), 2);
    assert_eq!(json["max_cost_usd"], 5.0);

    // Deserialization
    let parsed: FlowValidationRules = serde_json::from_value(serde_json::json!({
        "max_steps": 20,
        "banned_tools": ["eval"],
    })).unwrap();
    assert_eq!(parsed.max_steps, 20);
    assert_eq!(parsed.banned_tools, vec!["eval"]);
    assert!(parsed.required_anchors.is_empty()); // default
    assert!(parsed.allowed_backends.is_empty()); // default
    assert_eq!(parsed.max_cost_usd, 0.0); // default

    // CRUD in HashMap
    let mut rules_map: std::collections::HashMap<String, FlowValidationRules> = std::collections::HashMap::new();
    rules_map.insert("FlowA".into(), rules.clone());
    assert_eq!(rules_map.len(), 1);
    assert!(rules_map.get("FlowA").is_some());
    rules_map.remove("FlowA");
    assert!(rules_map.get("FlowA").is_none());
}

#[test]
fn flow_validation_rule_checking() {
    use axon::axon_server::FlowValidationRules;

    let rules = FlowValidationRules {
        max_steps: 5,
        required_anchors: Vec::new(),
        banned_tools: vec!["HttpTool".into(), "ShellExec".into()],
        allowed_backends: vec!["stub".into()],
        max_cost_usd: 0.0,
    };

    // Simulate validation
    let mut violations = Vec::new();

    // Check max_steps
    let step_count = 8;
    if rules.max_steps > 0 && step_count > rules.max_steps {
        violations.push(format!("step count {} exceeds max_steps {}", step_count, rules.max_steps));
    }

    // Check banned tools
    let tools_used = vec!["Calculator", "HttpTool"];
    for tool in &tools_used {
        if rules.banned_tools.iter().any(|b| b == tool) {
            violations.push(format!("uses banned tool '{}'", tool));
        }
    }

    // Check backend
    let backend = "anthropic";
    if !rules.allowed_backends.is_empty() && !rules.allowed_backends.contains(&backend.to_string()) {
        violations.push(format!("backend '{}' not allowed", backend));
    }

    assert_eq!(violations.len(), 3);
    assert!(violations[0].contains("step count 8 exceeds max_steps 5"));
    assert!(violations[1].contains("banned tool 'HttpTool'"));
    assert!(violations[2].contains("backend 'anthropic' not allowed"));
}

