// ── D116 — ΛD Epistemic Backup Compliance ───────────────────────────
//
// Certifies that ServerBackup carries full ΛD epistemic state:
//   ψ = ⟨T, V, E⟩ where E = ⟨c, τ, ρ, δ⟩
// preserving ontology, certainty, provenance, and derivation.

#[test]
fn lambda_d_epistemic_envelope_invariants() {
    use axon::axon_server::EpistemicEnvelope;

    // Raw config: c=1.0, δ=raw → valid
    let raw = EpistemicEnvelope::raw_config("config:pricing", "admin:session_42");
    assert_eq!(raw.ontology, "config:pricing");
    assert_eq!(raw.certainty, 1.0);
    assert_eq!(raw.derivation, "raw");
    assert_eq!(raw.provenance, "admin:session_42");
    assert_eq!(raw.temporal_end, "∞");
    assert!(raw.validate().is_ok());

    // Derived: c<1.0, δ=derived → valid
    let derived = EpistemicEnvelope::derived("config:computed_metric", 0.85, "system:aggregation");
    assert_eq!(derived.certainty, 0.85);
    assert_eq!(derived.derivation, "derived");
    assert!(derived.validate().is_ok());

    // Invariant 1: Ontological Rigidity (T ≠ ⊥)
    let empty_ontology = EpistemicEnvelope {
        ontology: "".into(), certainty: 0.5,
        temporal_start: "0".into(), temporal_end: "∞".into(),
        provenance: "test".into(), derivation: "raw".into(),
    };
    assert!(empty_ontology.validate().is_err());
    assert!(empty_ontology.validate().unwrap_err().contains("Ontological Rigidity"));

    // Invariant 4: Epistemic Bounding (c ∈ [0,1])
    let out_of_bounds = EpistemicEnvelope {
        ontology: "test".into(), certainty: 1.5,
        temporal_start: "0".into(), temporal_end: "∞".into(),
        provenance: "test".into(), derivation: "raw".into(),
    };
    assert!(out_of_bounds.validate().is_err());
    assert!(out_of_bounds.validate().unwrap_err().contains("Epistemic Bounding"));

    // Theorem 5.1: Epistemic Degradation (only raw may carry c=1.0)
    let degradation = EpistemicEnvelope {
        ontology: "test".into(), certainty: 1.0,
        temporal_start: "0".into(), temporal_end: "∞".into(),
        provenance: "test".into(), derivation: "derived".into(), // NOT raw!
    };
    assert!(degradation.validate().is_err());
    assert!(degradation.validate().unwrap_err().contains("Epistemic Degradation"));
}

#[test]
fn lambda_d_backup_preserves_epistemic_tensor() {
    use axon::axon_server::{ServerBackup, CostPricing, ReadinessGates, EpistemicEnvelope};
    use std::collections::HashMap;

    let mut section_prov = HashMap::new();
    section_prov.insert("cost_pricing".into(),
        EpistemicEnvelope::raw_config("config:pricing", "admin:D88"));
    section_prov.insert("readiness_gates".into(),
        EpistemicEnvelope::raw_config("config:readiness", "admin:D107"));

    let backup = ServerBackup {
        version: "1.0-ΛD".into(),
        created_at: 1700000000,
        lambda_d: EpistemicEnvelope::raw_config("axon:server_backup", "admin:D116"),
        section_provenance: section_prov,
        cost_pricing: CostPricing::default(),
        cost_budgets: HashMap::new(),
        flow_rules: HashMap::new(),
        flow_quotas: HashMap::new(),
        readiness_gates: ReadinessGates::default(),
        endpoint_rate_limits: HashMap::new(),
        schedules: Vec::new(),
        axon_stores: HashMap::new(),
        dataspaces: HashMap::new(),
        shields: HashMap::new(),
    };

    // Serialize — ψ = ⟨T, V, E⟩ preserved (NOT π_JSON(ψ) = V)
    let json = serde_json::to_value(&backup).unwrap();

    // ΛD envelope present at root level
    assert_eq!(json["version"], "1.0-ΛD");
    assert_eq!(json["lambda_d"]["ontology"], "axon:server_backup");
    assert_eq!(json["lambda_d"]["certainty"], 1.0);
    assert_eq!(json["lambda_d"]["derivation"], "raw");
    assert_eq!(json["lambda_d"]["provenance"], "admin:D116");

    // Per-section provenance preserved
    assert_eq!(json["section_provenance"]["cost_pricing"]["ontology"], "config:pricing");
    assert_eq!(json["section_provenance"]["cost_pricing"]["provenance"], "admin:D88");
    assert_eq!(json["section_provenance"]["readiness_gates"]["provenance"], "admin:D107");

    // Round-trip preserves epistemic tensor
    let json_str = serde_json::to_string(&backup).unwrap();
    let restored: ServerBackup = serde_json::from_str(&json_str).unwrap();
    assert_eq!(restored.lambda_d.ontology, "axon:server_backup");
    assert_eq!(restored.lambda_d.certainty, 1.0);
    assert_eq!(restored.section_provenance["cost_pricing"].provenance, "admin:D88");
}

#[test]
fn lambda_d_restore_validates_invariants() {
    use axon::axon_server::EpistemicEnvelope;

    // Valid envelope → ok
    let valid = EpistemicEnvelope::raw_config("axon:backup", "admin");
    assert!(valid.validate().is_ok());

    // Invalid envelope (empty ontology) → rejected at import boundary
    let invalid = EpistemicEnvelope {
        ontology: "".into(), certainty: 0.5,
        temporal_start: "0".into(), temporal_end: "∞".into(),
        provenance: "attacker".into(), derivation: "raw".into(),
    };
    let result = invalid.validate();
    assert!(result.is_err());

    // Invalid section provenance → rejected
    let bad_section = EpistemicEnvelope {
        ontology: "config:pricing".into(), certainty: 1.0,
        temporal_start: "0".into(), temporal_end: "∞".into(),
        provenance: "unknown".into(), derivation: "inferred".into(), // Theorem 5.1 violation
    };
    assert!(bad_section.validate().is_err());
    assert!(bad_section.validate().unwrap_err().contains("Epistemic Degradation"));

    // Derived with clamped certainty → valid
    let derived = EpistemicEnvelope::derived("config:metric", 0.95, "system");
    assert!(derived.validate().is_ok());
    assert!(derived.certainty < 1.0); // clamped to max 0.99

    // Negative certainty → rejected
    let neg = EpistemicEnvelope {
        ontology: "test".into(), certainty: -0.1,
        temporal_start: "0".into(), temporal_end: "∞".into(),
        provenance: "test".into(), derivation: "raw".into(),
    };
    assert!(neg.validate().is_err());
}

// ── D117 — Execution Result Caching ─────────────────────────────────

#[test]
fn execution_cache_crud_and_ttl() {
    use axon::axon_server::{CachedResult, EpistemicEnvelope};

    let mut cache: Vec<CachedResult> = Vec::new();

    let now = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap()
        .as_secs();

    // Put entry
    let entry = CachedResult {
        cache_key: "FlowA:stub".into(),
        flow_name: "FlowA".into(),
        backend: "stub".into(),
        result: serde_json::json!({"steps": 3, "output": "result"}),
        source_trace_id: 42,
        cached_at: now,
        ttl_secs: 300,
        epistemic: EpistemicEnvelope::derived("cache:execution:FlowA", 0.95, "trace:42"),
    };
    cache.push(entry);
    assert_eq!(cache.len(), 1);

    // Get — hit
    let found = cache.iter().find(|c| c.cache_key == "FlowA:stub");
    assert!(found.is_some());
    assert!(!found.unwrap().is_expired());

    // Get — miss
    let miss = cache.iter().find(|c| c.cache_key == "FlowB:stub");
    assert!(miss.is_none());

    // TTL expiry
    let expired_entry = CachedResult {
        cache_key: "Old:stub".into(),
        flow_name: "Old".into(),
        backend: "stub".into(),
        result: serde_json::json!({}),
        source_trace_id: 1,
        cached_at: now - 600, // 10 minutes ago
        ttl_secs: 300,        // 5 minute TTL
        epistemic: EpistemicEnvelope::derived("cache:execution:Old", 0.9, "trace:1"),
    };
    assert!(expired_entry.is_expired());

    // TTL=0 → never expires
    let no_expiry = CachedResult {
        cached_at: 1000, ttl_secs: 0,
        ..expired_entry.clone()
    };
    assert!(!no_expiry.is_expired());

    // Delete
    cache.retain(|c| c.cache_key != "FlowA:stub");
    assert_eq!(cache.len(), 0);
}

#[test]
fn execution_cache_lambda_d_epistemic_state() {
    use axon::axon_server::{CachedResult, EpistemicEnvelope};

    // Cached results are δ=derived, c<1.0 per Theorem 5.1
    let epistemic = EpistemicEnvelope::derived("cache:execution:Pipeline", 0.95, "trace:100");
    assert_eq!(epistemic.derivation, "derived");
    assert!(epistemic.certainty < 1.0); // Theorem 5.1 enforced
    assert!(epistemic.certainty > 0.0);
    assert!(epistemic.validate().is_ok());

    // Serialization preserves ΛD tensor
    let entry = CachedResult {
        cache_key: "Pipeline:anthropic".into(),
        flow_name: "Pipeline".into(),
        backend: "anthropic".into(),
        result: serde_json::json!({"success": true}),
        source_trace_id: 100,
        cached_at: 1700000000,
        ttl_secs: 600,
        epistemic: epistemic.clone(),
    };

    let json = serde_json::to_value(&entry).unwrap();
    assert_eq!(json["cache_key"], "Pipeline:anthropic");
    assert_eq!(json["epistemic"]["derivation"], "derived");
    assert_eq!(json["epistemic"]["ontology"], "cache:execution:Pipeline");
    assert!(json["epistemic"]["certainty"].as_f64().unwrap() < 1.0);
    assert_eq!(json["epistemic"]["provenance"], "trace:100");
}

#[test]
fn execution_cache_cap_and_replacement() {
    use axon::axon_server::{CachedResult, EpistemicEnvelope};

    let mut cache: Vec<CachedResult> = Vec::new();

    // Fill cache
    for i in 0..5 {
        cache.push(CachedResult {
            cache_key: format!("Flow{}:stub", i),
            flow_name: format!("Flow{}", i),
            backend: "stub".into(),
            result: serde_json::json!({"i": i}),
            source_trace_id: i as u64,
            cached_at: 1700000000 + i as u64,
            ttl_secs: 300,
            epistemic: EpistemicEnvelope::derived(&format!("cache:Flow{}", i), 0.95, &format!("trace:{}", i)),
        });
    }
    assert_eq!(cache.len(), 5);

    // Replace existing key
    let key = "Flow2:stub";
    cache.retain(|c| c.cache_key != key);
    cache.push(CachedResult {
        cache_key: key.into(),
        flow_name: "Flow2".into(),
        backend: "stub".into(),
        result: serde_json::json!({"i": 2, "updated": true}),
        source_trace_id: 200,
        cached_at: 1700001000,
        ttl_secs: 600,
        epistemic: EpistemicEnvelope::derived("cache:Flow2", 0.95, "trace:200"),
    });
    assert_eq!(cache.len(), 5); // same count (replaced, not added)
    let updated = cache.iter().find(|c| c.cache_key == key).unwrap();
    assert_eq!(updated.result["updated"], true);
    assert_eq!(updated.source_trace_id, 200);

    // Cap at N (simulate 200 cap)
    // Just verify truncation logic
    let mut big_cache: Vec<u32> = (0..205).collect();
    if big_cache.len() > 200 { big_cache.drain(0..5); }
    assert_eq!(big_cache.len(), 200);
    assert_eq!(big_cache[0], 5); // oldest evicted
}

// ── D118 — Cache-Aware Execution ────────────────────────────────────

#[test]
fn cache_aware_hit_returns_derived() {
    use axon::axon_server::{CachedResult, EpistemicEnvelope};

    let now = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap()
        .as_secs();

    let cache = vec![
        CachedResult {
            cache_key: "Pipeline:stub".into(),
            flow_name: "Pipeline".into(),
            backend: "stub".into(),
            result: serde_json::json!({"steps": 3, "output": "cached result"}),
            source_trace_id: 42,
            cached_at: now,
            ttl_secs: 300,
            epistemic: EpistemicEnvelope::derived("cache:execution:Pipeline", 0.95, "trace:42"),
        },
    ];

    // Simulate cache-aware lookup
    let key = "Pipeline:stub";
    let force = false;

    if !force {
        if let Some(entry) = cache.iter().find(|c| c.cache_key == key) {
            if !entry.is_expired() {
                // Cache HIT — return derived result
                assert_eq!(entry.epistemic.derivation, "derived");
                assert!(entry.epistemic.certainty < 1.0); // Theorem 5.1
                assert_eq!(entry.result["output"], "cached result");
                assert_eq!(entry.source_trace_id, 42);
                return; // early return = cache hit
            }
        }
    }
    panic!("should have returned from cache hit");
}

#[test]
fn cache_aware_miss_executes_fresh() {
    use axon::axon_server::CachedResult;

    // Empty cache → miss
    let cache: Vec<CachedResult> = Vec::new();
    let key = "FlowA:stub";

    let hit = cache.iter().find(|c| c.cache_key == key && !c.is_expired());
    assert!(hit.is_none()); // miss → would execute fresh

    // Fresh execution result: δ=raw, c=1.0
    let fresh_result = serde_json::json!({
        "success": true,
        "cached": false,
        "epistemic": {
            "derivation": "raw",
            "certainty": 1.0,
            "note": "fresh execution",
        },
    });
    assert_eq!(fresh_result["cached"], false);
    assert_eq!(fresh_result["epistemic"]["derivation"], "raw");
    assert_eq!(fresh_result["epistemic"]["certainty"], 1.0);

    // Expired entry → also miss
    let now = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap()
        .as_secs();

    let expired_cache = vec![CachedResult {
        cache_key: "FlowA:stub".into(),
        flow_name: "FlowA".into(),
        backend: "stub".into(),
        result: serde_json::json!({}),
        source_trace_id: 1,
        cached_at: now - 600,
        ttl_secs: 300,
        epistemic: axon::axon_server::EpistemicEnvelope::derived("cache:FlowA", 0.95, "trace:1"),
    }];
    let expired_hit = expired_cache.iter().find(|c| c.cache_key == key && !c.is_expired());
    assert!(expired_hit.is_none()); // expired → miss
}

#[test]
fn cache_aware_force_bypasses_cache() {
    use axon::axon_server::{CachedResult, EpistemicEnvelope};

    let now = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap()
        .as_secs();

    let cache = vec![CachedResult {
        cache_key: "FlowA:stub".into(),
        flow_name: "FlowA".into(),
        backend: "stub".into(),
        result: serde_json::json!({"old": true}),
        source_trace_id: 10,
        cached_at: now,
        ttl_secs: 3600,
        epistemic: EpistemicEnvelope::derived("cache:FlowA", 0.95, "trace:10"),
    }];

    // Without force → cache hit
    let force = false;
    let hit_no_force = if !force {
        cache.iter().find(|c| c.cache_key == "FlowA:stub" && !c.is_expired())
    } else {
        None
    };
    assert!(hit_no_force.is_some());

    // With force → bypassed (always execute fresh)
    let force = true;
    let hit_forced = if !force {
        cache.iter().find(|c| c.cache_key == "FlowA:stub" && !c.is_expired())
    } else {
        None // force = true → skip cache
    };
    assert!(hit_forced.is_none());

    // ΛD epistemic distinction:
    // Cache hit: δ=derived, c=0.95 (stale risk)
    // Fresh exec: δ=raw, c=1.0 (ground truth)
    // Force flag lets user explicitly choose fresh (raw) over cached (derived)
}

// ── D119 — Stream Consumer API ──────────────────────────────────────

#[test]
fn stream_consumer_cursor_pagination() {
    use axon::axon_server::StreamEmitter;
    use axon::event_bus::EventBus;

    let bus = EventBus::new();

    // Emit 5 tokens for trace 300
    let mut emitter = StreamEmitter::new(300, "Pipeline");
    emitter.emit("Step1", "chunk1");
    emitter.emit("Step1", "chunk2");
    emitter.emit("Step2", "chunk3");
    emitter.emit("Step2", "chunk4");
    emitter.finalize();
    emitter.publish_to_bus(&bus);

    // Consumer polls all (after=0)
    let topic = "flow.stream.300";
    let events = bus.recent_events(500, Some(topic));
    let mut chrono: Vec<_> = events.into_iter().collect();
    chrono.reverse();

    assert_eq!(chrono.len(), 5); // 4 tokens + 1 final

    // Filter: after=0 → all
    let after_0: Vec<_> = chrono.iter()
        .filter(|ev| ev.payload.get("token_index").and_then(|v| v.as_u64()).map_or(false, |i| i > 0))
        .collect();
    assert_eq!(after_0.len(), 5);

    // Filter: after=2 → tokens 3, 4, 5 (final)
    let after_2: Vec<_> = chrono.iter()
        .filter(|ev| ev.payload.get("token_index").and_then(|v| v.as_u64()).map_or(false, |i| i > 2))
        .collect();
    assert_eq!(after_2.len(), 3);

    // Filter: after=5 → nothing (all consumed)
    let after_5: Vec<_> = chrono.iter()
        .filter(|ev| ev.payload.get("token_index").and_then(|v| v.as_u64()).map_or(false, |i| i > 5))
        .collect();
    assert_eq!(after_5.len(), 0);
}

#[test]
fn stream_consumer_output_reconstruction() {
    use axon::axon_server::StreamEmitter;
    use axon::event_bus::EventBus;

    let bus = EventBus::new();

    let mut emitter = StreamEmitter::new(400, "Analyzer");
    emitter.emit("Validate", "input");
    emitter.emit("Validate", "looks");
    emitter.emit("Validate", "good");
    emitter.emit("Generate", "the");
    emitter.emit("Generate", "result");
    emitter.emit("Generate", "is");
    emitter.emit("Generate", "42");
    emitter.finalize();
    emitter.publish_to_bus(&bus);

    let events = bus.recent_events(500, Some("flow.stream.400"));
    let mut chrono: Vec<_> = events.into_iter().collect();
    chrono.reverse();

    // Reconstruct full output
    let mut reconstructed = String::new();
    for ev in &chrono {
        let content = ev.payload.get("content").and_then(|v| v.as_str()).unwrap_or("");
        let is_final = ev.payload.get("is_final").and_then(|v| v.as_bool()).unwrap_or(false);
        if is_final { continue; }
        if !reconstructed.is_empty() && !content.is_empty() { reconstructed.push(' '); }
        reconstructed.push_str(content);
    }
    assert_eq!(reconstructed, "input looks good the result is 42");

    // Per-step reconstruction
    let mut step_outputs: Vec<(String, String)> = Vec::new();
    let mut current_step = String::new();
    let mut current_content = String::new();

    for ev in &chrono {
        let step = ev.payload.get("step_name").and_then(|v| v.as_str()).unwrap_or("");
        let content = ev.payload.get("content").and_then(|v| v.as_str()).unwrap_or("");
        let is_final = ev.payload.get("is_final").and_then(|v| v.as_bool()).unwrap_or(false);
        if is_final { continue; }
        if !step.is_empty() && step != current_step.as_str() {
            if !current_step.is_empty() { step_outputs.push((current_step.clone(), current_content.trim().to_string())); }
            current_step = step.to_string();
            current_content = String::new();
        }
        if !content.is_empty() { current_content.push(' '); current_content.push_str(content); }
    }
    if !current_step.is_empty() { step_outputs.push((current_step, current_content.trim().to_string())); }

    assert_eq!(step_outputs.len(), 2);
    assert_eq!(step_outputs[0], ("Validate".into(), "input looks good".into()));
    assert_eq!(step_outputs[1], ("Generate".into(), "the result is 42".into()));
}

#[test]
fn stream_consumer_completion_and_epistemic() {
    use axon::axon_server::StreamEmitter;
    use axon::event_bus::EventBus;

    let bus = EventBus::new();

    // Incomplete stream (no finalize)
    let mut emitter1 = StreamEmitter::new(500, "Flow");
    emitter1.emit("Step", "partial");
    emitter1.publish_to_bus(&bus);

    let events1 = bus.recent_events(50, Some("flow.stream.500"));
    let is_complete1 = events1.iter().any(|ev| {
        ev.payload.get("is_final").and_then(|v| v.as_bool()).unwrap_or(false)
    });
    assert!(!is_complete1); // not finalized → incomplete

    // Complete stream (with finalize)
    let bus2 = EventBus::new();
    let mut emitter2 = StreamEmitter::new(501, "Flow");
    emitter2.emit("Step", "done");
    emitter2.finalize(); // final token has epistemic_state="know"
    emitter2.publish_to_bus(&bus2);

    let events2 = bus2.recent_events(50, Some("flow.stream.501"));
    let is_complete2 = events2.iter().any(|ev| {
        ev.payload.get("is_final").and_then(|v| v.as_bool()).unwrap_or(false)
    });
    assert!(is_complete2);

    // Final token's epistemic state
    let final_token = events2.iter()
        .find(|ev| ev.payload.get("is_final").and_then(|v| v.as_bool()).unwrap_or(false))
        .unwrap();
    assert_eq!(final_token.payload["epistemic_state"], "know");

    // Not-found trace
    let events_none = bus2.recent_events(50, Some("flow.stream.999"));
    assert_eq!(events_none.len(), 0);
}

