#[test]
fn batch_execute_result_structure() {
    use axon::axon_server::{BatchItem, BatchItemResult};

    let items = vec![
        BatchItem { flow_name: "FlowA".into(), backend: "stub".into() },
        BatchItem { flow_name: "FlowB".into(), backend: "anthropic".into() },
        BatchItem { flow_name: "FlowC".into(), backend: "stub".into() },
    ];
    assert_eq!(items.len(), 3);

    // Simulate results
    let results = vec![
        BatchItemResult { index: 0, flow_name: "FlowA".into(), backend: "stub".into(), success: true, trace_id: 1, latency_ms: 100, tokens_input: 500, tokens_output: 200, error: None, epistemic_derivation: "raw".into() },
        BatchItemResult { index: 1, flow_name: "FlowB".into(), backend: "anthropic".into(), success: false, trace_id: 0, latency_ms: 0, tokens_input: 0, tokens_output: 0, error: Some("flow not deployed".into()), epistemic_derivation: "none".into() },
        BatchItemResult { index: 2, flow_name: "FlowC".into(), backend: "stub".into(), success: true, trace_id: 2, latency_ms: 80, tokens_input: 300, tokens_output: 150, error: None, epistemic_derivation: "raw".into() },
    ];

    let succeeded = results.iter().filter(|r| r.success).count();
    let failed = results.iter().filter(|r| !r.success).count();
    let total_tokens: u64 = results.iter().map(|r| r.tokens_input + r.tokens_output).sum();

    assert_eq!(succeeded, 2);
    assert_eq!(failed, 1);
    assert_eq!(total_tokens, 1150);

    // Serialization
    let json = serde_json::to_value(&results[0]).unwrap();
    assert_eq!(json["flow_name"], "FlowA");
    assert_eq!(json["success"], true);
    assert_eq!(json["epistemic_derivation"], "raw");
    assert!(json["error"].is_null());

    let json_fail = serde_json::to_value(&results[1]).unwrap();
    assert_eq!(json_fail["success"], false);
    assert_eq!(json_fail["error"], "flow not deployed");
}

#[test]
fn batch_execute_continue_on_failure() {
    use axon::axon_server::BatchItemResult;

    // continue_on_failure=true → all items processed
    let items = vec!["A", "B_fail", "C"];
    let mut results: Vec<BatchItemResult> = Vec::new();
    let continue_on_failure = true;

    for (idx, name) in items.iter().enumerate() {
        let success = !name.contains("fail");
        results.push(BatchItemResult {
            index: idx, flow_name: name.to_string(), backend: "stub".into(),
            success, trace_id: if success { idx as u64 + 1 } else { 0 },
            latency_ms: 100, tokens_input: 100, tokens_output: 50,
            error: if success { None } else { Some("error".into()) },
            epistemic_derivation: if success { "raw".into() } else { "none".into() },
        });
        if !success && !continue_on_failure { break; }
    }
    assert_eq!(results.len(), 3); // all processed

    // continue_on_failure=false → stops at first failure
    let mut results2: Vec<BatchItemResult> = Vec::new();
    let continue_on_failure2 = false;
    for (idx, name) in items.iter().enumerate() {
        let success = !name.contains("fail");
        results2.push(BatchItemResult {
            index: idx, flow_name: name.to_string(), backend: "stub".into(),
            success, trace_id: 0, latency_ms: 0, tokens_input: 0, tokens_output: 0,
            error: if success { None } else { Some("error".into()) },
            epistemic_derivation: "raw".into(),
        });
        if !success && !continue_on_failure2 { break; }
    }
    assert_eq!(results2.len(), 2); // stopped at B_fail
}

#[test]
fn batch_execute_validation() {
    use axon::axon_server::BatchItem;

    // Empty batch → error
    let empty: Vec<BatchItem> = Vec::new();
    assert!(empty.is_empty());

    // Max 50 items
    let large: Vec<BatchItem> = (0..55).map(|i| BatchItem {
        flow_name: format!("Flow{}", i), backend: "stub".into(),
    }).collect();
    assert!(large.len() > 50); // would be rejected

    // Valid batch
    let valid: Vec<BatchItem> = (0..10).map(|i| BatchItem {
        flow_name: format!("Flow{}", i), backend: "stub".into(),
    }).collect();
    assert!(valid.len() <= 50);
    assert!(!valid.is_empty());
}

