#[test]
fn autoscale_config_default_and_serialization() {
    use axon::axon_server::{AutoscaleConfig, AutoscaleDecision};

    let config = AutoscaleConfig::default();
    assert!(!config.enabled);
    assert_eq!(config.min_daemons, 1);
    assert_eq!(config.max_daemons, 10);
    assert_eq!(config.scale_up_queue_depth, 5);
    assert_eq!(config.scale_up_events_per_sec, 100);
    assert_eq!(config.scale_down_idle_secs, 300);

    let json = serde_json::to_value(&config).unwrap();
    assert_eq!(json["enabled"], false);
    assert_eq!(json["max_daemons"], 10);

    // Deserialization
    let custom: AutoscaleConfig = serde_json::from_value(serde_json::json!({
        "enabled": true,
        "min_daemons": 2,
        "max_daemons": 20,
        "scale_up_queue_depth": 10,
    })).unwrap();
    assert!(custom.enabled);
    assert_eq!(custom.min_daemons, 2);
    assert_eq!(custom.max_daemons, 20);
    assert_eq!(custom.scale_up_queue_depth, 10);
    assert_eq!(custom.scale_up_events_per_sec, 100); // default

    // Decision serialization
    let decision = AutoscaleDecision {
        current_daemons: 3, active_daemons: 2, queue_depth: 8,
        events_per_sec: 45.2, recommendation: "scale_up".into(),
        reason: "queue depth 8 >= threshold 5".into(),
    };
    let dj = serde_json::to_value(&decision).unwrap();
    assert_eq!(dj["recommendation"], "scale_up");
    assert_eq!(dj["queue_depth"], 8);
}

#[test]
fn autoscale_decision_logic() {
    use axon::axon_server::AutoscaleConfig;

    let cfg = AutoscaleConfig {
        enabled: true, min_daemons: 1, max_daemons: 10,
        scale_up_queue_depth: 5, scale_up_events_per_sec: 100,
        scale_down_idle_secs: 300,
    };

    // Scale up: queue depth exceeds threshold
    let queue_depth = 8usize;
    let current_daemons = 3usize;
    if cfg.enabled && current_daemons < cfg.max_daemons && queue_depth >= cfg.scale_up_queue_depth {
        assert!(true); // would recommend scale_up
    } else {
        panic!("should scale up");
    }

    // Steady: within bounds
    let queue_depth_ok = 2usize;
    let active = 2usize;
    let should_scale_up = cfg.enabled && current_daemons < cfg.max_daemons && queue_depth_ok >= cfg.scale_up_queue_depth;
    let should_scale_down = cfg.enabled && current_daemons > cfg.min_daemons && active == 0;
    assert!(!should_scale_up);
    assert!(!should_scale_down); // active > 0

    // Scale down: no active daemons, above min
    let current_5 = 5usize;
    let active_0 = 0usize;
    let scale_down = cfg.enabled && current_5 > cfg.min_daemons && active_0 == 0;
    assert!(scale_down);

    // Disabled → no recommendation
    let disabled = AutoscaleConfig { enabled: false, ..cfg };
    assert!(!disabled.enabled);
}

#[test]
fn autoscale_at_limits() {
    use axon::axon_server::AutoscaleConfig;

    let cfg = AutoscaleConfig {
        enabled: true, min_daemons: 3, max_daemons: 3,
        scale_up_queue_depth: 1, scale_up_events_per_sec: 1,
        scale_down_idle_secs: 60,
    };

    // At max → can't scale up even if threshold exceeded
    let current = 3usize;
    let can_scale_up = current < cfg.max_daemons;
    assert!(!can_scale_up);

    // At min → can't scale down even if idle
    let can_scale_down = current > cfg.min_daemons;
    assert!(!can_scale_down);

    // min == max → always steady
    assert!(!can_scale_up && !can_scale_down);
}

