#[test]
fn flow_dashboard_execution_stats() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, build_trace};
    use std::collections::HashMap;

    let mut store = TraceStore::new(TraceStoreConfig {
        enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0,
    });

    // 5 executions: 3 success, 2 with errors
    for i in 0..5 {
        let mut t = build_trace("Pipeline", "p.axon", "stub", "k", TraceStatus::Success, 3, 100 + i * 20);
        t.tokens_input = 500;
        t.tokens_output = 200;
        if i >= 3 { t.errors = 1; }
        store.record(t);
    }

    let entries = store.recent(store.len(), None);
    let flow_traces: Vec<_> = entries.iter().filter(|e| e.flow_name == "Pipeline").collect();

    assert_eq!(flow_traces.len(), 5);
    let total = flow_traces.len() as u64;
    let error_traces = flow_traces.iter().filter(|e| e.errors > 0).count() as u64;
    let error_rate = error_traces as f64 / total as f64;
    let total_tokens: u64 = flow_traces.iter().map(|e| e.tokens_input + e.tokens_output).sum();

    assert_eq!(error_traces, 2);
    assert!((error_rate - 0.4).abs() < 0.01);
    assert_eq!(total_tokens, 5 * 700);

    // Latency stats
    let mut latencies: Vec<u64> = flow_traces.iter().map(|e| e.latency_ms).collect();
    latencies.sort();
    assert_eq!(latencies[0], 100); // min
    assert_eq!(latencies[4], 180); // max
    let p50 = latencies[2]; // median
    assert!(p50 > 0);

    // Status breakdown
    let mut status_counts: HashMap<String, u64> = HashMap::new();
    for e in &flow_traces {
        *status_counts.entry(e.status.as_str().to_string()).or_insert(0) += 1;
    }
    assert_eq!(status_counts["success"], 5);
}

