#[test]
fn auto_persist_disk_write_and_read() {
    use axon::axon_server::{ServerBackup, EpistemicEnvelope, CostPricing, ReadinessGates};

    let temp = std::env::temp_dir().join("axon_auto_persist_test.json");

    let backup = ServerBackup {
        version: "1.0-ΛD".into(),
        created_at: 1700000000,
        lambda_d: EpistemicEnvelope::raw_config("axon:auto_persist", "shutdown:system"),
        section_provenance: std::collections::HashMap::new(),
        cost_pricing: CostPricing::default(),
        cost_budgets: std::collections::HashMap::new(),
        flow_rules: std::collections::HashMap::new(),
        flow_quotas: std::collections::HashMap::new(),
        readiness_gates: ReadinessGates { min_daemons: 3, required_flows: vec!["FlowA".into()], max_error_rate: 0.05, min_uptime_secs: 60 },
        endpoint_rate_limits: std::collections::HashMap::new(),
        schedules: Vec::new(),
        axon_stores: std::collections::HashMap::new(),
        dataspaces: std::collections::HashMap::new(),
        shields: std::collections::HashMap::new(),
    };

    // Write (simulating persist_state_to_disk)
    let json = serde_json::to_string_pretty(&backup).unwrap();
    std::fs::write(&temp, &json).unwrap();

    // Read back (simulating server_recover_handler)
    let read = std::fs::read_to_string(&temp).unwrap();
    let recovered: ServerBackup = serde_json::from_str(&read).unwrap();

    assert_eq!(recovered.readiness_gates.min_daemons, 3);
    assert_eq!(recovered.readiness_gates.required_flows, vec!["FlowA"]);
    assert!(recovered.lambda_d.validate().is_ok());

    // Cleanup
    std::fs::remove_file(&temp).unwrap();
}

#[test]
fn auto_persist_toggle_flag() {
    // auto_persist_on_shutdown is a simple bool flag
    let mut enabled = true;
    assert!(enabled);

    // Toggle off
    enabled = false;
    assert!(!enabled);

    // When disabled, shutdown skips persist (returns None)
    let persist_result: Option<serde_json::Value> = if enabled {
        Some(serde_json::json!({"success": true}))
    } else {
        None
    };
    assert!(persist_result.is_none());

    // When enabled, shutdown persists (returns Some)
    enabled = true;
    let persist_result2: Option<serde_json::Value> = if enabled {
        Some(serde_json::json!({"success": true, "path": "axon_server_state.json"}))
    } else {
        None
    };
    assert!(persist_result2.is_some());
    assert_eq!(persist_result2.unwrap()["success"], true);
}

// ── D125 — Auto-Recover on Startup ──────────────────────────────────

#[test]
fn auto_recover_reads_persisted_state() {
    use axon::axon_server::{ServerBackup, CostPricing, CostBudget, ReadinessGates, EpistemicEnvelope, ScheduleBackupEntry};
    use std::collections::HashMap;

    // Simulate a persisted state file
    let mut budgets = HashMap::new();
    budgets.insert("FlowA".into(), CostBudget { max_cost_usd: 25.0, warn_threshold: 0.8 });

    let backup = ServerBackup {
        version: "1.0-ΛD".into(),
        created_at: 1700000000,
        lambda_d: EpistemicEnvelope::raw_config("axon:server_persist", "shutdown:admin"),
        section_provenance: HashMap::new(),
        cost_pricing: CostPricing::default(),
        cost_budgets: budgets.clone(),
        flow_rules: HashMap::new(),
        flow_quotas: HashMap::new(),
        readiness_gates: ReadinessGates { min_daemons: 5, required_flows: vec!["Critical".into()], max_error_rate: 0.01, min_uptime_secs: 120 },
        endpoint_rate_limits: HashMap::new(),
        schedules: vec![
            ScheduleBackupEntry { name: "hourly".into(), flow_name: "Pipeline".into(), interval_secs: 3600, enabled: true, backend: "stub".into() },
        ],
        axon_stores: HashMap::new(),
        dataspaces: HashMap::new(),
        shields: HashMap::new(),
    };

    // Write to temp file
    let temp = std::env::temp_dir().join("axon_auto_recover_test.json");
    let json = serde_json::to_string(&backup).unwrap();
    std::fs::write(&temp, &json).unwrap();

    // Simulate auto-recover logic (same as ServerState::new)
    let read = std::fs::read_to_string(&temp).unwrap();
    let recovered: ServerBackup = serde_json::from_str(&read).unwrap();

    assert!(recovered.lambda_d.validate().is_ok());
    assert_eq!(recovered.cost_budgets.len(), 1);
    assert_eq!(recovered.cost_budgets["FlowA"].max_cost_usd, 25.0);
    assert_eq!(recovered.readiness_gates.min_daemons, 5);
    assert_eq!(recovered.schedules.len(), 1);
    assert_eq!(recovered.schedules[0].name, "hourly");

    std::fs::remove_file(&temp).unwrap();
}

#[test]
fn auto_recover_validates_lambda_d_before_applying() {
    use axon::axon_server::EpistemicEnvelope;

    // Valid ΛD → apply state
    let valid = EpistemicEnvelope::raw_config("axon:server_persist", "system");
    assert!(valid.validate().is_ok());

    // Invalid ΛD (empty ontology) → skip recovery
    let invalid = EpistemicEnvelope {
        ontology: "".into(), certainty: 0.5,
        temporal_start: "0".into(), temporal_end: "∞".into(),
        provenance: "corrupted".into(), derivation: "raw".into(),
    };
    assert!(invalid.validate().is_err());
    // In ServerState::new, this would skip the recovery branch

    // Invalid ΛD (Theorem 5.1 violation) → skip recovery
    let theorem_violation = EpistemicEnvelope {
        ontology: "axon:persist".into(), certainty: 1.0,
        temporal_start: "0".into(), temporal_end: "∞".into(),
        provenance: "test".into(), derivation: "derived".into(),
    };
    assert!(theorem_violation.validate().is_err());
}

#[test]
fn auto_recover_no_file_uses_defaults() {
    use axon::axon_server::{CostPricing, ReadinessGates, AutoscaleConfig};

    // When no state file exists, defaults are used
    let nonexistent = std::path::Path::new("/tmp/axon_does_not_exist_99999.json");
    assert!(!nonexistent.exists());

    // Default values (what ServerState::new uses when no file)
    let pricing = CostPricing::default();
    assert_eq!(*pricing.input_per_million.get("anthropic").unwrap(), 3.0);

    let gates = ReadinessGates::default();
    assert_eq!(gates.min_daemons, 0);
    assert!(gates.required_flows.is_empty());

    let autoscale = AutoscaleConfig::default();
    assert!(!autoscale.enabled);
    assert_eq!(autoscale.max_daemons, 10);

    // Confirms: no file → clean defaults → no crash
}

