#[test]
fn flow_compare_multi_flow_stats() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, build_trace};

    let mut store = TraceStore::new(TraceStoreConfig {
        enabled: true, capacity: 200, max_events_per_trace: 50, max_age_secs: 0,
    });

    // FlowA: 10 executions, fast, no errors
    for _ in 0..10 {
        store.record(build_trace("FlowA", "a.axon", "stub", "k", TraceStatus::Success, 2, 50));
    }
    // FlowB: 5 executions, slow, some errors
    for i in 0..5 {
        let mut t = build_trace("FlowB", "b.axon", "stub", "k", TraceStatus::Success, 4, 300);
        if i >= 3 { t.errors = 1; }
        store.record(t);
    }
    // FlowC: no executions
    // (not recorded)

    let entries = store.recent(store.len(), None);

    // FlowA stats
    let a_traces: Vec<_> = entries.iter().filter(|e| e.flow_name == "FlowA").collect();
    assert_eq!(a_traces.len(), 10);
    let a_errors = a_traces.iter().filter(|e| e.errors > 0).count();
    assert_eq!(a_errors, 0);

    // FlowB stats
    let b_traces: Vec<_> = entries.iter().filter(|e| e.flow_name == "FlowB").collect();
    assert_eq!(b_traces.len(), 5);
    let b_errors = b_traces.iter().filter(|e| e.errors > 0).count();
    assert_eq!(b_errors, 2);
    let b_error_rate = b_errors as f64 / 5.0;
    assert!((b_error_rate - 0.4).abs() < 0.01);

    // FlowC stats
    let c_traces: Vec<_> = entries.iter().filter(|e| e.flow_name == "FlowC").collect();
    assert_eq!(c_traces.len(), 0);

    // Highlights
    let flows = vec![("FlowA", 50u64), ("FlowB", 300u64)];
    let fastest = flows.iter().min_by_key(|f| f.1).map(|f| f.0);
    let slowest = flows.iter().max_by_key(|f| f.1).map(|f| f.0);
    assert_eq!(fastest, Some("FlowA"));
    assert_eq!(slowest, Some("FlowB"));
}

#[test]
fn flow_compare_response_structure() {
    use axon::axon_server::FlowCompareEntry;

    let entries = vec![
        FlowCompareEntry {
            flow_name: "Ingest".into(), executions: 100, error_rate: 0.02,
            avg_latency_ms: 80, p50_latency_ms: 70, p95_latency_ms: 150,
            total_tokens: 50000, estimated_cost_usd: 0.25,
            daemon_state: Some("idle".into()), has_schedule: true, has_budget: false, has_quota: true,
        },
        FlowCompareEntry {
            flow_name: "Transform".into(), executions: 80, error_rate: 0.05,
            avg_latency_ms: 200, p50_latency_ms: 180, p95_latency_ms: 400,
            total_tokens: 80000, estimated_cost_usd: 0.60,
            daemon_state: Some("running".into()), has_schedule: false, has_budget: true, has_quota: false,
        },
    ];

    let fastest = entries.iter().min_by_key(|e| e.avg_latency_ms).map(|e| e.flow_name.clone());
    let most_expensive = entries.iter().max_by(|a, b| a.estimated_cost_usd.partial_cmp(&b.estimated_cost_usd).unwrap()).map(|e| e.flow_name.clone());

    let response = serde_json::json!({
        "compared": entries.len(),
        "flows": entries.iter().map(|e| serde_json::to_value(e).unwrap()).collect::<Vec<_>>(),
        "highlights": {
            "fastest": fastest,
            "most_expensive": most_expensive,
        },
    });

    assert_eq!(response["compared"], 2);
    assert_eq!(response["highlights"]["fastest"], "Ingest");
    assert_eq!(response["highlights"]["most_expensive"], "Transform");
    assert_eq!(response["flows"].as_array().unwrap().len(), 2);
}

// ── D127 — Batch Execution with Caching ─────────────────────────────

#[test]
fn cached_batch_item_result_structure() {
    use axon::axon_server::CachedBatchItemResult;

    // Cache hit
    let hit = CachedBatchItemResult {
        index: 0, flow_name: "FlowA".into(), success: true, cached: true,
        trace_id: 42, latency_ms: 0, tokens: 0, error: None,
        epistemic_derivation: "derived".into(),
    };
    let json = serde_json::to_value(&hit).unwrap();
    assert_eq!(json["cached"], true);
    assert_eq!(json["epistemic_derivation"], "derived");
    assert_eq!(json["latency_ms"], 0); // no execution latency for cache hit

    // Fresh execution
    let fresh = CachedBatchItemResult {
        index: 1, flow_name: "FlowB".into(), success: true, cached: false,
        trace_id: 43, latency_ms: 150, tokens: 700, error: None,
        epistemic_derivation: "raw".into(),
    };
    let fj = serde_json::to_value(&fresh).unwrap();
    assert_eq!(fj["cached"], false);
    assert_eq!(fj["epistemic_derivation"], "raw");
    assert_eq!(fj["tokens"], 700);

    // Failed
    let fail = CachedBatchItemResult {
        index: 2, flow_name: "FlowC".into(), success: false, cached: false,
        trace_id: 0, latency_ms: 0, tokens: 0, error: Some("not deployed".into()),
        epistemic_derivation: "none".into(),
    };
    assert_eq!(fail.epistemic_derivation, "none");
}

#[test]
fn cached_batch_mix_of_hits_and_misses() {
    use axon::axon_server::{CachedResult, CachedBatchItemResult, EpistemicEnvelope};

    let now = std::time::SystemTime::now().duration_since(std::time::UNIX_EPOCH).unwrap().as_secs();

    // Pre-populate cache with FlowA
    let cache = vec![CachedResult {
        cache_key: "FlowA:stub".into(), flow_name: "FlowA".into(), backend: "stub".into(),
        result: serde_json::json!({"steps": 3}), source_trace_id: 10,
        cached_at: now, ttl_secs: 300,
        epistemic: EpistemicEnvelope::derived("cache:FlowA", 0.95, "trace:10"),
    }];

    // Batch: FlowA (cached), FlowB (miss), FlowA again (cached)
    let items = vec!["FlowA", "FlowB", "FlowA"];
    let mut results: Vec<CachedBatchItemResult> = Vec::new();

    for (idx, flow) in items.iter().enumerate() {
        let key = format!("{}:stub", flow);
        let force = false;

        // Check cache
        if !force {
            if let Some(entry) = cache.iter().find(|c| c.cache_key == key && !c.is_expired()) {
                results.push(CachedBatchItemResult {
                    index: idx, flow_name: flow.to_string(), success: true, cached: true,
                    trace_id: entry.source_trace_id, latency_ms: 0, tokens: 0, error: None,
                    epistemic_derivation: "derived".into(),
                });
                continue;
            }
        }

        // Miss — would execute fresh
        results.push(CachedBatchItemResult {
            index: idx, flow_name: flow.to_string(), success: true, cached: false,
            trace_id: 100 + idx as u64, latency_ms: 120, tokens: 500, error: None,
            epistemic_derivation: "raw".into(),
        });
    }

    assert_eq!(results.len(), 3);
    assert!(results[0].cached);  // FlowA hit
    assert!(!results[1].cached); // FlowB miss
    assert!(results[2].cached);  // FlowA hit again

    let cache_hits = results.iter().filter(|r| r.cached).count();
    let fresh = results.iter().filter(|r| !r.cached).count();
    assert_eq!(cache_hits, 2);
    assert_eq!(fresh, 1);
}

#[test]
fn cached_batch_force_bypasses_cache() {
    use axon::axon_server::{CachedResult, EpistemicEnvelope};

    let now = std::time::SystemTime::now().duration_since(std::time::UNIX_EPOCH).unwrap().as_secs();

    let cache = vec![CachedResult {
        cache_key: "FlowA:stub".into(), flow_name: "FlowA".into(), backend: "stub".into(),
        result: serde_json::json!({}), source_trace_id: 5,
        cached_at: now, ttl_secs: 300,
        epistemic: EpistemicEnvelope::derived("cache:FlowA", 0.95, "trace:5"),
    }];

    // force=false → cache hit
    let key = "FlowA:stub";
    let force_false = false;
    let hit = if !force_false { cache.iter().find(|c| c.cache_key == key && !c.is_expired()) } else { None };
    assert!(hit.is_some());

    // force=true → bypass, always execute fresh (ΛD δ=raw)
    let force_true = true;
    let hit2 = if !force_true { cache.iter().find(|c| c.cache_key == key && !c.is_expired()) } else { None };
    assert!(hit2.is_none()); // forced → miss → execute fresh

    // Summary response structure
    let response = serde_json::json!({
        "batch_size": 3,
        "cache_hits": 1,
        "fresh_executions": 2,
        "failed": 0,
    });
    assert_eq!(response["cache_hits"], 1);
    assert_eq!(response["fresh_executions"], 2);
}

// ── D128 — Flow Tagging ─────────────────────────────────────────────

#[test]
fn flow_tags_crud() {
    use std::collections::HashMap;

    let mut tags: HashMap<String, Vec<String>> = HashMap::new();

    // Set tags
    tags.insert("Pipeline".into(), vec!["production".into(), "critical".into(), "v2".into()]);
    tags.insert("Analyzer".into(), vec!["staging".into(), "experimental".into()]);

    assert_eq!(tags["Pipeline"].len(), 3);
    assert!(tags["Pipeline"].contains(&"production".to_string()));

    // Update tags (replace)
    tags.insert("Pipeline".into(), vec!["production".into(), "v3".into()]);
    assert_eq!(tags["Pipeline"].len(), 2);
    assert!(tags["Pipeline"].contains(&"v3".to_string()));
    assert!(!tags["Pipeline"].contains(&"critical".to_string()));

    // Delete tags
    tags.remove("Analyzer");
    assert!(tags.get("Analyzer").is_none());

    // Get missing flow → empty
    let missing = tags.get("NonExistent").cloned().unwrap_or_default();
    assert!(missing.is_empty());
}

#[test]
fn flow_tags_search_by_tag() {
    use std::collections::HashMap;

    let mut tags: HashMap<String, Vec<String>> = HashMap::new();
    tags.insert("Pipeline".into(), vec!["production".into(), "critical".into()]);
    tags.insert("Analyzer".into(), vec!["production".into(), "experimental".into()]);
    tags.insert("Exporter".into(), vec!["staging".into()]);
    tags.insert("Monitor".into(), vec!["production".into(), "infra".into()]);

    // Find by tag "production"
    let production: Vec<&str> = tags.iter()
        .filter(|(_, t)| t.contains(&"production".to_string()))
        .map(|(name, _)| name.as_str())
        .collect();
    assert_eq!(production.len(), 3);

    // Find by tag "staging"
    let staging: Vec<&str> = tags.iter()
        .filter(|(_, t)| t.contains(&"staging".to_string()))
        .map(|(name, _)| name.as_str())
        .collect();
    assert_eq!(staging.len(), 1);
    assert_eq!(staging[0], "Exporter");

    // Find by tag that doesn't exist
    let none: Vec<&str> = tags.iter()
        .filter(|(_, t)| t.contains(&"deprecated".to_string()))
        .map(|(name, _)| name.as_str())
        .collect();
    assert_eq!(none.len(), 0);
}

#[test]
fn flow_tags_serialization() {
    // Tags are simple Vec<String>
    let tags = vec!["production".to_string(), "v2".to_string(), "critical".to_string()];
    let json = serde_json::json!({"flow": "Pipeline", "tags": tags});
    assert_eq!(json["tags"].as_array().unwrap().len(), 3);
    assert_eq!(json["tags"][0], "production");

    // by-tag response
    let response = serde_json::json!({
        "tag": "production",
        "count": 3,
        "flows": [
            {"flow": "Pipeline", "tags": ["production", "critical"]},
            {"flow": "Analyzer", "tags": ["production", "experimental"]},
            {"flow": "Monitor", "tags": ["production", "infra"]},
        ],
    });
    assert_eq!(response["count"], 3);
    assert_eq!(response["flows"][1]["flow"], "Analyzer");
}

// ── D129 — Health Degradation Tracking ──────────────────────────────

#[test]
fn health_transition_recording() {
    use axon::axon_server::HealthTransition;

    let mut history: Vec<HealthTransition> = Vec::new();

    // No transition when status unchanged
    let old = "healthy";
    let new = "healthy";
    if old != new {
        history.push(HealthTransition { timestamp: 100, from_status: old.into(), to_status: new.into(), component: "test".into(), detail: "".into() });
    }
    assert_eq!(history.len(), 0);

    // Transition recorded when status changes
    let old2 = "healthy";
    let new2 = "degraded";
    if old2 != new2 {
        history.push(HealthTransition { timestamp: 200, from_status: old2.into(), to_status: new2.into(), component: "trace_store".into(), detail: "at capacity".into() });
    }
    assert_eq!(history.len(), 1);
    assert_eq!(history[0].from_status, "healthy");
    assert_eq!(history[0].to_status, "degraded");
    assert_eq!(history[0].component, "trace_store");

    // Recovery transition
    history.push(HealthTransition { timestamp: 300, from_status: "degraded".into(), to_status: "healthy".into(), component: "trace_store".into(), detail: "evicted old entries".into() });
    assert_eq!(history.len(), 2);

    // Serialization
    let json = serde_json::to_value(&history[0]).unwrap();
    assert_eq!(json["component"], "trace_store");
    assert_eq!(json["from_status"], "healthy");
    assert_eq!(json["to_status"], "degraded");
}

#[test]
fn health_history_cap_and_filtering() {
    use axon::axon_server::HealthTransition;

    let mut history: Vec<HealthTransition> = Vec::new();

    // Add 510 transitions
    for i in 0..510 {
        history.push(HealthTransition {
            timestamp: i as u64,
            from_status: "healthy".into(),
            to_status: "degraded".into(),
            component: if i % 2 == 0 { "trace_store" } else { "event_bus" }.into(),
            detail: format!("event {}", i),
        });
        if history.len() > 500 { history.remove(0); }
    }
    assert_eq!(history.len(), 500);
    assert_eq!(history[0].timestamp, 10); // first 10 evicted

    // Filter by component
    let trace_only: Vec<_> = history.iter().filter(|h| h.component == "trace_store").collect();
    let bus_only: Vec<_> = history.iter().filter(|h| h.component == "event_bus").collect();
    assert_eq!(trace_only.len() + bus_only.len(), 500);

    // Count degradations
    let degradations = history.iter().filter(|h| h.to_status == "degraded").count();
    assert_eq!(degradations, 500); // all are degradations in this test
}

#[test]
fn health_check_component_statuses() {
    // Simulate component health evaluation
    let trace_at_capacity = true;
    let events_dropped = 5u64;
    let dead_daemons = 1usize;
    let error_rate = 0.15f64;

    let ts_status = if trace_at_capacity { "degraded" } else { "healthy" };
    let bus_status = if events_dropped > 0 { "degraded" } else { "healthy" };
    let sup_status = if dead_daemons > 0 { "degraded" } else { "healthy" };
    let err_status = if error_rate > 0.1 { "degraded" } else { "healthy" };

    assert_eq!(ts_status, "degraded");
    assert_eq!(bus_status, "degraded");
    assert_eq!(sup_status, "degraded");
    assert_eq!(err_status, "degraded");

    // All healthy scenario
    let ts2 = if false { "degraded" } else { "healthy" };
    let bus2 = if 0u64 > 0 { "degraded" } else { "healthy" };
    let sup2 = if 0usize > 0 { "degraded" } else { "healthy" };
    let err2 = if 0.02f64 > 0.1 { "degraded" } else { "healthy" };
    assert_eq!(ts2, "healthy");
    assert_eq!(bus2, "healthy");
    assert_eq!(sup2, "healthy");
    assert_eq!(err2, "healthy");

    // Response structure
    let response = serde_json::json!({
        "checked": 4,
        "transitions": 3,
        "new_degradations": 3,
        "components": { "trace_store": ts_status, "event_bus": bus_status, "supervisor": sup_status, "error_rate": err_status },
    });
    assert_eq!(response["checked"], 4);
    assert_eq!(response["components"]["trace_store"], "degraded");
}

