#[test]
fn tag_group_flow_discovery() {
    use std::collections::HashMap;

    let mut tags: HashMap<String, Vec<String>> = HashMap::new();
    tags.insert("Pipeline".into(), vec!["production".into(), "critical".into()]);
    tags.insert("Analyzer".into(), vec!["production".into()]);
    tags.insert("Exporter".into(), vec!["staging".into()]);
    tags.insert("Monitor".into(), vec!["production".into(), "infra".into()]);

    // Find "production" group
    let production: Vec<String> = tags.iter()
        .filter(|(_, t)| t.contains(&"production".to_string()))
        .map(|(name, _)| name.clone())
        .collect();
    assert_eq!(production.len(), 3);

    // Find "staging" group
    let staging: Vec<String> = tags.iter()
        .filter(|(_, t)| t.contains(&"staging".to_string()))
        .map(|(name, _)| name.clone())
        .collect();
    assert_eq!(staging.len(), 1);

    // Find nonexistent tag
    let none: Vec<String> = tags.iter()
        .filter(|(_, t)| t.contains(&"deprecated".to_string()))
        .map(|(name, _)| name.clone())
        .collect();
    assert!(none.is_empty());
}

#[test]
fn tag_group_dashboard_aggregation() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, build_trace};

    let mut store = TraceStore::new(TraceStoreConfig {
        enabled: true, capacity: 200, max_events_per_trace: 50, max_age_secs: 0,
    });

    // Group: Pipeline + Analyzer (tagged "production")
    for _ in 0..5 { store.record(build_trace("Pipeline", "p.axon", "stub", "k", TraceStatus::Success, 3, 100)); }
    for _ in 0..3 {
        let mut t = build_trace("Analyzer", "a.axon", "stub", "k", TraceStatus::Success, 2, 200);
        t.errors = 1;
        store.record(t);
    }
    // Not in group
    store.record(build_trace("Exporter", "e.axon", "stub", "k", TraceStatus::Success, 1, 50));

    let group_flows = vec!["Pipeline".to_string(), "Analyzer".to_string()];
    let entries = store.recent(store.len(), None);
    let group_traces: Vec<_> = entries.iter().filter(|e| group_flows.contains(&e.flow_name)).collect();

    assert_eq!(group_traces.len(), 8); // 5 + 3
    let errors = group_traces.iter().filter(|e| e.errors > 0).count();
    assert_eq!(errors, 3);
    let total_latency: u64 = group_traces.iter().map(|e| e.latency_ms).sum();
    let avg = total_latency / group_traces.len() as u64;
    assert_eq!(avg, 137); // (5*100 + 3*200) / 8 = 1100/8

    let response = serde_json::json!({
        "tag": "production",
        "flows_count": 2,
        "executions": 8,
        "error_rate": 3.0 / 8.0,
        "avg_latency_ms": avg,
    });
    assert_eq!(response["flows_count"], 2);
    assert_eq!(response["executions"], 8);
}

// ── D131 — Execution Replay from Cache ──────────────────────────────

#[test]
fn cache_replay_diff_structure() {
    // Simulate cached vs fresh comparison
    let cached_result = serde_json::json!({"steps": 3, "latency_ms": 100, "tokens_input": 500, "tokens_output": 200});
    let fresh_steps = 3u64;
    let fresh_latency = 120i64;

    let steps_match = cached_result["steps"].as_u64().unwrap() == fresh_steps;
    let latency_delta = fresh_latency - cached_result["latency_ms"].as_i64().unwrap();

    assert!(steps_match);
    assert_eq!(latency_delta, 20);

    let diff = serde_json::json!({
        "steps_match": steps_match,
        "latency_delta_ms": latency_delta,
        "fresh_success": true,
    });
    assert_eq!(diff["steps_match"], true);
    assert_eq!(diff["latency_delta_ms"], 20);
}

#[test]
fn cache_replay_epistemic_comparison() {
    // Cached result: ΛD δ=derived, c=0.95 (stale)
    // Fresh result:  ΛD δ=raw, c=1.0 (ground truth)
    let response = serde_json::json!({
        "success": true,
        "cached_trace_id": 42,
        "replay_trace_id": 100,
        "epistemic": {
            "cached_certainty": 0.95,
            "cached_derivation": "derived",
            "fresh_derivation": "raw",
            "fresh_certainty": 1.0,
        },
    });

    assert_eq!(response["epistemic"]["cached_derivation"], "derived");
    assert_eq!(response["epistemic"]["fresh_derivation"], "raw");
    assert!(response["epistemic"]["fresh_certainty"].as_f64().unwrap() > response["epistemic"]["cached_certainty"].as_f64().unwrap());

    // The replay proves whether the cached result was still valid
    // If steps_match=true and fresh_success=true → cache was reliable
    // If steps_match=false → cache was stale (ΛD certainty should have been lower)
}

#[test]
fn cache_replay_no_cache_returns_error() {
    use axon::axon_server::CachedResult;

    // Empty cache → replay fails
    let cache: Vec<CachedResult> = Vec::new();
    let key = "FlowA:stub";
    let found = cache.iter().find(|c| c.cache_key == key);
    assert!(found.is_none());

    // Response for missing cache
    let response = serde_json::json!({
        "success": false,
        "error": format!("no cached result for '{}'", key),
    });
    assert_eq!(response["success"], false);
    assert!(response["error"].as_str().unwrap().contains("no cached result"));

    // With expired cache → also fails (not found in non-expired filter)
    let now = std::time::SystemTime::now().duration_since(std::time::UNIX_EPOCH).unwrap().as_secs();
    let expired = CachedResult {
        cache_key: key.into(), flow_name: "FlowA".into(), backend: "stub".into(),
        result: serde_json::json!({}), source_trace_id: 1,
        cached_at: now - 600, ttl_secs: 300,
        epistemic: axon::axon_server::EpistemicEnvelope::derived("cache:FlowA", 0.95, "trace:1"),
    };
    assert!(expired.is_expired());
}

