#[test]
fn version_pinning_lookup_via_registry() {
    use axon::flow_version::VersionRegistry;

    let mut reg = VersionRegistry::new();

    // Deploy 3 versions
    reg.record_deploy(&["Pipeline".into()], "v1 source", "p.axon", "stub");
    reg.record_deploy(&["Pipeline".into()], "v2 source", "p.axon", "stub");
    reg.record_deploy(&["Pipeline".into()], "v3 source", "p.axon", "stub");

    // Active is v3
    let active = reg.get_active("Pipeline").unwrap();
    assert_eq!(active.version, 3);

    // Pin to v1
    let v1 = reg.get_version("Pipeline", 1).unwrap();
    assert_eq!(v1.version, 1);
    assert_eq!(v1.source, "v1 source");
    assert!(!v1.active);

    // Pin to v2
    let v2 = reg.get_version("Pipeline", 2).unwrap();
    assert_eq!(v2.version, 2);
    assert_eq!(v2.source, "v2 source");

    // Non-existent version
    assert!(reg.get_version("Pipeline", 99).is_none());

    // Non-existent flow
    assert!(reg.get_version("NonExistent", 1).is_none());
}

