#[test]
fn ab_test_diff_computation() {
    use axon::axon_server::ABTestSide;

    let a = ABTestSide { version: 1, success: true, trace_id: 1, steps_executed: 3, latency_ms: 150, tokens_input: 500, tokens_output: 200, errors: 0 };
    let b = ABTestSide { version: 2, success: true, trace_id: 2, steps_executed: 3, latency_ms: 100, tokens_input: 400, tokens_output: 150, errors: 0 };

    let latency_delta = b.latency_ms as i64 - a.latency_ms as i64;
    let steps_delta = b.steps_executed as i64 - a.steps_executed as i64;
    let tokens_a = a.tokens_input + a.tokens_output;
    let tokens_b = b.tokens_input + b.tokens_output;
    let tokens_delta = tokens_b as i64 - tokens_a as i64;

    assert_eq!(latency_delta, -50); // B is 50ms faster
    assert_eq!(steps_delta, 0);     // same steps
    assert_eq!(tokens_delta, -150); // B uses fewer tokens

    // Winner: B (lower latency, both succeeded)
    let winner = if a.success && !b.success { "a" }
        else if !a.success && b.success { "b" }
        else if a.latency_ms <= b.latency_ms { "a" }
        else { "b" };
    assert_eq!(winner, "b");

    // If A fails, B wins regardless
    let a_fail = ABTestSide { success: false, ..a };
    let winner2 = if a_fail.success && !b.success { "a" }
        else if !a_fail.success && b.success { "b" }
        else { "tie" };
    assert_eq!(winner2, "b");
}

#[test]
fn ab_test_response_structure() {
    use axon::axon_server::ABTestSide;

    let a = ABTestSide { version: 3, success: true, trace_id: 50, steps_executed: 5, latency_ms: 200, tokens_input: 1000, tokens_output: 500, errors: 0 };
    let b = ABTestSide { version: 4, success: true, trace_id: 51, steps_executed: 5, latency_ms: 180, tokens_input: 900, tokens_output: 400, errors: 0 };

    let response = serde_json::json!({
        "success": true,
        "flow": "Pipeline",
        "a": serde_json::to_value(&a).unwrap(),
        "b": serde_json::to_value(&b).unwrap(),
        "diff": {
            "latency_delta_ms": -20,
            "steps_delta": 0,
            "tokens_delta": -200,
            "both_succeeded": true,
            "winner": "b",
        },
    });

    assert_eq!(response["a"]["version"], 3);
    assert_eq!(response["b"]["version"], 4);
    assert_eq!(response["diff"]["winner"], "b");
    assert_eq!(response["diff"]["both_succeeded"], true);
    assert_eq!(response["diff"]["latency_delta_ms"], -20);

    // Same versions → error
    let error_response = serde_json::json!({"error": "version_a and version_b must differ"});
    assert!(error_response["error"].as_str().unwrap().contains("must differ"));
}

