#[test]
fn annotation_template_apply_to_trace() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, TraceAnnotation, build_trace};
    use axon::axon_server::builtin_annotation_templates;

    let mut store = TraceStore::new(TraceStoreConfig {
        enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0,
    });

    let id = store.record(build_trace("Flow", "f.axon", "stub", "k", TraceStatus::Success, 2, 100));

    // Apply "bug" template
    let templates = builtin_annotation_templates();
    let bug_tmpl = templates.iter().find(|t| t.name == "bug").unwrap();

    let annotation = TraceAnnotation {
        author: bug_tmpl.author.clone(),
        text: bug_tmpl.text.clone(),
        tags: bug_tmpl.tags.clone(),
        timestamp: 1000,
    };

    assert!(store.annotate(id, annotation));

    let entry = store.get(id).unwrap();
    assert_eq!(entry.annotations.len(), 1);
    assert_eq!(entry.annotations[0].text, "Bug identified in this execution");
    assert!(entry.annotations[0].tags.contains(&"bug".to_string()));
    assert!(entry.annotations[0].tags.contains(&"needs-fix".to_string()));

    // Apply "baseline" template too (multiple annotations)
    let baseline_tmpl = templates.iter().find(|t| t.name == "baseline").unwrap();
    store.annotate(id, TraceAnnotation {
        author: baseline_tmpl.author.clone(), text: baseline_tmpl.text.clone(),
        tags: baseline_tmpl.tags.clone(), timestamp: 2000,
    });

    let entry2 = store.get(id).unwrap();
    assert_eq!(entry2.annotations.len(), 2);
    assert!(entry2.annotations[1].tags.contains(&"baseline".to_string()));
}

// ── D135 — Webhook Event Filtering ──────────────────────────────────

#[test]
fn webhook_filters_get_and_set() {
    use axon::webhooks::WebhookRegistry;

    let mut reg = WebhookRegistry::new();
    let id = reg.register("hook1", "https://example.com/hook", vec!["deploy".into(), "daemon.*".into()], None);

    // Get initial filters
    let filters = reg.get_filters(&id).unwrap();
    assert_eq!(filters.len(), 2);
    assert!(filters.contains(&"deploy".to_string()));
    assert!(filters.contains(&"daemon.*".to_string()));

    // Update filters
    assert!(reg.set_filters(&id, vec!["*".into()]));
    let updated = reg.get_filters(&id).unwrap();
    assert_eq!(updated.len(), 1);
    assert_eq!(updated[0], "*");

    // Set specific filters
    assert!(reg.set_filters(&id, vec!["trace.complete".into(), "flow.stream.*".into(), "alert.fired".into()]));
    let specific = reg.get_filters(&id).unwrap();
    assert_eq!(specific.len(), 3);

    // Non-existent webhook
    assert!(!reg.set_filters("wh_999", vec!["test".into()]));
    assert!(reg.get_filters("wh_999").is_none());
}

#[test]
fn webhook_filters_affect_matching() {
    use axon::webhooks::WebhookRegistry;

    let mut reg = WebhookRegistry::new();
    let id = reg.register("narrow", "https://example.com", vec!["deploy".into()], None);

    // Initially only matches "deploy"
    let matched = reg.match_topic("deploy");
    assert_eq!(matched.len(), 1);
    let no_match = reg.match_topic("daemon.started");
    assert_eq!(no_match.len(), 0);

    // Widen filters to include daemon events
    reg.set_filters(&id, vec!["deploy".into(), "daemon.*".into()]);
    let daemon_match = reg.match_topic("daemon.started");
    assert_eq!(daemon_match.len(), 1);

    // Wildcard catches everything
    reg.set_filters(&id, vec!["*".into()]);
    let all_match = reg.match_topic("anything.at.all");
    assert_eq!(all_match.len(), 1);

    // Narrow back
    reg.set_filters(&id, vec!["specific.topic".into()]);
    let narrow = reg.match_topic("deploy");
    assert_eq!(narrow.len(), 0);
    let exact = reg.match_topic("specific.topic");
    assert_eq!(exact.len(), 1);
}

#[test]
fn webhook_filters_multiple_webhooks() {
    use axon::webhooks::WebhookRegistry;

    let mut reg = WebhookRegistry::new();
    let id1 = reg.register("deploy-hook", "https://a.com", vec!["deploy".into()], None);
    let id2 = reg.register("all-hook", "https://b.com", vec!["*".into()], None);
    let id3 = reg.register("daemon-hook", "https://c.com", vec!["daemon.*".into()], None);

    // "deploy" matches hook1 and hook2
    let deploy_matches = reg.match_topic("deploy");
    assert_eq!(deploy_matches.len(), 2);

    // "daemon.started" matches hook2 and hook3
    let daemon_matches = reg.match_topic("daemon.started");
    assert_eq!(daemon_matches.len(), 2);

    // Update hook3 to also match trace events
    reg.set_filters(&id3, vec!["daemon.*".into(), "trace.*".into()]);
    let trace_matches = reg.match_topic("trace.complete");
    assert_eq!(trace_matches.len(), 2); // hook2 (*) + hook3 (trace.*)

    // Verify hook1 still only matches deploy
    let h1_filters = reg.get_filters(&id1).unwrap();
    assert_eq!(h1_filters, &vec!["deploy".to_string()]);
}

