#[test]
fn flow_sla_crud_and_serialization() {
    use axon::axon_server::FlowSLA;
    use std::collections::HashMap;

    let sla = FlowSLA { max_latency_ms: 200, max_error_rate: 0.05, min_success_rate: 0.95, max_p95_latency_ms: 500 };

    let json = serde_json::to_value(&sla).unwrap();
    assert_eq!(json["max_latency_ms"], 200);
    assert_eq!(json["max_error_rate"], 0.05);
    assert_eq!(json["min_success_rate"], 0.95);
    assert_eq!(json["max_p95_latency_ms"], 500);

    // Deserialization with defaults
    let parsed: FlowSLA = serde_json::from_value(serde_json::json!({"max_latency_ms": 100})).unwrap();
    assert_eq!(parsed.max_latency_ms, 100);
    assert_eq!(parsed.max_error_rate, 0.0); // default
    assert_eq!(parsed.min_success_rate, 0.0);
    assert_eq!(parsed.max_p95_latency_ms, 0);

    // CRUD
    let mut slas: HashMap<String, FlowSLA> = HashMap::new();
    slas.insert("Pipeline".into(), sla);
    assert!(slas.get("Pipeline").is_some());
    slas.remove("Pipeline");
    assert!(slas.get("Pipeline").is_none());
}

#[test]
fn flow_sla_breach_detection() {
    use axon::axon_server::{FlowSLA, SLABreach};

    let sla = FlowSLA { max_latency_ms: 100, max_error_rate: 0.05, min_success_rate: 0.95, max_p95_latency_ms: 300 };

    // Simulate metrics
    let avg_latency = 150.0f64; // > 100 → breach
    let p95 = 250u64;           // < 300 → ok
    let error_rate = 0.08f64;   // > 0.05 → breach
    let success_rate = 0.92f64; // < 0.95 → breach

    let mut breaches: Vec<SLABreach> = Vec::new();

    if sla.max_latency_ms > 0 && avg_latency > sla.max_latency_ms as f64 {
        breaches.push(SLABreach { flow_name: "Flow".into(), metric: "avg_latency_ms".into(), threshold: sla.max_latency_ms as f64, actual: avg_latency, breached: true });
    }
    if sla.max_p95_latency_ms > 0 && p95 > sla.max_p95_latency_ms {
        breaches.push(SLABreach { flow_name: "Flow".into(), metric: "p95_latency_ms".into(), threshold: sla.max_p95_latency_ms as f64, actual: p95 as f64, breached: true });
    }
    if sla.max_error_rate > 0.0 && error_rate > sla.max_error_rate {
        breaches.push(SLABreach { flow_name: "Flow".into(), metric: "error_rate".into(), threshold: sla.max_error_rate, actual: error_rate, breached: true });
    }
    if sla.min_success_rate > 0.0 && success_rate < sla.min_success_rate {
        breaches.push(SLABreach { flow_name: "Flow".into(), metric: "success_rate".into(), threshold: sla.min_success_rate, actual: success_rate, breached: true });
    }

    assert_eq!(breaches.len(), 3); // latency, error_rate, success_rate (p95 ok)
    assert!(breaches.iter().any(|b| b.metric == "avg_latency_ms"));
    assert!(breaches.iter().any(|b| b.metric == "error_rate"));
    assert!(breaches.iter().any(|b| b.metric == "success_rate"));
    assert!(!breaches.iter().any(|b| b.metric == "p95_latency_ms"));
}

#[test]
fn flow_sla_compliant_scenario() {
    use axon::axon_server::FlowSLA;

    let sla = FlowSLA { max_latency_ms: 500, max_error_rate: 0.1, min_success_rate: 0.9, max_p95_latency_ms: 1000 };

    // All metrics within bounds
    let avg_latency = 120.0f64;
    let p95 = 300u64;
    let error_rate = 0.02f64;
    let success_rate = 0.98f64;

    let mut breaches = 0;
    if sla.max_latency_ms > 0 && avg_latency > sla.max_latency_ms as f64 { breaches += 1; }
    if sla.max_p95_latency_ms > 0 && p95 > sla.max_p95_latency_ms { breaches += 1; }
    if sla.max_error_rate > 0.0 && error_rate > sla.max_error_rate { breaches += 1; }
    if sla.min_success_rate > 0.0 && success_rate < sla.min_success_rate { breaches += 1; }

    assert_eq!(breaches, 0); // fully compliant

    // Zero SLA (all limits 0) → always compliant
    let zero_sla = FlowSLA { max_latency_ms: 0, max_error_rate: 0.0, min_success_rate: 0.0, max_p95_latency_ms: 0 };
    let mut zero_breaches = 0;
    if zero_sla.max_latency_ms > 0 && 9999.0 > zero_sla.max_latency_ms as f64 { zero_breaches += 1; }
    assert_eq!(zero_breaches, 0);

    // Serialization of SLABreach
    let breach = axon::axon_server::SLABreach { flow_name: "X".into(), metric: "latency".into(), threshold: 100.0, actual: 200.0, breached: true };
    let bj = serde_json::to_value(&breach).unwrap();
    assert_eq!(bj["breached"], true);
    assert_eq!(bj["actual"], 200.0);
}

