// ── D138 — Flow Canary Deployment ───────────────────────────────────

#[test]
fn canary_config_routing_logic() {
    use axon::axon_server::CanaryConfig;

    let mut cfg = CanaryConfig {
        stable_version: 1, canary_version: 2, canary_weight: 20,
        stable_count: 0, canary_count: 0,
    };

    // First request: canary_pct=0% < 20% weight → canary
    let v1 = cfg.route();
    assert_eq!(v1, 2); // canary
    assert_eq!(cfg.canary_count, 1);

    // Route 9 more: should get ~20% canary
    for _ in 0..9 {
        cfg.route();
    }
    let total = cfg.stable_count + cfg.canary_count;
    assert_eq!(total, 10);
    // Canary should be around 20% (2 out of 10)
    assert!(cfg.canary_count >= 1 && cfg.canary_count <= 4);

    // 0% canary → all stable
    let mut cfg0 = CanaryConfig {
        stable_version: 1, canary_version: 2, canary_weight: 0,
        stable_count: 0, canary_count: 0,
    };
    for _ in 0..10 { cfg0.route(); }
    assert_eq!(cfg0.canary_count, 0);
    assert_eq!(cfg0.stable_count, 10);

    // 100% canary → almost all canary (routing converges to weight)
    let mut cfg100 = CanaryConfig {
        stable_version: 1, canary_version: 2, canary_weight: 100,
        stable_count: 0, canary_count: 0,
    };
    for _ in 0..10 { cfg100.route(); }
    // With weight=100, canary gets vast majority
    assert!(cfg100.canary_count >= 5);
}

#[test]
fn canary_config_crud() {
    use axon::axon_server::CanaryConfig;
    use std::collections::HashMap;

    let mut configs: HashMap<String, CanaryConfig> = HashMap::new();

    // Set
    configs.insert("Pipeline".into(), CanaryConfig {
        stable_version: 3, canary_version: 4, canary_weight: 10,
        stable_count: 0, canary_count: 0,
    });
    assert!(configs.contains_key("Pipeline"));
    assert_eq!(configs["Pipeline"].canary_weight, 10);

    // Update weight (simulate gradual increase)
    configs.get_mut("Pipeline").unwrap().canary_weight = 50;
    assert_eq!(configs["Pipeline"].canary_weight, 50);

    // Delete (promote canary → remove config)
    configs.remove("Pipeline");
    assert!(!configs.contains_key("Pipeline"));

    // Serialization
    let cfg = CanaryConfig {
        stable_version: 1, canary_version: 2, canary_weight: 25,
        stable_count: 75, canary_count: 25,
    };
    let json = serde_json::to_value(&cfg).unwrap();
    assert_eq!(json["stable_version"], 1);
    assert_eq!(json["canary_version"], 2);
    assert_eq!(json["canary_weight"], 25);
    assert_eq!(json["stable_count"], 75);
}

#[test]
fn canary_validation() {
    // Weight must be 0–100
    let valid_weight = 50u32;
    assert!(valid_weight <= 100);

    let invalid_weight = 150u32;
    assert!(invalid_weight > 100);

    // Same versions → error
    let stable = 3u32;
    let canary = 3u32;
    assert_eq!(stable, canary); // would be rejected

    let different_canary = 4u32;
    assert_ne!(stable, different_canary); // valid

    // Route response structure
    let response = serde_json::json!({
        "flow": "Pipeline",
        "routed_version": 4,
        "is_canary": true,
        "stable_count": 80,
        "canary_count": 20,
        "canary_weight": 20,
    });
    assert_eq!(response["is_canary"], true);
    assert_eq!(response["routed_version"], 4);
}

