#[test]
fn alert_rule_crud() {
    use axon::axon_server::{AlertRule, FiredAlert};

    let rule = AlertRule {
        name: "high_error_rate".into(), metric: "error_rate".into(),
        comparison: "gt".into(), threshold: 0.1, severity: "critical".into(), enabled: true,
        escalate_after: 0, escalation_window_secs: 300, cooldown_secs: 0,
    };

    let json = serde_json::to_value(&rule).unwrap();
    assert_eq!(json["name"], "high_error_rate");
    assert_eq!(json["metric"], "error_rate");
    assert_eq!(json["comparison"], "gt");
    assert_eq!(json["threshold"], 0.1);
    assert_eq!(json["severity"], "critical");
    assert_eq!(json["enabled"], true);

    // Deserialization
    let parsed: AlertRule = serde_json::from_value(serde_json::json!({
        "name": "slow", "metric": "latency_avg", "comparison": "gt", "threshold": 500.0, "severity": "warning",
    })).unwrap();
    assert_eq!(parsed.name, "slow");
    assert!(parsed.enabled); // default

    // FiredAlert serialization
    let fired = FiredAlert {
        rule_name: "high_error_rate".into(), metric: "error_rate".into(),
        threshold: 0.1, actual: 0.15, severity: "critical".into(), timestamp: 1700000000,
    };
    let fj = serde_json::to_value(&fired).unwrap();
    assert_eq!(fj["actual"], 0.15);
    assert_eq!(fj["severity"], "critical");
}

#[test]
fn alert_evaluation_logic() {
    // gt comparison
    let threshold = 0.05f64;
    let actual_high = 0.08f64;
    let actual_low = 0.03f64;
    assert!(actual_high > threshold); // fires
    assert!(!(actual_low > threshold)); // doesn't fire

    // lt comparison
    let min_threshold = 0.95f64;
    let actual_ok = 0.98f64;
    let actual_bad = 0.90f64;
    assert!(!(actual_ok < min_threshold)); // doesn't fire
    assert!(actual_bad < min_threshold); // fires

    // 5 supported metrics
    let metrics = vec!["error_rate", "latency_avg", "queue_depth", "trace_buffer_pct", "dead_daemons"];
    assert_eq!(metrics.len(), 5);

    // Disabled rule → skipped
    let enabled = false;
    if enabled { panic!("should not evaluate"); }

    // Multiple rules can fire simultaneously
    let rules_fired = vec![true, false, true, false, true];
    let alert_count = rules_fired.iter().filter(|&&f| f).count();
    assert_eq!(alert_count, 3);
}

#[test]
fn alert_history_cap() {
    use axon::axon_server::FiredAlert;

    let mut history: Vec<FiredAlert> = Vec::new();

    // Add 510 alerts
    for i in 0..510 {
        history.push(FiredAlert {
            rule_name: format!("rule_{}", i % 5), metric: "error_rate".into(),
            threshold: 0.1, actual: 0.15, severity: "warning".into(), timestamp: i as u64,
        });
    }

    // Cap at 500
    let excess = history.len().saturating_sub(500);
    if excess > 0 { history.drain(0..excess); }
    assert_eq!(history.len(), 500);
    assert_eq!(history[0].timestamp, 10);

    // Recent (last N)
    let recent: Vec<&FiredAlert> = history.iter().rev().take(10).collect();
    assert_eq!(recent.len(), 10);
    assert_eq!(recent[0].timestamp, 509); // newest first
}

// ── D140 — Alert Webhook Integration ────────────────────────────────

#[test]
fn alert_publishes_to_event_bus() {
    use axon::event_bus::EventBus;

    let bus = EventBus::new();

    // Simulate alert firing → publish to bus
    let alerts = vec![
        ("high_error_rate", "error_rate", "critical", 0.15f64),
        ("slow_latency", "latency_avg", "warning", 500.0f64),
    ];

    for (rule, metric, severity, actual) in &alerts {
        let topic = format!("alert.{}", severity);
        bus.publish(&topic, serde_json::json!({
            "rule": rule, "metric": metric, "severity": severity, "actual": actual,
        }), "alert_system");
    }

    assert_eq!(bus.stats().events_published, 2);

    // Critical alerts on alert.critical topic
    let critical = bus.recent_events(10, Some("alert.critical"));
    assert_eq!(critical.len(), 1);
    assert_eq!(critical[0].payload["rule"], "high_error_rate");

    // Warning alerts on alert.warning topic
    let warnings = bus.recent_events(10, Some("alert.warning"));
    assert_eq!(warnings.len(), 1);
    assert_eq!(warnings[0].payload["rule"], "slow_latency");

    // All alerts via wildcard
    let all = bus.recent_events(10, Some("alert.*"));
    assert_eq!(all.len(), 2);
}

#[test]
fn alert_webhook_matching() {
    use axon::webhooks::WebhookRegistry;

    let mut reg = WebhookRegistry::new();

    // Webhook subscribed to alert.* → receives all alerts
    let id1 = reg.register("alert-hook", "https://alerts.example.com", vec!["alert.*".into()], None);
    // Webhook subscribed to alert.critical only
    let id2 = reg.register("critical-hook", "https://pager.example.com", vec!["alert.critical".into()], None);
    // Webhook not subscribed to alerts
    let _id3 = reg.register("deploy-hook", "https://deploy.example.com", vec!["deploy".into()], None);

    // alert.critical matches both alert-hook and critical-hook
    let critical_matches = reg.match_topic("alert.critical");
    assert_eq!(critical_matches.len(), 2);
    assert!(critical_matches.contains(&id1));
    assert!(critical_matches.contains(&id2));

    // alert.warning matches only alert-hook
    let warning_matches = reg.match_topic("alert.warning");
    assert_eq!(warning_matches.len(), 1);
    assert!(warning_matches.contains(&id1));

    // alert.info matches only alert-hook
    let info_matches = reg.match_topic("alert.info");
    assert_eq!(info_matches.len(), 1);

    // deploy doesn't match alert hooks
    let deploy_matches = reg.match_topic("deploy");
    assert_eq!(deploy_matches.len(), 1); // only deploy-hook
}

#[test]
fn alert_event_bus_to_sse_chain() {
    use axon::event_bus::EventBus;

    let bus = EventBus::new();

    // Fire alerts → EventBus → SSE consumable
    bus.publish("alert.critical", serde_json::json!({"rule": "error_rate", "actual": 0.15}), "alert_system");
    bus.publish("alert.warning", serde_json::json!({"rule": "latency", "actual": 800}), "alert_system");
    bus.publish("alert.info", serde_json::json!({"rule": "queue_depth", "actual": 3}), "alert_system");

    // SSE client can consume via GET /v1/events/stream?topic=alert.*
    let all_alerts = bus.recent_events(50, Some("alert.*"));
    assert_eq!(all_alerts.len(), 3);

    // Or filter by severity
    let critical_only = bus.recent_events(50, Some("alert.critical"));
    assert_eq!(critical_only.len(), 1);
    assert_eq!(critical_only[0].payload["rule"], "error_rate");

    // Alert events are in history for replay too
    let history = bus.recent_events(50, None);
    assert!(history.len() >= 3);
}

