#[test]
fn warm_result_structure() {
    use axon::axon_server::WarmResult;

    // Warmed (fresh execution)
    let warmed = WarmResult { flow_name: "Pipeline".into(), success: true, cached: false, trace_id: 42, latency_ms: 120, error: None };
    let json = serde_json::to_value(&warmed).unwrap();
    assert_eq!(json["cached"], false);
    assert_eq!(json["trace_id"], 42);
    assert_eq!(json["latency_ms"], 120);

    // Already cached (skipped)
    let already = WarmResult { flow_name: "Pipeline".into(), success: true, cached: true, trace_id: 0, latency_ms: 0, error: None };
    let aj = serde_json::to_value(&already).unwrap();
    assert_eq!(aj["cached"], true);
    assert_eq!(aj["latency_ms"], 0);

    // Failed
    let failed = WarmResult { flow_name: "Broken".into(), success: false, cached: false, trace_id: 0, latency_ms: 0, error: Some("compile error".into()) };
    let fj = serde_json::to_value(&failed).unwrap();
    assert_eq!(fj["success"], false);
    assert_eq!(fj["error"], "compile error");
}

#[test]
fn warm_skip_if_cached() {
    use axon::axon_server::{CachedResult, EpistemicEnvelope};

    let now = std::time::SystemTime::now().duration_since(std::time::UNIX_EPOCH).unwrap().as_secs();

    let cache = vec![
        CachedResult {
            cache_key: "Pipeline:stub".into(), flow_name: "Pipeline".into(), backend: "stub".into(),
            result: serde_json::json!({"warmed": true}), source_trace_id: 10,
            cached_at: now, ttl_secs: 600,
            epistemic: EpistemicEnvelope::derived("warm:Pipeline", 0.95, "trace:10"),
        },
    ];

    // Pipeline already cached → skip
    let key = "Pipeline:stub";
    let already = cache.iter().any(|c| c.cache_key == key && !c.is_expired());
    assert!(already);

    // Analyzer not cached → would execute
    let key2 = "Analyzer:stub";
    let not_cached = !cache.iter().any(|c| c.cache_key == key2 && !c.is_expired());
    assert!(not_cached);

    // Expired cache → would re-execute
    let expired_cache = vec![CachedResult {
        cache_key: "Old:stub".into(), flow_name: "Old".into(), backend: "stub".into(),
        result: serde_json::json!({}), source_trace_id: 1,
        cached_at: now - 1000, ttl_secs: 600,
        epistemic: EpistemicEnvelope::derived("warm:Old", 0.95, "trace:1"),
    }];
    let expired = !expired_cache.iter().any(|c| c.cache_key == "Old:stub" && !c.is_expired());
    assert!(expired);
}

#[test]
fn warm_response_summary() {
    use axon::axon_server::WarmResult;

    let results = vec![
        WarmResult { flow_name: "A".into(), success: true, cached: false, trace_id: 1, latency_ms: 100, error: None },
        WarmResult { flow_name: "B".into(), success: true, cached: true, trace_id: 0, latency_ms: 0, error: None },
        WarmResult { flow_name: "C".into(), success: false, cached: false, trace_id: 0, latency_ms: 0, error: Some("err".into()) },
        WarmResult { flow_name: "D".into(), success: true, cached: false, trace_id: 2, latency_ms: 80, error: None },
    ];

    let warmed = results.iter().filter(|r| r.success && !r.cached).count();
    let already = results.iter().filter(|r| r.cached).count();
    let failed = results.iter().filter(|r| !r.success).count();

    assert_eq!(warmed, 2);  // A, D
    assert_eq!(already, 1); // B
    assert_eq!(failed, 1);  // C

    let response = serde_json::json!({
        "total_flows": 4, "warmed": warmed, "already_cached": already, "failed": failed,
        "cache_ttl_secs": 600,
    });
    assert_eq!(response["warmed"], 2);
    assert_eq!(response["already_cached"], 1);
}

// ── D142 — Flow Execution Profiling ─────────────────────────────────

#[test]
fn step_profile_from_events() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, TraceEvent, build_trace};

    let mut store = TraceStore::new(TraceStoreConfig {
        enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0,
    });

    let mut t = build_trace("Pipeline", "p.axon", "stub", "k", TraceStatus::Success, 3, 300);
    t.events = vec![
        TraceEvent { event_type: "step_start".into(), offset_ms: 0, step_name: "Init".into(), detail: "".into() },
        TraceEvent { event_type: "step_end".into(), offset_ms: 50, step_name: "Init".into(), detail: "".into() },
        TraceEvent { event_type: "step_start".into(), offset_ms: 50, step_name: "Process".into(), detail: "".into() },
        TraceEvent { event_type: "model_call".into(), offset_ms: 100, step_name: "claude".into(), detail: "".into() },
        TraceEvent { event_type: "step_end".into(), offset_ms: 250, step_name: "Process".into(), detail: "".into() },
        TraceEvent { event_type: "step_start".into(), offset_ms: 250, step_name: "Output".into(), detail: "".into() },
        TraceEvent { event_type: "step_end".into(), offset_ms: 300, step_name: "Output".into(), detail: "".into() },
    ];
    let id = store.record(t);
    let entry = store.get(id).unwrap();

    // Build profiles
    let mut profiles: Vec<(String, u64, u64, usize)> = Vec::new(); // (name, start, duration, events)
    let mut stack: Vec<(String, u64, usize)> = Vec::new();
    for ev in &entry.events {
        match ev.event_type.as_str() {
            "step_start" => stack.push((ev.step_name.clone(), ev.offset_ms, 0)),
            "step_end" => {
                if let Some((name, start, events)) = stack.pop() {
                    profiles.push((name, start, ev.offset_ms - start, events));
                }
            }
            _ => { if let Some(last) = stack.last_mut() { last.2 += 1; } }
        }
    }

    assert_eq!(profiles.len(), 3);
    assert_eq!(profiles[0], ("Init".into(), 0, 50, 0));
    assert_eq!(profiles[1], ("Process".into(), 50, 200, 1)); // 1 model_call event
    assert_eq!(profiles[2], ("Output".into(), 250, 50, 0));

    // Hotspot = Process (200ms)
    let hotspot = profiles.iter().max_by_key(|p| p.2).map(|p| p.0.clone());
    assert_eq!(hotspot.as_deref(), Some("Process"));
}

#[test]
fn step_profile_percentage() {
    let total_latency = 500u64;
    let durations = vec![100u64, 300, 100]; // Init=100, Process=300, Output=100

    let pcts: Vec<f64> = durations.iter().map(|&d| {
        (d as f64 / total_latency as f64 * 100.0 * 100.0).round() / 100.0
    }).collect();

    assert_eq!(pcts[0], 20.0);  // Init: 20%
    assert_eq!(pcts[1], 60.0);  // Process: 60%
    assert_eq!(pcts[2], 20.0);  // Output: 20%
    let sum: f64 = pcts.iter().sum();
    assert_eq!(sum, 100.0);
}

#[test]
fn step_profile_empty_and_unclosed() {
    use axon::trace_store::{TraceStore, TraceStoreConfig, TraceStatus, TraceEvent, build_trace};

    let mut store = TraceStore::new(TraceStoreConfig {
        enabled: true, capacity: 100, max_events_per_trace: 50, max_age_secs: 0,
    });

    // Empty events → no profile
    let t1 = build_trace("Empty", "e.axon", "stub", "k", TraceStatus::Success, 0, 10);
    let id1 = store.record(t1);
    assert!(store.get(id1).unwrap().events.is_empty());

    // Unclosed step → uses total_latency as end
    let mut t2 = build_trace("Crash", "c.axon", "stub", "k", TraceStatus::Failed, 1, 200);
    t2.events = vec![
        TraceEvent { event_type: "step_start".into(), offset_ms: 0, step_name: "Broken".into(), detail: "".into() },
        TraceEvent { event_type: "error".into(), offset_ms: 150, step_name: "Broken".into(), detail: "crash".into() },
    ];
    let id2 = store.record(t2);
    let entry = store.get(id2).unwrap();

    // Stack has unclosed "Broken" → flush with latency_ms
    let mut stack: Vec<(String, u64, usize)> = Vec::new();
    for ev in &entry.events {
        match ev.event_type.as_str() {
            "step_start" => stack.push((ev.step_name.clone(), ev.offset_ms, 0)),
            "step_end" => { stack.pop(); }
            _ => { if let Some(last) = stack.last_mut() { last.2 += 1; } }
        }
    }
    assert_eq!(stack.len(), 1); // unclosed
    let (name, start, events) = &stack[0];
    assert_eq!(name, "Broken");
    assert_eq!(*start, 0);
    assert_eq!(*events, 1); // error event
    let duration = entry.latency_ms - start;
    assert_eq!(duration, 200);
}

// ── D143 · Alert escalation ─────────────────────────────────────────

#[test]
fn alert_escalation_fields_serde() {
    use axon::axon_server::{AlertRule, FiredAlert};

    // Escalation fields serialize correctly
    let rule = AlertRule {
        name: "esc_rule".into(), metric: "error_rate".into(),
        comparison: "gt".into(), threshold: 0.1, severity: "info".into(), enabled: true,
        escalate_after: 3, escalation_window_secs: 600, cooldown_secs: 0,
    };
    let json = serde_json::to_value(&rule).unwrap();
    assert_eq!(json["escalate_after"], 3);
    assert_eq!(json["escalation_window_secs"], 600);

    // Defaults when omitted
    let parsed: AlertRule = serde_json::from_value(serde_json::json!({
        "name": "minimal", "metric": "latency_avg", "comparison": "gt",
        "threshold": 100.0, "severity": "warning",
    })).unwrap();
    assert_eq!(parsed.escalate_after, 0);       // default: no escalation
    assert_eq!(parsed.escalation_window_secs, 300); // default: 300s

    // Escalation severity ladder: info → warning → critical → critical (ceiling)
    let escalate = |base: &str| -> String {
        match base {
            "info" => "warning".to_string(),
            "warning" => "critical".to_string(),
            _ => base.to_string(),
        }
    };
    assert_eq!(escalate("info"), "warning");
    assert_eq!(escalate("warning"), "critical");
    assert_eq!(escalate("critical"), "critical"); // ceiling
}

#[test]
fn alert_escalation_window_logic() {
    use axon::axon_server::FiredAlert;

    let now = 1700000300u64;
    let window_secs = 300u64;
    let window_start = now.saturating_sub(window_secs);

    // Simulate fired_alerts history
    let history: Vec<FiredAlert> = vec![
        FiredAlert { rule_name: "r1".into(), metric: "error_rate".into(), threshold: 0.1, actual: 0.2, severity: "info".into(), timestamp: 1700000000 }, // exactly at window_start
        FiredAlert { rule_name: "r1".into(), metric: "error_rate".into(), threshold: 0.1, actual: 0.3, severity: "info".into(), timestamp: 1700000100 },
        FiredAlert { rule_name: "r2".into(), metric: "latency_avg".into(), threshold: 50.0, actual: 80.0, severity: "warning".into(), timestamp: 1700000200 }, // different rule
        FiredAlert { rule_name: "r1".into(), metric: "error_rate".into(), threshold: 0.1, actual: 0.25, severity: "info".into(), timestamp: 1699999900 }, // outside window
    ];

    // Count r1 fires within window
    let r1_in_window = history.iter()
        .filter(|fa| fa.rule_name == "r1" && fa.timestamp >= window_start)
        .count() as u32;
    assert_eq!(r1_in_window, 2); // two r1 fires within [1700000000, 1700000300]

    // escalate_after=2 → should escalate
    let escalate_after = 2u32;
    assert!(r1_in_window >= escalate_after);

    // escalate_after=3 → not enough yet
    let escalate_after_3 = 3u32;
    assert!(r1_in_window < escalate_after_3);

    // r2 count — only 1 in window, not enough for escalation
    let r2_in_window = history.iter()
        .filter(|fa| fa.rule_name == "r2" && fa.timestamp >= window_start)
        .count() as u32;
    assert_eq!(r2_in_window, 1);
}

#[test]
fn alert_escalation_no_escalation_when_disabled() {
    use axon::axon_server::FiredAlert;

    // escalate_after=0 means no escalation regardless of history
    let escalate_after = 0u32;
    let base_severity = "info";

    // Simulate 10 fires in window
    let fires_in_window = 10u32;

    // When escalate_after is 0, never escalate
    let severity = if escalate_after > 0 && fires_in_window >= escalate_after {
        match base_severity {
            "info" => "warning",
            "warning" => "critical",
            other => other,
        }
    } else {
        base_severity
    };
    assert_eq!(severity, "info"); // stays info, no escalation

    // Same logic but with escalate_after=5 and 10 fires → should escalate
    let escalate_after = 5u32;
    let severity = if escalate_after > 0 && fires_in_window >= escalate_after {
        match base_severity {
            "info" => "warning",
            "warning" => "critical",
            other => other,
        }
    } else {
        base_severity
    };
    assert_eq!(severity, "warning"); // escalated
}

