#[test]
fn cost_forecast_linear_regression() {
    // Test the linear regression logic: y = a + b*x
    // Data: day 0 → $1, day 1 → $3, day 2 → $5 (perfect line, slope=2, intercept=1)
    let points: Vec<(f64, f64)> = vec![(0.0, 1.0), (1.0, 3.0), (2.0, 5.0)];
    let n = points.len() as f64;
    let sum_x: f64 = points.iter().map(|p| p.0).sum();
    let sum_y: f64 = points.iter().map(|p| p.1).sum();
    let sum_xy: f64 = points.iter().map(|p| p.0 * p.1).sum();
    let sum_x2: f64 = points.iter().map(|p| p.0.powi(2)).sum();

    let denom = n * sum_x2 - sum_x * sum_x;
    let slope = (n * sum_xy - sum_x * sum_y) / denom;
    let intercept = (sum_y - slope * sum_x) / n;

    assert!((slope - 2.0).abs() < 1e-10);
    assert!((intercept - 1.0).abs() < 1e-10);

    // Forecast day 3: 1 + 2*3 = 7
    let forecast_day3 = intercept + slope * 3.0;
    assert!((forecast_day3 - 7.0).abs() < 1e-10);

    // Forecast day 5: 1 + 2*5 = 11
    let forecast_day5 = intercept + slope * 5.0;
    assert!((forecast_day5 - 11.0).abs() < 1e-10);

    // Edge: single data point → denom=0, fallback to average
    let single: Vec<(f64, f64)> = vec![(0.0, 4.0)];
    let n1 = 1.0f64;
    let denom1 = n1 * 0.0 - 0.0;
    assert!(denom1.abs() < 1e-12); // triggers flat fallback
    let avg = 4.0 / 1.0;
    assert_eq!(avg, 4.0);
}

#[test]
fn cost_forecast_negative_clamped_to_zero() {
    // If trend is negative, forecast should clamp predictions to 0 (no negative costs)
    // Data: day 0 → $10, day 1 → $5, day 2 → $0 (slope = -5)
    let points: Vec<(f64, f64)> = vec![(0.0, 10.0), (1.0, 5.0), (2.0, 0.0)];
    let n = points.len() as f64;
    let sum_x: f64 = points.iter().map(|p| p.0).sum();
    let sum_y: f64 = points.iter().map(|p| p.1).sum();
    let sum_xy: f64 = points.iter().map(|p| p.0 * p.1).sum();
    let sum_x2: f64 = points.iter().map(|p| p.0.powi(2)).sum();

    let denom = n * sum_x2 - sum_x * sum_x;
    let slope = (n * sum_xy - sum_x * sum_y) / denom;
    let intercept = (sum_y - slope * sum_x) / n;

    assert!((slope - (-5.0)).abs() < 1e-10);
    assert!((intercept - 10.0).abs() < 1e-10);

    // Day 3: 10 + (-5)*3 = -5 → clamped to 0
    let raw = intercept + slope * 3.0;
    assert!(raw < 0.0);
    let clamped = raw.max(0.0);
    assert_eq!(clamped, 0.0);

    // Day 2: 10 + (-5)*2 = 0 → exactly zero
    let raw2 = intercept + slope * 2.0;
    assert!((raw2 - 0.0).abs() < 1e-10);
}

