#[test]
fn alert_cooldown_suppression_logic() {
    use axon::axon_server::FiredAlert;

    let now = 1700000300u64;
    let cooldown_secs = 120u64;
    let cooldown_start = now.saturating_sub(cooldown_secs); // 1700000180

    let history: Vec<FiredAlert> = vec![
        FiredAlert { rule_name: "r1".into(), metric: "error_rate".into(), threshold: 0.1, actual: 0.2, severity: "info".into(), timestamp: 1700000250 }, // within cooldown
        FiredAlert { rule_name: "r2".into(), metric: "latency_avg".into(), threshold: 50.0, actual: 80.0, severity: "warning".into(), timestamp: 1700000100 }, // r2 outside cooldown
        FiredAlert { rule_name: "r1".into(), metric: "error_rate".into(), threshold: 0.1, actual: 0.15, severity: "info".into(), timestamp: 1700000100 }, // r1 outside cooldown
    ];

    // r1 has a fire at 1700000250 which is >= cooldown_start (1700000180) → suppressed
    let r1_in_cooldown = history.iter().rev()
        .any(|fa| fa.rule_name == "r1" && fa.timestamp >= cooldown_start);
    assert!(r1_in_cooldown); // suppressed

    // r2 last fire at 1700000100 < cooldown_start (1700000180) → not suppressed
    let r2_in_cooldown = history.iter().rev()
        .any(|fa| fa.rule_name == "r2" && fa.timestamp >= cooldown_start);
    assert!(!r2_in_cooldown); // not suppressed, fires normally

    // r3 not in history at all → not suppressed
    let r3_in_cooldown = history.iter().rev()
        .any(|fa| fa.rule_name == "r3" && fa.timestamp >= cooldown_start);
    assert!(!r3_in_cooldown);
}

#[test]
fn alert_cooldown_zero_means_no_suppression() {
    use axon::axon_server::FiredAlert;

    let now = 1700000300u64;
    let cooldown_secs = 0u64; // disabled

    let history: Vec<FiredAlert> = vec![
        FiredAlert { rule_name: "r1".into(), metric: "error_rate".into(), threshold: 0.1, actual: 0.2, severity: "info".into(), timestamp: 1700000299 }, // 1 second ago
    ];

    // When cooldown_secs == 0, the check is skipped entirely — never suppressed
    let should_suppress = if cooldown_secs > 0 {
        let cooldown_start = now.saturating_sub(cooldown_secs);
        history.iter().rev().any(|fa| fa.rule_name == "r1" && fa.timestamp >= cooldown_start)
    } else {
        false
    };
    assert!(!should_suppress); // cooldown disabled → fires every time
}

