#[test]
fn alert_silence_expiry_logic() {
    use axon::axon_server::AlertSilence;

    let now = 1700000300u64;

    let silences = vec![
        AlertSilence { rule_name: "r1".into(), created_by: "a".into(), reason: "".into(), created_at: 1700000000, expires_at: 1700000400 }, // active (400 > 300)
        AlertSilence { rule_name: "r2".into(), created_by: "b".into(), reason: "".into(), created_at: 1700000000, expires_at: 1700000200 }, // expired (200 < 300)
        AlertSilence { rule_name: "r3".into(), created_by: "c".into(), reason: "".into(), created_at: 1700000000, expires_at: 0 },          // indefinite (0 = never expires)
    ];

    // Filter active: expires_at == 0 || expires_at > now
    let active: Vec<_> = silences.iter()
        .filter(|si| si.expires_at == 0 || si.expires_at > now)
        .collect();
    assert_eq!(active.len(), 2); // r1 (not yet expired) and r3 (indefinite)
    assert_eq!(active[0].rule_name, "r1");
    assert_eq!(active[1].rule_name, "r3");

    // r2 is expired
    let r2_active = silences.iter().any(|si| si.rule_name == "r2" && (si.expires_at == 0 || si.expires_at > now));
    assert!(!r2_active);

    // Evict expired (same as retain in evaluate handler)
    let mut mutable_silences = silences.clone();
    mutable_silences.retain(|si| si.expires_at == 0 || si.expires_at > now);
    assert_eq!(mutable_silences.len(), 2);
}

#[test]
fn alert_silence_suppression_in_evaluation() {
    use axon::axon_server::AlertSilence;

    let now = 1700000300u64;

    // Simulate silences after eviction (only active)
    let silences = vec![
        AlertSilence { rule_name: "r1".into(), created_by: "admin".into(), reason: "deploy".into(), created_at: 1700000000, expires_at: 1700000600 },
    ];

    // Rules to evaluate
    let rules = vec!["r1", "r2", "r3"];
    let mut suppressed = 0u32;
    let mut evaluated = 0u32;

    for rule_name in &rules {
        if silences.iter().any(|si| si.rule_name == *rule_name) {
            suppressed += 1;
            continue;
        }
        evaluated += 1;
    }

    assert_eq!(suppressed, 1);  // r1 silenced
    assert_eq!(evaluated, 2);   // r2, r3 proceed
}

