#[test]
fn backend_resolve_key_priority() {
    use axon::axon_server::{BackendRegistryEntry, ServerState};
    use axon::axon_server::resolve_backend_key;

    // We can't easily construct a full ServerState in tests, so test the logic inline
    // Priority: server registry key > env var > error

    // Test 1: disabled backend returns error
    let entry = BackendRegistryEntry {
        name: "test_backend".into(),
        api_key: "sk-123".into(),
        enabled: false,
        status: "healthy".into(),
        last_check_at: 0,
        last_check_latency_ms: 0,
        total_calls: 0,
        total_errors: 0,
        total_tokens_input: 0,
        total_tokens_output: 0,
        total_latency_ms: 0,
        last_call_at: 0,
        fallback_chain: vec![],
        consecutive_failures: 0,
        circuit_open_until: 0,
        circuit_breaker_threshold: 5,
        circuit_breaker_cooldown_secs: 60,
        total_cost_usd: 0.0,
        max_rpm: 0, max_tpm: 0, rpm_window_start: 0, rpm_count: 0, tpm_count: 0,
    };
    // Disabled + has key → should still be rejected
    assert!(!entry.enabled);
    assert!(!entry.api_key.is_empty());
    // The resolve logic: if !enabled → error
    let result = if !entry.enabled {
        Err("disabled".to_string())
    } else if !entry.api_key.is_empty() {
        Ok(entry.api_key.clone())
    } else {
        Err("no key".to_string())
    };
    assert!(result.is_err());

    // Test 2: enabled + has key → returns key
    let entry2 = BackendRegistryEntry {
        name: "anthropic".into(),
        api_key: "sk-from-server".into(),
        enabled: true,
        status: "healthy".into(),
        last_check_at: 0,
        last_check_latency_ms: 0,
        total_calls: 0,
        total_errors: 0,
        total_tokens_input: 0,
        total_tokens_output: 0,
        total_latency_ms: 0,
        last_call_at: 0,
        fallback_chain: vec![],
        consecutive_failures: 0,
        circuit_open_until: 0,
        circuit_breaker_threshold: 5,
        circuit_breaker_cooldown_secs: 60,
        total_cost_usd: 0.0,
        max_rpm: 0, max_tpm: 0, rpm_window_start: 0, rpm_count: 0, tpm_count: 0,
    };
    let result2 = if !entry2.enabled {
        Err("disabled".to_string())
    } else if !entry2.api_key.is_empty() {
        Ok(entry2.api_key.clone())
    } else {
        Err("no key".to_string())
    };
    assert_eq!(result2.unwrap(), "sk-from-server");
}

