#[test]
fn backend_key_override_none_vs_some_semantics() {
    // Test the semantics: None means "resolve from env", Some means "use this key directly"
    use axon::backend::BackendError;

    // Simulate the resolution logic from execute_real:
    // api_key = match api_key_override { Some(key) => key, None => get_api_key(backend) }
    let override_some: Option<&str> = Some("sk-override-key");
    let override_none: Option<&str> = None;

    // With Some: always returns the override
    let key_from_some = match override_some {
        Some(key) => Ok(key.to_string()),
        None => Err("would call get_api_key".to_string()),
    };
    assert_eq!(key_from_some.unwrap(), "sk-override-key");

    // With None: would call get_api_key (which reads env)
    let key_from_none = match override_none {
        Some(key) => Ok(key.to_string()),
        None => Err("would call get_api_key".to_string()),
    };
    assert!(key_from_none.is_err()); // falls through to env lookup

    // Unknown backend returns an error mentioning "Supported"
    let unknown_key = axon::backend::get_api_key("nonexistent");
    assert!(unknown_key.is_err());
    assert!(unknown_key.unwrap_err().message.contains("Supported"));
}

