#[test]
fn backend_fallback_chain_validation() {
    // Self-reference should be rejected
    let backend = "anthropic";
    let chain = vec!["openai".to_string(), "anthropic".to_string()];
    let has_self_ref = chain.contains(&backend.to_string());
    assert!(has_self_ref); // would be rejected

    // No self-reference is valid
    let chain2 = vec!["openai".to_string(), "gemini".to_string()];
    let has_self_ref2 = chain2.contains(&backend.to_string());
    assert!(!has_self_ref2); // valid

    // Unknown backend in chain should be rejected
    let supported = axon::backend::SUPPORTED_BACKENDS;
    let chain3 = vec!["openai".to_string(), "nonexistent".to_string()];
    let all_valid = chain3.iter().all(|fb| supported.contains(&fb.as_str()));
    assert!(!all_valid); // "nonexistent" not supported

    // All valid chain
    let chain4 = vec!["openai".to_string(), "gemini".to_string()];
    let all_valid4 = chain4.iter().all(|fb| supported.contains(&fb.as_str()));
    assert!(all_valid4);
}

#[test]
fn backend_fallback_execution_logic() {
    // Simulate fallback: primary fails → try chain in order
    let primary = "anthropic";
    let chain = vec!["openai".to_string(), "gemini".to_string()];

    // Simulate: primary fails, first fallback fails, second succeeds
    let results: Vec<(&str, bool)> = vec![
        (primary, false),           // primary fails
        (&chain[0], false),         // openai fails
        (&chain[1], true),          // gemini succeeds
    ];

    let mut actual_backend = primary;
    let mut succeeded = false;

    // Primary attempt
    if results[0].1 {
        succeeded = true;
    } else {
        // Try fallbacks
        for (i, fb) in chain.iter().enumerate() {
            if results[i + 1].1 {
                actual_backend = fb;
                succeeded = true;
                break;
            }
        }
    }

    assert!(succeeded);
    assert_eq!(actual_backend, "gemini"); // fell through to second fallback

    // All fail scenario
    let results_all_fail: Vec<bool> = vec![false, false, false];
    let mut any_succeeded = false;
    for r in &results_all_fail {
        if *r { any_succeeded = true; break; }
    }
    assert!(!any_succeeded); // returns original error
}

