#[test]
fn circuit_breaker_open_close_logic() {
    // Simulate consecutive failures opening the circuit
    let threshold = 5u32;
    let cooldown_secs = 60u64;
    let now = 1700000000u64;

    let mut consecutive_failures = 0u32;
    let mut circuit_open_until = 0u64;

    // 4 failures — not enough
    for _ in 0..4 {
        consecutive_failures += 1;
    }
    assert_eq!(consecutive_failures, 4);
    assert!(consecutive_failures < threshold);
    assert_eq!(circuit_open_until, 0); // still closed

    // 5th failure — opens circuit
    consecutive_failures += 1;
    if threshold > 0 && consecutive_failures >= threshold {
        circuit_open_until = now + cooldown_secs;
    }
    assert_eq!(consecutive_failures, 5);
    assert_eq!(circuit_open_until, 1700000060);

    // Check at now+30 → still open
    let check_time = now + 30;
    assert!(check_time < circuit_open_until); // open

    // Check at now+61 → cooldown expired, half-open
    let check_time2 = now + 61;
    assert!(check_time2 >= circuit_open_until); // allow through

    // Success resets
    consecutive_failures = 0;
    circuit_open_until = 0;
    assert_eq!(consecutive_failures, 0);
    assert_eq!(circuit_open_until, 0);
}

#[test]
fn circuit_breaker_disabled_when_threshold_zero() {
    // threshold=0 means circuit breaker is disabled
    let threshold = 0u32;
    let mut consecutive_failures = 0u32;
    let mut circuit_open_until = 0u64;
    let now = 1700000000u64;
    let cooldown = 60u64;

    // Even 100 failures don't open the circuit
    for _ in 0..100 {
        consecutive_failures += 1;
        if threshold > 0 && consecutive_failures >= threshold {
            circuit_open_until = now + cooldown;
        }
    }
    assert_eq!(consecutive_failures, 100);
    assert_eq!(circuit_open_until, 0); // still closed — disabled
}

