#[test]
fn mcp_jsonrpc_protocol_shapes() {
    // Verify JSON-RPC 2.0 shapes used by MCP protocol

    // Initialize response shape
    let init_resp = serde_json::json!({
        "jsonrpc": "2.0",
        "id": 1,
        "result": {
            "protocolVersion": "2024-11-05",
            "capabilities": { "tools": { "listChanged": false } },
            "serverInfo": { "name": "axon-server", "version": "0.1.0" }
        }
    });
    assert_eq!(init_resp["jsonrpc"], "2.0");
    assert_eq!(init_resp["result"]["protocolVersion"], "2024-11-05");
    assert_eq!(init_resp["result"]["capabilities"]["tools"]["listChanged"], false);

    // tools/list response shape
    let list_resp = serde_json::json!({
        "jsonrpc": "2.0",
        "id": 2,
        "result": {
            "tools": [{
                "name": "axon_flow1",
                "description": "Execute AXON flow 'flow1' (v1)",
                "inputSchema": {
                    "type": "object",
                    "properties": {
                        "backend": { "type": "string" },
                        "input": { "type": "string" }
                    }
                }
            }]
        }
    });
    let tools = list_resp["result"]["tools"].as_array().unwrap();
    assert_eq!(tools.len(), 1);
    assert_eq!(tools[0]["name"], "axon_flow1");
    assert!(tools[0]["inputSchema"]["properties"].is_object());

    // tools/call response shape (success)
    let call_resp = serde_json::json!({
        "jsonrpc": "2.0",
        "id": 3,
        "result": {
            "content": [{ "type": "text", "text": "Flow output here" }],
            "isError": false,
            "_axon": {
                "flow": "flow1",
                "backend": "stub",
                "epistemic_taint": "speculate",
                "effects": ["io", "epistemic:speculate"],
            }
        }
    });
    let content = call_resp["result"]["content"].as_array().unwrap();
    assert_eq!(content[0]["type"], "text");
    assert_eq!(call_resp["result"]["isError"], false);
    assert_eq!(call_resp["result"]["_axon"]["epistemic_taint"], "speculate");

    // Error response shape
    let err_resp = serde_json::json!({
        "jsonrpc": "2.0",
        "id": 4,
        "error": { "code": -32601, "message": "method 'unknown' not found" }
    });
    assert_eq!(err_resp["error"]["code"], -32601);
}

#[test]
fn mcp_tool_name_prefix_convention() {
    // AXON flows are exposed with "axon_" prefix
    let flow_name = "summarize";
    let tool_name = format!("axon_{}", flow_name);
    assert_eq!(tool_name, "axon_summarize");

    // Stripping prefix to recover flow name
    let recovered = tool_name.strip_prefix("axon_").unwrap_or(&tool_name);
    assert_eq!(recovered, "summarize");

    // If no prefix, fallback to full name
    let raw = "custom_tool";
    let recovered2 = raw.strip_prefix("axon_").unwrap_or(raw);
    assert_eq!(recovered2, "custom_tool");
}

// ── E7 · ℰMCP Formal Compliance ────────────────────────────────────

#[test]
fn emcp_epistemic_envelope_in_mcp_response() {
    use axon::axon_server::EpistemicEnvelope;

    // ΛD: ψ = ⟨T, V, E⟩ where E = ⟨c, τ, ρ, δ⟩
    // MCP tools/call must produce a derived envelope, not raw

    // Case 1: successful execution, no anchor breaches → c=0.85 (speculate)
    let env_success = EpistemicEnvelope::derived("mcp:tool:summarize", 0.85, "emcp:axon_server:summarize:anthropic");
    assert_eq!(env_success.ontology, "mcp:tool:summarize");
    assert!((env_success.certainty - 0.85).abs() < 0.01);
    assert_eq!(env_success.derivation, "derived");
    assert!(env_success.validate().is_ok());
    // Theorem 5.1: derived cannot carry c=1.0
    assert!(env_success.certainty < 1.0);

    // Case 2: success with anchor breaches → c=0.5 (doubt)
    let env_doubt = EpistemicEnvelope::derived("mcp:tool:analyze", 0.5, "emcp:axon_server:analyze:openai");
    assert!((env_doubt.certainty - 0.5).abs() < 0.01);
    assert!(env_doubt.validate().is_ok());

    // Case 3: failure → c=0.1 (near ⊥)
    let env_fail = EpistemicEnvelope::derived("mcp:tool:broken", 0.1, "emcp:axon_server:broken:stub");
    assert!((env_fail.certainty - 0.1).abs() < 0.01);
    assert!(env_fail.validate().is_ok());

    // Invariant: derived envelope NEVER carries c=1.0 (Theorem 5.1)
    let env_raw_attempt = EpistemicEnvelope::derived("mcp:tool:test", 1.0, "test");
    // derived() clamps to 0.99
    assert!(env_raw_attempt.certainty <= 0.99);
    assert!(env_raw_attempt.validate().is_ok());
}

#[test]
fn emcp_blame_calculus_findler_felleisen() {
    use axon::emcp::Blame;

    // CT-2: Caller blame — invalid parameters (flow not found)
    let caller_blame = Blame::Caller;
    assert_eq!(caller_blame.as_str(), "caller");

    // CT-3: Server blame — execution failure
    let server_blame = Blame::Server;
    assert_eq!(server_blame.as_str(), "server");

    // Network blame — infrastructure failure
    let network_blame = Blame::Network;
    assert_eq!(network_blame.as_str(), "network");

    // No blame on success
    let no_blame = Blame::None;
    assert_eq!(no_blame.as_str(), "none");

    // Blame assignment logic for MCP errors
    let error_messages = vec![
        ("Backend error: timeout", "network"),
        ("flow 'x' not found in compiled IR", "server"),
        ("lex error: unexpected token", "server"),
        ("parse error: expected step", "server"),
        ("connection refused", "network"),
    ];

    for (msg, expected_blame) in &error_messages {
        let blame = if msg.contains("Backend error") || msg.contains("timeout") || msg.contains("connect") {
            "network"
        } else if msg.contains("not found") || msg.contains("parse error") || msg.contains("lex error") {
            "server"
        } else {
            "server"
        };
        assert_eq!(blame, *expected_blame, "Wrong blame for: {}", msg);
    }
}

#[test]
fn emcp_csp_effect_row_and_lattice() {
    // §5.3: Tool as CSP — effect rows computed from execution context
    // Effect row format: <io, network?, epistemic:X>

    // Stub backend → no network effect
    let backend_stub = "stub";
    let mut effects_stub = vec!["io".to_string()];
    if backend_stub != "stub" { effects_stub.push("network".into()); }
    effects_stub.push("epistemic:speculate".into());
    assert_eq!(effects_stub, vec!["io", "epistemic:speculate"]);

    // Real backend → includes network effect
    let backend_real = "anthropic";
    let mut effects_real = vec!["io".to_string()];
    if backend_real != "stub" { effects_real.push("network".into()); }
    effects_real.push("epistemic:speculate".into());
    assert_eq!(effects_real, vec!["io", "network", "epistemic:speculate"]);

    // Epistemic lattice: ⊥ ⊑ doubt ⊑ speculate ⊑ believe ⊑ know
    let lattice_levels: Vec<(&str, f64)> = vec![
        ("⊥", 0.1),
        ("doubt", 0.5),
        ("speculate", 0.85),
    ];
    for (expected_level, certainty) in &lattice_levels {
        let level = if *certainty >= 0.85 {
            "speculate"
        } else if *certainty >= 0.5 {
            "doubt"
        } else {
            "⊥"
        };
        assert_eq!(level, *expected_level, "Wrong lattice for c={}", certainty);
    }

    // CSP constraint: anchors bound the output space
    let anchors = vec!["NoHallucination", "FactualOnly", "SafeOutput"];
    assert_eq!(anchors.len(), 3);
    // These would appear in _axon_csp.constraints in tools/list schema
}

