#[test]
fn server_execute_full_records_metrics_on_failure() {
    // Even when execution fails, metrics should be recorded (total_errors increments)
    let success = false;
    let mut total_calls = 5u64;
    let mut total_errors = 1u64;
    let mut consecutive_failures = 2u32;

    // Simulate failed execution recording
    total_calls += 1;
    if !success {
        total_errors += 1;
        consecutive_failures += 1;
    }

    assert_eq!(total_calls, 6);
    assert_eq!(total_errors, 2);
    assert_eq!(consecutive_failures, 3);

    // After enough failures, circuit breaker opens
    let threshold = 5u32;
    assert!(consecutive_failures < threshold); // not yet

    // Two more failures
    for _ in 0..2 {
        total_calls += 1;
        total_errors += 1;
        consecutive_failures += 1;
    }
    assert_eq!(consecutive_failures, 5);
    assert!(consecutive_failures >= threshold); // circuit opens
}

