#[test]
fn backend_cost_computation_from_pricing() {
    // CostPricing: anthropic → $3/M input, $15/M output
    // 1000 input tokens + 500 output tokens:
    //   input cost = 1000 / 1_000_000 * 3.0 = 0.003
    //   output cost = 500 / 1_000_000 * 15.0 = 0.0075
    //   total = 0.0105
    let input_per_million = 3.0f64;
    let output_per_million = 15.0f64;
    let tokens_input = 1000u64;
    let tokens_output = 500u64;

    let cost = (tokens_input as f64 / 1_000_000.0) * input_per_million
             + (tokens_output as f64 / 1_000_000.0) * output_per_million;
    let rounded = (cost * 10000.0).round() / 10000.0;
    assert_eq!(rounded, 0.0105);

    // Accumulated over 100 calls
    let total_cost = rounded * 100.0;
    assert!((total_cost - 1.05).abs() < 0.001);

    // Unknown backend → price 0
    let unknown_price = 0.0f64;
    let unknown_cost = (tokens_input as f64 / 1_000_000.0) * unknown_price
                     + (tokens_output as f64 / 1_000_000.0) * unknown_price;
    assert_eq!(unknown_cost, 0.0);
}

#[test]
fn backend_cost_accumulation_across_calls() {
    // Simulate cost accumulation in record_backend_metrics
    let mut total_cost_usd = 0.0f64;
    let input_price = 3.0f64;  // anthropic
    let output_price = 15.0f64;

    // Call 1: 2000 input, 1000 output
    let cost1 = (2000.0 / 1_000_000.0) * input_price + (1000.0 / 1_000_000.0) * output_price;
    total_cost_usd += (cost1 * 10000.0).round() / 10000.0;
    assert_eq!(total_cost_usd, 0.021);

    // Call 2: 5000 input, 3000 output
    let cost2 = (5000.0 / 1_000_000.0) * input_price + (3000.0 / 1_000_000.0) * output_price;
    total_cost_usd += (cost2 * 10000.0).round() / 10000.0;
    assert!((total_cost_usd - 0.081).abs() < 0.001);

    // Call 3: stub backend (price 0)
    let cost3: f64 = (10000.0 / 1_000_000.0) * 0.0 + (5000.0 / 1_000_000.0) * 0.0;
    total_cost_usd += (cost3 * 10000.0).round() / 10000.0;
    assert!((total_cost_usd - 0.081).abs() < 0.001); // unchanged — stub is free
}

