#[test]
fn backend_selection_strategies() {
    // Simulate 3 backends with different profiles
    // A: cheap but slow (cost 0.001, latency 2000ms, errors 1%)
    // B: fast but expensive (cost 0.05, latency 200ms, errors 2%)
    // C: balanced (cost 0.01, latency 500ms, errors 0.5%)

    let backends = vec![
        ("A", 0.001f64, 2000.0f64, 0.01f64),
        ("B", 0.05, 200.0, 0.02),
        ("C", 0.01, 500.0, 0.005),
    ];

    // Strategy: cheapest → A wins (lowest cost per call)
    let mut cheapest: Vec<(&str, f64)> = backends.iter().map(|(name, cost, _, _)| {
        (*name, (100.0 - cost * 1000.0).max(0.0))
    }).collect();
    cheapest.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap());
    assert_eq!(cheapest[0].0, "A"); // cheapest

    // Strategy: fastest → B wins (lowest latency)
    let mut fastest: Vec<(&str, f64)> = backends.iter().map(|(name, _, lat, _)| {
        (*name, (100.0 - lat / 50.0).max(0.0))
    }).collect();
    fastest.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap());
    assert_eq!(fastest[0].0, "B"); // fastest

    // Strategy: most_reliable → C wins (lowest error rate)
    let mut reliable: Vec<(&str, f64)> = backends.iter().map(|(name, _, _, err)| {
        (*name, (1.0 - err) * 100.0)
    }).collect();
    reliable.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap());
    assert_eq!(reliable[0].0, "C"); // most reliable

    // Strategy: balanced → C wins (best composite)
    let mut balanced: Vec<(&str, f64)> = backends.iter().map(|(name, cost, lat, err)| {
        let r = (1.0 - err) * 100.0;
        let s = (100.0 - lat / 50.0).max(0.0);
        let c = (100.0 - cost * 1000.0).max(0.0);
        (*name, r * 0.4 + s * 0.3 + c * 0.3)
    }).collect();
    balanced.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap());
    assert_eq!(balanced[0].0, "C"); // balanced winner
}

#[test]
fn backend_selection_circuit_open_excluded() {
    // Circuit-open backends get score 0 — never selected
    let circuit_open = true;
    let base_score = if circuit_open { 0.0 } else { 100.0 };
    assert_eq!(base_score, 0.0);

    // A healthy backend with any metrics beats a circuit-open one
    let healthy_score = 50.0; // even mediocre
    assert!(healthy_score > base_score);

    // No enabled backends → error response
    let scores: Vec<f64> = vec![]; // empty registry
    assert!(scores.is_empty());
    let selected = scores.first();
    assert!(selected.is_none()); // "no enabled backends with metrics available"
}

// ── F4 · Auto-backend in execute ────────────────────────────────────

#[test]
fn auto_backend_resolves_to_best() {
    // When backend="auto", the system selects the highest-scoring backend
    let backend_input = "auto";
    let is_auto = backend_input == "auto";
    assert!(is_auto);

    // Simulate: 2 backends in registry, balanced strategy
    // anthropic: 100 calls, 2% errors, 500ms avg, $0.02/call
    // openai: 80 calls, 5% errors, 300ms avg, $0.01/call
    let anthropic_score: f64 = {
        let r: f64 = (1.0 - 0.02) * 100.0;  // 98.0
        let s: f64 = (100.0f64 - 500.0 / 50.0).max(0.0);  // 90.0
        let c: f64 = (100.0f64 - 0.02 * 1000.0).max(0.0);  // 80.0
        r * 0.4 + s * 0.3 + c * 0.3  // 39.2 + 27.0 + 24.0 = 90.2
    };
    let openai_score: f64 = {
        let r: f64 = (1.0 - 0.05) * 100.0;  // 95.0
        let s: f64 = (100.0f64 - 300.0 / 50.0).max(0.0);  // 94.0
        let c: f64 = (100.0f64 - 0.01 * 1000.0).max(0.0);  // 90.0
        r * 0.4 + s * 0.3 + c * 0.3  // 38.0 + 28.2 + 27.0 = 93.2
    };

    let selected = if anthropic_score > openai_score { "anthropic" } else { "openai" };
    assert_eq!(selected, "openai"); // openai wins balanced
}

#[test]
fn auto_backend_fallback_to_stub_when_empty() {
    // If no backends are registered/enabled, "auto" falls back to "stub"
    let scores: Vec<(&str, f64)> = vec![]; // empty registry
    let selected = scores.first().map(|s| s.0).unwrap_or("stub");
    assert_eq!(selected, "stub");

    // If only circuit-open backends exist, all score 0
    let scores2: Vec<(&str, f64)> = vec![("anthropic", 0.0), ("openai", 0.0)];
    let best = scores2.first().unwrap();
    // Score 0 means circuit-open — should still return something but not ideal
    assert_eq!(best.1, 0.0);
}

#[test]
fn auto_backend_propagates_through_all_handlers() {
    // "auto" works in server_execute_full which is used by all 16 handlers
    // The auto-resolution happens at the top of server_execute_full,
    // before resolve_backend_key and execute_with_fallback

    // Verify the resolution chain:
    // 1. backend="auto" → compute_backend_scores("balanced") → best.name
    // 2. effective_backend used in resolve_backend_key → key
    // 3. effective_backend used in execute_with_fallback → fallback chain
    // 4. actual_backend used in record_backend_metrics → cost tracking

    let backend = "auto";
    let effective = if backend == "auto" { "anthropic" } else { backend }; // simulated selection
    assert_eq!(effective, "anthropic");

    // The effective backend is what gets passed to all downstream functions
    // This means fallback chain is looked up for "anthropic", not "auto"
    assert_ne!(effective, "auto");

    // Primary execute_handler also supports "auto" independently
    // (resolves inside its lock scope before calling execute_with_fallback)
    let payload_backend = "auto";
    let handler_effective = if payload_backend == "auto" { "openai" } else { payload_backend };
    assert_ne!(handler_effective, "auto");
}

