#[test]
fn test_backend_dashboard_fleet_aggregation() {
    use axon::axon_server::BackendRegistryEntry;
    // Simulate fleet-wide aggregation across multiple backends
    let backends = vec![
        BackendRegistryEntry {
            name: "anthropic".into(),
            api_key: "sk-1".into(),
            enabled: true,
            status: "healthy".into(),
            last_check_at: 1700000000,
            last_check_latency_ms: 200,
            total_calls: 100,
            total_errors: 3,
            total_tokens_input: 50000,
            total_tokens_output: 20000,
            total_latency_ms: 30000,
            last_call_at: 1700000000,
            fallback_chain: vec!["openai".into()],
            consecutive_failures: 0,
            circuit_open_until: 0,
            circuit_breaker_threshold: 5,
            circuit_breaker_cooldown_secs: 60,
            total_cost_usd: 1.25,
            max_rpm: 60, max_tpm: 100000, rpm_window_start: 0, rpm_count: 0, tpm_count: 0,
        },
        BackendRegistryEntry {
            name: "openai".into(),
            api_key: "sk-2".into(),
            enabled: true,
            status: "healthy".into(),
            last_check_at: 1700000000,
            last_check_latency_ms: 300,
            total_calls: 50,
            total_errors: 1,
            total_tokens_input: 25000,
            total_tokens_output: 10000,
            total_latency_ms: 20000,
            last_call_at: 1700000000,
            fallback_chain: vec![],
            consecutive_failures: 0,
            circuit_open_until: 0,
            circuit_breaker_threshold: 5,
            circuit_breaker_cooldown_secs: 60,
            total_cost_usd: 0.75,
            max_rpm: 0, max_tpm: 0, rpm_window_start: 0, rpm_count: 0, tpm_count: 0,
        },
    ];

    // Fleet aggregation logic (mirrors handler)
    let fleet_total_calls: u64 = backends.iter().map(|b| b.total_calls).sum();
    let fleet_total_errors: u64 = backends.iter().map(|b| b.total_errors).sum();
    let fleet_total_cost: f64 = backends.iter().map(|b| b.total_cost_usd).sum();
    let fleet_total_tokens_input: u64 = backends.iter().map(|b| b.total_tokens_input).sum();
    let fleet_total_tokens_output: u64 = backends.iter().map(|b| b.total_tokens_output).sum();
    let fleet_total_latency: u64 = backends.iter().map(|b| b.total_latency_ms).sum();

    assert_eq!(fleet_total_calls, 150);
    assert_eq!(fleet_total_errors, 4);
    assert!((fleet_total_cost - 2.0).abs() < 0.001);
    assert_eq!(fleet_total_tokens_input, 75000);
    assert_eq!(fleet_total_tokens_output, 30000);
    assert_eq!(fleet_total_latency, 50000);

    let fleet_avg_latency = fleet_total_latency as f64 / fleet_total_calls as f64;
    assert!((fleet_avg_latency - 333.33).abs() < 1.0);

    let fleet_error_rate = fleet_total_errors as f64 / fleet_total_calls as f64;
    assert!((fleet_error_rate - 0.0267).abs() < 0.001);
}

#[test]
fn test_backend_dashboard_circuit_state_classification() {
    use axon::axon_server::BackendRegistryEntry;
    let now = 1700000100u64;

    // Closed: no failures
    let closed = BackendRegistryEntry {
        name: "healthy_backend".into(),
        api_key: "".into(),
        enabled: true,
        status: "healthy".into(),
        last_check_at: 0, last_check_latency_ms: 0,
        total_calls: 50, total_errors: 0,
        total_tokens_input: 10000, total_tokens_output: 5000,
        total_latency_ms: 5000, last_call_at: 0,
        fallback_chain: vec![],
        consecutive_failures: 0,
        circuit_open_until: 0,
        circuit_breaker_threshold: 5,
        circuit_breaker_cooldown_secs: 60,
        total_cost_usd: 0.0,
        max_rpm: 0, max_tpm: 0, rpm_window_start: 0, rpm_count: 0, tpm_count: 0,
    };

    // Open: circuit_open_until in the future
    let open = BackendRegistryEntry {
        name: "broken_backend".into(),
        api_key: "".into(),
        enabled: true,
        status: "degraded".into(),
        last_check_at: 0, last_check_latency_ms: 0,
        total_calls: 30, total_errors: 10,
        total_tokens_input: 5000, total_tokens_output: 2000,
        total_latency_ms: 15000, last_call_at: 0,
        fallback_chain: vec![],
        consecutive_failures: 5,
        circuit_open_until: now + 60, // opens 60s from now
        circuit_breaker_threshold: 5,
        circuit_breaker_cooldown_secs: 60,
        total_cost_usd: 0.0,
        max_rpm: 0, max_tpm: 0, rpm_window_start: 0, rpm_count: 0, tpm_count: 0,
    };

    // Half-open: has failures but circuit not open
    let half_open = BackendRegistryEntry {
        name: "recovering_backend".into(),
        api_key: "".into(),
        enabled: true,
        status: "healthy".into(),
        last_check_at: 0, last_check_latency_ms: 0,
        total_calls: 20, total_errors: 3,
        total_tokens_input: 3000, total_tokens_output: 1000,
        total_latency_ms: 4000, last_call_at: 0,
        fallback_chain: vec![],
        consecutive_failures: 2,
        circuit_open_until: 0,
        circuit_breaker_threshold: 5,
        circuit_breaker_cooldown_secs: 60,
        total_cost_usd: 0.0,
        max_rpm: 0, max_tpm: 0, rpm_window_start: 0, rpm_count: 0, tpm_count: 0,
    };

    // Classify circuit state (same logic as handler)
    let classify = |e: &BackendRegistryEntry| -> &str {
        let circuit_open = e.circuit_open_until > 0 && now < e.circuit_open_until;
        if circuit_open { "open" }
        else if e.consecutive_failures > 0 { "half-open" }
        else { "closed" }
    };

    assert_eq!(classify(&closed), "closed");
    assert_eq!(classify(&open), "open");
    assert_eq!(classify(&half_open), "half-open");

    // Fleet counts
    let all = vec![&closed, &open, &half_open];
    let enabled_count = all.iter().filter(|b| b.enabled).count();
    let circuit_open_count = all.iter().filter(|b| {
        b.circuit_open_until > 0 && now < b.circuit_open_until
    }).count();
    let degraded_count = all.iter().filter(|b| b.status == "degraded").count();

    assert_eq!(enabled_count, 3);
    assert_eq!(circuit_open_count, 1);
    assert_eq!(degraded_count, 1);
}

#[test]
fn test_backend_dashboard_rate_limit_remaining() {
    use axon::axon_server::BackendRegistryEntry;
    let now = 1700000050u64; // 50s into a window that started at 1700000000

    let entry = BackendRegistryEntry {
        name: "rate_limited_backend".into(),
        api_key: "".into(),
        enabled: true,
        status: "healthy".into(),
        last_check_at: 0, last_check_latency_ms: 0,
        total_calls: 40, total_errors: 0,
        total_tokens_input: 20000, total_tokens_output: 8000,
        total_latency_ms: 8000, last_call_at: now,
        fallback_chain: vec![],
        consecutive_failures: 0,
        circuit_open_until: 0,
        circuit_breaker_threshold: 5,
        circuit_breaker_cooldown_secs: 60,
        total_cost_usd: 0.50,
        max_rpm: 60, max_tpm: 100000,
        rpm_window_start: 1700000000,
        rpm_count: 40,
        tpm_count: 28000,
    };

    // Dashboard rate-limit remaining computation (mirrors handler)
    let in_window = now.saturating_sub(entry.rpm_window_start) < 60;
    assert!(in_window); // 50s < 60s

    let rpm_remaining = if entry.max_rpm > 0 {
        if in_window { entry.max_rpm.saturating_sub(entry.rpm_count) } else { entry.max_rpm }
    } else {
        0
    };
    let tpm_remaining = if entry.max_tpm > 0 {
        if in_window { entry.max_tpm.saturating_sub(entry.tpm_count) } else { entry.max_tpm }
    } else {
        0
    };

    assert_eq!(rpm_remaining, 20);  // 60 - 40
    assert_eq!(tpm_remaining, 72000); // 100000 - 28000

    // Window expired scenario
    let now_expired = 1700000061u64; // 61s > 60s window
    let in_window2 = now_expired.saturating_sub(entry.rpm_window_start) < 60;
    assert!(!in_window2);

    let rpm_remaining_reset = if in_window2 { entry.max_rpm.saturating_sub(entry.rpm_count) } else { entry.max_rpm };
    let tpm_remaining_reset = if in_window2 { entry.max_tpm.saturating_sub(entry.tpm_count) } else { entry.max_tpm };
    assert_eq!(rpm_remaining_reset, 60);    // full capacity after reset
    assert_eq!(tpm_remaining_reset, 100000); // full capacity after reset
}

