#[test]
fn test_axonstore_persist_retrieve_with_epistemic_envelope() {
    use axon::axon_server::{AxonStoreInstance, AxonStoreEntry, EpistemicEnvelope};
    use std::collections::HashMap;

    let mut store = AxonStoreInstance {
        name: "knowledge".into(),
        ontology: "facts".into(),
        entries: HashMap::new(),
        created_at: 1700000000,
        total_ops: 0,
    };

    // persist: c=1.0, δ=raw (direct write)
    let envelope = EpistemicEnvelope::raw_config("facts", "test_client");
    assert_eq!(envelope.certainty, 1.0);
    assert_eq!(envelope.derivation, "raw");
    assert!(envelope.validate().is_ok()); // ΛD invariants hold

    let entry = AxonStoreEntry {
        key: "earth_radius_km".into(),
        value: serde_json::json!(6371),
        envelope,
        created_at: 1700000000,
        updated_at: 1700000000,
        version: 1,
    };

    store.entries.insert("earth_radius_km".into(), entry);
    store.total_ops += 1;

    // Retrieve
    let retrieved = store.entries.get("earth_radius_km").unwrap();
    assert_eq!(retrieved.value, serde_json::json!(6371));
    assert_eq!(retrieved.version, 1);
    assert_eq!(retrieved.envelope.certainty, 1.0);
    assert_eq!(retrieved.envelope.derivation, "raw");
    assert_eq!(retrieved.envelope.ontology, "facts");
    assert_eq!(store.total_ops, 1);
}

#[test]
fn test_axonstore_mutate_degrades_certainty_theorem_5_1() {
    use axon::axon_server::{AxonStoreInstance, AxonStoreEntry, EpistemicEnvelope};
    use std::collections::HashMap;

    let mut store = AxonStoreInstance {
        name: "observations".into(),
        ontology: "measurements".into(),
        entries: HashMap::new(),
        created_at: 1700000000,
        total_ops: 0,
    };

    // Initial persist: raw, c=1.0
    let raw_env = EpistemicEnvelope::raw_config("measurements", "sensor_a");
    let entry = AxonStoreEntry {
        key: "temperature".into(),
        value: serde_json::json!(22.5),
        envelope: raw_env,
        created_at: 1700000000,
        updated_at: 1700000000,
        version: 1,
    };
    store.entries.insert("temperature".into(), entry);
    store.total_ops += 1;

    // Mutate: Theorem 5.1 — derived values MUST have c ≤ 0.99
    let derived_env = EpistemicEnvelope::derived("measurements", 0.99, "analyst_b");
    assert_eq!(derived_env.certainty, 0.99);
    assert_eq!(derived_env.derivation, "derived");
    assert!(derived_env.validate().is_ok());

    // Attempting c=1.0 with δ=derived MUST fail Theorem 5.1
    let bad_env = EpistemicEnvelope {
        ontology: "measurements".into(),
        certainty: 1.0,
        temporal_start: "0".into(),
        temporal_end: "∞".into(),
        provenance: "bad_actor".into(),
        derivation: "derived".into(),
    };
    let validation = bad_env.validate();
    assert!(validation.is_err());
    assert!(validation.unwrap_err().contains("Theorem 5.1"));

    // Apply mutation to entry
    if let Some(e) = store.entries.get_mut("temperature") {
        e.value = serde_json::json!(23.1);
        e.version += 1;
        e.updated_at = 1700000100;
        e.envelope = derived_env;
        store.total_ops += 1;
    }

    let mutated = store.entries.get("temperature").unwrap();
    assert_eq!(mutated.value, serde_json::json!(23.1));
    assert_eq!(mutated.version, 2);
    assert_eq!(mutated.envelope.certainty, 0.99); // degraded per Theorem 5.1
    assert_eq!(mutated.envelope.derivation, "derived");
    assert_eq!(store.total_ops, 2);
}

#[test]
fn test_axonstore_transact_batch_and_purge() {
    use axon::axon_server::{AxonStoreInstance, AxonStoreEntry, AxonStoreTransactOp, EpistemicEnvelope};
    use std::collections::HashMap;

    let mut store = AxonStoreInstance {
        name: "workspace".into(),
        ontology: "project_data".into(),
        entries: HashMap::new(),
        created_at: 1700000000,
        total_ops: 0,
    };

    // Simulate transact: persist 3 entries atomically
    let ops = vec![
        AxonStoreTransactOp { op: "persist".into(), key: "alpha".into(), value: serde_json::json!(1) },
        AxonStoreTransactOp { op: "persist".into(), key: "beta".into(), value: serde_json::json!(2) },
        AxonStoreTransactOp { op: "persist".into(), key: "gamma".into(), value: serde_json::json!(3) },
    ];

    // Validate all ops first (all-or-nothing)
    let all_valid = ops.iter().all(|op| match op.op.as_str() {
        "persist" => !op.key.is_empty(),
        "mutate" => !op.key.is_empty() && store.entries.contains_key(&op.key),
        "purge" => !op.key.is_empty() && store.entries.contains_key(&op.key),
        _ => false,
    });
    assert!(all_valid);

    // Apply
    for op in &ops {
        if op.op == "persist" {
            let envelope = EpistemicEnvelope::raw_config("project_data", "batch");
            store.entries.insert(op.key.clone(), AxonStoreEntry {
                key: op.key.clone(),
                value: op.value.clone(),
                envelope,
                created_at: 1700000000,
                updated_at: 1700000000,
                version: 1,
            });
            store.total_ops += 1;
        }
    }

    assert_eq!(store.entries.len(), 3);
    assert_eq!(store.total_ops, 3);

    // Now transact: mutate alpha, purge beta
    let entry_exists = store.entries.contains_key("alpha") && store.entries.contains_key("beta");
    assert!(entry_exists);

    // Mutate alpha
    if let Some(e) = store.entries.get_mut("alpha") {
        e.value = serde_json::json!(100);
        e.version += 1;
        e.envelope = EpistemicEnvelope::derived("project_data", 0.99, "batch");
        store.total_ops += 1;
    }

    // Purge beta
    store.entries.remove("beta");
    store.total_ops += 1;

    assert_eq!(store.entries.len(), 2); // alpha + gamma
    assert_eq!(store.total_ops, 5); // 3 persists + 1 mutate + 1 purge
    assert!(store.entries.contains_key("alpha"));
    assert!(!store.entries.contains_key("beta"));
    assert!(store.entries.contains_key("gamma"));

    let alpha = store.entries.get("alpha").unwrap();
    assert_eq!(alpha.value, serde_json::json!(100));
    assert_eq!(alpha.version, 2);
    assert_eq!(alpha.envelope.certainty, 0.99); // Theorem 5.1
}

