#[test]
fn test_dataspace_ingest_focus_with_epistemic_envelopes() {
    use axon::axon_server::{DataspaceInstance, DataspaceEntry, EpistemicEnvelope};
    use std::collections::HashMap;

    let mut ds = DataspaceInstance {
        name: "research".into(),
        ontology: "scientific".into(),
        entries: HashMap::new(),
        associations: Vec::new(),
        created_at: 1700000000,
        total_ops: 0,
        next_id: 1,
    };

    // Ingest 3 entries with different ontologies and tags
    let items = vec![
        ("observation", serde_json::json!({"temp": 22.5, "unit": "C"}), vec!["sensor", "lab_a"]),
        ("observation", serde_json::json!({"temp": 23.1, "unit": "C"}), vec!["sensor", "lab_b"]),
        ("hypothesis", serde_json::json!({"claim": "temp rising"}), vec!["analysis"]),
    ];

    for (ont, data, tags) in &items {
        let id = format!("ds_research_{}", ds.next_id);
        ds.next_id += 1;

        // ΛD: ingest = raw → c=1.0, δ=raw
        let envelope = EpistemicEnvelope::raw_config(ont, "researcher_a");
        assert_eq!(envelope.certainty, 1.0);
        assert_eq!(envelope.derivation, "raw");

        let entry = DataspaceEntry {
            id: id.clone(),
            ontology: ont.to_string(),
            data: data.clone(),
            envelope,
            ingested_at: 1700000000,
            tags: tags.iter().map(|t| t.to_string()).collect(),
        };
        ds.entries.insert(id, entry);
        ds.total_ops += 1;
    }

    assert_eq!(ds.entries.len(), 3);
    assert_eq!(ds.total_ops, 3);

    // Focus: filter by ontology "observation"
    let focused: Vec<&DataspaceEntry> = ds.entries.values()
        .filter(|e| e.ontology == "observation")
        .collect();
    assert_eq!(focused.len(), 2);

    // Focus: filter by tag "lab_a"
    let lab_a: Vec<&DataspaceEntry> = ds.entries.values()
        .filter(|e| e.tags.contains(&"lab_a".to_string()))
        .collect();
    assert_eq!(lab_a.len(), 1);
    assert_eq!(lab_a[0].data["temp"], 22.5);

    // All raw entries should have c=1.0
    for entry in ds.entries.values() {
        assert_eq!(entry.envelope.certainty, 1.0);
        assert_eq!(entry.envelope.derivation, "raw");
        assert!(entry.envelope.validate().is_ok());
    }
}

#[test]
fn test_dataspace_associate_and_explore() {
    use axon::axon_server::{DataspaceInstance, DataspaceEntry, DataspaceAssociation, EpistemicEnvelope};
    use std::collections::HashMap;

    let mut ds = DataspaceInstance {
        name: "knowledge_graph".into(),
        ontology: "concepts".into(),
        entries: HashMap::new(),
        associations: Vec::new(),
        created_at: 1700000000,
        total_ops: 0,
        next_id: 1,
    };

    // Ingest 3 concept entries
    for (i, concept) in ["gravity", "mass", "acceleration"].iter().enumerate() {
        let id = format!("ds_kg_{}", i + 1);
        ds.entries.insert(id.clone(), DataspaceEntry {
            id,
            ontology: "physics".into(),
            data: serde_json::json!({"concept": concept}),
            envelope: EpistemicEnvelope::raw_config("physics", "textbook"),
            ingested_at: 1700000000,
            tags: vec!["mechanics".into()],
        });
    }

    // Associate: gravity → mass (causes), gravity → acceleration (causes)
    // ΛD: association certainty clamped to [0, 0.99] — associations are derived knowledge
    let assoc1 = DataspaceAssociation {
        from: "ds_kg_1".into(),
        to: "ds_kg_2".into(),
        relation: "relates_to".into(),
        certainty: 0.95f64.clamp(0.0, 0.99),
        created_at: 1700000000,
    };
    let assoc2 = DataspaceAssociation {
        from: "ds_kg_1".into(),
        to: "ds_kg_3".into(),
        relation: "causes".into(),
        certainty: 0.99f64.clamp(0.0, 0.99),
        created_at: 1700000000,
    };
    ds.associations.push(assoc1);
    ds.associations.push(assoc2);
    ds.total_ops += 2;

    assert_eq!(ds.associations.len(), 2);
    assert_eq!(ds.associations[0].certainty, 0.95);
    assert_eq!(ds.associations[1].certainty, 0.99);

    // Explore: ontology distribution
    let mut ontology_counts: HashMap<&str, u64> = HashMap::new();
    for entry in ds.entries.values() {
        *ontology_counts.entry(&entry.ontology).or_insert(0) += 1;
    }
    assert_eq!(ontology_counts["physics"], 3);

    // Explore: relation types
    let mut relation_counts: HashMap<&str, u64> = HashMap::new();
    for assoc in &ds.associations {
        *relation_counts.entry(&assoc.relation).or_insert(0) += 1;
    }
    assert_eq!(relation_counts["relates_to"], 1);
    assert_eq!(relation_counts["causes"], 1);

    // Explore: epistemic summary
    let certainties: Vec<f64> = ds.entries.values().map(|e| e.envelope.certainty).collect();
    let avg_certainty = certainties.iter().sum::<f64>() / certainties.len() as f64;
    assert_eq!(avg_certainty, 1.0); // all raw ingestions
}

#[test]
fn test_dataspace_aggregate_operations() {
    use axon::axon_server::{DataspaceInstance, DataspaceEntry, EpistemicEnvelope};
    use std::collections::HashMap;

    let mut ds = DataspaceInstance {
        name: "metrics".into(),
        ontology: "measurements".into(),
        entries: HashMap::new(),
        associations: Vec::new(),
        created_at: 1700000000,
        total_ops: 0,
        next_id: 1,
    };

    // Ingest measurement entries with numeric scores
    let scores = [85.0, 92.0, 78.0, 95.0, 88.0];
    for (i, &score) in scores.iter().enumerate() {
        let id = format!("ds_metrics_{}", i + 1);
        ds.entries.insert(id.clone(), DataspaceEntry {
            id,
            ontology: "measurement".into(),
            data: serde_json::json!({"score": score, "label": format!("test_{}", i + 1)}),
            envelope: EpistemicEnvelope::raw_config("measurement", "evaluator"),
            ingested_at: 1700000000,
            tags: vec!["exam".into()],
        });
    }

    // Aggregate: count
    let count = ds.entries.values()
        .filter(|e| e.ontology == "measurement")
        .count();
    assert_eq!(count, 5);

    // Aggregate: sum
    let sum: f64 = ds.entries.values()
        .filter_map(|e| e.data.get("score").and_then(|v| v.as_f64()))
        .sum();
    assert!((sum - 438.0).abs() < 0.001);

    // Aggregate: avg
    let values: Vec<f64> = ds.entries.values()
        .filter_map(|e| e.data.get("score").and_then(|v| v.as_f64()))
        .collect();
    let avg = values.iter().sum::<f64>() / values.len() as f64;
    assert!((avg - 87.6).abs() < 0.001);

    // Aggregate: min/max
    let min = values.iter().cloned().fold(f64::INFINITY, f64::min);
    let max = values.iter().cloned().fold(f64::NEG_INFINITY, f64::max);
    assert_eq!(min, 78.0);
    assert_eq!(max, 95.0);

    // ΛD: aggregation results are derived (c ≤ 0.99, δ = aggregated)
    // The handler wraps results with result_envelope confirming this
    let derived_env = EpistemicEnvelope::derived("measurement", 0.99, "aggregator");
    assert_eq!(derived_env.certainty, 0.99);
    assert_eq!(derived_env.derivation, "derived");
    assert!(derived_env.validate().is_ok());
}

