#[test]
fn test_emcp_dataspace_tool_name_parsing() {
    // Tool names follow pattern: axon_ds_{dataspace_name}_{op}
    // The handler uses rfind('_') to split name from op.

    let tool_names = vec![
        ("axon_ds_research_ingest", "research", "ingest"),
        ("axon_ds_knowledge_graph_focus", "knowledge_graph", "focus"),
        ("axon_ds_metrics_aggregate", "metrics", "aggregate"),
    ];

    for (full_name, expected_ds, expected_op) in &tool_names {
        let ds_suffix = full_name.strip_prefix("axon_ds_").unwrap();
        let pos = ds_suffix.rfind('_').unwrap();
        let ds_name = &ds_suffix[..pos];
        let op = &ds_suffix[pos+1..];
        assert_eq!(ds_name, *expected_ds, "name parse failed for {}", full_name);
        assert_eq!(op, *expected_op, "op parse failed for {}", full_name);
    }
}

#[test]
fn test_emcp_dataspace_tool_csp_schemas() {
    // Verify CSP §5.3 schema structure for each dataspace tool type.
    // Each tool must have: inputSchema with _axon_csp (constraints, effect_row, output_taint)

    // Ingest schema
    let ingest_schema = serde_json::json!({
        "type": "object",
        "properties": {
            "ontology": { "type": "string", "default": "general" },
            "data": {},
            "tags": { "type": "array", "items": { "type": "string" } }
        },
        "required": ["data"],
        "_axon_csp": {
            "constraints": ["ontology ∈ general"],
            "effect_row": "<io, epistemic:know>",
            "output_taint": "Raw",
        }
    });

    assert!(ingest_schema["_axon_csp"]["constraints"].is_array());
    assert_eq!(ingest_schema["_axon_csp"]["effect_row"], "<io, epistemic:know>");
    assert_eq!(ingest_schema["_axon_csp"]["output_taint"], "Raw");
    assert!(ingest_schema["required"].as_array().unwrap().contains(&serde_json::json!("data")));

    // Focus schema — derived output
    let focus_csp = serde_json::json!({
        "constraints": ["result ⊆ dataspace", "Theorem 5.1: derived"],
        "effect_row": "<io, epistemic:speculate>",
        "output_taint": "Uncertainty",
    });
    assert_eq!(focus_csp["output_taint"], "Uncertainty");
    assert!(focus_csp["constraints"].as_array().unwrap().iter()
        .any(|c| c.as_str().unwrap().contains("Theorem 5.1")));

    // Aggregate schema — aggregated output
    let agg_csp = serde_json::json!({
        "constraints": ["op ∈ {count,sum,avg,min,max}", "Theorem 5.1: aggregated"],
        "effect_row": "<io, epistemic:speculate>",
        "output_taint": "Uncertainty",
    });
    assert_eq!(agg_csp["effect_row"], "<io, epistemic:speculate>");
    assert!(agg_csp["constraints"].as_array().unwrap().iter()
        .any(|c| c.as_str().unwrap().contains("count,sum,avg,min,max")));
}

#[test]
fn test_emcp_dataspace_tool_call_epistemic_envelopes() {
    use axon::axon_server::EpistemicEnvelope;

    // Ingest tool call: ΛD = raw, c=1.0, lattice = know
    let ingest_envelope = EpistemicEnvelope::raw_config("observation", "mcp_client");
    assert_eq!(ingest_envelope.certainty, 1.0);
    assert_eq!(ingest_envelope.derivation, "raw");
    assert!(ingest_envelope.validate().is_ok());
    // Lattice: "know" for raw ingestion
    let ingest_lattice = "know";
    assert_eq!(ingest_lattice, "know");

    // Focus tool call: ΛD = derived, c=0.99, lattice = speculate
    let focus_envelope = EpistemicEnvelope::derived("observation", 0.99, "mcp_focus");
    assert_eq!(focus_envelope.certainty, 0.99);
    assert_eq!(focus_envelope.derivation, "derived");
    assert!(focus_envelope.validate().is_ok());
    let focus_lattice = "speculate";
    assert_eq!(focus_lattice, "speculate");

    // Aggregate tool call: ΛD = derived, c=0.99, lattice = speculate
    let agg_envelope = EpistemicEnvelope::derived("measurement", 0.99, "mcp_aggregate");
    assert_eq!(agg_envelope.certainty, 0.99);
    assert_eq!(agg_envelope.derivation, "derived");
    let agg_lattice = "speculate";
    assert_eq!(agg_lattice, "speculate");

    // Effect rows per operation
    let ingest_effects = vec!["io", "epistemic:know"];
    let focus_effects = vec!["io", "epistemic:speculate"];
    let agg_effects = vec!["io", "epistemic:speculate"];

    assert!(ingest_effects.contains(&"epistemic:know"));
    assert!(focus_effects.contains(&"epistemic:speculate"));
    assert!(agg_effects.contains(&"epistemic:speculate"));

    // Theorem 5.1 enforcement: derived cannot have c=1.0
    let bad = EpistemicEnvelope {
        ontology: "test".into(),
        certainty: 1.0,
        temporal_start: "0".into(),
        temporal_end: "∞".into(),
        provenance: "bad".into(),
        derivation: "derived".into(),
    };
    assert!(bad.validate().is_err());
}

