#[test]
fn test_server_backup_includes_axon_stores_and_dataspaces() {
    use axon::axon_server::{ServerBackup, EpistemicEnvelope, CostPricing, ReadinessGates,
        AxonStoreInstance, AxonStoreEntry, DataspaceInstance, DataspaceEntry};
    use std::collections::HashMap;

    let mut axon_stores = HashMap::new();
    let mut store = AxonStoreInstance {
        name: "facts".into(),
        ontology: "knowledge".into(),
        entries: HashMap::new(),
        created_at: 1700000000,
        total_ops: 1,
    };
    store.entries.insert("pi".into(), AxonStoreEntry {
        key: "pi".into(),
        value: serde_json::json!(3.14159),
        envelope: EpistemicEnvelope::raw_config("knowledge", "admin"),
        created_at: 1700000000,
        updated_at: 1700000000,
        version: 1,
    });
    axon_stores.insert("facts".into(), store);

    let mut dataspaces = HashMap::new();
    let mut ds = DataspaceInstance {
        name: "research".into(),
        ontology: "science".into(),
        entries: HashMap::new(),
        associations: Vec::new(),
        created_at: 1700000000,
        total_ops: 1,
        next_id: 2,
    };
    ds.entries.insert("ds_research_1".into(), DataspaceEntry {
        id: "ds_research_1".into(),
        ontology: "observation".into(),
        data: serde_json::json!({"temp": 22.5}),
        envelope: EpistemicEnvelope::raw_config("observation", "sensor"),
        ingested_at: 1700000000,
        tags: vec!["lab".into()],
    });
    dataspaces.insert("research".into(), ds);

    let backup = ServerBackup {
        version: "1.0-ΛD".into(),
        created_at: 1700000000,
        lambda_d: EpistemicEnvelope::raw_config("axon:server_backup", "test"),
        section_provenance: HashMap::new(),
        cost_pricing: CostPricing::default(),
        cost_budgets: HashMap::new(),
        flow_rules: HashMap::new(),
        flow_quotas: HashMap::new(),
        readiness_gates: ReadinessGates::default(),
        endpoint_rate_limits: HashMap::new(),
        schedules: Vec::new(),
        axon_stores,
        dataspaces,
        shields: HashMap::new(),
    };

    // Serialize
    let json = serde_json::to_string(&backup).unwrap();
    assert!(json.contains("\"facts\""));
    assert!(json.contains("3.14159"));
    assert!(json.contains("\"research\""));
    assert!(json.contains("\"observation\""));

    // Round-trip
    let recovered: ServerBackup = serde_json::from_str(&json).unwrap();
    assert_eq!(recovered.axon_stores.len(), 1);
    assert_eq!(recovered.dataspaces.len(), 1);
    let restored_store = recovered.axon_stores.get("facts").unwrap();
    assert_eq!(restored_store.entries.len(), 1);
    assert_eq!(restored_store.entries.get("pi").unwrap().value, serde_json::json!(3.14159));
    let restored_ds = recovered.dataspaces.get("research").unwrap();
    assert_eq!(restored_ds.entries.len(), 1);
    assert_eq!(restored_ds.next_id, 2);
}

