#[test]
fn test_server_backup_epistemic_envelopes_preserved_on_roundtrip() {
    use axon::axon_server::{ServerBackup, EpistemicEnvelope, CostPricing, ReadinessGates,
        AxonStoreInstance, AxonStoreEntry, DataspaceInstance};
    use std::collections::HashMap;

    // AxonStore with a raw entry and a derived entry
    let mut store = AxonStoreInstance {
        name: "config".into(),
        ontology: "settings".into(),
        entries: HashMap::new(),
        created_at: 1700000000,
        total_ops: 2,
    };
    store.entries.insert("raw_val".into(), AxonStoreEntry {
        key: "raw_val".into(),
        value: serde_json::json!(42),
        envelope: EpistemicEnvelope::raw_config("settings", "admin"),
        created_at: 1700000000,
        updated_at: 1700000000,
        version: 1,
    });
    store.entries.insert("derived_val".into(), AxonStoreEntry {
        key: "derived_val".into(),
        value: serde_json::json!(84),
        envelope: EpistemicEnvelope::derived("settings", 0.95, "optimizer"),
        created_at: 1700000000,
        updated_at: 1700000100,
        version: 3,
    });

    let mut axon_stores = HashMap::new();
    axon_stores.insert("config".into(), store);

    let backup = ServerBackup {
        version: "1.0-ΛD".into(),
        created_at: 1700000000,
        lambda_d: EpistemicEnvelope::raw_config("axon:server_backup", "test"),
        section_provenance: HashMap::new(),
        cost_pricing: CostPricing::default(),
        cost_budgets: HashMap::new(),
        flow_rules: HashMap::new(),
        flow_quotas: HashMap::new(),
        readiness_gates: ReadinessGates::default(),
        endpoint_rate_limits: HashMap::new(),
        schedules: Vec::new(),
        axon_stores,
        dataspaces: HashMap::new(),
        shields: HashMap::new(),
    };

    let json = serde_json::to_string(&backup).unwrap();
    let recovered: ServerBackup = serde_json::from_str(&json).unwrap();

    let st = recovered.axon_stores.get("config").unwrap();

    // Raw entry: c=1.0, δ=raw — preserved through serialization
    let raw = st.entries.get("raw_val").unwrap();
    assert_eq!(raw.envelope.certainty, 1.0);
    assert_eq!(raw.envelope.derivation, "raw");
    assert!(raw.envelope.validate().is_ok());

    // Derived entry: c=0.95, δ=derived — preserved through serialization
    let derived = st.entries.get("derived_val").unwrap();
    assert_eq!(derived.envelope.certainty, 0.95);
    assert_eq!(derived.envelope.derivation, "derived");
    assert_eq!(derived.version, 3);
    assert!(derived.envelope.validate().is_ok());

    // Theorem 5.1: derived with c=0.95 < 1.0 — valid
    // Total ops preserved
    assert_eq!(st.total_ops, 2);
}

// ── G7: Cognitive Primitive Inventory ──────────────────────────────────

#[test]
fn test_primitive_inventory_covers_all_47() {
    // The AXON_COGNITIVE_PRIMITIVES const must contain exactly 47 entries
    use axon::axon_server::AXON_COGNITIVE_PRIMITIVES;

    assert_eq!(AXON_COGNITIVE_PRIMITIVES.len(), 47);

    // Verify category distribution: 20 declarations + 14 step + 4 epistemic + 9 navigation = 47
    let declarations = ["persona", "context", "flow", "anchor", "tool", "memory", "type",
        "agent", "shield", "pix", "psyche", "corpus", "dataspace",
        "ots", "mandate", "compute", "daemon", "axonstore", "axonendpoint", "lambda"];
    let step = ["step", "reason", "validate", "refine", "weave", "probe",
        "use", "remember", "recall", "par", "hibernate", "deliberate", "consensus", "forge"];
    let epistemic = ["know", "believe", "speculate", "doubt"];
    let navigation = ["stream", "navigate", "drill", "trail", "corroborate",
        "focus", "associate", "aggregate", "explore"];

    assert_eq!(declarations.len(), 20);
    assert_eq!(step.len(), 14);
    assert_eq!(epistemic.len(), 4);
    assert_eq!(navigation.len(), 9);
    assert_eq!(declarations.len() + step.len() + epistemic.len() + navigation.len(), 47);

    // Every primitive in the const must exist in exactly one category
    for prim in AXON_COGNITIVE_PRIMITIVES {
        let in_decl = declarations.contains(prim);
        let in_step = step.contains(prim);
        let in_epi = epistemic.contains(prim);
        let in_nav = navigation.contains(prim);
        let count = [in_decl, in_step, in_epi, in_nav].iter().filter(|&&b| b).count();
        assert_eq!(count, 1, "primitive '{}' must be in exactly one category, found in {}", prim, count);
    }
}

#[test]
fn test_primitive_wiring_status_classification() {
    // Simulate the wiring map and verify counts.
    // Wired primitives (as of G7): those with HTTP endpoints or MCP exposition
    let wired_primitives = vec![
        // Declarations
        "axonstore", "dataspace", "flow", "persona", "context", "anchor",
        "tool", "memory", "daemon", "agent", "type", "lambda",
        // Step
        "step", "reason", "validate", "use", "remember", "recall", "par",
        // Epistemic
        "know", "believe", "speculate", "doubt",
        // Navigation
        "stream", "focus", "associate", "aggregate", "explore", "navigate",
    ];

    let pending_primitives = vec![
        "shield", "pix", "psyche", "corpus", "ots", "mandate", "compute",
        "axonendpoint", "refine", "weave", "probe", "hibernate",
        "deliberate", "consensus", "forge", "drill", "trail", "corroborate",
    ];

    let total = wired_primitives.len() + pending_primitives.len();
    assert_eq!(total, 47);

    let coverage = wired_primitives.len() as f64 / total as f64 * 100.0;
    assert!(coverage > 60.0, "coverage should be > 60%, got {:.1}%", coverage);

    // No overlap between wired and pending
    for p in &wired_primitives {
        assert!(!pending_primitives.contains(p), "primitive '{}' in both wired and pending", p);
    }
}

#[test]
fn test_primitive_lambda_d_alignment_metadata() {
    // The /v1/primitives endpoint should report ΛD alignment metadata.
    // Verify the formal structures are correct.

    // ΛD envelope structure: ψ = ⟨T, V, E⟩ where E = ⟨c, τ, ρ, δ⟩
    use axon::axon_server::EpistemicEnvelope;

    // Theorem 5.1: Epistemic Degradation
    let raw = EpistemicEnvelope::raw_config("test", "admin");
    assert_eq!(raw.certainty, 1.0);
    assert_eq!(raw.derivation, "raw");

    let derived = EpistemicEnvelope::derived("test", 0.99, "system");
    assert!(derived.certainty <= 0.99);
    assert_eq!(derived.derivation, "derived");

    // Lattice: ⊥ ⊑ doubt ⊑ speculate ⊑ believe ⊑ know
    let lattice = vec!["⊥", "doubt", "speculate", "believe", "know"];
    assert_eq!(lattice.len(), 5);

    // Certainty thresholds for lattice positions
    let lattice_thresholds = vec![
        (0.0, "⊥"),
        (0.5, "doubt"),
        (0.85, "speculate"),
        (0.95, "believe"),
        (1.0, "know"),
    ];
    for (c, expected_pos) in &lattice_thresholds {
        // Verify ordering: higher c → higher lattice position
        let idx = lattice.iter().position(|&l| l == *expected_pos).unwrap();
        if *c > 0.0 {
            assert!(idx > 0, "c={} should map above ⊥", c);
        }
        let _ = idx; // used above
    }

    // Blame calculus taxonomy
    let blame_types = vec!["caller", "server", "network"];
    assert_eq!(blame_types.len(), 3);
    // CT-2 = caller, CT-3 = server
    assert_eq!(blame_types[0], "caller");  // Findler-Felleisen CT-2
    assert_eq!(blame_types[1], "server");  // Findler-Felleisen CT-3
}

