#[test]
fn test_shield_evaluate_deny_list_and_redact() {
    use axon::axon_server::{ShieldInstance, ShieldRule};

    let shield = ShieldInstance {
        name: "toxicity".into(),
        mode: "output".into(),
        rules: vec![
            ShieldRule {
                id: "block_harmful".into(),
                kind: "deny_list".into(),
                value: "harmful".into(),
                action: "block".into(),
                enabled: true,
                description: "Block harmful content".into(),
            },
            ShieldRule {
                id: "redact_secret".into(),
                kind: "deny_list".into(),
                value: "secret123".into(),
                action: "redact".into(),
                enabled: true,
                description: "Redact secrets".into(),
            },
            ShieldRule {
                id: "warn_maybe".into(),
                kind: "deny_list".into(),
                value: "uncertain".into(),
                action: "warn".into(),
                enabled: true,
                description: "Warn on uncertain content".into(),
            },
            ShieldRule {
                id: "disabled_rule".into(),
                kind: "deny_list".into(),
                value: "anything".into(),
                action: "block".into(),
                enabled: false,
                description: "This rule is disabled".into(),
            },
        ],
        created_at: 1700000000,
        total_evaluations: 0,
        total_blocks: 0,
    };

    // Test blocking
    let result = shield.evaluate("This is harmful content");
    assert!(result.blocked, "deny_list 'harmful' should block");
    assert_eq!(result.rules_triggered, 1);
    assert_eq!(result.rules_evaluated, 3); // 4 rules - 1 disabled = 3 evaluated

    // Test redaction
    let result = shield.evaluate("The password is secret123 and it works");
    assert!(!result.blocked, "redact should not block");
    assert_eq!(result.redactions.len(), 1);
    assert_eq!(result.redactions[0], "redact_secret");
    assert!(result.content.contains("█"), "content should contain redaction mask");
    assert!(!result.content.contains("secret123"), "secret should be redacted");

    // Test warning
    let result = shield.evaluate("The outcome is uncertain");
    assert!(!result.blocked);
    assert_eq!(result.warnings.len(), 1);
    assert_eq!(result.warnings[0], "warn_maybe");

    // Test clean content (no triggers)
    let result = shield.evaluate("This is perfectly fine content");
    assert!(!result.blocked);
    assert_eq!(result.rules_triggered, 0);
    assert_eq!(result.warnings.len(), 0);
    assert_eq!(result.redactions.len(), 0);
}

#[test]
fn test_shield_pii_detection_and_length_rules() {
    use axon::axon_server::{ShieldInstance, ShieldRule};

    let shield = ShieldInstance {
        name: "pii_guard".into(),
        mode: "both".into(),
        rules: vec![
            ShieldRule {
                id: "email_detect".into(),
                kind: "pii".into(),
                value: "email".into(),
                action: "redact".into(),
                enabled: true,
                description: "Detect and redact emails".into(),
            },
            ShieldRule {
                id: "phone_detect".into(),
                kind: "pii".into(),
                value: "phone".into(),
                action: "warn".into(),
                enabled: true,
                description: "Warn on phone numbers".into(),
            },
            ShieldRule {
                id: "max_length".into(),
                kind: "length".into(),
                value: "50".into(),
                action: "block".into(),
                enabled: true,
                description: "Block content over 50 chars".into(),
            },
        ],
        created_at: 1700000000,
        total_evaluations: 0,
        total_blocks: 0,
    };

    // Email PII detection
    let result = shield.evaluate("Contact me at user@example.com");
    assert!(!result.blocked);
    assert_eq!(result.redactions.len(), 1);
    assert_eq!(result.redactions[0], "email_detect");
    assert!(result.content.contains("[EMAIL REDACTED]"), "email should be redacted to [EMAIL REDACTED]");

    // Phone PII detection
    let result = shield.evaluate("Call 1234567890");
    assert!(!result.blocked);
    assert_eq!(result.warnings.len(), 1);
    assert_eq!(result.warnings[0], "phone_detect");

    // Length rule — short content passes
    let result = shield.evaluate("Short");
    assert!(!result.blocked);

    // Length rule — long content blocked
    let result = shield.evaluate("This is a very long content string that exceeds the fifty character limit imposed by the length rule");
    assert!(result.blocked, "content over 50 chars should be blocked");

    // Mode compatibility: "both" accepts both input and output
    assert_eq!(shield.mode, "both");
}

#[test]
fn test_shield_epistemic_alignment() {
    use axon::axon_server::{ShieldInstance, ShieldRule, EpistemicEnvelope};

    // Shield evaluation is always derived (δ=derived) per Theorem 5.1:
    // pattern matching is an approximation, not raw knowledge.
    let shield = ShieldInstance {
        name: "test_epistemic".into(),
        mode: "input".into(),
        rules: vec![
            ShieldRule {
                id: "r1".into(),
                kind: "deny_list".into(),
                value: "bad".into(),
                action: "block".into(),
                enabled: true,
                description: "test".into(),
            },
        ],
        created_at: 1700000000,
        total_evaluations: 0,
        total_blocks: 0,
    };

    // No triggers → c=0.95 (high confidence content is safe, but speculative)
    let clean = shield.evaluate("good content");
    assert!(!clean.blocked);
    assert_eq!(clean.rules_triggered, 0);
    let clean_certainty = 0.95; // as set in handler
    assert!(clean_certainty < 1.0, "Theorem 5.1: shield evaluation cannot be raw (c=1.0)");

    // Triggered → c=0.85 (lower confidence due to pattern match uncertainty)
    let blocked = shield.evaluate("bad content");
    assert!(blocked.blocked);
    let blocked_certainty = 0.85;
    assert!(blocked_certainty < clean_certainty, "triggered should have lower certainty");

    // Both certainties are derived (< 1.0), satisfying Theorem 5.1
    let derived_envelope = EpistemicEnvelope::derived("guardrail", 0.95, "shield_eval");
    assert_eq!(derived_envelope.derivation, "derived");
    assert!(derived_envelope.certainty <= 0.99);
    assert!(derived_envelope.validate().is_ok());

    // Lattice positions
    let clean_lattice = "speculate"; // no triggers, shield speculates content is safe
    let blocked_lattice = "doubt";   // triggers, shield doubts content safety
    assert_eq!(clean_lattice, "speculate");
    assert_eq!(blocked_lattice, "doubt");

    // Effect row: shield is io + epistemic:speculate
    let effects = vec!["io", "epistemic:speculate"];
    assert!(effects.contains(&"epistemic:speculate"));

    // Shield mode validation
    assert_eq!(shield.mode, "input");
    let valid_modes = vec!["input", "output", "both"];
    assert!(valid_modes.contains(&shield.mode.as_str()));
}

