#[test]
fn test_backend_health_probe_configuration() {
    use axon::axon_server::BackendHealthProbe;

    // Default probe configuration
    let probe = BackendHealthProbe::default();
    assert_eq!(probe.interval_secs, 300); // 5 minutes
    assert_eq!(probe.unhealthy_threshold, 3);
    assert_eq!(probe.healthy_threshold, 2);
    assert_eq!(probe.timeout_ms, 10000); // 10 seconds
    assert!(!probe.enabled); // disabled by default
    assert_eq!(probe.consecutive_ok, 0);
    assert_eq!(probe.consecutive_fail, 0);

    // Custom probe configuration
    let custom = BackendHealthProbe {
        backend: "anthropic".into(),
        interval_secs: 60,
        unhealthy_threshold: 5,
        healthy_threshold: 3,
        timeout_ms: 5000,
        enabled: true,
        consecutive_ok: 0,
        consecutive_fail: 0,
    };
    assert_eq!(custom.backend, "anthropic");
    assert_eq!(custom.interval_secs, 60);
    assert!(custom.enabled);

    // Probe serializes cleanly
    let json = serde_json::to_string(&custom).unwrap();
    assert!(json.contains("\"backend\":\"anthropic\""));
    assert!(json.contains("\"interval_secs\":60"));
    assert!(json.contains("\"enabled\":true"));

    // Deserialize round-trip
    let restored: BackendHealthProbe = serde_json::from_str(&json).unwrap();
    assert_eq!(restored.backend, "anthropic");
    assert_eq!(restored.interval_secs, 60);
    assert_eq!(restored.unhealthy_threshold, 5);
}

#[test]
fn test_health_check_record_tracking() {
    use axon::axon_server::HealthCheckRecord;

    // Build a history of health checks
    let mut history: Vec<HealthCheckRecord> = Vec::new();

    history.push(HealthCheckRecord {
        timestamp: 1700000000,
        status: "healthy".into(),
        latency_ms: 120,
        error: None,
        previous_status: "unknown".into(),
    });
    history.push(HealthCheckRecord {
        timestamp: 1700000300,
        status: "healthy".into(),
        latency_ms: 95,
        error: None,
        previous_status: "healthy".into(),
    });
    history.push(HealthCheckRecord {
        timestamp: 1700000600,
        status: "degraded".into(),
        latency_ms: 5000,
        error: Some("timeout".into()),
        previous_status: "healthy".into(),
    });
    history.push(HealthCheckRecord {
        timestamp: 1700000900,
        status: "healthy".into(),
        latency_ms: 110,
        error: None,
        previous_status: "degraded".into(),
    });

    assert_eq!(history.len(), 4);

    // Count transitions (status changed from previous, excluding unknown)
    let transitions: Vec<&HealthCheckRecord> = history.iter()
        .filter(|r| r.status != r.previous_status && r.previous_status != "unknown")
        .collect();
    assert_eq!(transitions.len(), 2); // healthy→degraded, degraded→healthy

    // Uptime calculation
    let healthy_count = history.iter().filter(|r| r.status == "healthy").count();
    assert_eq!(healthy_count, 3);
    let uptime_pct = healthy_count as f64 / history.len() as f64 * 100.0;
    assert!((uptime_pct - 75.0).abs() < 0.01, "uptime should be 75%");

    // Average latency
    let total_latency: u64 = history.iter().map(|r| r.latency_ms).sum();
    let avg_latency = total_latency as f64 / history.len() as f64;
    assert!(avg_latency > 0.0);

    // History cap behavior (100 entries max)
    let mut capped_history: Vec<HealthCheckRecord> = Vec::new();
    for i in 0..105 {
        capped_history.push(HealthCheckRecord {
            timestamp: 1700000000 + i * 300,
            status: "healthy".into(),
            latency_ms: 100,
            error: None,
            previous_status: "healthy".into(),
        });
        if capped_history.len() > 100 {
            capped_history.remove(0);
        }
    }
    assert_eq!(capped_history.len(), 100, "history should be capped at 100");
}

#[test]
fn test_health_probe_consecutive_counter_logic() {
    use axon::axon_server::BackendHealthProbe;

    let mut probe = BackendHealthProbe {
        backend: "openai".into(),
        interval_secs: 120,
        unhealthy_threshold: 3,
        healthy_threshold: 2,
        timeout_ms: 5000,
        enabled: true,
        consecutive_ok: 0,
        consecutive_fail: 0,
    };

    // Simulate healthy checks
    for _ in 0..2 {
        probe.consecutive_ok += 1;
        probe.consecutive_fail = 0;
    }
    assert_eq!(probe.consecutive_ok, 2);
    assert_eq!(probe.consecutive_fail, 0);
    assert!(probe.consecutive_ok >= probe.healthy_threshold,
        "should meet healthy threshold after 2 successes");

    // Simulate failure
    probe.consecutive_fail += 1;
    probe.consecutive_ok = 0;
    assert_eq!(probe.consecutive_fail, 1);
    assert_eq!(probe.consecutive_ok, 0);
    assert!(probe.consecutive_fail < probe.unhealthy_threshold,
        "1 failure should not meet unhealthy threshold of 3");

    // Simulate more failures to reach threshold
    probe.consecutive_fail += 1;
    probe.consecutive_fail += 1;
    assert_eq!(probe.consecutive_fail, 3);
    assert!(probe.consecutive_fail >= probe.unhealthy_threshold,
        "3 failures should meet unhealthy threshold");

    // Recovery: consecutive successes reset fail counter
    probe.consecutive_ok = 1;
    probe.consecutive_fail = 0;
    assert_eq!(probe.consecutive_fail, 0, "fail counter reset on success");

    // Disabled probe should not be evaluated
    probe.enabled = false;
    assert!(!probe.enabled);
}

