#[test]
fn test_corpus_document_ingest_and_epistemic_envelope() {
    use axon::axon_server::{CorpusDocument, CorpusInstance, EpistemicEnvelope};

    let mut corpus = CorpusInstance {
        name: "papers".into(),
        ontology: "academic".into(),
        documents: std::collections::HashMap::new(),
        created_at: 1700000000,
        total_ops: 0,
        next_id: 1,
    };

    // Ingest a document — ΛD: raw, c=1.0
    let envelope = EpistemicEnvelope::raw_config("academic", "researcher");
    let doc = CorpusDocument {
        id: format!("doc_papers_{}", corpus.next_id),
        title: "Attention Is All You Need".into(),
        content: "The dominant sequence transduction models are based on complex recurrent or convolutional neural networks".into(),
        tags: vec!["transformers".into(), "nlp".into()],
        source: "arxiv:1706.03762".into(),
        envelope: envelope.clone(),
        ingested_at: 1700000000,
        word_count: 15,
    };
    corpus.next_id += 1;

    let doc_id = doc.id.clone();
    corpus.documents.insert(doc_id.clone(), doc);
    corpus.total_ops += 1;

    // Verify document stored correctly
    assert_eq!(corpus.documents.len(), 1);
    let stored = corpus.documents.get(&doc_id).unwrap();
    assert_eq!(stored.title, "Attention Is All You Need");
    assert_eq!(stored.word_count, 15);
    assert_eq!(stored.tags, vec!["transformers", "nlp"]);
    assert_eq!(stored.source, "arxiv:1706.03762");

    // ΛD: ingest = raw → c=1.0, δ=raw (Theorem 5.1 satisfied)
    assert_eq!(stored.envelope.certainty, 1.0);
    assert_eq!(stored.envelope.derivation, "raw");
    assert!(stored.envelope.validate().is_ok());

    // Ingest second document
    let doc2 = CorpusDocument {
        id: format!("doc_papers_{}", corpus.next_id),
        title: "BERT: Pre-training of Deep Bidirectional Transformers".into(),
        content: "We introduce a new language representation model called BERT".into(),
        tags: vec!["transformers".into(), "pretraining".into()],
        source: "arxiv:1810.04805".into(),
        envelope: EpistemicEnvelope::raw_config("academic", "researcher"),
        ingested_at: 1700000100,
        word_count: 11,
    };
    corpus.next_id += 1;
    corpus.documents.insert(doc2.id.clone(), doc2);
    assert_eq!(corpus.documents.len(), 2);
    assert_eq!(corpus.next_id, 3);
}

#[test]
fn test_corpus_search_relevance_scoring() {
    use axon::axon_server::{CorpusDocument, CorpusInstance, EpistemicEnvelope};

    let mut corpus = CorpusInstance {
        name: "knowledge".into(),
        ontology: "science".into(),
        documents: std::collections::HashMap::new(),
        created_at: 1700000000,
        total_ops: 0,
        next_id: 1,
    };

    // Add documents with varying relevance to "neural networks"
    let docs = vec![
        ("Neural Network Architectures", "Neural networks are composed of layers of neurons. Deep neural networks have many layers.", vec!["ml"]),
        ("Introduction to Databases", "Databases store structured data. SQL is a query language for relational databases.", vec!["db"]),
        ("Machine Learning Overview", "Machine learning includes neural networks, decision trees, and support vector machines.", vec!["ml"]),
    ];

    for (title, content, tags) in docs {
        let id = format!("doc_knowledge_{}", corpus.next_id);
        corpus.next_id += 1;
        corpus.documents.insert(id.clone(), CorpusDocument {
            id,
            title: title.into(),
            content: content.into(),
            tags: tags.into_iter().map(String::from).collect(),
            source: "manual".into(),
            envelope: EpistemicEnvelope::raw_config("science", "admin"),
            ingested_at: 1700000000,
            word_count: content.split_whitespace().count() as u64,
        });
    }

    // Search for "neural networks"
    let query = "neural networks";
    let query_lower = query.to_lowercase();
    let query_terms: Vec<&str> = query_lower.split_whitespace().collect();

    let mut scored: Vec<(&str, f64)> = Vec::new();
    for doc in corpus.documents.values() {
        let content_lower = doc.content.to_lowercase();
        let title_lower = doc.title.to_lowercase();
        let mut hits = 0.0f64;
        for term in &query_terms {
            hits += content_lower.matches(term).count() as f64;
            hits += title_lower.matches(term).count() as f64 * 3.0;
        }
        if hits > 0.0 {
            let total_words = doc.word_count.max(1) as f64 + doc.title.split_whitespace().count() as f64;
            let relevance = (hits / total_words).min(1.0);
            scored.push((&doc.title, relevance));
        }
    }

    scored.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap_or(std::cmp::Ordering::Equal));

    // "Neural Network Architectures" should rank highest (most term hits + title match)
    assert!(!scored.is_empty(), "should find at least one match");
    assert_eq!(scored[0].0, "Neural Network Architectures");
    assert!(scored[0].1 > 0.0, "relevance should be positive");

    // "Introduction to Databases" should NOT appear (no matching terms)
    assert!(!scored.iter().any(|(title, _)| *title == "Introduction to Databases"),
        "database doc should not match neural networks query");

    // "Machine Learning Overview" should appear (partial match)
    assert!(scored.iter().any(|(title, _)| *title == "Machine Learning Overview"),
        "ML overview should match (contains 'neural networks')");

    // Search result epistemic: derived, c≤0.99 (Theorem 5.1)
    let search_certainty = 0.99;
    assert!(search_certainty < 1.0, "search results are derived, not raw");
}

#[test]
fn test_corpus_citation_extraction_with_theorem_5_1() {
    use axon::axon_server::{CorpusDocument, CorpusInstance, EpistemicEnvelope};

    let mut corpus = CorpusInstance {
        name: "references".into(),
        ontology: "technical".into(),
        documents: std::collections::HashMap::new(),
        created_at: 1700000000,
        total_ops: 0,
        next_id: 1,
    };

    let content = "The transformer architecture was introduced in the paper Attention Is All You Need. \
        It relies on self-attention mechanisms to process sequences in parallel, \
        unlike recurrent neural networks which process tokens sequentially.";

    corpus.documents.insert("doc_1".into(), CorpusDocument {
        id: "doc_1".into(),
        title: "Transformer Survey".into(),
        content: content.into(),
        tags: vec!["survey".into()],
        source: "manual".into(),
        envelope: EpistemicEnvelope::raw_config("technical", "admin"),
        ingested_at: 1700000000,
        word_count: content.split_whitespace().count() as u64,
    });

    // Simulate citation extraction for query "attention mechanisms"
    let query = "attention";
    let query_lower = query.to_lowercase();
    let content_lower = content.to_lowercase();

    // Find match position
    let pos = content_lower.find(&query_lower);
    assert!(pos.is_some(), "query should match document content");

    let pos = pos.unwrap();
    let excerpt_length = 100usize;
    let start = pos.saturating_sub(excerpt_length / 4);
    let end = (pos + query.len() + excerpt_length * 3 / 4).min(content.len());
    let excerpt = &content[start..end];
    assert!(!excerpt.is_empty(), "excerpt should not be empty");
    assert!(excerpt.to_lowercase().contains("attention"), "excerpt should contain query term");

    // ΛD: citation = derived → c≤0.99, δ=derived (Theorem 5.1)
    let citation_envelope = EpistemicEnvelope::derived("technical", 0.99, "cite_engine");
    assert_eq!(citation_envelope.certainty, 0.99);
    assert_eq!(citation_envelope.derivation, "derived");
    assert!(citation_envelope.validate().is_ok());

    // Theorem 5.1: citation cannot carry c=1.0 (it's an interpretation)
    let bad_citation = EpistemicEnvelope {
        ontology: "technical".into(),
        certainty: 1.0,
        temporal_start: "0".into(),
        temporal_end: "∞".into(),
        provenance: "cite".into(),
        derivation: "derived".into(),
    };
    assert!(bad_citation.validate().is_err(),
        "Theorem 5.1: derived citation cannot have c=1.0");

    // Lattice position: citation → speculate (not know, because it's interpretive)
    let cite_lattice = "speculate";
    assert_eq!(cite_lattice, "speculate");

    // Relevance score properties
    let relevance = 1.0 - (pos as f64 / content.len().max(1) as f64 * 0.1);
    assert!(relevance > 0.0 && relevance <= 1.0, "relevance should be in (0,1]");
}

