#[test]
fn test_compute_arithmetic_and_operator_precedence() {
    use axon::axon_server::compute_evaluate;
    use std::collections::HashMap;

    let vars = HashMap::new();

    // Basic arithmetic
    let r = compute_evaluate("2 + 3", &vars).unwrap();
    assert_eq!(r.value, 5.0);
    assert!(r.exact, "integer addition should be exact");
    assert_eq!(r.certainty, 1.0);
    assert_eq!(r.derivation, "raw");

    // Operator precedence: * before +
    let r = compute_evaluate("2 + 3 * 4", &vars).unwrap();
    assert_eq!(r.value, 14.0);

    // Parentheses override precedence
    let r = compute_evaluate("(2 + 3) * 4", &vars).unwrap();
    assert_eq!(r.value, 20.0);

    // Power operator
    let r = compute_evaluate("2 ^ 10", &vars).unwrap();
    assert_eq!(r.value, 1024.0);

    // Modulo
    let r = compute_evaluate("17 % 5", &vars).unwrap();
    assert_eq!(r.value, 2.0);

    // Nested parentheses
    let r = compute_evaluate("((2 + 3) * (4 - 1)) ^ 2", &vars).unwrap();
    assert_eq!(r.value, 225.0); // (5 * 3)^2 = 15^2 = 225

    // Unary minus
    let r = compute_evaluate("-5 + 3", &vars).unwrap();
    assert_eq!(r.value, -2.0);

    // Division makes result non-exact (derived)
    let r = compute_evaluate("10 / 3", &vars).unwrap();
    assert!((r.value - 3.3333333333333335).abs() < 1e-10);
    assert!(!r.exact, "division should be non-exact");
    assert_eq!(r.certainty, 0.99);
    assert_eq!(r.derivation, "derived");

    // Error: division by zero
    let r = compute_evaluate("5 / 0", &vars);
    assert!(r.is_err());
    assert!(r.unwrap_err().contains("division by zero"));

    // Error: empty expression
    let r = compute_evaluate("", &vars);
    assert!(r.is_err());
}

#[test]
fn test_compute_variables_and_functions() {
    use axon::axon_server::compute_evaluate;
    use std::collections::HashMap;

    // Variables
    let mut vars = HashMap::new();
    vars.insert("x".into(), 10.0);
    vars.insert("y".into(), 5.0);

    let r = compute_evaluate("x + y", &vars).unwrap();
    assert_eq!(r.value, 15.0);
    assert_eq!(r.variables["x"], 10.0);
    assert_eq!(r.variables["y"], 5.0);

    let r = compute_evaluate("x * y + 2", &vars).unwrap();
    assert_eq!(r.value, 52.0);

    // Functions
    let empty = HashMap::new();

    let r = compute_evaluate("sqrt(16)", &empty).unwrap();
    assert_eq!(r.value, 4.0);
    assert!(!r.exact, "sqrt makes result non-exact");
    assert_eq!(r.certainty, 0.99);

    let r = compute_evaluate("abs(-42)", &empty).unwrap();
    assert_eq!(r.value, 42.0);

    let r = compute_evaluate("floor(3.7)", &empty).unwrap();
    assert_eq!(r.value, 3.0);

    let r = compute_evaluate("ceil(3.2)", &empty).unwrap();
    assert_eq!(r.value, 4.0);

    let r = compute_evaluate("round(3.5)", &empty).unwrap();
    assert_eq!(r.value, 4.0);

    // Constants
    let r = compute_evaluate("pi", &empty).unwrap();
    assert!((r.value - std::f64::consts::PI).abs() < 1e-10);
    assert!(!r.exact, "pi is not exact");

    let r = compute_evaluate("e", &empty).unwrap();
    assert!((r.value - std::f64::consts::E).abs() < 1e-10);

    // Composed: sqrt(x^2 + y^2)
    let r = compute_evaluate("sqrt(x ^ 2 + y ^ 2)", &vars).unwrap();
    let expected = (100.0f64 + 25.0).sqrt(); // sqrt(125) ≈ 11.18
    assert!((r.value - expected).abs() < 1e-10);

    // Error: unknown variable
    let r = compute_evaluate("z + 1", &empty);
    assert!(r.is_err());
    assert!(r.unwrap_err().contains("unknown"));
}

#[test]
fn test_compute_epistemic_alignment_theorem_5_1() {
    use axon::axon_server::{compute_evaluate, EpistemicEnvelope};
    use std::collections::HashMap;

    let vars = HashMap::new();

    // Exact integer arithmetic → c=1.0, δ=raw (ground truth)
    let exact = compute_evaluate("2 + 3 * 4", &vars).unwrap();
    assert_eq!(exact.certainty, 1.0);
    assert_eq!(exact.derivation, "raw");
    assert!(exact.exact);
    // Lattice: exact → know
    let exact_lattice = if exact.exact { "know" } else { "speculate" };
    assert_eq!(exact_lattice, "know");

    // Floating point / transcendental → c=0.99, δ=derived (Theorem 5.1)
    let approx = compute_evaluate("pi * 2", &vars).unwrap();
    assert_eq!(approx.certainty, 0.99);
    assert_eq!(approx.derivation, "derived");
    assert!(!approx.exact);
    let approx_lattice = if approx.exact { "know" } else { "speculate" };
    assert_eq!(approx_lattice, "speculate");

    // Division always derived
    let div = compute_evaluate("10 / 3", &vars).unwrap();
    assert_eq!(div.certainty, 0.99);
    assert_eq!(div.derivation, "derived");

    // sqrt always derived
    let sqrt_r = compute_evaluate("sqrt(4)", &vars).unwrap();
    assert_eq!(sqrt_r.certainty, 0.99);
    assert_eq!(sqrt_r.derivation, "derived");

    // Verify Theorem 5.1 with EpistemicEnvelope
    // Exact computation envelope
    let exact_env = EpistemicEnvelope::raw_config("computation", "compute_engine");
    assert_eq!(exact_env.certainty, 1.0);
    assert_eq!(exact_env.derivation, "raw");
    assert!(exact_env.validate().is_ok());

    // Approximate computation envelope
    let approx_env = EpistemicEnvelope::derived("computation", 0.99, "compute_engine");
    assert_eq!(approx_env.certainty, 0.99);
    assert_eq!(approx_env.derivation, "derived");
    assert!(approx_env.validate().is_ok());

    // Theorem 5.1 violation: derived cannot have c=1.0
    let bad = EpistemicEnvelope {
        ontology: "computation".into(),
        certainty: 1.0,
        temporal_start: "0".into(),
        temporal_end: "∞".into(),
        provenance: "compute".into(),
        derivation: "derived".into(),
    };
    assert!(bad.validate().is_err(),
        "Theorem 5.1: derived computation cannot have c=1.0");

    // Effect rows
    let exact_effects = vec!["compute", "epistemic:know"];
    let approx_effects = vec!["compute", "epistemic:speculate"];
    assert!(exact_effects.contains(&"epistemic:know"));
    assert!(approx_effects.contains(&"epistemic:speculate"));
}

