#[test]
fn test_mandate_policy_evaluation_first_match_wins() {
    use axon::axon_server::{MandatePolicy, MandateRule};

    let policy = MandatePolicy {
        name: "flow_access".into(),
        description: "Controls flow execution".into(),
        rules: vec![
            MandateRule {
                id: "admin_all".into(),
                subject: "admin".into(),
                action: "*".into(),
                resource: "*".into(),
                effect: "allow".into(),
                priority: 100,
                enabled: true,
            },
            MandateRule {
                id: "operator_execute".into(),
                subject: "operator".into(),
                action: "execute".into(),
                resource: "/v1/flows/*".into(),
                effect: "allow".into(),
                priority: 50,
                enabled: true,
            },
            MandateRule {
                id: "deny_delete".into(),
                subject: "*".into(),
                action: "delete".into(),
                resource: "/v1/flows/*".into(),
                effect: "deny".into(),
                priority: 90,
                enabled: true,
            },
            MandateRule {
                id: "disabled_rule".into(),
                subject: "*".into(),
                action: "*".into(),
                resource: "*".into(),
                effect: "allow".into(),
                priority: 200,
                enabled: false, // disabled → skipped
            },
        ],
        created_at: 1700000000,
        total_evaluations: 0,
        total_denials: 0,
    };

    // Admin can do anything (priority 100, wildcard match)
    let r = policy.evaluate("admin", "execute", "/v1/flows/analyze");
    assert!(r.allowed);
    assert_eq!(r.matched_rule.as_deref(), Some("admin_all"));
    assert_eq!(r.effect, "allow");
    assert_eq!(r.certainty, 1.0);
    assert_eq!(r.derivation, "raw");

    // Admin can even delete (admin_all at priority 100 > deny_delete at 90)
    let r = policy.evaluate("admin", "delete", "/v1/flows/old");
    assert!(r.allowed);
    assert_eq!(r.matched_rule.as_deref(), Some("admin_all"));

    // Operator can execute flows (prefix match on /v1/flows/*)
    let r = policy.evaluate("operator", "execute", "/v1/flows/report");
    assert!(r.allowed);
    assert_eq!(r.matched_rule.as_deref(), Some("operator_execute"));

    // Anyone's delete on flows is denied (deny_delete priority 90 > operator_execute 50)
    let r = policy.evaluate("operator", "delete", "/v1/flows/old");
    assert!(!r.allowed);
    assert_eq!(r.matched_rule.as_deref(), Some("deny_delete"));
    assert_eq!(r.effect, "deny");

    // Unknown subject, no matching rule → default deny
    let r = policy.evaluate("guest", "read", "/v1/secrets");
    assert!(!r.allowed);
    assert!(r.matched_rule.is_none());
    assert_eq!(r.effect, "default_deny");

    // Disabled rule is skipped even though it has highest priority
    assert_eq!(r.rules_evaluated, 3); // only 3 enabled rules checked
}

#[test]
fn test_mandate_resource_pattern_matching() {
    use axon::axon_server::{MandatePolicy, MandateRule};

    let policy = MandatePolicy {
        name: "resource_patterns".into(),
        description: "Tests resource matching".into(),
        rules: vec![
            MandateRule {
                id: "exact_match".into(),
                subject: "*".into(),
                action: "read".into(),
                resource: "/v1/status".into(),
                effect: "allow".into(),
                priority: 10,
                enabled: true,
            },
            MandateRule {
                id: "prefix_match".into(),
                subject: "*".into(),
                action: "read".into(),
                resource: "/v1/backends/*".into(),
                effect: "allow".into(),
                priority: 10,
                enabled: true,
            },
            MandateRule {
                id: "wildcard_all".into(),
                subject: "superadmin".into(),
                action: "*".into(),
                resource: "*".into(),
                effect: "allow".into(),
                priority: 5,
                enabled: true,
            },
        ],
        created_at: 1700000000,
        total_evaluations: 0,
        total_denials: 0,
    };

    // Exact resource match
    let r = policy.evaluate("user", "read", "/v1/status");
    assert!(r.allowed);
    assert_eq!(r.matched_rule.as_deref(), Some("exact_match"));

    // Exact match does NOT prefix-match
    let r = policy.evaluate("user", "read", "/v1/status/deep");
    assert!(!r.allowed); // /v1/status != /v1/status/deep
    assert_eq!(r.effect, "default_deny");

    // Prefix match with trailing *
    let r = policy.evaluate("user", "read", "/v1/backends/anthropic");
    assert!(r.allowed);
    assert_eq!(r.matched_rule.as_deref(), Some("prefix_match"));

    let r = policy.evaluate("user", "read", "/v1/backends/openai/metrics");
    assert!(r.allowed);
    assert_eq!(r.matched_rule.as_deref(), Some("prefix_match"));

    // Prefix doesn't match unrelated path
    let r = policy.evaluate("user", "read", "/v1/flows/test");
    assert!(!r.allowed);

    // Wildcard resource * matches everything
    let r = policy.evaluate("superadmin", "write", "/anything/at/all");
    assert!(r.allowed);
    assert_eq!(r.matched_rule.as_deref(), Some("wildcard_all"));
}

#[test]
fn test_mandate_epistemic_alignment_theorem_5_1() {
    use axon::axon_server::{MandatePolicy, MandateRule, EpistemicEnvelope};

    let policy = MandatePolicy {
        name: "epistemic_test".into(),
        description: "Test ΛD alignment".into(),
        rules: vec![
            MandateRule {
                id: "allow_known".into(),
                subject: "admin".into(),
                action: "execute".into(),
                resource: "/v1/flows/*".into(),
                effect: "allow".into(),
                priority: 10,
                enabled: true,
            },
        ],
        created_at: 1700000000,
        total_evaluations: 0,
        total_denials: 0,
    };

    // Explicit rule match → c=1.0, δ=raw (deterministic decision)
    let explicit = policy.evaluate("admin", "execute", "/v1/flows/test");
    assert!(explicit.allowed);
    assert_eq!(explicit.certainty, 1.0);
    assert_eq!(explicit.derivation, "raw");
    // Lattice: explicit match → know
    let explicit_lattice = if explicit.certainty == 1.0 { "know" } else { "speculate" };
    assert_eq!(explicit_lattice, "know");

    // Default deny → c=0.99, δ=derived (Theorem 5.1: inferential)
    let default_deny = policy.evaluate("guest", "read", "/v1/secrets");
    assert!(!default_deny.allowed);
    assert_eq!(default_deny.certainty, 0.99);
    assert_eq!(default_deny.derivation, "derived");
    let deny_lattice = if default_deny.certainty == 1.0 { "know" } else { "speculate" };
    assert_eq!(deny_lattice, "speculate");

    // Verify with EpistemicEnvelope
    // Explicit decision envelope (raw, c=1.0)
    let explicit_env = EpistemicEnvelope::raw_config("authorization", "mandate_engine");
    assert_eq!(explicit_env.certainty, 1.0);
    assert_eq!(explicit_env.derivation, "raw");
    assert!(explicit_env.validate().is_ok());

    // Default deny envelope (derived, c=0.99)
    let deny_env = EpistemicEnvelope::derived("authorization", 0.99, "mandate_default_deny");
    assert_eq!(deny_env.certainty, 0.99);
    assert_eq!(deny_env.derivation, "derived");
    assert!(deny_env.validate().is_ok());

    // Theorem 5.1: derived cannot carry c=1.0
    let bad = EpistemicEnvelope {
        ontology: "authorization".into(),
        certainty: 1.0,
        temporal_start: "0".into(),
        temporal_end: "∞".into(),
        provenance: "inferred".into(),
        derivation: "derived".into(),
    };
    assert!(bad.validate().is_err(),
        "Theorem 5.1: default deny (derived) cannot have c=1.0");

    // Effect rows
    let know_effects = vec!["io", "epistemic:know"];       // explicit match
    let speculate_effects = vec!["io", "epistemic:speculate"]; // default deny
    assert!(know_effects.contains(&"epistemic:know"));
    assert!(speculate_effects.contains(&"epistemic:speculate"));
}

