#[test]
fn test_refine_session_iteration_and_convergence() {
    use axon::axon_server::RefineSession;

    let mut session = RefineSession {
        id: "refine_test_1".into(),
        name: "improve_summary".into(),
        target_quality: 0.9,
        convergence_threshold: 0.01,
        max_iterations: 10,
        converged: false,
        iterations: Vec::new(),
        created_at: 1700000000,
    };

    // Initial iteration
    let r = session.add_iteration("Draft summary v1".into(), 0.3, "initial".into());
    assert!(r.is_ok());
    assert_eq!(session.iteration_count(), 1);
    assert_eq!(session.current_quality(), 0.3);
    assert!(!session.converged);

    // Second iteration — improvement
    let r = session.add_iteration("Better summary v2".into(), 0.6, "add more detail".into());
    assert!(r.is_ok());
    let iter = r.unwrap();
    assert_eq!(iter.iteration, 2);
    assert!((iter.delta - 0.3).abs() < 0.001, "delta should be +0.3");
    assert!(!session.converged);

    // Third iteration — big improvement
    let r = session.add_iteration("Excellent summary v3".into(), 0.85, "polish language".into());
    assert!(r.is_ok());
    assert!(!session.converged); // 0.85 < 0.9 target

    // Fourth iteration — reaches target quality → converges
    let r = session.add_iteration("Perfect summary v4".into(), 0.92, "final polish".into());
    assert!(r.is_ok());
    assert!(session.converged, "should converge when quality >= target");
    assert_eq!(session.current_quality(), 0.92);
    assert_eq!(session.iteration_count(), 4);

    // Cannot add more iterations after convergence
    let r = session.add_iteration("Overkill v5".into(), 0.95, "unnecessary".into());
    assert!(r.is_err());
    assert!(r.unwrap_err().contains("already converged"));
}

#[test]
fn test_refine_convergence_by_delta_and_max_iterations() {
    use axon::axon_server::RefineSession;

    // Test convergence by delta threshold
    let mut session = RefineSession {
        id: "refine_delta_1".into(),
        name: "plateau_test".into(),
        target_quality: 0.99, // unreachable target
        convergence_threshold: 0.02,
        max_iterations: 20,
        converged: false,
        iterations: Vec::new(),
        created_at: 1700000000,
    };

    let _ = session.add_iteration("v1".into(), 0.5, "init".into());
    assert!(!session.converged);

    let _ = session.add_iteration("v2".into(), 0.7, "improve".into());
    assert!(!session.converged); // delta=0.2, above threshold

    let _ = session.add_iteration("v3".into(), 0.71, "minor tweak".into());
    assert!(session.converged, "delta=0.01 < threshold=0.02 → converge");

    // Test max iterations limit
    let mut session2 = RefineSession {
        id: "refine_max_1".into(),
        name: "max_test".into(),
        target_quality: 0.99,
        convergence_threshold: 0.001, // very tight
        max_iterations: 3,
        converged: false,
        iterations: Vec::new(),
        created_at: 1700000000,
    };

    let _ = session2.add_iteration("v1".into(), 0.3, "init".into());
    let _ = session2.add_iteration("v2".into(), 0.5, "improve".into());
    let _ = session2.add_iteration("v3".into(), 0.7, "more".into());

    // Max reached
    let r = session2.add_iteration("v4".into(), 0.8, "over limit".into());
    assert!(r.is_err());
    assert!(r.unwrap_err().contains("max iterations"));
    assert_eq!(session2.iteration_count(), 3);
}

#[test]
fn test_refine_epistemic_alignment_theorem_5_1() {
    use axon::axon_server::{RefineSession, EpistemicEnvelope};

    let mut session = RefineSession {
        id: "refine_epistemic_1".into(),
        name: "epistemic_test".into(),
        target_quality: 0.95,
        convergence_threshold: 0.01,
        max_iterations: 10,
        converged: false,
        iterations: Vec::new(),
        created_at: 1700000000,
    };

    // All refinement iterations are derived (Theorem 5.1)
    let _ = session.add_iteration("initial draft".into(), 0.3, "start".into());
    let _ = session.add_iteration("improved draft".into(), 0.7, "feedback".into());

    // ΛD: certainty increases with quality but capped at 0.99
    let quality = 0.7;
    let certainty: f64 = (0.5 + quality * 0.49_f64).min(0.99);
    assert!(certainty < 1.0, "refinement certainty must be < 1.0");
    assert!(certainty > 0.5, "higher quality should have higher certainty");

    // Low quality → lower certainty
    let low_cert: f64 = (0.5_f64 + 0.3_f64 * 0.49_f64).min(0.99);
    assert!(low_cert < certainty, "lower quality should have lower certainty");

    // Max certainty even at quality=1.0 is still 0.99
    let max_cert: f64 = (0.5_f64 + 1.0_f64 * 0.49_f64).min(0.99);
    assert_eq!(max_cert, 0.99, "max certainty for refinement is 0.99");

    // EpistemicEnvelope: all refinements are derived
    let env = EpistemicEnvelope::derived("refinement", 0.99, "refine_engine");
    assert_eq!(env.certainty, 0.99);
    assert_eq!(env.derivation, "derived");
    assert!(env.validate().is_ok());

    // Theorem 5.1: refinement (derived) cannot carry c=1.0
    let bad = EpistemicEnvelope {
        ontology: "refinement".into(),
        certainty: 1.0,
        temporal_start: "0".into(),
        temporal_end: "∞".into(),
        provenance: "refined".into(),
        derivation: "derived".into(),
    };
    assert!(bad.validate().is_err(),
        "Theorem 5.1: refined output cannot have c=1.0");

    // Lattice positions
    let converged_lattice = "believe";    // converged refinement
    let iterating_lattice = "speculate";  // still iterating
    assert_eq!(converged_lattice, "believe");
    assert_eq!(iterating_lattice, "speculate");

    // Quality trend should be monotonically tracked
    let trend: Vec<f64> = session.iterations.iter().map(|i| i.quality).collect();
    assert_eq!(trend, vec![0.3, 0.7]);
    let delta_trend: Vec<f64> = session.iterations.iter().map(|i| i.delta).collect();
    assert_eq!(delta_trend.len(), 2);
    assert!(delta_trend[1] > 0.0, "second iteration should show improvement");
}

