#[test]
fn test_trail_step_recording_and_completion() {
    use axon::axon_server::TrailRecord;
    use std::collections::HashMap;

    let mut trail = TrailRecord {
        id: "trail_test_1".into(),
        name: "analyze_trace".into(),
        target: "flow:analyze".into(),
        completed: false,
        outcome: "in_progress".into(),
        steps: Vec::new(),
        created_at: 1700000000,
        completed_at: 0,
        total_duration_ms: 0,
    };

    // Add steps
    let r = trail.add_step("parse".into(), "source code".into(), "AST".into(), 5, "success".into(), HashMap::new());
    assert!(r.is_ok());
    assert_eq!(r.unwrap(), 1);
    assert_eq!(trail.step_count(), 1);
    assert_eq!(trail.total_duration_ms, 5);

    let r = trail.add_step("type_check".into(), "AST".into(), "typed IR".into(), 12, "success".into(), HashMap::new());
    assert!(r.is_ok());
    assert_eq!(r.unwrap(), 2);

    let mut meta = HashMap::new();
    meta.insert("backend".into(), serde_json::json!("anthropic"));
    let r = trail.add_step("execute".into(), "typed IR".into(), "result".into(), 200, "success".into(), meta);
    assert!(r.is_ok());
    assert_eq!(r.unwrap(), 3);
    assert_eq!(trail.step_count(), 3);
    assert_eq!(trail.total_duration_ms, 217); // 5 + 12 + 200

    // Verify step details
    assert_eq!(trail.steps[0].operation, "parse");
    assert_eq!(trail.steps[2].metadata.get("backend").unwrap(), &serde_json::json!("anthropic"));

    // Complete the trail
    let r = trail.complete("success".into());
    assert!(r.is_ok());
    assert!(trail.completed);
    assert_eq!(trail.outcome, "success");
    assert!(trail.completed_at > 0);

    // Cannot add steps after completion
    let r = trail.add_step("extra".into(), "x".into(), "y".into(), 1, "success".into(), HashMap::new());
    assert!(r.is_err());
    assert!(r.unwrap_err().contains("already completed"));

    // Cannot complete again
    let r = trail.complete("failure".into());
    assert!(r.is_err());
}

#[test]
fn test_trail_success_failure_counts() {
    use axon::axon_server::TrailRecord;
    use std::collections::HashMap;

    let mut trail = TrailRecord {
        id: "trail_counts_1".into(),
        name: "mixed_outcomes".into(),
        target: "pipeline:etl".into(),
        completed: false,
        outcome: "in_progress".into(),
        steps: Vec::new(),
        created_at: 1700000000,
        completed_at: 0,
        total_duration_ms: 0,
    };

    let _ = trail.add_step("extract".into(), "source".into(), "data".into(), 100, "success".into(), HashMap::new());
    let _ = trail.add_step("transform".into(), "data".into(), "error".into(), 50, "failure".into(), HashMap::new());
    let _ = trail.add_step("retry_transform".into(), "data".into(), "transformed".into(), 80, "success".into(), HashMap::new());
    let _ = trail.add_step("load".into(), "transformed".into(), "loaded".into(), 30, "success".into(), HashMap::new());
    let _ = trail.add_step("optional_index".into(), "loaded".into(), "n/a".into(), 0, "skipped".into(), HashMap::new());

    assert_eq!(trail.step_count(), 5);
    assert_eq!(trail.success_count(), 3);
    assert_eq!(trail.failure_count(), 1);
    assert_eq!(trail.total_duration_ms, 260); // 100 + 50 + 80 + 30 + 0

    // Skipped steps are neither success nor failure
    let skipped_count = trail.steps.iter().filter(|s| s.outcome == "skipped").count();
    assert_eq!(skipped_count, 1);

    // Complete with partial outcome
    let _ = trail.complete("partial".into());
    assert!(trail.completed);
    assert_eq!(trail.outcome, "partial");
}

#[test]
fn test_trail_epistemic_alignment() {
    use axon::axon_server::{TrailRecord, EpistemicEnvelope};
    use std::collections::HashMap;

    let mut trail = TrailRecord {
        id: "trail_epistemic_1".into(),
        name: "epistemic_test".into(),
        target: "flow:test".into(),
        completed: false,
        outcome: "in_progress".into(),
        steps: Vec::new(),
        created_at: 1700000000,
        completed_at: 0,
        total_duration_ms: 0,
    };

    // ΛD: trail recording is raw observation — c=1.0 for completed trails
    // In-progress trails are provisional: c=0.95

    // In-progress trail
    let in_progress_certainty = if trail.completed { 1.0 } else { 0.95 };
    assert_eq!(in_progress_certainty, 0.95);

    let _ = trail.add_step("step1".into(), "in".into(), "out".into(), 10, "success".into(), HashMap::new());
    let _ = trail.complete("success".into());

    // Completed trail → c=1.0, δ=raw (ground truth recording)
    let completed_certainty = if trail.completed { 1.0 } else { 0.95 };
    assert_eq!(completed_certainty, 1.0);

    // Trail steps are raw observations (not interpretations)
    let step_env = EpistemicEnvelope::raw_config("trail", "trail_recorder");
    assert_eq!(step_env.certainty, 1.0);
    assert_eq!(step_env.derivation, "raw");
    assert!(step_env.validate().is_ok());

    // Completed trail envelope
    let trail_env = EpistemicEnvelope::raw_config("trail", "completed_trail");
    assert_eq!(trail_env.certainty, 1.0);
    assert_eq!(trail_env.derivation, "raw");

    // Unlike other primitives, trails CAN carry c=1.0 because they are raw observations
    // This is consistent with Theorem 5.1: raw data may carry c=1.0
    assert!(trail_env.validate().is_ok(), "raw trail observation can have c=1.0");

    // A derived interpretation of a trail would be different
    let interpreted_env = EpistemicEnvelope::derived("trail_analysis", 0.99, "analyzer");
    assert_eq!(interpreted_env.certainty, 0.99);
    assert_eq!(interpreted_env.derivation, "derived");

    // Lattice: completed trail → know (ground truth)
    let completed_lattice = "know";
    let in_progress_lattice = "believe"; // provisional
    assert_eq!(completed_lattice, "know");
    assert_eq!(in_progress_lattice, "believe");

    // Serialization
    let json = serde_json::to_string(&trail).unwrap();
    assert!(json.contains("\"completed\":true"));
    assert!(json.contains("\"outcome\":\"success\""));
}

