#[test]
fn test_probe_session_findings_and_aggregation() {
    use axon::axon_server::ProbeSession;

    let mut probe = ProbeSession {
        id: "probe_test_1".into(),
        name: "investigate_attention".into(),
        question: "How does attention work in transformers?".into(),
        sources: vec!["corpus:papers".into(), "axonstore:facts".into()],
        findings: Vec::new(),
        completed: false,
        created_at: 1700000000,
        total_queries: 0,
    };

    // Add findings from multiple sources
    probe.add_finding(
        "corpus:papers".into(), "attention mechanism".into(),
        "Self-attention computes queries, keys, and values from input embeddings".into(),
        0.95,
    );
    probe.add_finding(
        "corpus:papers".into(), "attention mechanism".into(),
        "Multi-head attention allows attending to different representation subspaces".into(),
        0.88,
    );
    probe.add_finding(
        "axonstore:facts".into(), "transformer architecture".into(),
        "Transformers use scaled dot-product attention".into(),
        0.72,
    );

    assert_eq!(probe.findings.len(), 3);
    probe.total_queries = 2;

    // Certainty derived from relevance, capped at 0.99
    assert!((probe.findings[0].certainty - 0.9405).abs() < 0.001); // 0.95 * 0.99
    assert!(probe.findings[0].certainty <= 0.99);

    // Aggregate certainty
    let agg = probe.aggregate_certainty();
    assert!(agg > 0.0 && agg <= 0.99);

    // Top findings sorted by relevance
    let top = probe.top_findings(2);
    assert_eq!(top.len(), 2);
    assert!(top[0].relevance >= top[1].relevance, "should be sorted descending");
    assert_eq!(top[0].source, "corpus:papers");

    // Findings per source
    let per_source = probe.findings_per_source();
    assert_eq!(per_source.get("corpus:papers"), Some(&2));
    assert_eq!(per_source.get("axonstore:facts"), Some(&1));
}

#[test]
fn test_probe_completion_and_top_findings() {
    use axon::axon_server::ProbeSession;

    let mut probe = ProbeSession {
        id: "probe_complete_1".into(),
        name: "research_nlp".into(),
        question: "What are the latest NLP techniques?".into(),
        sources: vec!["corpus:papers".into()],
        findings: Vec::new(),
        completed: false,
        created_at: 1700000000,
        total_queries: 0,
    };

    // Add varied-relevance findings
    for i in 0..8 {
        let relevance = 0.3 + (i as f64) * 0.08;
        probe.add_finding(
            "corpus:papers".into(),
            format!("nlp query {}", i),
            format!("Finding about NLP technique {}", i),
            relevance,
        );
    }
    probe.total_queries = 8;

    assert_eq!(probe.findings.len(), 8);
    assert!(!probe.completed);

    // Top 3 findings
    let top3 = probe.top_findings(3);
    assert_eq!(top3.len(), 3);
    // Highest relevance should be from last added (0.3 + 7*0.08 = 0.86)
    assert!((top3[0].relevance - 0.86).abs() < 0.01);

    // Complete the probe
    probe.completed = true;

    // Post-completion: aggregate certainty reflects all findings
    let agg = probe.aggregate_certainty();
    assert!(agg > 0.0);
    assert!(agg <= 0.99, "aggregate certainty must be ≤0.99 (derived)");

    // Lattice position based on aggregate certainty
    let lattice = if agg > 0.8 { "believe" } else { "speculate" };
    // With relevances 0.3-0.86, average certainty should be moderate
    assert!(lattice == "speculate" || lattice == "believe");

    // Verify top_findings with limit > total returns all
    let all = probe.top_findings(100);
    assert_eq!(all.len(), 8);
}

#[test]
fn test_probe_epistemic_alignment_theorem_5_1() {
    use axon::axon_server::{ProbeSession, EpistemicEnvelope};

    let mut probe = ProbeSession {
        id: "probe_epistemic_1".into(),
        name: "epistemic_test".into(),
        question: "Test ΛD alignment".into(),
        sources: vec!["source:a".into()],
        findings: Vec::new(),
        completed: false,
        created_at: 1700000000,
        total_queries: 0,
    };

    // All probe findings are derived (Theorem 5.1)
    probe.add_finding("source:a".into(), "q1".into(), "result1".into(), 1.0);
    probe.add_finding("source:a".into(), "q2".into(), "result2".into(), 0.5);

    // Even with relevance=1.0, certainty is capped at 0.99
    assert!(probe.findings[0].certainty <= 0.99,
        "probe certainty must be ≤0.99 even for perfect relevance");
    assert_eq!(probe.findings[0].certainty, 0.99); // 1.0 * 0.99 = 0.99

    // Lower relevance → lower certainty
    assert!(probe.findings[1].certainty < probe.findings[0].certainty);

    // EpistemicEnvelope for probe findings
    let env = EpistemicEnvelope::derived("probe", 0.99, "probe_engine");
    assert_eq!(env.certainty, 0.99);
    assert_eq!(env.derivation, "derived");
    assert!(env.validate().is_ok());

    // Theorem 5.1: probe findings (derived) cannot carry c=1.0
    let bad = EpistemicEnvelope {
        ontology: "probe".into(),
        certainty: 1.0,
        temporal_start: "0".into(),
        temporal_end: "∞".into(),
        provenance: "exploration".into(),
        derivation: "derived".into(),
    };
    assert!(bad.validate().is_err(),
        "Theorem 5.1: probe finding (derived) cannot have c=1.0");

    // Aggregate certainty is always ≤0.99
    let agg = probe.aggregate_certainty();
    assert!(agg <= 0.99);
    assert!(agg > 0.0);

    // Lattice: probe is always speculate or believe (never know)
    let lattice = if agg > 0.8 { "believe" } else { "speculate" };
    assert!(lattice == "speculate" || lattice == "believe");
    assert!(lattice != "know", "probe findings cannot reach 'know' (always derived)");

    // Effect row
    let effects = vec!["io", "epistemic:speculate"];
    assert!(effects.contains(&"epistemic:speculate"));
}

