#[test]
fn test_weave_strand_collection_and_synthesis() {
    use axon::axon_server::WeaveSession;

    let mut weave = WeaveSession {
        id: "weave_test_1".into(),
        name: "attention_synthesis".into(),
        goal: "Combine findings on attention mechanisms".into(),
        strands: Vec::new(),
        synthesis: String::new(),
        synthesized: false,
        created_at: 1700000000,
        next_strand_id: 1,
    };

    // Add strands from different sources
    let id1 = weave.add_strand(
        "corpus:papers/doc_1".into(),
        "Self-attention computes queries, keys, and values".into(),
        0.9, 1.0, // raw source, high weight
    );
    assert_eq!(id1, 1);

    let id2 = weave.add_strand(
        "probe:findings".into(),
        "Multi-head attention allows different subspace representation".into(),
        0.7, 0.85, // derived source, medium weight
    );
    assert_eq!(id2, 2);

    let id3 = weave.add_strand(
        "axonstore:facts".into(),
        "Transformers use scaled dot-product attention".into(),
        0.5, 0.99, // derived source, lower weight
    );
    assert_eq!(id3, 3);

    assert_eq!(weave.strands.len(), 3);
    assert!(!weave.synthesized);

    // Attributions
    let attr = weave.attributions();
    assert_eq!(attr.len(), 3);
    assert_eq!(attr[0].0, "corpus:papers/doc_1");
    assert_eq!(attr[0].1, 0.9);

    // Synthesize
    let result = weave.synthesize();
    assert!(result.is_ok());
    let synthesis = result.unwrap();

    // Synthesis should contain all strand contents with source attribution
    assert!(synthesis.contains("[corpus:papers/doc_1]"));
    assert!(synthesis.contains("[probe:findings]"));
    assert!(synthesis.contains("[axonstore:facts]"));
    assert!(synthesis.contains("Self-attention"));
    assert!(weave.synthesized);

    // Cannot synthesize again
    let result2 = weave.synthesize();
    assert!(result2.is_err());
    assert!(result2.unwrap_err().contains("already synthesized"));

    // Cannot add strands after synthesis (tested in handler, not struct)
}

#[test]
fn test_weave_synthesis_certainty_weighted() {
    use axon::axon_server::WeaveSession;

    let mut weave = WeaveSession {
        id: "weave_cert_1".into(),
        name: "certainty_test".into(),
        goal: "Test weighted certainty".into(),
        strands: Vec::new(),
        synthesis: String::new(),
        synthesized: false,
        created_at: 1700000000,
        next_strand_id: 1,
    };

    // Strand with high weight, high certainty
    weave.add_strand("source_a".into(), "High confidence content".into(), 0.8, 1.0);
    // Strand with low weight, low certainty
    weave.add_strand("source_b".into(), "Low confidence content".into(), 0.2, 0.5);

    // Weighted certainty: (1.0*0.8 + 0.5*0.2) / (0.8+0.2) = (0.8+0.1)/1.0 = 0.9
    let cert = weave.synthesis_certainty();
    assert!((cert - 0.9).abs() < 0.01, "weighted certainty should be ~0.9, got {}", cert);

    // Equal weights, different certainties
    let mut weave2 = WeaveSession {
        id: "weave_cert_2".into(),
        name: "equal_weights".into(),
        goal: "Test equal weight certainty".into(),
        strands: Vec::new(),
        synthesis: String::new(),
        synthesized: false,
        created_at: 1700000000,
        next_strand_id: 1,
    };

    weave2.add_strand("s1".into(), "c1".into(), 1.0, 0.8);
    weave2.add_strand("s2".into(), "c2".into(), 1.0, 0.6);

    // Equal weights: (0.8*1.0 + 0.6*1.0) / (1.0+1.0) = 1.4/2.0 = 0.7
    let cert2 = weave2.synthesis_certainty();
    assert!((cert2 - 0.7).abs() < 0.01, "equal weight certainty should be 0.7, got {}", cert2);

    // Empty weave has zero certainty
    let empty = WeaveSession {
        id: "empty".into(), name: "e".into(), goal: "e".into(),
        strands: Vec::new(), synthesis: String::new(), synthesized: false,
        created_at: 0, next_strand_id: 1,
    };
    assert_eq!(empty.synthesis_certainty(), 0.0);

    // Synthesis on empty fails
    let mut empty2 = empty.clone();
    assert!(empty2.synthesize().is_err());
}

#[test]
fn test_weave_epistemic_alignment_theorem_5_1() {
    use axon::axon_server::{WeaveSession, EpistemicEnvelope};

    let mut weave = WeaveSession {
        id: "weave_epistemic_1".into(),
        name: "epistemic_test".into(),
        goal: "Test ΛD alignment".into(),
        strands: Vec::new(),
        synthesis: String::new(),
        synthesized: false,
        created_at: 1700000000,
        next_strand_id: 1,
    };

    // Even with all raw sources (c=1.0), synthesis is derived
    weave.add_strand("raw_source_1".into(), "Raw fact 1".into(), 1.0, 1.0);
    weave.add_strand("raw_source_2".into(), "Raw fact 2".into(), 1.0, 1.0);

    let raw_cert = weave.synthesis_certainty();
    assert_eq!(raw_cert, 1.0, "raw weighted avg is 1.0");

    // But in the handler, synthesis certainty is capped at 0.99 (Theorem 5.1)
    let capped = raw_cert.min(0.99);
    assert_eq!(capped, 0.99, "synthesis certainty must be capped at 0.99");

    // EpistemicEnvelope for synthesis is always derived
    let env = EpistemicEnvelope::derived("weave", 0.99, "weave_engine");
    assert_eq!(env.certainty, 0.99);
    assert_eq!(env.derivation, "derived");
    assert!(env.validate().is_ok());

    // Theorem 5.1: synthesis (derived) cannot carry c=1.0
    let bad = EpistemicEnvelope {
        ontology: "weave".into(),
        certainty: 1.0,
        temporal_start: "0".into(),
        temporal_end: "∞".into(),
        provenance: "synthesis".into(),
        derivation: "derived".into(),
    };
    assert!(bad.validate().is_err(),
        "Theorem 5.1: synthesis (derived) cannot have c=1.0");

    // Lattice: high certainty synthesis → believe, low → speculate
    let high_lattice = if capped > 0.8 { "believe" } else { "speculate" };
    assert_eq!(high_lattice, "believe");

    // Weight clamping: weights are clamped to [0.0, 1.0]
    let mut weave2 = WeaveSession {
        id: "clamp_test".into(), name: "clamp".into(), goal: "test".into(),
        strands: Vec::new(), synthesis: String::new(), synthesized: false,
        created_at: 0, next_strand_id: 1,
    };
    weave2.add_strand("s".into(), "c".into(), -0.5, 2.0); // should clamp to 0.0, 1.0
    assert_eq!(weave2.strands[0].weight, 0.0);
    assert_eq!(weave2.strands[0].source_certainty, 1.0);

    // Attributions preserve source provenance
    let _ = weave.synthesize();
    assert!(weave.synthesis.contains("[raw_source_1]"));
    assert!(weave.synthesis.contains("[raw_source_2]"));
}

// ── G18: Corroborate Primitive Runtime ──────────────────────────────────

#[test]
fn test_corroborate_evidence_and_agreement_scoring() {
    use axon::axon_server::CorroborateSession;

    let mut session = CorroborateSession {
        id: "corr_test_1".into(),
        name: "transformer_claim".into(),
        claim: "Transformers outperform RNNs on long sequences".into(),
        evidence: Vec::new(),
        verified: false,
        verdict: "pending".into(),
        created_at: 1700000000,
        next_evidence_id: 1,
    };

    // Add supporting evidence
    let r = session.add_evidence(
        "corpus:papers/doc_1".into(),
        "Study shows transformers achieve lower perplexity on sequences >1000 tokens".into(),
        "supports".into(), 0.9,
    );
    assert!(r.is_ok());
    assert_eq!(r.unwrap(), 1);

    let _ = session.add_evidence(
        "corpus:papers/doc_2".into(),
        "Benchmark results confirm transformer superiority on long-range tasks".into(),
        "supports".into(), 0.85,
    );

    // Add contradicting evidence
    let _ = session.add_evidence(
        "corpus:papers/doc_3".into(),
        "For certain sequential tasks, optimized LSTMs remain competitive".into(),
        "contradicts".into(), 0.6,
    );

    // Add neutral evidence
    let _ = session.add_evidence(
        "axonstore:facts/note_1".into(),
        "Performance depends on task-specific factors".into(),
        "neutral".into(), 0.5,
    );

    assert_eq!(session.evidence.len(), 4);

    // Stance counts
    let (sup, con, neu) = session.stance_counts();
    assert_eq!(sup, 2);
    assert_eq!(con, 1);
    assert_eq!(neu, 1);

    // Agreement: (0.9+0.85 - 0.6) / (0.9+0.85+0.6+0.5) = 1.15/2.85 ≈ 0.4035
    let (agreement, certainty, verdict) = session.compute_agreement();
    assert!(agreement > 0.0, "net support should be positive");
    assert!(agreement < 1.0);
    assert!(certainty <= 0.99);
    // Agreement ~0.4 → inconclusive (not > 0.5)
    assert_eq!(verdict, "inconclusive");

    // Invalid stance rejected
    let r = session.add_evidence("s".into(), "c".into(), "maybe".into(), 0.5);
    assert!(r.is_err());
    assert!(r.unwrap_err().contains("invalid stance"));
}

#[test]
fn test_corroborate_verify_verdicts() {
    use axon::axon_server::CorroborateSession;

    // Test "corroborated" verdict (strong support)
    let mut corr = CorroborateSession {
        id: "corr_v1".into(), name: "v1".into(),
        claim: "Claim A".into(), evidence: Vec::new(),
        verified: false, verdict: "pending".into(),
        created_at: 1700000000, next_evidence_id: 1,
    };
    let _ = corr.add_evidence("s1".into(), "strong support".into(), "supports".into(), 0.9);
    let _ = corr.add_evidence("s2".into(), "more support".into(), "supports".into(), 0.8);

    let r = corr.verify();
    assert!(r.is_ok());
    let (agreement, certainty, verdict) = r.unwrap();
    assert!(agreement > 0.5, "strong support should have agreement > 0.5");
    assert_eq!(verdict, "corroborated");
    assert!(certainty > 0.0 && certainty <= 0.99);
    assert!(corr.verified);

    // Cannot verify again
    assert!(corr.verify().is_err());

    // Cannot add evidence after verification
    assert!(corr.add_evidence("s3".into(), "late".into(), "supports".into(), 0.5).is_err());

    // Test "disputed" verdict (strong contradiction)
    let mut disp = CorroborateSession {
        id: "corr_v2".into(), name: "v2".into(),
        claim: "Claim B".into(), evidence: Vec::new(),
        verified: false, verdict: "pending".into(),
        created_at: 1700000000, next_evidence_id: 1,
    };
    let _ = disp.add_evidence("s1".into(), "refutation".into(), "contradicts".into(), 0.95);
    let _ = disp.add_evidence("s2".into(), "another refutation".into(), "contradicts".into(), 0.8);

    let (agreement, _, verdict) = disp.verify().unwrap();
    assert!(agreement < -0.5, "strong contradiction should have agreement < -0.5");
    assert_eq!(verdict, "disputed");

    // Test empty session cannot verify
    let mut empty = CorroborateSession {
        id: "corr_v3".into(), name: "v3".into(),
        claim: "Claim C".into(), evidence: Vec::new(),
        verified: false, verdict: "pending".into(),
        created_at: 1700000000, next_evidence_id: 1,
    };
    assert!(empty.verify().is_err());
}

#[test]
fn test_corroborate_epistemic_alignment_theorem_5_1() {
    use axon::axon_server::{CorroborateSession, EpistemicEnvelope};

    let mut session = CorroborateSession {
        id: "corr_epi_1".into(), name: "epistemic".into(),
        claim: "Test ΛD alignment".into(), evidence: Vec::new(),
        verified: false, verdict: "pending".into(),
        created_at: 1700000000, next_evidence_id: 1,
    };

    // All-supporting evidence
    let _ = session.add_evidence("s1".into(), "support".into(), "supports".into(), 1.0);
    let _ = session.add_evidence("s2".into(), "support".into(), "supports".into(), 1.0);

    let (agreement, certainty, _) = session.compute_agreement();
    assert_eq!(agreement, 1.0, "all-support should have agreement=1.0");
    // Certainty: |1.0| * 0.99 = 0.99
    assert!(certainty <= 0.99, "certainty must be ≤0.99 (derived)");

    // EpistemicEnvelope for corroboration is always derived
    let env = EpistemicEnvelope::derived("corroboration", certainty, "corroborate_engine");
    assert_eq!(env.derivation, "derived");
    assert!(env.certainty <= 0.99);
    assert!(env.validate().is_ok());

    // Theorem 5.1: corroboration (derived) cannot carry c=1.0
    let bad = EpistemicEnvelope {
        ontology: "corroboration".into(),
        certainty: 1.0,
        temporal_start: "0".into(),
        temporal_end: "∞".into(),
        provenance: "verification".into(),
        derivation: "derived".into(),
    };
    assert!(bad.validate().is_err(),
        "Theorem 5.1: corroboration (derived) cannot have c=1.0");

    // Lattice positions per verdict
    let corroborated_lattice = "believe";  // strong agreement
    let disputed_lattice = "doubt";         // strong disagreement
    let inconclusive_lattice = "speculate"; // mixed evidence
    assert_eq!(corroborated_lattice, "believe");
    assert_eq!(disputed_lattice, "doubt");
    assert_eq!(inconclusive_lattice, "speculate");

    // Confidence clamping: values are clamped to [0.0, 1.0]
    let _ = session.add_evidence("s3".into(), "c".into(), "supports".into(), 2.0);
    assert_eq!(session.evidence.last().unwrap().confidence, 1.0, "confidence clamped to 1.0");

    let _ = session.add_evidence("s4".into(), "c".into(), "contradicts".into(), -0.5);
    assert_eq!(session.evidence.last().unwrap().confidence, 0.0, "confidence clamped to 0.0");
}

// ── G19: Drill Primitive Runtime ────────────────────────────────────────

#[test]
fn test_drill_tree_expansion_and_depth_limit() {
    use axon::axon_server::DrillSession;
    use std::collections::HashMap;

    let mut drill = DrillSession {
        id: "drill_test_1".into(),
        name: "explore_attention".into(),
        root_question: "How does attention work?".into(),
        max_depth: 3,
        nodes: HashMap::new(),
        completed: false,
        created_at: 1700000000,
    };

    // Add root
    let r = drill.add_root("Attention computes weighted sums of values".into());
    assert!(r.is_ok());
    assert_eq!(r.unwrap(), "root");
    assert_eq!(drill.node_count(), 1);

    // Cannot add root again
    assert!(drill.add_root("duplicate".into()).is_err());

    // Expand root → depth 1
    let c1 = drill.expand("root", "What is self-attention?".into(), "Q, K, V projections".into());
    assert!(c1.is_ok());
    assert_eq!(c1.unwrap(), "root.0");

    let c2 = drill.expand("root", "What is multi-head attention?".into(), "Parallel attention heads".into());
    assert!(c2.is_ok());
    assert_eq!(c2.unwrap(), "root.1");

    assert_eq!(drill.node_count(), 3);
    assert_eq!(drill.nodes.get("root").unwrap().children.len(), 2);

    // Expand depth 1 → depth 2
    let c3 = drill.expand("root.0", "How are Q, K, V computed?".into(), "Linear projections of input".into());
    assert!(c3.is_ok());
    assert_eq!(c3.unwrap(), "root.0.0");
    assert_eq!(drill.nodes.get("root.0.0").unwrap().depth, 2);

    // Expand depth 2 → depth 3 (max_depth)
    let c4 = drill.expand("root.0.0", "What are the projection dimensions?".into(), "d_k = d_model / n_heads".into());
    assert!(c4.is_ok());
    let leaf_id = c4.unwrap();
    assert_eq!(drill.nodes.get(&leaf_id).unwrap().depth, 3);
    assert!(drill.nodes.get(&leaf_id).unwrap().is_leaf, "depth=max_depth should be leaf");

    // Cannot expand beyond max_depth
    let c5 = drill.expand(&leaf_id, "deeper?".into(), "nope".into());
    assert!(c5.is_err());
    assert!(c5.unwrap_err().contains("max depth"));

    // Expand non-existent parent
    let bad = drill.expand("nonexistent", "q".into(), "a".into());
    assert!(bad.is_err());

    assert_eq!(drill.node_count(), 5);
    assert_eq!(drill.max_depth_reached(), 3);
    assert_eq!(drill.leaf_count(), 2); // root.1 and root.0.0.0 (nodes with no children)
}

#[test]
fn test_drill_certainty_degradation_with_depth() {
    use axon::axon_server::DrillSession;
    use std::collections::HashMap;

    // Certainty formula: (1.0 - depth * 0.05).max(0.5).min(0.99)
    assert_eq!(DrillSession::certainty_at_depth(0), 0.99);  // 1.0 capped at 0.99
    assert_eq!(DrillSession::certainty_at_depth(1), 0.95);
    assert_eq!(DrillSession::certainty_at_depth(2), 0.9);
    assert_eq!(DrillSession::certainty_at_depth(5), 0.75);
    assert_eq!(DrillSession::certainty_at_depth(10), 0.5);   // min 0.5
    assert_eq!(DrillSession::certainty_at_depth(20), 0.5);   // stays at min

    // Build a drill and verify node certainties
    let mut drill = DrillSession {
        id: "drill_cert_1".into(),
        name: "cert_test".into(),
        root_question: "Root?".into(),
        max_depth: 10,
        nodes: HashMap::new(),
        completed: false,
        created_at: 1700000000,
    };

    let _ = drill.add_root("root answer".into());
    assert_eq!(drill.nodes.get("root").unwrap().certainty, 0.99);

    let _ = drill.expand("root", "d1?".into(), "d1 answer".into());
    assert_eq!(drill.nodes.get("root.0").unwrap().certainty, 0.95);

    let _ = drill.expand("root.0", "d2?".into(), "d2 answer".into());
    assert_eq!(drill.nodes.get("root.0.0").unwrap().certainty, 0.9);

    // Average certainty should decrease as we go deeper
    let avg = drill.avg_certainty();
    assert!(avg > 0.9 && avg < 0.99, "avg certainty for shallow drill should be ~0.95");

    // All certainties are < 1.0 (derived)
    for node in drill.nodes.values() {
        assert!(node.certainty <= 0.99, "all drill certainties must be ≤0.99");
        assert!(node.certainty >= 0.5, "all drill certainties must be ≥0.5");
    }
}

#[test]
fn test_drill_epistemic_alignment_theorem_5_1() {
    use axon::axon_server::{DrillSession, EpistemicEnvelope};
    use std::collections::HashMap;

    let mut drill = DrillSession {
        id: "drill_epi_1".into(),
        name: "epistemic_test".into(),
        root_question: "Test?".into(),
        max_depth: 5,
        nodes: HashMap::new(),
        completed: false,
        created_at: 1700000000,
    };

    let _ = drill.add_root("answer".into());
    let _ = drill.expand("root", "sub?".into(), "sub answer".into());

    // All drill findings are derived (Theorem 5.1)
    // Even the root (depth=0) is capped at 0.99
    assert_eq!(drill.nodes.get("root").unwrap().certainty, 0.99);
    assert!(drill.nodes.get("root").unwrap().certainty < 1.0);

    // EpistemicEnvelope for drill nodes
    let env = EpistemicEnvelope::derived("drill", 0.95, "drill_engine");
    assert_eq!(env.derivation, "derived");
    assert!(env.certainty <= 0.99);
    assert!(env.validate().is_ok());

    // Theorem 5.1: drill (derived) cannot carry c=1.0
    let bad = EpistemicEnvelope {
        ontology: "drill".into(),
        certainty: 1.0,
        temporal_start: "0".into(),
        temporal_end: "∞".into(),
        provenance: "exploration".into(),
        derivation: "derived".into(),
    };
    assert!(bad.validate().is_err(),
        "Theorem 5.1: drill exploration (derived) cannot have c=1.0");

    // Lattice: shallow → believe, deep → speculate
    let shallow_cert = DrillSession::certainty_at_depth(1); // 0.95
    let deep_cert = DrillSession::certainty_at_depth(8);    // 0.6
    let shallow_lattice = if shallow_cert > 0.8 { "believe" } else { "speculate" };
    let deep_lattice = if deep_cert > 0.8 { "believe" } else { "speculate" };
    assert_eq!(shallow_lattice, "believe");
    assert_eq!(deep_lattice, "speculate");

    // Completion
    drill.completed = true;
    assert!(drill.expand("root", "more?".into(), "no".into()).is_err());

    // Serialization
    let json = serde_json::to_string(&drill).unwrap();
    assert!(json.contains("\"completed\":true"));
    assert!(json.contains("\"root_question\":\"Test?\""));
}

