#[test]
fn test_forge_template_variable_extraction_and_rendering() {
    use axon::axon_server::ForgeSession;
    use std::collections::HashMap;

    let mut forge = ForgeSession {
        id: "forge_test_1".into(),
        name: "report_gen".into(),
        templates: HashMap::new(),
        artifacts: Vec::new(),
        created_at: 1700000000,
        next_artifact_id: 1,
    };

    // Variable extraction
    let vars = ForgeSession::extract_variables("Hello {{name}}, your score is {{score}}.");
    assert_eq!(vars, vec!["name", "score"]);

    // No variables
    let vars_empty = ForgeSession::extract_variables("No placeholders here.");
    assert!(vars_empty.is_empty());

    // Duplicate variables extracted once
    let vars_dup = ForgeSession::extract_variables("{{x}} + {{x}} = {{result}}");
    assert_eq!(vars_dup, vec!["x", "result"]);

    // Register template
    let r = forge.add_template(
        "summary".into(),
        "# {{title}}\n\nBy: {{author}}\n\n{{body}}".into(),
        "markdown".into(),
    );
    assert!(r.is_ok());
    assert_eq!(forge.templates.len(), 1);
    assert_eq!(forge.templates.get("summary").unwrap().variables, vec!["title", "author", "body"]);

    // Duplicate template rejected
    assert!(forge.add_template("summary".into(), "dup".into(), "text".into()).is_err());

    // Render
    let mut vars_map = HashMap::new();
    vars_map.insert("title".into(), "Attention Survey".into());
    vars_map.insert("author".into(), "Research Team".into());
    vars_map.insert("body".into(), "This paper surveys attention mechanisms.".into());

    let artifact = forge.render("summary", &vars_map).unwrap();
    assert!(artifact.content.contains("# Attention Survey"));
    assert!(artifact.content.contains("By: Research Team"));
    assert!(artifact.content.contains("This paper surveys"));
    assert_eq!(artifact.format, "markdown");
    assert_eq!(artifact.certainty, 0.99);
    assert_eq!(forge.artifacts.len(), 1);
}

#[test]
fn test_forge_render_errors_and_multiple_artifacts() {
    use axon::axon_server::ForgeSession;
    use std::collections::HashMap;

    let mut forge = ForgeSession {
        id: "forge_err_1".into(),
        name: "test".into(),
        templates: HashMap::new(),
        artifacts: Vec::new(),
        created_at: 1700000000,
        next_artifact_id: 1,
    };

    forge.add_template(
        "greeting".into(),
        "Hello {{name}}! Welcome to {{place}}.".into(),
        "text".into(),
    ).unwrap();

    // Missing variable
    let mut partial = HashMap::new();
    partial.insert("name".into(), "Alice".into());
    let r = forge.render("greeting", &partial);
    assert!(r.is_err());
    assert!(r.unwrap_err().contains("missing required variable 'place'"));

    // Non-existent template
    let r = forge.render("nonexistent", &HashMap::new());
    assert!(r.is_err());
    assert!(r.unwrap_err().contains("not found"));

    // Successful render
    let mut full = HashMap::new();
    full.insert("name".into(), "Alice".into());
    full.insert("place".into(), "AXON".into());
    let a1 = forge.render("greeting", &full).unwrap();
    assert_eq!(a1.content, "Hello Alice! Welcome to AXON.");

    // Multiple renders produce unique artifact IDs
    full.insert("name".into(), "Bob".into());
    let a2 = forge.render("greeting", &full).unwrap();
    assert_eq!(a2.content, "Hello Bob! Welcome to AXON.");
    assert_ne!(a1.id, a2.id, "artifact IDs should be unique");

    assert_eq!(forge.artifacts.len(), 2);
    assert_eq!(forge.next_artifact_id, 3);
}

#[test]
fn test_forge_epistemic_alignment_theorem_5_1() {
    use axon::axon_server::{ForgeSession, EpistemicEnvelope};
    use std::collections::HashMap;

    let mut forge = ForgeSession {
        id: "forge_epi_1".into(),
        name: "epistemic".into(),
        templates: HashMap::new(),
        artifacts: Vec::new(),
        created_at: 1700000000,
        next_artifact_id: 1,
    };

    forge.add_template(
        "fact".into(),
        "Fact: {{content}}".into(),
        "text".into(),
    ).unwrap();

    let mut vars = HashMap::new();
    vars.insert("content".into(), "The sky is blue".into());
    let artifact = forge.render("fact", &vars).unwrap();

    // Template rendering is deterministic but derived (transformation)
    assert_eq!(artifact.certainty, 0.99);
    // Even though the input fact might be raw, the rendered artifact is derived
    // because template instantiation is a transformation operation

    // EpistemicEnvelope for forge artifacts
    let env = EpistemicEnvelope::derived("forge", 0.99, "forge_engine");
    assert_eq!(env.derivation, "derived");
    assert_eq!(env.certainty, 0.99);
    assert!(env.validate().is_ok());

    // Theorem 5.1: forge artifact (derived) cannot carry c=1.0
    let bad = EpistemicEnvelope {
        ontology: "forge".into(),
        certainty: 1.0,
        temporal_start: "0".into(),
        temporal_end: "∞".into(),
        provenance: "template".into(),
        derivation: "derived".into(),
    };
    assert!(bad.validate().is_err(),
        "Theorem 5.1: forge artifact (derived) cannot have c=1.0");

    // Lattice: forge output is deterministic → believe (high confidence derived)
    let lattice = "believe";
    assert_eq!(lattice, "believe");

    // Effect row
    let effects = vec!["io", "epistemic:believe"];
    assert!(effects.contains(&"epistemic:believe"));

    // All artifacts carry certainty 0.99
    for a in &forge.artifacts {
        assert_eq!(a.certainty, 0.99, "all forge artifacts must have c=0.99");
    }
}

