#[test]
fn test_deliberate_option_evaluation_and_scoring() {
    use axon::axon_server::DeliberateSession;

    let mut session = DeliberateSession {
        id: "delib_test_1".into(),
        name: "choose_backend".into(),
        question: "Which backend for production?".into(),
        options: Vec::new(),
        decided: false,
        chosen_option: None,
        created_at: 1700000000,
        next_option_id: 1,
    };

    // Add options
    let id1 = session.add_option("Anthropic".into(), "Claude API".into()).unwrap();
    let id2 = session.add_option("OpenAI".into(), "GPT API".into()).unwrap();
    let id3 = session.add_option("Ollama".into(), "Local LLM".into()).unwrap();
    assert_eq!(id1, 1);
    assert_eq!(id2, 2);
    assert_eq!(id3, 3);
    assert_eq!(session.options.len(), 3);

    // Initial scores are 0.5 (neutral)
    assert_eq!(session.options[0].score, 0.5);

    // Evaluate option 1: 3 pros, 1 con → score = 3/4 = 0.75
    session.evaluate(1, Some("High reliability".into()), None).unwrap();
    session.evaluate(1, Some("Great reasoning".into()), None).unwrap();
    session.evaluate(1, Some("Good documentation".into()), None).unwrap();
    session.evaluate(1, None, Some("Expensive".into())).unwrap();
    assert_eq!(session.options[0].score, 0.75);
    assert_eq!(session.options[0].pros.len(), 3);
    assert_eq!(session.options[0].cons.len(), 1);

    // Evaluate option 2: 1 pro, 2 cons → score = 1/3 ≈ 0.3333
    session.evaluate(2, Some("Fast".into()), None).unwrap();
    session.evaluate(2, None, Some("Rate limits".into())).unwrap();
    session.evaluate(2, None, Some("Inconsistent".into())).unwrap();
    assert!((session.options[1].score - 0.3333).abs() < 0.01);

    // Option 3: no evaluation → stays at 0.5
    assert_eq!(session.options[2].score, 0.5);

    assert_eq!(session.viable_count(), 3);
}

#[test]
fn test_deliberate_backtrack_and_decide() {
    use axon::axon_server::DeliberateSession;

    let mut session = DeliberateSession {
        id: "delib_bt_1".into(),
        name: "backtrack_test".into(),
        question: "Best approach?".into(),
        options: Vec::new(),
        decided: false,
        chosen_option: None,
        created_at: 1700000000,
        next_option_id: 1,
    };

    let _ = session.add_option("Option A".into(), "First approach".into());
    let _ = session.add_option("Option B".into(), "Second approach".into());
    let _ = session.add_option("Option C".into(), "Third approach".into());

    // Give A the best score
    session.evaluate(1, Some("pro1".into()), None).unwrap();
    session.evaluate(1, Some("pro2".into()), None).unwrap();
    // B gets medium score
    session.evaluate(2, Some("pro1".into()), Some("con1".into())).unwrap();
    // C gets low score
    session.evaluate(3, None, Some("con1".into())).unwrap();

    // Eliminate C (backtrack)
    session.eliminate(3, "Too risky".into()).unwrap();
    assert!(session.options[2].eliminated);
    assert_eq!(session.options[2].score, 0.0);
    assert_eq!(session.viable_count(), 2);

    // Cannot eliminate again
    assert!(session.eliminate(3, "again".into()).is_err());

    // Cannot evaluate eliminated option
    assert!(session.evaluate(3, Some("late pro".into()), None).is_err());

    // Decide — A should win (score 1.0, two pros zero cons)
    let (chosen, score, certainty) = session.decide().unwrap();
    assert_eq!(chosen, 1);
    assert_eq!(score, 1.0); // 2 pros, 0 cons
    assert!(certainty > 0.0 && certainty <= 0.99);
    assert!(session.decided);
    assert_eq!(session.chosen_option, Some(1));

    // Cannot decide again
    assert!(session.decide().is_err());

    // Cannot add options after decision
    assert!(session.add_option("Late".into(), "Too late".into()).is_err());

    // No viable options → decide fails
    let mut empty = DeliberateSession {
        id: "delib_empty".into(), name: "e".into(), question: "q".into(),
        options: Vec::new(), decided: false, chosen_option: None,
        created_at: 0, next_option_id: 1,
    };
    let _ = empty.add_option("Only".into(), "One option".into());
    empty.eliminate(1, "bad".into()).unwrap();
    assert!(empty.decide().is_err()); // no viable options
}

#[test]
fn test_deliberate_epistemic_alignment_theorem_5_1() {
    use axon::axon_server::{DeliberateSession, EpistemicEnvelope};

    let mut session = DeliberateSession {
        id: "delib_epi_1".into(),
        name: "epistemic".into(),
        question: "Test ΛD".into(),
        options: Vec::new(),
        decided: false,
        chosen_option: None,
        created_at: 1700000000,
        next_option_id: 1,
    };

    // Clear winner → high certainty (large margin)
    let _ = session.add_option("Strong".into(), "Clearly best".into());
    let _ = session.add_option("Weak".into(), "Clearly worse".into());
    session.evaluate(1, Some("p1".into()), None).unwrap();
    session.evaluate(1, Some("p2".into()), None).unwrap();
    session.evaluate(2, None, Some("c1".into())).unwrap();

    let (_, _, certainty) = session.decide().unwrap();
    // Margin: 1.0 - 0.0 = 1.0, certainty = 1.0 * 0.99 = 0.99
    assert!(certainty <= 0.99, "deliberation certainty must be ≤0.99");
    assert!(certainty > 0.5, "clear winner should have high certainty");

    // EpistemicEnvelope for deliberation
    let env = EpistemicEnvelope::derived("deliberation", certainty, "deliberate_engine");
    assert_eq!(env.derivation, "derived");
    assert!(env.certainty <= 0.99);
    assert!(env.validate().is_ok());

    // Theorem 5.1: deliberation (derived) cannot carry c=1.0
    let bad = EpistemicEnvelope {
        ontology: "deliberation".into(),
        certainty: 1.0,
        temporal_start: "0".into(),
        temporal_end: "∞".into(),
        provenance: "reasoning".into(),
        derivation: "derived".into(),
    };
    assert!(bad.validate().is_err(),
        "Theorem 5.1: deliberation (derived) cannot have c=1.0");

    // Lattice: high certainty → believe, low → speculate
    let lattice = if certainty > 0.5 { "believe" } else { "speculate" };
    assert_eq!(lattice, "believe");

    // Close contest → low certainty
    let mut close = DeliberateSession {
        id: "delib_close".into(), name: "close".into(), question: "q".into(),
        options: Vec::new(), decided: false, chosen_option: None,
        created_at: 0, next_option_id: 1,
    };
    let _ = close.add_option("A".into(), "a".into());
    let _ = close.add_option("B".into(), "b".into());
    close.evaluate(1, Some("p".into()), Some("c".into())).unwrap(); // score 0.5
    close.evaluate(2, Some("p".into()), Some("c".into())).unwrap(); // score 0.5
    let (_, _, close_cert) = close.decide().unwrap();
    // Margin: 0.5 - 0.5 = 0.0, certainty ≈ 0.0
    assert!(close_cert < 0.1, "close contest should have near-zero certainty, got {}", close_cert);
}

