#[test]
fn test_consensus_voting_and_tally() {
    use axon::axon_server::ConsensusSession;

    let mut session = ConsensusSession {
        id: "cons_test_1".into(),
        name: "model_vote".into(),
        proposal: "Which model for production?".into(),
        choices: vec!["claude".into(), "gpt4".into(), "gemini".into()],
        quorum: 3,
        votes: Vec::new(),
        resolved: false,
        winner: String::new(),
        created_at: 1700000000,
    };

    // Cast votes
    session.vote("agent_1".into(), "claude".into(), 0.9, "Best reasoning".into()).unwrap();
    session.vote("agent_2".into(), "claude".into(), 0.8, "Reliable".into()).unwrap();
    session.vote("agent_3".into(), "gpt4".into(), 0.7, "Fast".into()).unwrap();

    assert_eq!(session.vote_count(), 3);
    assert!(session.has_quorum());

    // Tally: claude = 0.9+0.8 = 1.7, gpt4 = 0.7, gemini = 0
    let tally = session.tally();
    assert_eq!(tally[0].0, "claude");
    assert!((tally[0].1 - 1.7).abs() < 0.01);
    assert_eq!(tally[0].2, 2); // 2 votes for claude
    assert_eq!(tally[1].0, "gpt4");

    // Duplicate voter rejected
    let r = session.vote("agent_1".into(), "gemini".into(), 0.5, "changed mind".into());
    assert!(r.is_err());
    assert!(r.unwrap_err().contains("already voted"));

    // Invalid choice rejected
    let r = session.vote("agent_4".into(), "llama".into(), 0.5, "".into());
    assert!(r.is_err());
    assert!(r.unwrap_err().contains("invalid choice"));
}

#[test]
fn test_consensus_quorum_and_resolve() {
    use axon::axon_server::ConsensusSession;

    let mut session = ConsensusSession {
        id: "cons_quorum_1".into(),
        name: "quorum_test".into(),
        proposal: "Approve deployment?".into(),
        choices: vec!["approve".into(), "reject".into()],
        quorum: 3,
        votes: Vec::new(),
        resolved: false,
        winner: String::new(),
        created_at: 1700000000,
    };

    // Not enough votes → cannot resolve
    session.vote("v1".into(), "approve".into(), 0.9, "".into()).unwrap();
    session.vote("v2".into(), "approve".into(), 0.8, "".into()).unwrap();
    assert!(!session.has_quorum());
    assert!(session.resolve().is_err());

    // Third vote meets quorum
    session.vote("v3".into(), "reject".into(), 0.6, "".into()).unwrap();
    assert!(session.has_quorum());

    // Resolve: approve wins (0.9+0.8=1.7 vs reject 0.6)
    let (winner, agreement, certainty) = session.resolve().unwrap();
    assert_eq!(winner, "approve");
    // agreement = 1.7 / (1.7+0.6) = 1.7/2.3 ≈ 0.7391
    assert!(agreement > 0.7 && agreement < 0.8);
    assert!(certainty <= 0.99);
    assert!(session.resolved);
    assert_eq!(session.winner, "approve");

    // Cannot resolve again
    assert!(session.resolve().is_err());

    // Cannot vote after resolution
    assert!(session.vote("v4".into(), "reject".into(), 1.0, "".into()).is_err());

    // Unanimous → high agreement
    let mut unanimous = ConsensusSession {
        id: "cons_uni".into(), name: "u".into(),
        proposal: "p".into(), choices: vec!["yes".into(), "no".into()],
        quorum: 2, votes: Vec::new(), resolved: false, winner: String::new(),
        created_at: 0,
    };
    unanimous.vote("a".into(), "yes".into(), 1.0, "".into()).unwrap();
    unanimous.vote("b".into(), "yes".into(), 1.0, "".into()).unwrap();
    let (w, agr, _) = unanimous.resolve().unwrap();
    assert_eq!(w, "yes");
    assert_eq!(agr, 1.0, "unanimous should have agreement=1.0");
}

#[test]
fn test_consensus_epistemic_alignment_theorem_5_1() {
    use axon::axon_server::{ConsensusSession, EpistemicEnvelope};

    let mut session = ConsensusSession {
        id: "cons_epi_1".into(), name: "e".into(),
        proposal: "Test ΛD".into(), choices: vec!["a".into(), "b".into()],
        quorum: 2, votes: Vec::new(), resolved: false, winner: String::new(),
        created_at: 1700000000,
    };

    // Unanimous → high certainty but still ≤0.99
    session.vote("v1".into(), "a".into(), 1.0, "".into()).unwrap();
    session.vote("v2".into(), "a".into(), 1.0, "".into()).unwrap();

    let (_, agreement, certainty) = session.resolve().unwrap();
    assert_eq!(agreement, 1.0);
    assert!(certainty <= 0.99, "consensus certainty must be ≤0.99 (derived)");

    // EpistemicEnvelope for consensus
    let env = EpistemicEnvelope::derived("consensus", certainty, "consensus_engine");
    assert_eq!(env.derivation, "derived");
    assert!(env.certainty <= 0.99);
    assert!(env.validate().is_ok());

    // Theorem 5.1: consensus (derived) cannot carry c=1.0
    let bad = EpistemicEnvelope {
        ontology: "consensus".into(),
        certainty: 1.0,
        temporal_start: "0".into(),
        temporal_end: "∞".into(),
        provenance: "voting".into(),
        derivation: "derived".into(),
    };
    assert!(bad.validate().is_err(),
        "Theorem 5.1: consensus (derived) cannot have c=1.0");

    // Lattice positions based on agreement
    // >0.8 → believe, >0.5 → speculate, ≤0.5 → doubt
    assert_eq!(if agreement > 0.8 { "believe" } else { "speculate" }, "believe");

    // Split vote → low agreement → doubt
    let mut split = ConsensusSession {
        id: "cons_split".into(), name: "s".into(),
        proposal: "p".into(), choices: vec!["x".into(), "y".into()],
        quorum: 2, votes: Vec::new(), resolved: false, winner: String::new(),
        created_at: 0,
    };
    split.vote("v1".into(), "x".into(), 0.5, "".into()).unwrap();
    split.vote("v2".into(), "y".into(), 0.5, "".into()).unwrap();
    let (_, split_agr, _) = split.resolve().unwrap();
    assert_eq!(split_agr, 0.5, "even split should have agreement=0.5");
    let split_lattice = if split_agr > 0.8 { "believe" } else if split_agr > 0.5 { "speculate" } else { "doubt" };
    assert_eq!(split_lattice, "doubt");

    // Confidence clamping
    let mut clamp = ConsensusSession {
        id: "cons_clamp".into(), name: "c".into(),
        proposal: "p".into(), choices: vec!["a".into(), "b".into()],
        quorum: 1, votes: Vec::new(), resolved: false, winner: String::new(),
        created_at: 0,
    };
    clamp.vote("v1".into(), "a".into(), 2.0, "".into()).unwrap(); // clamped to 1.0
    assert_eq!(clamp.votes[0].confidence, 1.0);
}

