#[test]
fn test_hibernate_checkpoint_and_suspend() {
    use axon::axon_server::HibernateSession;

    let mut session = HibernateSession {
        id: "hib_test_1".into(),
        name: "long_analysis".into(),
        operation: "flow:deep_analysis".into(),
        status: "active".into(),
        checkpoints: Vec::new(),
        resumed_from: None,
        created_at: 1700000000,
        last_status_change: 1700000000,
        next_checkpoint_id: 1,
    };

    assert_eq!(session.status, "active");

    // Create checkpoints
    let cp1 = session.checkpoint(
        "after_phase_1".into(),
        serde_json::json!({"progress": 0.3, "data": [1, 2, 3]}),
        "phase_1".into(),
    );
    assert!(cp1.is_ok());
    assert_eq!(cp1.unwrap(), 1);

    let cp2 = session.checkpoint(
        "after_phase_2".into(),
        serde_json::json!({"progress": 0.6, "results": "partial"}),
        "phase_2".into(),
    );
    assert!(cp2.is_ok());
    assert_eq!(cp2.unwrap(), 2);

    assert_eq!(session.checkpoints.len(), 2);
    assert_eq!(session.checkpoints[0].label, "after_phase_1");
    assert_eq!(session.checkpoints[1].phase, "phase_2");

    // Suspend
    session.suspend().unwrap();
    assert_eq!(session.status, "suspended");

    // Cannot suspend again
    assert!(session.suspend().is_err());

    // Can still checkpoint while suspended
    let cp3 = session.checkpoint("pre_resume".into(), serde_json::json!({}), "suspended".into());
    assert!(cp3.is_ok());
    assert_eq!(session.checkpoints.len(), 3);
}

#[test]
fn test_hibernate_resume_and_complete() {
    use axon::axon_server::HibernateSession;

    let mut session = HibernateSession {
        id: "hib_resume_1".into(),
        name: "resumable".into(),
        operation: "pipeline:etl".into(),
        status: "active".into(),
        checkpoints: Vec::new(),
        resumed_from: None,
        created_at: 1700000000,
        last_status_change: 1700000000,
        next_checkpoint_id: 1,
    };

    // Checkpoint and suspend
    session.checkpoint("cp1".into(), serde_json::json!({"step": 1}), "step_1".into()).unwrap();
    session.checkpoint("cp2".into(), serde_json::json!({"step": 2}), "step_2".into()).unwrap();
    session.suspend().unwrap();

    // Cannot resume from non-suspended state (first must be suspended)
    // — already suspended, so resume should work

    // Resume from checkpoint 2
    let cp = session.resume(2).unwrap();
    assert_eq!(cp.label, "cp2");
    assert_eq!(cp.state, serde_json::json!({"step": 2}));
    assert_eq!(session.status, "resumed");
    assert_eq!(session.resumed_from, Some(2));

    // Cannot resume again (not suspended)
    assert!(session.resume(1).is_err());

    // Resume from non-existent checkpoint
    let mut session2 = HibernateSession {
        id: "hib_resume_2".into(), name: "r2".into(), operation: "op".into(),
        status: "active".into(), checkpoints: Vec::new(), resumed_from: None,
        created_at: 0, last_status_change: 0, next_checkpoint_id: 1,
    };
    session2.checkpoint("cp1".into(), serde_json::json!({}), "p".into()).unwrap();
    session2.suspend().unwrap();
    assert!(session2.resume(99).is_err()); // non-existent checkpoint

    // Complete
    session.complete().unwrap();
    assert_eq!(session.status, "completed");

    // Cannot complete again
    assert!(session.complete().is_err());

    // Cannot checkpoint completed session
    assert!(session.checkpoint("late".into(), serde_json::json!({}), "".into()).is_err());

    // Cannot suspend completed session
    assert!(session.suspend().is_err());
}

#[test]
fn test_hibernate_epistemic_alignment() {
    use axon::axon_server::{HibernateSession, EpistemicEnvelope};

    let mut session = HibernateSession {
        id: "hib_epi_1".into(), name: "epistemic".into(), operation: "test".into(),
        status: "active".into(), checkpoints: Vec::new(), resumed_from: None,
        created_at: 1700000000, last_status_change: 1700000000, next_checkpoint_id: 1,
    };

    // Checkpoint state is raw (exact snapshot) → c=1.0, δ=raw
    session.checkpoint("snap".into(), serde_json::json!({"x": 42}), "init".into()).unwrap();

    let cp_env = EpistemicEnvelope::raw_config("hibernate", "checkpoint_engine");
    assert_eq!(cp_env.certainty, 1.0);
    assert_eq!(cp_env.derivation, "raw");
    assert!(cp_env.validate().is_ok());

    // Resumed execution is derived → c=0.99, δ=derived
    // (resumption reconstructs from checkpoint — a transformation)
    let resume_env = EpistemicEnvelope::derived("hibernate", 0.99, "resume_engine");
    assert_eq!(resume_env.certainty, 0.99);
    assert_eq!(resume_env.derivation, "derived");
    assert!(resume_env.validate().is_ok());

    // Theorem 5.1: raw checkpoint CAN carry c=1.0 (it's an exact state capture)
    assert!(cp_env.validate().is_ok(), "raw checkpoint can have c=1.0");

    // But resumed/derived cannot
    let bad = EpistemicEnvelope {
        ontology: "hibernate".into(),
        certainty: 1.0,
        temporal_start: "0".into(),
        temporal_end: "∞".into(),
        provenance: "resumed".into(),
        derivation: "derived".into(),
    };
    assert!(bad.validate().is_err(),
        "Theorem 5.1: resumed execution (derived) cannot have c=1.0");

    // Status lifecycle: active → suspended → resumed → completed
    assert_eq!(session.status, "active");
    session.suspend().unwrap();
    assert_eq!(session.status, "suspended");
    session.resume(1).unwrap();
    assert_eq!(session.status, "resumed");
    session.complete().unwrap();
    assert_eq!(session.status, "completed");

    // Lattice: checkpoint → know, resume → believe
    let cp_lattice = "know";
    let resume_lattice = "believe";
    assert_eq!(cp_lattice, "know");
    assert_eq!(resume_lattice, "believe");
}

