#[test]
fn test_ots_create_and_consume_once() {
    use axon::axon_server::OtsSecret;

    let mut secret = OtsSecret {
        token: "ots_test_abc123".into(),
        value: "supersecret_password".into(),
        consumed: false,
        created_at: 1700000000,
        ttl_secs: 3600,
        created_by: "admin".into(),
        label: "db_password".into(),
    };

    assert!(!secret.consumed);
    assert!(!secret.is_expired(1700000000));
    assert!(!secret.is_expired(1700003599)); // 1 second before expiry

    // Consume — returns value and clears it
    let now = 1700001000;
    let result = secret.consume(now);
    assert!(result.is_ok());
    assert_eq!(result.unwrap(), "supersecret_password");
    assert!(secret.consumed);
    assert!(secret.value.is_empty(), "value should be cleared after consume");

    // Cannot consume again
    let result2 = secret.consume(now);
    assert!(result2.is_err());
    assert!(result2.unwrap_err().contains("already consumed"));
}

#[test]
fn test_ots_expiry_and_ttl() {
    use axon::axon_server::OtsSecret;

    // Secret with TTL
    let mut secret = OtsSecret {
        token: "ots_ttl_test".into(),
        value: "temporary".into(),
        consumed: false,
        created_at: 1700000000,
        ttl_secs: 60, // 60 second TTL
        created_by: "system".into(),
        label: "temp_token".into(),
    };

    // Not expired within TTL
    assert!(!secret.is_expired(1700000030)); // 30 seconds
    assert!(!secret.is_expired(1700000060)); // exactly at expiry boundary

    // Expired after TTL
    assert!(secret.is_expired(1700000061)); // 1 second past
    assert!(secret.is_expired(1700003600)); // way past

    // Cannot consume expired secret
    let result = secret.consume(1700000061);
    assert!(result.is_err());
    assert!(result.unwrap_err().contains("expired"));

    // Secret with no TTL (ttl_secs = 0) never expires
    let mut no_expiry = OtsSecret {
        token: "ots_no_ttl".into(),
        value: "permanent".into(),
        consumed: false,
        created_at: 1700000000,
        ttl_secs: 0,
        created_by: "system".into(),
        label: "no_expiry".into(),
    };

    assert!(!no_expiry.is_expired(1800000000)); // 100M seconds later, still valid
    let result = no_expiry.consume(1800000000);
    assert!(result.is_ok());
    assert_eq!(result.unwrap(), "permanent");
}

#[test]
fn test_ots_epistemic_alignment() {
    use axon::axon_server::{OtsSecret, EpistemicEnvelope};

    // Created secret: c=1.0, δ=raw (the secret IS the ground truth)
    let secret = OtsSecret {
        token: "ots_epi_1".into(),
        value: "secret_value".into(),
        consumed: false,
        created_at: 1700000000,
        ttl_secs: 3600,
        created_by: "admin".into(),
        label: "test".into(),
    };

    let create_env = EpistemicEnvelope::raw_config("ots", "ots_creator");
    assert_eq!(create_env.certainty, 1.0);
    assert_eq!(create_env.derivation, "raw");
    assert!(create_env.validate().is_ok());

    // Retrieved secret: c=1.0, δ=raw (exact value returned before destruction)
    let retrieve_env = EpistemicEnvelope::raw_config("ots", "ots_consumer");
    assert_eq!(retrieve_env.certainty, 1.0);
    assert!(retrieve_env.validate().is_ok());

    // Consumed/expired secret: c=0.0, δ=void (no longer exists)
    let void_certainty = 0.0;
    let void_derivation = "void";
    assert_eq!(void_certainty, 0.0);
    assert_eq!(void_derivation, "void");

    // OTS is one of the few primitives where raw (c=1.0) is correct
    // because the secret itself IS the data, not a transformation
    // This is consistent with Theorem 5.1: raw data may carry c=1.0

    // Lattice: available → know, consumed/expired → ⊥ (bottom)
    let available_lattice = "know";
    let consumed_lattice = "⊥";
    assert_eq!(available_lattice, "know");
    assert_eq!(consumed_lattice, "⊥");

    // Security: value is cleared on consume
    let mut consumable = OtsSecret {
        token: "t".into(), value: "secret".into(), consumed: false,
        created_at: 1700000000, ttl_secs: 0, created_by: "a".into(), label: "l".into(),
    };
    let _ = consumable.consume(1700000000);
    assert!(consumable.value.is_empty(), "value must be zeroed after consume");

    // Token generation produces unique tokens
    let t1 = axon::axon_server::generate_ots_token("test");
    // Small delay to ensure different nanos
    let t2 = axon::axon_server::generate_ots_token("test");
    assert!(t1.starts_with("ots_test_"));
    // Tokens should be non-empty and contain hex
    assert!(t1.len() > 10);
}

