#[test]
fn test_psyche_insight_categories_and_validation() {
    use axon::axon_server::PsycheSession;

    let mut session = PsycheSession {
        id: "psyche_test_1".into(),
        name: "analysis_review".into(),
        context: "After analyzing attention mechanisms".into(),
        insights: Vec::new(),
        completed: false,
        created_at: 1700000000,
        next_insight_id: 1,
    };

    // Valid categories
    let id1 = session.add_insight("knowledge_gap".into(), "Unclear on cross-attention".into(), 0.7, "warning".into());
    assert!(id1.is_ok());
    assert_eq!(id1.unwrap(), 1);

    let _ = session.add_insight("uncertainty".into(), "Confidence in latency claims is low".into(), 0.5, "info".into());
    let _ = session.add_insight("bias".into(), "Over-reliance on transformer papers".into(), 0.6, "warning".into());
    let _ = session.add_insight("strength".into(), "Strong understanding of self-attention".into(), 0.9, "info".into());
    let _ = session.add_insight("recommendation".into(), "Investigate RNN alternatives".into(), 0.8, "info".into());

    assert_eq!(session.insights.len(), 5);

    // Invalid category rejected
    let bad_cat = session.add_insight("invalid_cat".into(), "test".into(), 0.5, "info".into());
    assert!(bad_cat.is_err());
    assert!(bad_cat.unwrap_err().contains("invalid category"));

    // Invalid severity rejected
    let bad_sev = session.add_insight("strength".into(), "test".into(), 0.5, "fatal".into());
    assert!(bad_sev.is_err());
    assert!(bad_sev.unwrap_err().contains("invalid severity"));

    // Confidence clamping
    let _ = session.add_insight("strength".into(), "clamped".into(), 2.0, "info".into());
    assert_eq!(session.insights.last().unwrap().confidence, 1.0);
}

#[test]
fn test_psyche_introspection_report() {
    use axon::axon_server::PsycheSession;

    let mut session = PsycheSession {
        id: "psyche_report_1".into(),
        name: "full_review".into(),
        context: "Complete project review".into(),
        insights: Vec::new(),
        completed: false,
        created_at: 1700000000,
        next_insight_id: 1,
    };

    // Add diverse insights across all categories
    let _ = session.add_insight("knowledge_gap".into(), "gap1".into(), 0.6, "warning".into());
    let _ = session.add_insight("uncertainty".into(), "uncertain1".into(), 0.5, "info".into());
    let _ = session.add_insight("bias".into(), "bias1".into(), 0.4, "critical".into());
    let _ = session.add_insight("strength".into(), "strong1".into(), 0.9, "info".into());
    let _ = session.add_insight("recommendation".into(), "rec1".into(), 0.8, "info".into());

    let report = session.report();

    // Category counts
    assert_eq!(report["by_category"]["knowledge_gaps"], 1);
    assert_eq!(report["by_category"]["uncertainties"], 1);
    assert_eq!(report["by_category"]["biases"], 1);
    assert_eq!(report["by_category"]["strengths"], 1);
    assert_eq!(report["by_category"]["recommendations"], 1);

    // Severity summary
    assert_eq!(report["severity_summary"]["critical"], 1);
    assert_eq!(report["severity_summary"]["warning"], 1);
    assert_eq!(report["severity_summary"]["info"], 3);

    // Average confidence: (0.6+0.5+0.4+0.9+0.8)/5 = 3.2/5 = 0.64
    let avg = report["avg_confidence"].as_f64().unwrap();
    assert!((avg - 0.64).abs() < 0.01);

    // Self-awareness score: diversity=5/5=1.0, penalty=1*0.1=0.1
    // awareness = (1.0*0.7 + 0.64*0.3 - 0.1) = (0.7 + 0.192 - 0.1) = 0.792
    let awareness = report["self_awareness_score"].as_f64().unwrap();
    assert!(awareness > 0.7 && awareness < 0.9, "awareness should be ~0.79, got {}", awareness);

    // Low diversity → lower awareness
    let mut narrow = PsycheSession {
        id: "psyche_narrow".into(), name: "n".into(), context: "c".into(),
        insights: Vec::new(), completed: false, created_at: 0, next_insight_id: 1,
    };
    let _ = narrow.add_insight("strength".into(), "s1".into(), 0.9, "info".into());
    let _ = narrow.add_insight("strength".into(), "s2".into(), 0.8, "info".into());
    let narrow_report = narrow.report();
    let narrow_awareness = narrow_report["self_awareness_score"].as_f64().unwrap();
    assert!(narrow_awareness < awareness, "narrow insights should have lower awareness");

    // Completed session rejects new insights
    session.completed = true;
    assert!(session.add_insight("strength".into(), "late".into(), 0.5, "info".into()).is_err());
}

#[test]
fn test_psyche_epistemic_alignment_theorem_5_1() {
    use axon::axon_server::{PsycheSession, EpistemicEnvelope};

    let mut session = PsycheSession {
        id: "psyche_epi_1".into(), name: "e".into(), context: "c".into(),
        insights: Vec::new(), completed: false, created_at: 1700000000, next_insight_id: 1,
    };

    let _ = session.add_insight("knowledge_gap".into(), "gap".into(), 0.7, "warning".into());
    let _ = session.add_insight("strength".into(), "strong".into(), 0.9, "info".into());

    // Self-reflection is always derived (Theorem 5.1)
    // Reasoning about one's own reasoning is a meta-operation
    let env = EpistemicEnvelope::derived("psyche", 0.99, "psyche_engine");
    assert_eq!(env.derivation, "derived");
    assert!(env.certainty <= 0.99);
    assert!(env.validate().is_ok());

    // Theorem 5.1: psyche (derived) cannot carry c=1.0
    let bad = EpistemicEnvelope {
        ontology: "psyche".into(),
        certainty: 1.0,
        temporal_start: "0".into(),
        temporal_end: "∞".into(),
        provenance: "self-reflection".into(),
        derivation: "derived".into(),
    };
    assert!(bad.validate().is_err(),
        "Theorem 5.1: self-reflection (derived) cannot have c=1.0");

    // Certainty scales with awareness score
    let report = session.report();
    let awareness = report["self_awareness_score"].as_f64().unwrap();
    let certainty = (awareness * 0.99).min(0.99);
    assert!(certainty <= 0.99);
    assert!(certainty > 0.0);

    // Lattice: high awareness → believe, low → speculate
    let lattice = if awareness > 0.7 { "believe" } else { "speculate" };
    assert!(lattice == "believe" || lattice == "speculate");

    // Empty session has zero awareness
    let empty = PsycheSession {
        id: "empty".into(), name: "e".into(), context: "c".into(),
        insights: Vec::new(), completed: false, created_at: 0, next_insight_id: 1,
    };
    let empty_report = empty.report();
    assert_eq!(empty_report["self_awareness_score"].as_f64().unwrap(), 0.0);
    assert_eq!(empty_report["avg_confidence"].as_f64().unwrap(), 0.0);
}

