#[test]
fn test_axonendpoint_binding_and_url_resolution() {
    use axon::axon_server::EndpointBinding;
    use std::collections::HashMap;

    let binding = EndpointBinding {
        name: "weather_api".into(),
        method: "GET".into(),
        url_template: "https://api.weather.com/v1/{city}/forecast?units={units}".into(),
        headers: {
            let mut h = HashMap::new();
            h.insert("Accept".into(), "application/json".into());
            h
        },
        auth_type: "api_key".into(),
        auth_ref: "WEATHER_API_KEY".into(),
        timeout_ms: 5000,
        enabled: true,
        description: "Weather forecast API".into(),
        created_at: 1700000000,
        total_calls: 0,
        total_errors: 0,
    };

    assert_eq!(binding.name, "weather_api");
    assert_eq!(binding.method, "GET");
    assert!(binding.enabled);

    // URL template resolution
    let mut url = binding.url_template.clone();
    let mut params = HashMap::new();
    params.insert("city".to_string(), "London".to_string());
    params.insert("units".to_string(), "metric".to_string());
    for (key, value) in &params {
        url = url.replace(&format!("{{{}}}", key), value);
    }
    assert_eq!(url, "https://api.weather.com/v1/London/forecast?units=metric");

    // Headers preserved
    assert_eq!(binding.headers.get("Accept").unwrap(), "application/json");

    // Auth config
    assert_eq!(binding.auth_type, "api_key");
    assert_eq!(binding.auth_ref, "WEATHER_API_KEY");

    // Serialization
    let json = serde_json::to_string(&binding).unwrap();
    assert!(json.contains("\"weather_api\""));
    assert!(json.contains("\"api_key\""));
}

#[test]
fn test_axonendpoint_call_record_and_history() {
    use axon::axon_server::{EndpointBinding, EndpointCallRecord};
    use std::collections::HashMap;

    let mut binding = EndpointBinding {
        name: "data_api".into(),
        method: "POST".into(),
        url_template: "https://api.data.com/v2/{resource}".into(),
        headers: HashMap::new(),
        auth_type: "bearer".into(),
        auth_ref: "DATA_TOKEN".into(),
        timeout_ms: 10000,
        enabled: true,
        description: "Data ingestion API".into(),
        created_at: 1700000000,
        total_calls: 0,
        total_errors: 0,
    };

    // Simulate call recording
    let mut params: HashMap<String, String> = HashMap::new();
    params.insert("resource".into(), "documents".into());

    let mut resolved = binding.url_template.clone();
    for (key, value) in &params {
        resolved = resolved.replace(&format!("{{{}}}", key), value);
    }

    binding.total_calls += 1;

    let record = EndpointCallRecord {
        id: format!("call_data_api_{}", binding.total_calls),
        binding: binding.name.clone(),
        resolved_url: resolved.clone(),
        method: binding.method.clone(),
        body: serde_json::json!({"title": "Test Document", "content": "Hello"}),
        params: params.clone(),
        called_at: 1700001000,
    };

    assert_eq!(record.resolved_url, "https://api.data.com/v2/documents");
    assert_eq!(record.method, "POST");
    assert_eq!(record.params.get("resource").unwrap(), "documents");
    assert_eq!(binding.total_calls, 1);

    // Multiple calls increment counter
    binding.total_calls += 1;
    binding.total_calls += 1;
    assert_eq!(binding.total_calls, 3);

    // Disabled binding should be rejected by handler
    binding.enabled = false;
    assert!(!binding.enabled);

    // Valid methods
    let valid_methods = vec!["GET", "POST", "PUT", "DELETE"];
    assert!(valid_methods.contains(&binding.method.as_str()));
}

#[test]
fn test_axonendpoint_epistemic_alignment() {
    use axon::axon_server::{EndpointBinding, EpistemicEnvelope};
    use std::collections::HashMap;

    let binding = EndpointBinding {
        name: "external_api".into(),
        method: "GET".into(),
        url_template: "https://example.com/{path}".into(),
        headers: HashMap::new(),
        auth_type: "none".into(),
        auth_ref: String::new(),
        timeout_ms: 5000,
        enabled: true,
        description: "Test".into(),
        created_at: 1700000000,
        total_calls: 0,
        total_errors: 0,
    };

    // External API calls are always derived (Theorem 5.1)
    // The response from an external service is not raw data in our ontology —
    // it's data that crossed a trust boundary and may be unreliable
    let env = EpistemicEnvelope::derived("axonendpoint", 0.99, "endpoint_caller");
    assert_eq!(env.derivation, "derived");
    assert_eq!(env.certainty, 0.99);
    assert!(env.validate().is_ok());

    // Theorem 5.1: external API result (derived) cannot carry c=1.0
    let bad = EpistemicEnvelope {
        ontology: "axonendpoint".into(),
        certainty: 1.0,
        temporal_start: "0".into(),
        temporal_end: "∞".into(),
        provenance: "external_api".into(),
        derivation: "derived".into(),
    };
    assert!(bad.validate().is_err(),
        "Theorem 5.1: external API result (derived) cannot have c=1.0");

    // Effect row includes network (external call crosses trust boundary)
    let effects = vec!["io", "network", "epistemic:speculate"];
    assert!(effects.contains(&"network"), "external calls have network effect");
    assert!(effects.contains(&"epistemic:speculate"));

    // Lattice: external API results are speculative (trust boundary)
    let lattice = "speculate";
    assert_eq!(lattice, "speculate");

    // The binding itself is configuration (raw, deterministic)
    // But the RESULT of calling through it is derived
    let binding_env = EpistemicEnvelope::raw_config("axonendpoint_config", "admin");
    assert_eq!(binding_env.certainty, 1.0);
    assert_eq!(binding_env.derivation, "raw");

    // Binding serialization round-trip
    let json = serde_json::to_string(&binding).unwrap();
    let restored: EndpointBinding = serde_json::from_str(&json).unwrap();
    assert_eq!(restored.name, "external_api");
    assert_eq!(restored.method, "GET");
}

