#[test]
fn test_emcp_compute_tool_dispatch() {
    use axon::axon_server::compute_evaluate;
    use std::collections::HashMap;

    // Compute tool: axon_compute_evaluate — single global tool (not per-instance)
    let tool_name = "axon_compute_evaluate";
    assert_eq!(tool_name, "axon_compute_evaluate");

    // Exact arithmetic → c=1.0, lattice=know
    let vars = HashMap::new();
    let exact = compute_evaluate("2 + 3 * 4", &vars).unwrap();
    assert_eq!(exact.value, 14.0);
    assert!(exact.exact);
    assert_eq!(exact.certainty, 1.0);
    let exact_lattice = if exact.exact { "know" } else { "speculate" };
    assert_eq!(exact_lattice, "know");

    // Approximate → c=0.99, lattice=speculate
    let approx = compute_evaluate("pi * 2", &vars).unwrap();
    assert!(!approx.exact);
    assert_eq!(approx.certainty, 0.99);
    let approx_lattice = if approx.exact { "know" } else { "speculate" };
    assert_eq!(approx_lattice, "speculate");

    // Variables in MCP call
    let mut vars_map = HashMap::new();
    vars_map.insert("x".into(), 10.0);
    let with_vars = compute_evaluate("x ^ 2", &vars_map).unwrap();
    assert_eq!(with_vars.value, 100.0);

    // Error produces CT-2 blame
    let err = compute_evaluate("5 / 0", &vars);
    assert!(err.is_err());
}

#[test]
fn test_emcp_mandate_tool_name_parsing() {
    // Tool names: axon_mandate_{name}_evaluate
    let tool_names = vec![
        ("axon_mandate_flow_access_evaluate", "flow_access", "evaluate"),
        ("axon_mandate_admin_policy_evaluate", "admin_policy", "evaluate"),
    ];

    for (full_name, expected_mandate, expected_op) in &tool_names {
        let suffix = full_name.strip_prefix("axon_mandate_").unwrap();
        let pos = suffix.rfind('_').unwrap();
        let mandate_name = &suffix[..pos];
        let op = &suffix[pos+1..];
        assert_eq!(mandate_name, *expected_mandate);
        assert_eq!(op, *expected_op);
    }

    // Mandate evaluate epistemic:
    // explicit match → c=1.0, lattice=know
    // default deny → c=0.99, lattice=speculate
    use axon::axon_server::{MandatePolicy, MandateRule};
    let policy = MandatePolicy {
        name: "test".into(), description: "t".into(),
        rules: vec![MandateRule {
            id: "r1".into(), subject: "admin".into(), action: "*".into(),
            resource: "*".into(), effect: "allow".into(), priority: 10, enabled: true,
        }],
        created_at: 0, total_evaluations: 0, total_denials: 0,
    };

    let explicit = policy.evaluate("admin", "read", "/v1/test");
    assert!(explicit.allowed);
    assert_eq!(explicit.certainty, 1.0);
    let explicit_lattice = if explicit.certainty == 1.0 { "know" } else { "speculate" };
    assert_eq!(explicit_lattice, "know");

    let default_deny = policy.evaluate("guest", "read", "/v1/test");
    assert!(!default_deny.allowed);
    assert_eq!(default_deny.certainty, 0.99);
    let deny_lattice = if default_deny.certainty == 1.0 { "know" } else { "speculate" };
    assert_eq!(deny_lattice, "speculate");
}

