#[test]
fn test_cross_chain_consensus_mandate() {
    // Chain: consensus (vote on policy) → mandate (enforce the decided policy)
    // ΛD propagation: agreement-based → deterministic authorization
    use axon::axon_server::{ConsensusSession, MandatePolicy, MandateRule, EpistemicEnvelope};

    // ── Stage 1: Consensus — agents vote on access policy ──
    let mut consensus = ConsensusSession {
        id: "cons_mandate_1".into(),
        name: "access_policy_vote".into(),
        proposal: "Should operators have execute access to all flows?".into(),
        choices: vec!["grant_all".into(), "grant_limited".into(), "deny".into()],
        quorum: 3,
        votes: Vec::new(),
        resolved: false,
        winner: String::new(),
        created_at: 1700000000,
    };

    consensus.vote("security_agent".into(), "grant_limited".into(), 0.9, "Principle of least privilege".into()).unwrap();
    consensus.vote("ops_agent".into(), "grant_all".into(), 0.7, "Operational efficiency".into()).unwrap();
    consensus.vote("compliance_agent".into(), "grant_limited".into(), 0.85, "Audit requirements".into()).unwrap();

    let (winner, agreement, cons_certainty) = consensus.resolve().unwrap();
    assert_eq!(winner, "grant_limited", "majority voted for limited access");
    assert!(agreement > 0.5);
    assert!(cons_certainty <= 0.99);

    // ── Stage 2: Mandate — create and enforce the consensus-decided policy ──
    let policy = MandatePolicy {
        name: "consensus_derived_policy".into(),
        description: format!("Policy from consensus: {} (agreement: {:.2})", winner, agreement),
        rules: vec![
            MandateRule {
                id: "operator_limited".into(),
                subject: "operator".into(),
                action: "execute".into(),
                resource: "/v1/flows/*".into(),
                effect: "allow".into(),
                priority: 50,
                enabled: true,
            },
            MandateRule {
                id: "operator_no_delete".into(),
                subject: "operator".into(),
                action: "delete".into(),
                resource: "*".into(),
                effect: "deny".into(),
                priority: 60,
                enabled: true,
            },
        ],
        created_at: 1700000000,
        total_evaluations: 0,
        total_denials: 0,
    };

    // Operator can execute (granted by consensus)
    let exec_result = policy.evaluate("operator", "execute", "/v1/flows/analyze");
    assert!(exec_result.allowed);
    assert_eq!(exec_result.certainty, 1.0, "explicit match → deterministic");

    // Operator cannot delete (limited by consensus)
    let del_result = policy.evaluate("operator", "delete", "/v1/flows/old");
    assert!(!del_result.allowed);
    assert_eq!(del_result.effect, "deny");

    // ΛD Chain: consensus(c≤0.99, derived) → mandate(c=1.0, raw for explicit)
    // The mandate decision is deterministic GIVEN the rules,
    // but the rules themselves were derived from consensus
    assert!(cons_certainty <= 0.99);
    assert_eq!(exec_result.certainty, 1.0);

    // Chain envelope: the overall chain certainty is bounded by consensus
    let chain_certainty = cons_certainty.min(exec_result.certainty).min(0.99);
    let chain_env = EpistemicEnvelope::derived("chain:consensus→mandate", chain_certainty, "cross_integration");
    assert!(chain_env.validate().is_ok());
}

#[test]
fn test_cross_chain_hibernate_refine_ots() {
    // Chain: hibernate (checkpoint state) → refine (improve from checkpoint) → ots (secure delivery)
    // ΛD propagation: raw checkpoint → derived refinement → raw secret
    use axon::axon_server::{HibernateSession, RefineSession, OtsSecret, EpistemicEnvelope};

    // ── Stage 1: Hibernate — checkpoint work-in-progress ──
    let mut hibernate = HibernateSession {
        id: "hib_chain_1".into(),
        name: "report_wip".into(),
        operation: "long_report_generation".into(),
        status: "active".into(),
        checkpoints: Vec::new(),
        resumed_from: None,
        created_at: 1700000000,
        last_status_change: 1700000000,
        next_checkpoint_id: 1,
    };

    // Checkpoint: save draft state
    hibernate.checkpoint(
        "draft_v1".into(),
        serde_json::json!({"content": "Initial report draft about AI safety", "quality": 0.4}),
        "drafting".into(),
    ).unwrap();

    // Suspend and resume
    hibernate.suspend().unwrap();
    let cp = hibernate.resume(1).unwrap();
    let draft_content = cp.state["content"].as_str().unwrap().to_string();
    let draft_quality = cp.state["quality"].as_f64().unwrap();

    assert_eq!(hibernate.status, "resumed");
    assert_eq!(draft_quality, 0.4);

    // ── Stage 2: Refine — improve the resumed draft ──
    let mut refine = RefineSession {
        id: "refine_chain_2".into(),
        name: "improve_report".into(),
        target_quality: 0.85,
        convergence_threshold: 0.02,
        max_iterations: 5,
        converged: false,
        iterations: Vec::new(),
        created_at: 1700000000,
    };

    refine.add_iteration(draft_content, draft_quality, "resumed from hibernate checkpoint".into()).unwrap();
    refine.add_iteration(
        "Comprehensive report on AI safety covering alignment, robustness, and interpretability.".into(),
        0.75, "expanded content from resumed state".into(),
    ).unwrap();
    refine.add_iteration(
        "Comprehensive report on AI safety: alignment ensures goals match human values, robustness handles edge cases, interpretability enables audit.".into(),
        0.88, "added specifics, met quality target".into(),
    ).unwrap();

    assert!(refine.converged);
    let final_report = refine.iterations.last().unwrap().content.clone();

    // ── Stage 3: OTS — deliver report as one-time secret ──
    let mut ots = OtsSecret {
        token: "ots_report_delivery_abc".into(),
        value: final_report.clone(),
        consumed: false,
        created_at: 1700001000,
        ttl_secs: 3600,
        created_by: "report_pipeline".into(),
        label: "final_report".into(),
    };

    assert!(!ots.consumed);
    let delivered = ots.consume(1700001500).unwrap();
    assert_eq!(delivered, final_report);
    assert!(ots.consumed);
    assert!(ots.value.is_empty(), "secret value cleared after delivery");

    // Cannot retrieve again
    assert!(ots.consume(1700001600).is_err());

    // ΛD Chain: hibernate(c=1.0 checkpoint) → refine(c≤0.99 derived) → ots(c=1.0 raw, then void)
    let cp_env = EpistemicEnvelope::raw_config("hibernate", "checkpoint");
    assert_eq!(cp_env.certainty, 1.0);

    let refine_env = EpistemicEnvelope::derived("refine", 0.99, "refine_engine");
    assert_eq!(refine_env.certainty, 0.99);

    // The OTS value is raw (exact content), but the content itself was derived (refined)
    // This is a key ΛD insight: the container certainty differs from content certainty
}

#[test]
fn test_cross_chain_psyche_probe_weave() {
    // Chain: psyche (self-reflect) → probe (investigate gaps) → weave (synthesize findings)
    // ΛD propagation: derived reflection → derived exploration → derived synthesis
    use axon::axon_server::{PsycheSession, ProbeSession, WeaveSession, EpistemicEnvelope};

    // ── Stage 1: Psyche — identify knowledge gaps ──
    let mut psyche = PsycheSession {
        id: "psyche_chain_1".into(),
        name: "knowledge_audit".into(),
        context: "After processing 100 documents on distributed systems".into(),
        insights: Vec::new(),
        completed: false,
        created_at: 1700000000,
        next_insight_id: 1,
    };

    psyche.add_insight("strength".into(), "Strong understanding of consensus algorithms".into(), 0.9, "info".into()).unwrap();
    psyche.add_insight("knowledge_gap".into(), "Weak on Byzantine fault tolerance specifics".into(), 0.7, "warning".into()).unwrap();
    psyche.add_insight("knowledge_gap".into(), "No coverage of PBFT variants".into(), 0.6, "warning".into()).unwrap();
    psyche.add_insight("recommendation".into(), "Investigate BFT literature".into(), 0.8, "info".into()).unwrap();

    let report = psyche.report();
    let awareness = report["self_awareness_score"].as_f64().unwrap();
    assert!(awareness > 0.0);

    // Extract gaps to guide probing
    let gaps: Vec<&str> = psyche.insights.iter()
        .filter(|i| i.category == "knowledge_gap")
        .map(|i| i.content.as_str())
        .collect();
    assert_eq!(gaps.len(), 2);

    // ── Stage 2: Probe — investigate the identified gaps ──
    let mut probe = ProbeSession {
        id: "probe_chain_2".into(),
        name: "bft_investigation".into(),
        question: "What are the key Byzantine fault tolerance mechanisms?".into(),
        sources: vec!["corpus:papers".into(), "axonstore:facts".into()],
        findings: Vec::new(),
        completed: false,
        created_at: 1700000000,
        total_queries: 0,
    };

    // Probe findings guided by psyche's knowledge gaps
    probe.add_finding("corpus:papers".into(), "byzantine fault tolerance".into(),
        "PBFT achieves consensus in O(n²) message complexity with 3f+1 nodes".into(), 0.92);
    probe.add_finding("corpus:papers".into(), "BFT variants".into(),
        "HotStuff improves on PBFT with linear communication complexity".into(), 0.88);
    probe.add_finding("axonstore:facts".into(), "distributed consensus".into(),
        "BFT requires at least 3f+1 nodes to tolerate f Byzantine faults".into(), 0.95);
    probe.total_queries = 2;
    probe.completed = true;

    let probe_certainty = probe.aggregate_certainty();
    assert!(probe_certainty > 0.8);

    // ── Stage 3: Weave — synthesize psyche insights + probe findings ──
    let mut weave = WeaveSession {
        id: "weave_chain_2".into(),
        name: "bft_synthesis".into(),
        goal: "Fill knowledge gaps identified by psyche with probe findings".into(),
        strands: Vec::new(),
        synthesis: String::new(),
        synthesized: false,
        created_at: 1700000000,
        next_strand_id: 1,
    };

    // Strand 1: psyche strength (what we already know)
    weave.add_strand(
        "psyche:strength".into(),
        "Strong understanding of consensus algorithms".into(),
        0.6, // lower weight — we already know this
        awareness.min(0.99),
    );

    // Strands 2-4: probe findings (filling gaps)
    for finding in probe.top_findings(3) {
        weave.add_strand(
            finding.source.clone(),
            finding.content.clone(),
            0.9, // high weight — these fill identified gaps
            finding.certainty,
        );
    }

    assert_eq!(weave.strands.len(), 4);

    let synthesis = weave.synthesize().unwrap();
    assert!(synthesis.contains("[psyche:strength]"), "psyche insight attributed");
    assert!(synthesis.contains("[corpus:papers]"), "probe finding attributed");
    assert!(synthesis.contains("PBFT"));
    assert!(synthesis.contains("HotStuff"));

    let weave_certainty = weave.synthesis_certainty().min(0.99);

    // ── ΛD Chain Verification ──
    // psyche(c=awareness×0.99) → probe(c≤0.99) → weave(c≤0.99)
    // All stages are derived — metacognition, exploration, and synthesis
    assert!(awareness <= 1.0);
    assert!(probe_certainty <= 0.99);
    assert!(weave_certainty <= 0.99);

    // Chain envelope
    let chain_env = EpistemicEnvelope::derived("chain:psyche→probe→weave", weave_certainty, "cross_integration");
    assert!(chain_env.validate().is_ok());
    assert_eq!(chain_env.derivation, "derived");

    // The chain demonstrates the metacognitive loop:
    // reflect → identify gaps → investigate → synthesize → (could loop back to reflect)
    let metacognitive_loop_stages = 3;
    assert_eq!(metacognitive_loop_stages, 3);
}

