#[test]
fn test_emcp_resource_read_epistemic_envelopes() {
    use axon::axon_server::EpistemicEnvelope;

    // All resource listings carry raw epistemic metadata (c=1.0)
    // because the registry itself IS the ground truth about what exists

    let registry_env = EpistemicEnvelope::raw_config("resource:registry", "axon_server");
    assert_eq!(registry_env.certainty, 1.0);
    assert_eq!(registry_env.derivation, "raw");
    assert!(registry_env.validate().is_ok());

    // Individual resource reads also carry raw provenance
    let shield_env = EpistemicEnvelope::raw_config("shield:toxicity", "axon_server:shield:toxicity");
    assert_eq!(shield_env.certainty, 1.0);

    let corpus_env = EpistemicEnvelope::raw_config("corpus:papers", "axon_server:corpus:papers");
    assert_eq!(corpus_env.certainty, 1.0);

    let mandate_env = EpistemicEnvelope::raw_config("mandate:flow_access", "axon_server:mandate:flow_access");
    assert_eq!(mandate_env.certainty, 1.0);

    let forge_env = EpistemicEnvelope::raw_config("forge:report_gen", "axon_server:forge:report_gen");
    assert_eq!(forge_env.certainty, 1.0);

    // This is consistent: reading ABOUT a resource is raw observation,
    // but USING a resource (tool call) produces derived output
    // e.g., reading shield config = raw, evaluating content through shield = derived
    let shield_eval_env = EpistemicEnvelope::derived("shield:evaluation", 0.95, "shield_engine");
    assert_eq!(shield_eval_env.derivation, "derived");
    assert!(shield_eval_env.certainty < 1.0);

    // Blame on missing resources: CT-2 (caller referenced non-existent)
    let blame_reason = "CT-2";
    assert_eq!(blame_reason, "CT-2");
}

