#[test]
fn test_cross_chain_pix_compute_axonendpoint() {
    // Chain: pix (analyze image) → compute (calculate metrics) → axonendpoint (report externally)
    // ΛD propagation: raw metadata + derived annotations → exact/approx compute → derived external call
    use axon::axon_server::{PixSession, EndpointBinding, EpistemicEnvelope, compute_evaluate};
    use std::collections::HashMap;

    // ── Stage 1: Pix — register and annotate an image ──
    let mut pix = PixSession {
        id: "pix_chain_1".into(),
        name: "object_detection".into(),
        images: HashMap::new(),
        created_at: 1700000000,
        next_image_id: 1,
    };

    let img_id = pix.register_image("camera://feed/frame_001.png".into(), 1920, 1080, "png".into(), "camera_system");

    // Raw image metadata → c=1.0
    assert_eq!(pix.images.get(&img_id).unwrap().envelope.certainty, 1.0);

    pix.annotate(&img_id, "vehicle".into(), [0.1, 0.3, 0.4, 0.3], 0.92, "object".into(), "Red sedan".into()).unwrap();
    pix.annotate(&img_id, "pedestrian".into(), [0.6, 0.2, 0.15, 0.5], 0.87, "object".into(), "Person walking".into()).unwrap();
    pix.annotate(&img_id, "speed_sign".into(), [0.8, 0.1, 0.1, 0.1], 0.95, "text".into(), "30 mph".into()).unwrap();

    assert_eq!(pix.total_annotations(), 3);
    // After annotation → c=0.99, derived
    assert_eq!(pix.images.get(&img_id).unwrap().envelope.derivation, "derived");

    // ── Stage 2: Compute — calculate scene metrics from annotations ──
    let annotations = &pix.images.get(&img_id).unwrap().annotations;
    let avg_confidence: f64 = annotations.iter().map(|a| a.confidence).sum::<f64>() / annotations.len() as f64;

    // Use compute to evaluate: total area covered by annotations
    let mut vars = HashMap::new();
    vars.insert("w1".into(), annotations[0].bbox[2] * annotations[0].bbox[3]); // vehicle area
    vars.insert("w2".into(), annotations[1].bbox[2] * annotations[1].bbox[3]); // pedestrian area
    vars.insert("w3".into(), annotations[2].bbox[2] * annotations[2].bbox[3]); // sign area

    let total_area = compute_evaluate("w1 + w2 + w3", &vars).unwrap();
    assert!(total_area.value > 0.0);
    // Area computation is exact (addition of known values)
    assert_eq!(total_area.certainty, 0.99); // contains division in bbox calc, so derived

    let density = compute_evaluate("3 * 100", &HashMap::new()).unwrap(); // objects per 100 frames
    assert_eq!(density.value, 300.0);
    assert!(density.exact);

    // ── Stage 3: AxonEndpoint — report to external monitoring service ──
    let mut endpoint = EndpointBinding {
        name: "scene_monitor".into(),
        method: "POST".into(),
        url_template: "https://monitor.example.com/v1/scenes/{scene_id}/report".into(),
        headers: HashMap::new(),
        auth_type: "bearer".into(),
        auth_ref: "MONITOR_TOKEN".into(),
        timeout_ms: 5000,
        enabled: true,
        description: "Scene analysis reporting endpoint".into(),
        created_at: 1700000000,
        total_calls: 0,
        total_errors: 0,
    };

    // Resolve URL
    let mut url = endpoint.url_template.clone();
    url = url.replace("{scene_id}", "frame_001");
    assert_eq!(url, "https://monitor.example.com/v1/scenes/frame_001/report");
    endpoint.total_calls += 1;

    // ΛD Chain: pix(raw→derived on annotate) → compute(exact/derived) → endpoint(derived, network)
    let pix_cert = 0.99; // annotations are derived
    let compute_cert = total_area.certainty; // 0.99 (has float ops)
    let endpoint_cert = 0.99; // external call is always derived
    assert!(pix_cert <= 0.99);
    assert!(compute_cert <= 0.99);
    assert!(endpoint_cert <= 0.99);

    // Network effect row present for external call
    let endpoint_effects = vec!["io", "network", "epistemic:speculate"];
    assert!(endpoint_effects.contains(&"network"));

    let chain_env = EpistemicEnvelope::derived("chain:pix→compute→endpoint", 0.99, "cross_integration");
    assert!(chain_env.validate().is_ok());
}

#[test]
fn test_cross_chain_dataspace_drill_corroborate_consensus() {
    // Chain: dataspace (ingest data) → drill (explore patterns) → corroborate (verify claims) → consensus (agree)
    // ΛD: raw ingest → depth-degrading exploration → agreement-based verification → vote-weighted consensus
    use axon::axon_server::{
        DataspaceInstance, DataspaceEntry, DrillSession,
        CorroborateSession, ConsensusSession, EpistemicEnvelope,
    };
    use std::collections::HashMap;

    // ── Stage 1: Dataspace — ingest performance data ──
    let mut ds = DataspaceInstance {
        name: "benchmarks".into(),
        ontology: "performance".into(),
        entries: HashMap::new(),
        associations: Vec::new(),
        created_at: 1700000000,
        total_ops: 0,
        next_id: 1,
    };

    let entries = vec![
        ("Anthropic: 120ms avg, 99.5% uptime", vec!["latency", "reliability"]),
        ("OpenAI: 80ms avg, 98.2% uptime", vec!["latency", "reliability"]),
        ("Ollama: 200ms avg, 100% uptime (local)", vec!["latency", "reliability"]),
    ];

    for (content, tags) in entries {
        let id = format!("ds_benchmarks_{}", ds.next_id);
        ds.next_id += 1;
        ds.entries.insert(id.clone(), DataspaceEntry {
            id,
            ontology: "performance".into(),
            data: serde_json::json!(content),
            envelope: EpistemicEnvelope::raw_config("performance", "benchmark_runner"),
            ingested_at: 1700000000,
            tags: tags.into_iter().map(String::from).collect(),
        });
    }
    assert_eq!(ds.entries.len(), 3);

    // ── Stage 2: Drill — explore which backend is best ──
    let mut drill = DrillSession {
        id: "drill_chain_2".into(),
        name: "backend_analysis".into(),
        root_question: "Which backend has the best performance profile?".into(),
        max_depth: 2,
        nodes: HashMap::new(),
        completed: false,
        created_at: 1700000000,
    };

    drill.add_root("Analyzing 3 backends from dataspace benchmarks".into()).unwrap();
    drill.expand("root", "Latency comparison?".into(), "OpenAI fastest (80ms), Anthropic mid (120ms), Ollama slow (200ms)".into()).unwrap();
    drill.expand("root", "Reliability comparison?".into(), "Ollama 100%, Anthropic 99.5%, OpenAI 98.2%".into()).unwrap();

    let drill_cert = drill.avg_certainty();
    assert!(drill_cert > 0.9, "shallow drill has high certainty");

    // ── Stage 3: Corroborate — verify claim "Anthropic is the best balanced choice" ──
    let mut corr = CorroborateSession {
        id: "corr_chain_2".into(),
        name: "balanced_claim".into(),
        claim: "Anthropic offers the best balance of speed and reliability".into(),
        evidence: Vec::new(),
        verified: false,
        verdict: "pending".into(),
        created_at: 1700000000,
        next_evidence_id: 1,
    };

    corr.add_evidence("drill:latency".into(), "Mid-range latency (120ms)".into(), "supports".into(), 0.8).unwrap();
    corr.add_evidence("drill:reliability".into(), "High uptime (99.5%)".into(), "supports".into(), 0.9).unwrap();
    corr.add_evidence("dataspace:benchmarks".into(), "Not the fastest option".into(), "neutral".into(), 0.6).unwrap();

    let (agreement, corr_cert, verdict) = corr.verify().unwrap();
    assert_eq!(verdict, "corroborated");
    assert!(agreement > 0.5);

    // ── Stage 4: Consensus — agents vote based on evidence ──
    let mut consensus = ConsensusSession {
        id: "cons_chain_2".into(),
        name: "backend_final".into(),
        proposal: "Select production backend based on drill+corroborate evidence".into(),
        choices: vec!["anthropic".into(), "openai".into(), "ollama".into()],
        quorum: 3,
        votes: Vec::new(),
        resolved: false,
        winner: String::new(),
        created_at: 1700000000,
    };

    // Votes informed by corroboration evidence
    consensus.vote("reliability_agent".into(), "anthropic".into(), 0.9, "Corroborated as balanced".into()).unwrap();
    consensus.vote("speed_agent".into(), "openai".into(), 0.7, "Fastest latency".into()).unwrap();
    consensus.vote("cost_agent".into(), "anthropic".into(), 0.8, "Good balance per corroboration".into()).unwrap();

    let (winner, cons_agreement, cons_cert) = consensus.resolve().unwrap();
    assert_eq!(winner, "anthropic");
    assert!(cons_cert <= 0.99);

    // ΛD Chain: dataspace(c=1.0 raw) → drill(c≤0.99 depth) → corroborate(c≤0.99 agreement) → consensus(c≤0.99 votes)
    for entry in ds.entries.values() {
        assert_eq!(entry.envelope.certainty, 1.0, "dataspace ingest is raw");
    }
    assert!(drill_cert <= 0.99);
    assert!(corr_cert <= 0.99);
    assert!(cons_cert <= 0.99);

    let chain_env = EpistemicEnvelope::derived("chain:dataspace→drill→corroborate→consensus", cons_cert, "cross_integration");
    assert!(chain_env.validate().is_ok());
}

#[test]
fn test_cross_chain_axonstore_shield_ots_mandate() {
    // Chain: axonstore (persist credentials) → shield (validate content) → ots (secure transfer) → mandate (authorize access)
    // ΛD: raw persist → derived evaluation → raw secret → deterministic authorization
    use axon::axon_server::{
        AxonStoreInstance, AxonStoreEntry, ShieldInstance, ShieldRule,
        OtsSecret, MandatePolicy, MandateRule, EpistemicEnvelope,
    };
    use std::collections::HashMap;

    // ── Stage 1: AxonStore — persist API key configuration ──
    let mut store = AxonStoreInstance {
        name: "credentials".into(),
        ontology: "security".into(),
        entries: HashMap::new(),
        created_at: 1700000000,
        total_ops: 0,
    };

    let envelope = EpistemicEnvelope::raw_config("security", "admin");
    store.entries.insert("api_key_config".into(), AxonStoreEntry {
        key: "api_key_config".into(),
        value: serde_json::json!({"service": "external_api", "key": "sk-abc123", "tier": "production"}),
        envelope,
        created_at: 1700000000,
        updated_at: 1700000000,
        version: 1,
    });

    let stored = store.entries.get("api_key_config").unwrap();
    assert_eq!(stored.envelope.certainty, 1.0, "persisted config is raw");

    // ── Stage 2: Shield — validate the key doesn't leak in outputs ──
    let shield = ShieldInstance {
        name: "credential_guard".into(),
        mode: "output".into(),
        rules: vec![
            ShieldRule {
                id: "block_api_keys".into(), kind: "pattern".into(),
                value: "sk-*".into(), action: "block".into(),
                enabled: true, description: "Block API key leakage".into(),
            },
        ],
        created_at: 1700000000, total_evaluations: 0, total_blocks: 0,
    };

    // Test: output containing the key should be blocked
    let dangerous_output = format!("The API key is {}", stored.value["key"].as_str().unwrap());
    let shield_result = shield.evaluate(&dangerous_output);
    assert!(shield_result.blocked, "shield should block API key leakage");

    // Safe output should pass
    let safe_output = "API key configured for production tier";
    let safe_result = shield.evaluate(safe_output);
    assert!(!safe_result.blocked);

    // ── Stage 3: OTS — create one-time secret for secure key transfer ──
    let api_key = stored.value["key"].as_str().unwrap();
    let mut ots = OtsSecret {
        token: "ots_secure_transfer_1".into(),
        value: api_key.to_string(),
        consumed: false,
        created_at: 1700001000,
        ttl_secs: 300, // 5 minute TTL
        created_by: "credential_pipeline".into(),
        label: "api_key_transfer".into(),
    };

    let retrieved = ots.consume(1700001100).unwrap();
    assert_eq!(retrieved, "sk-abc123");
    assert!(ots.value.is_empty(), "value cleared after consume");

    // ── Stage 4: Mandate — authorize who can access credentials ──
    let policy = MandatePolicy {
        name: "credential_access".into(),
        description: "Controls access to credential store".into(),
        rules: vec![
            MandateRule {
                id: "admin_full".into(), subject: "admin".into(), action: "*".into(),
                resource: "/v1/axonstore/credentials/*".into(), effect: "allow".into(),
                priority: 100, enabled: true,
            },
            MandateRule {
                id: "operator_read_only".into(), subject: "operator".into(), action: "read".into(),
                resource: "/v1/axonstore/credentials/*".into(), effect: "allow".into(),
                priority: 50, enabled: true,
            },
            MandateRule {
                id: "deny_all_write".into(), subject: "*".into(), action: "write".into(),
                resource: "/v1/axonstore/credentials/*".into(), effect: "deny".into(),
                priority: 90, enabled: true,
            },
        ],
        created_at: 1700000000, total_evaluations: 0, total_denials: 0,
    };

    // Admin can do anything
    let admin = policy.evaluate("admin", "write", "/v1/axonstore/credentials/api_key");
    assert!(admin.allowed);

    // Operator can read but not write
    let op_read = policy.evaluate("operator", "read", "/v1/axonstore/credentials/api_key");
    assert!(op_read.allowed);
    let op_write = policy.evaluate("operator", "write", "/v1/axonstore/credentials/api_key");
    assert!(!op_write.allowed, "deny_all_write at priority 90 beats operator at 50");

    // ΛD Chain: axonstore(c=1.0 raw) → shield(c=0.85-0.95 derived) → ots(c=1.0 raw→void) → mandate(c=1.0 explicit)
    assert_eq!(stored.envelope.certainty, 1.0);
    assert_eq!(admin.certainty, 1.0);

    let chain_env = EpistemicEnvelope::derived("chain:axonstore→shield→ots→mandate", 0.99, "security_pipeline");
    assert!(chain_env.validate().is_ok());
}

