// ── K5.2: Resilience — Circuit breaker lifecycle ─────────────────────────

#[test]
fn test_k5_circuit_breaker_full_lifecycle() {
    use axon::circuit_breaker::{CircuitBreaker, CircuitState};
    use std::time::Duration;

    let mut cb = CircuitBreaker::new("test_provider", 3, 2, Duration::from_millis(20));

    // Phase 1: Closed state — calls pass through
    assert_eq!(cb.state(), CircuitState::Closed);
    assert!(cb.can_execute());

    // Phase 2: Accumulate failures until threshold
    cb.record_failure();
    cb.record_failure();
    assert_eq!(cb.state(), CircuitState::Closed);
    cb.record_failure(); // 3rd failure → Open
    assert_eq!(cb.state(), CircuitState::Open);

    // Phase 3: Open state — calls rejected
    assert!(!cb.can_execute());

    // Phase 4: Wait for cooldown → HalfOpen
    std::thread::sleep(Duration::from_millis(25));
    assert!(cb.can_execute());
    assert_eq!(cb.state(), CircuitState::HalfOpen);

    // Phase 5: Success in HalfOpen → accumulate toward close
    cb.record_success();
    assert_eq!(cb.state(), CircuitState::HalfOpen);
    cb.record_success(); // 2nd success → Closed
    assert_eq!(cb.state(), CircuitState::Closed);
}

#[test]
fn test_k5_circuit_breaker_half_open_failure_reopens() {
    use axon::circuit_breaker::{CircuitBreaker, CircuitState};
    use std::time::Duration;

    let mut cb = CircuitBreaker::new("test", 2, 2, Duration::from_millis(10));

    // Open the circuit
    cb.record_failure();
    cb.record_failure();
    assert_eq!(cb.state(), CircuitState::Open);

    // Wait for cooldown
    std::thread::sleep(Duration::from_millis(15));
    cb.can_execute(); // → HalfOpen

    // Failure in HalfOpen → back to Open
    cb.record_failure();
    assert_eq!(cb.state(), CircuitState::Open);
    assert_eq!(cb.total_opens(), 2);
}

// ── K5.3: Resilience — Retry policy ─────────────────────────────────────

#[test]
fn test_k5_retry_policy_backoff_escalation() {
    use axon::retry_policy::RetryPolicy;
    use std::time::Duration;

    let p = RetryPolicy {
        max_retries: 5,
        base_delay: Duration::from_millis(100),
        max_delay: Duration::from_secs(10),
        backoff_multiplier: 2.0,
        jitter: false,
    };

    let d0 = p.delay_for_attempt(0); // 100ms
    let d1 = p.delay_for_attempt(1); // 200ms
    let d2 = p.delay_for_attempt(2); // 400ms
    let d3 = p.delay_for_attempt(3); // 800ms

    assert_eq!(d0, Duration::from_millis(100));
    assert_eq!(d1, Duration::from_millis(200));
    assert_eq!(d2, Duration::from_millis(400));
    assert_eq!(d3, Duration::from_millis(800));

    // Verify escalation (each delay > previous)
    assert!(d1 > d0);
    assert!(d2 > d1);
    assert!(d3 > d2);
}

#[test]
fn test_k5_retry_policy_respects_rate_limit_hint() {
    use axon::retry_policy::RetryPolicy;
    use axon::backend_error::BackendErrorKind;
    use std::time::Duration;

    let p = RetryPolicy::default();
    let error = BackendErrorKind::RateLimit {
        retry_after: Some(Duration::from_secs(10)),
    };

    // Should use provider's hint, not calculated backoff
    let delay = p.effective_delay(0, &error);
    assert_eq!(delay, Duration::from_secs(10));
}

// ── K5.4: Resilience — Error classification ─────────────────────────────

#[test]
fn test_k5_error_classification_comprehensive() {
    use axon::backend_error::BackendErrorKind;

    // Status code classification
    assert!(matches!(BackendErrorKind::from_status(500), BackendErrorKind::ServerError { status: 500 }));
    assert!(matches!(BackendErrorKind::from_status(502), BackendErrorKind::ServerError { status: 502 }));
    assert!(matches!(BackendErrorKind::from_status(503), BackendErrorKind::ServerError { status: 503 }));
    assert!(matches!(BackendErrorKind::from_status(429), BackendErrorKind::RateLimit { .. }));
    assert!(matches!(BackendErrorKind::from_status(401), BackendErrorKind::AuthError));
    assert!(matches!(BackendErrorKind::from_status(403), BackendErrorKind::AuthError));
    assert!(matches!(BackendErrorKind::from_status(408), BackendErrorKind::Timeout));

    // Retryable classification
    assert!(BackendErrorKind::Timeout.is_retryable());
    assert!(BackendErrorKind::RateLimit { retry_after: None }.is_retryable());
    assert!(BackendErrorKind::ServerError { status: 500 }.is_retryable());
    assert!(BackendErrorKind::NetworkError.is_retryable());
    assert!(BackendErrorKind::StreamDropped.is_retryable());

    // Non-retryable classification
    assert!(!BackendErrorKind::AuthError.is_retryable());
    assert!(!BackendErrorKind::InvalidResponse.is_retryable());
    assert!(!BackendErrorKind::ProviderUnavailable.is_retryable());
    assert!(!BackendErrorKind::CircuitOpen.is_retryable());
}

