// ── K5.7: Persistence — Hibernation for Kivi KAS ────────────────────────

#[tokio::test]
async fn test_k5_hibernation_lifecycle_kivi_kas() {
    use axon::storage::{StorageBackend, StorageDispatcher, HibernationRow};

    let storage = StorageDispatcher::in_memory();

    // Create hibernation session for Kivi KAS agent
    let hib = HibernationRow {
        tenant_id: "default".into(),
        id: "kivi-agent-001".into(),
        name: "kivi_document_processor".into(),
        operation: "analyze_medical_research".into(),
        status: "active".into(),
        checkpoints: serde_json::json!([
            {"id": 0, "label": "document_ingested", "state": {"pages": 42}},
            {"id": 1, "label": "analysis_started", "state": {"sections_done": 3}}
        ]),
        resumed_from: None,
        created_at: 1700000000,
        last_status_change: 1700000000,
        next_checkpoint_id: 2,
    };

    assert!(storage.save_hibernation(&hib).await.is_ok());

    // Suspend the agent
    let suspended = HibernationRow {
        status: "suspended".into(),
        last_status_change: 1700001000,
        ..hib.clone()
    };
    assert!(storage.save_hibernation(&suspended).await.is_ok());

    // Resume from checkpoint
    let resumed = HibernationRow {
        status: "active".into(),
        resumed_from: Some(1),
        last_status_change: 1700002000,
        ..suspended
    };
    assert!(storage.save_hibernation(&resumed).await.is_ok());
}

